def _safe_str(value: Any) -> str:
    return "" if value is None else str(value).strip()

def money(x) -> float:
    return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

def _next_suffix(n: int) -> str:
    return f"-{n:02d}"

def _tb_signed(r: Dict[str, Any]) -> float:
    """Signed closing balance using TB convention: debit - credit."""
    dr, cr = _tb_dr_cr(r)
    return dr - cr


# ---------------------------
# Small numeric helper
# ---------------------------
def _d(x: Any) -> Decimal:
    """
    Safe Decimal coercion used across AR/GL reporting.
    Accepts None/''/numbers/Decimal/strings.
    """
    try:
        if x is None:
            return Decimal("0")
        if isinstance(x, Decimal):
            return x
        s = str(x).strip()
        if s == "":
            return Decimal("0")
        return Decimal(s)
    except Exception:
        return Decimal("0")

def _is_cash_bank_tb_row(r: Dict[str, Any]) -> bool:
    """
    Detect cash/bank TB rows.
    Use code_family when available (best), then fall back to name keywords.
    """
    fam = str(r.get("code_family") or "").upper().strip()
    name = str(r.get("name") or r.get("account_name") or "").lower()

    # If you tag cash in COA more explicitly later (is_cash_equiv), add it here too.
    if fam == "BS_CA":
        # still need to ensure it's actually cash/bank, not receivables etc.
        # so require cash/bank keywords:
        return ("cash" in name) or ("bank" in name)

    # fallback keywords
    return ("cash" in name) or ("bank" in name) or ("petty" in name)

def normalize_invoice_candidate(s: str) -> str:
    return s.upper().replace(" ", "").replace("_", "-")

def _parse_reporting_code(code: str) -> Tuple[Optional[str], Optional[int]]:
    """
    Parse codes like PL_OPEX_6001 -> ("PL_OPEX", 6001)
    """
    if not code:
        return (None, None)
    m = re.match(r"^([A-Z_]+)_(\d+)$", str(code).strip())
    if not m:
        return (None, None)
    return (m.group(1), int(m.group(2)))

# ------------------------------------------------------------
# Cashflow metadata derivation (authoritative)
# ------------------------------------------------------------
WC_BUCKETS = {
    "receivables", "payables", "inventory",
    "vat_input", "vat_output", "vat",         # keep vat optional alias
    "tax_payable", "tax_receivable",
    "prepaids", "deposits_paid", "deferred_revenue",
}

FIN_BUCKETS = {
    "debt", "overdraft",
    "lease_liability", "lease_principal", "loan_principal",
    "equity", "dividends", "owner_drawings", "share_capital",
}

INV_BUCKETS = {
    "ppe", "capex", "intangible", "software",
    "investment", "investment_property",
    "asset_purchase", "asset_sale",
    "rou_asset", "lease_receivable",
    "long_term_investment",
}

NONCASH_BUCKETS = {"depreciation", "amortization", "impairment"}

def _boolish(v: Any, default: bool = False) -> bool:
    if v is None:
        return default
    if isinstance(v, bool):
        return v
    s = str(v).strip().lower()
    if s in ("1", "true", "t", "yes", "y", "on"):
        return True
    if s in ("0", "false", "f", "no", "n", "off"):
        return False
    return default

def _norm_cf_section(v: Any) -> str:
    s = str(v or "").strip().lower()
    return s if s in ("operating", "investing", "financing", "none", "ignore") else ""

def _derive_cf_section_from_bucket(bucket: str) -> str:
    b = (bucket or "").strip().lower()
    if not b:
        return "operating"
    if b == "cash":
        return "none"
    if b in FIN_BUCKETS:
        return "financing"
    if b in INV_BUCKETS:
        return "investing"
    # WC + everything else defaults operating
    return "operating"

def _derive_flags_from_bucket(bucket: str) -> Dict[str, bool]:
    b = (bucket or "").strip().lower()
    return {
        "is_cash_equiv": (b == "cash"),
        "is_working_capital": (b in WC_BUCKETS),
        "is_non_cash_addback": (b in NONCASH_BUCKETS),
    }

def _apply_cf_metadata(row: Dict[str, Any]) -> None:
    b = (row.get("cf_bucket") or "").strip().lower()
    flags = _derive_flags_from_bucket(b)

    # If caller already set flags explicitly, respect them;
    # otherwise fill them from bucket.
    row["is_cash_equiv"] = _boolish(row.get("is_cash_equiv"), flags["is_cash_equiv"])
    row["is_working_capital"] = _boolish(row.get("is_working_capital"), flags["is_working_capital"])
    row["is_non_cash_addback"] = _boolish(row.get("is_non_cash_addback"), flags["is_non_cash_addback"])

    # ✅ Section: bucket wins (prevents "loan under operating")
    derived = _derive_cf_section_from_bucket(b)
    row["cf_section"] = derived

def _resolve_role(row: Dict[str, Any]) -> str:
    existing_role = (
        " ".join(str(row.get("role") or "").split())
        .strip()
        .lower()
        .replace(" ", "_")
    )

    if existing_role:
        return existing_role

    return ac._coa_role_from_text(
        row.get("name", ""),
        row.get("section", ""),
        row.get("category", ""),
        row.get("subcategory", ""),
        row.get("standard", ""),
    )

def _money(x) -> Decimal:
    return Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

def _safe_date(x):
    if x is None or x == "":
        return None
    if isinstance(x, date):
        return x
    return datetime.strptime(str(x), "%Y-%m-%d").date()

def _normalize_coa_rows_codes(
    rows: List[Any],
    reserved_codes: Optional[set] = None,
    existing_codes: Optional[set] = None,
) -> List[Dict[str, Any]]:
    """
    Normalizes COA rows into canonical reporting codes:
      code_family + code_numeric + code (e.g., BS_CA_1000, PL_OPEX_6002)

    Key rules:
    - template_code MUST come from input template_code (not from input code)
    - output code is always generated via bucket + numeric: ac._make_reporting_code(bucket, code_numeric)
    - preserves input role if provided; otherwise derives role from text
    - supports dict rows and tuple/list rows (with a best-effort mapping)
    - NOTE: reserved_codes/existing_codes should contain FULL reporting codes like 'BS_CA_1410'
            (raw '1410' will not reserve unless your _parse_reporting_code supports it)
    """
    reserved_codes = reserved_codes or set()
    existing_codes = existing_codes or set()

    out: List[Dict[str, Any]] = []
    next_num_by_bucket: Dict[str, int] = {}
    used_numeric_by_bucket: Dict[str, set] = {}

    def is_locked_reporting_code(c: str) -> bool:
        c = (c or "").strip()
        return c in reserved_codes

    def mark_used(c: str) -> None:
        fam, num = _parse_reporting_code(c)
        if fam and num is not None:
            used_numeric_by_bucket.setdefault(fam, set()).add(num)

    # Prime "used" map with anything already in the company COA + reserved codes
    for c in (existing_codes | reserved_codes):
        mark_used(str(c))

    def _boolish(v: Any, default: bool = False) -> bool:
        if v is None:
            return default
        if isinstance(v, bool):
            return v
        s = str(v).strip().lower()
        if s in ("1", "true", "t", "yes", "y", "on"):
            return True
        if s in ("0", "false", "f", "no", "n", "off"):
            return False
        return default

    def _as_int(v: Any) -> Optional[int]:
        try:
            if v is None or v == "":
                return None
            return int(v)
        except Exception:
            return None

    # ------------------------------------------------------------
    # Row parser: supports dict OR tuple/list.
    # If tuple/list, we attempt best-effort mapping; adjust indexes
    # if your tuple schema differs.
    # ------------------------------------------------------------
    def make_row_dict(r: Any) -> Dict[str, Any]:
        # ✅ DICT rows (pool-first seeding uses dicts)
        if isinstance(r, dict):
            # keep everything + ensure keys exist
            d = dict(r)
            # normalize common keys so downstream code doesn't KeyError
            d.setdefault("subcategory", "")
            d.setdefault("reporting_description", "")
            d.setdefault("posting", True)
            d.setdefault("posting_rules", "")
            d.setdefault("cf_section", "operating")
            d.setdefault("cf_bucket", "")
            d.setdefault("is_working_capital", False)
            d.setdefault("is_cash_equiv", False)
            d.setdefault("is_non_cash_addback", False)
            d.setdefault("is_contra", False)
            d.setdefault("role", "")

            # ✅ CRITICAL: preserve scoped identifier
            d.setdefault("template_code_scoped", r.get("template_code_scoped"))
            return d

        # tuple/list rows
        if isinstance(r, (list, tuple)):
            def g(i: int, default: Any = "") -> Any:
                return r[i] if len(r) > i else default

            # CASE 1: build_coa style tuple (len == 6)
            if len(r) == 6:
                base = _safe_str(g(1, ""))
                return {
                    "name": _safe_str(g(0, "")),
                    "code": base,
                    "category": _safe_str(g(2, "")),
                    "section": _safe_str(g(3, "")),
                    "subcategory": "",
                    "description": _safe_str(g(4, "")),
                    "reporting_description": "",
                    "standard": _safe_str(g(5, "")),
                    "template_code": base,
                    "template_code_scoped": None,   # ✅ not available in this tuple shape
                    "code_family": "",
                    "code_numeric": None,
                    "cf_section": "operating",
                    "cf_bucket": "",
                    "posting": True,
                    "posting_rules": "",
                    "is_working_capital": False,
                    "is_cash_equiv": False,
                    "is_non_cash_addback": False,
                    "is_contra": False,
                    "role": "",
                }

            # CASE 2: long tuple/list (pool/db style)
            return {
                "name": _safe_str(g(0, "")),
                "code": _safe_str(g(1, "")),
                "category": _safe_str(g(2, "")),
                "section": _safe_str(g(3, "")),
                "description": _safe_str(g(4, "")),
                "reporting_description": _safe_str(g(5, "")),
                "standard": _safe_str(g(6, "")),
                "template_code": _safe_str(g(7, "")),
                "template_code_scoped": _safe_str(g(8, "")),  # ✅ if your tuple includes it here
                "subcategory": _safe_str(g(9, "")),

                "code_family": _safe_str(g(10, "")) if isinstance(g(10, ""), str) else "",
                "code_numeric": g(11, None),
                "cf_section": _safe_str(g(12, "operating")),
                "cf_bucket": _safe_str(g(13, "")),
                "posting": _boolish(g(14, True), True),
                "posting_rules": _safe_str(g(15, "")),
                "is_working_capital": _boolish(g(16, False), False),
                "is_cash_equiv": _boolish(g(17, False), False),
                "is_non_cash_addback": _boolish(g(18, False), False),
                "is_contra": _boolish(g(19, False), False),
                "role": _safe_str(g(20, "")),
            }

        # Unknown type
        return {
            "name": "",
            "code": "",
            "category": "",
            "section": "",
            "subcategory": "",
            "description": "",
            "reporting_description": "",
            "standard": "",
            "template_code": "",
            "template_code_scoped": None,  # ✅
            "code_family": "",
            "code_numeric": None,
            "cf_section": "operating",
            "cf_bucket": "",
            "posting": True,
            "posting_rules": "",
            "is_working_capital": False,
            "is_cash_equiv": False,
            "is_non_cash_addback": False,
            "is_contra": False,
            "role": "",
        }

    def in_bucket_range(bucket: str, n: int) -> bool:
        base = ac.BUCKET_BASE.get(bucket)
        if base is None:
            return False
        return base <= n < (base + 1000)

    def allocate_numeric(bucket: str) -> int:
        base = ac.BUCKET_BASE.get(bucket, 9000)
        used = used_numeric_by_bucket.setdefault(bucket, set())

        ptr = next_num_by_bucket.get(bucket, base)
        if ptr < base:
            ptr = base

        while ptr in used:
            ptr += 1

        used.add(ptr)
        next_num_by_bucket[bucket] = ptr + 1
        return ptr

    # ------------------------------------------------------------
    # Main normalize loop
    # ------------------------------------------------------------
    for r in rows:
        row = make_row_dict(r)

        # ✅ NORMALIZE SECTION LABELS EARLY (before bucket + role)
        sec = (row.get("section") or "").strip().lower()
        if sec in ("assets", "asset"):
            row["section"] = "Asset"
        elif sec in ("liabilities", "liability"):
            row["section"] = "Liability"
        elif sec in ("equity",):
            row["section"] = "Equity"
        elif sec in ("income", "revenue"):
            row["section"] = "Income"
        elif sec in ("expense", "expenses"):
            row["section"] = "Expense"
        elif sec in ("profit or loss", "p&l"):
            row["section"] = "Profit or Loss"
        elif sec in ("adjustment", "adjustments"):
            row["section"] = "Adjustment"

        # ... then your existing code continues
        tcs_raw = (row.get("template_code_scoped") or "").strip()
        row["template_code_scoped"] = tcs_raw or None
        row["source_code"] = row.get("code", "")
        template_code_raw = (row.get("template_code") or "").strip()

        bucket = _bucket_from_category_section(
            row.get("category", ""),
            row.get("section", ""),       # ✅ now normalized
            row.get("subcategory", ""),
            row.get("standard", ""),
        )

        # ✅ carry scoped identifier if present (pool-first seeding)
        tcs_raw = (row.get("template_code_scoped") or "").strip()
        row["template_code_scoped"] = tcs_raw or None

        # Preserve incoming code (if any) for debugging / migration analysis
        row["source_code"] = row.get("code", "")

        # ✅ semantic identifier MUST come from template_code, not code
        template_code_raw = (row.get("template_code") or "").strip()

        # ✅ If the incoming code is a reserved/control reporting code, KEEP IT.
        src_code = (row.get("source_code") or "").strip()
        if is_locked_reporting_code(src_code):
            fam, num = _parse_reporting_code(src_code)
            if not fam or num is None:
                raise ValueError(
                    f"Reserved code '{src_code}' could not be parsed by _parse_reporting_code"
                )

            required_template_by_code = {
                "BS_CA_1000": "1000",
               
                "BS_CL_2105": "2105",
                "BS_CA_1410": "1410",
                "BS_CL_2310": "2310",
            }

            expected_tc = required_template_by_code.get(src_code)
            actual_tc = (row.get("template_code") or "").strip() or None

            # Critical: do NOT allow a wrong semantic row to keep a reserved code
            if expected_tc and actual_tc != expected_tc:
                raise RuntimeError(
                    f"Reserved reporting code misuse: code={src_code!r} "
                    f"name={row.get('name')!r} template_code={actual_tc!r} "
                    f"expected_template_code={expected_tc!r}"
                )

            used_numeric_by_bucket.setdefault(fam, set()).add(int(num))
            next_num_by_bucket[fam] = max(
                next_num_by_bucket.get(fam, ac.BUCKET_BASE.get(fam, 0)),
                int(num) + 1
            )

            row["template_code"] = actual_tc
            row["code_family"] = fam
            row["code_numeric"] = int(num)
            row["code"] = src_code

            existing_codes.add(src_code)

            row["role"] = _resolve_role(row)

            out.append(row)
            continue

        # Use None for blank template_code (better than 'UNMAPPED' in DB)
        template_code: Optional[str] = template_code_raw if template_code_raw else None

        bucket = _bucket_from_category_section(
            row.get("category", ""),
            row.get("section", ""),
            row.get("subcategory", ""),
            row.get("standard", ""),
        )

        # ✅ Fill cf_bucket if missing/blank
        if not (row.get("cf_bucket") or "").strip():
            row["cf_bucket"] = ac._cf_bucket_from_text(
                row.get("name",""),
                row.get("category",""),
                row.get("section",""),
                row.get("subcategory",""),
                row.get("standard",""),
            )

        _apply_cf_metadata(row)

        # Determine numeric for reporting code:
        # - prefer numeric template_code if it fits bucket range and not used
        # - else allocate within bucket
        code_numeric: Optional[int] = None
        if template_code and template_code.isdigit():
            n = int(template_code)
            if in_bucket_range(bucket, n) and (n not in used_numeric_by_bucket.get(bucket, set())):
                code_numeric = n
                used_numeric_by_bucket.setdefault(bucket, set()).add(n)

        if code_numeric is None:
            # Also allow explicit code_numeric from input if valid and unused
            explicit = _as_int(row.get("code_numeric"))
            if explicit is not None and in_bucket_range(bucket, explicit) and (
                explicit not in used_numeric_by_bucket.get(bucket, set())
            ):
                code_numeric = explicit
                used_numeric_by_bucket.setdefault(bucket, set()).add(explicit)
            else:
                code_numeric = allocate_numeric(bucket)

        reporting_code = ac._make_reporting_code(bucket, code_numeric)

        # ✅ Auto-mark contra accounts
        def _s(v):
            return "" if v is None else str(v)

        txt = " ".join([
            _s(row.get("name")),
            _s(row.get("category")),
            _s(row.get("subcategory")),
            _s(row.get("description")),
            _s(row.get("reporting_description")),
        ]).lower()

        if "accumulated depreciation" in txt or "accum depreciation" in txt or "contra-asset" in txt:
            row["is_contra"] = True

        if any(k in txt for k in ("accumulated depreciation", "accum depreciation", "accum dep", "contra-asset", "contra asset")):
            row["is_contra"] = True

        # Ensure uniqueness vs existing/reserved
        if reporting_code in existing_codes or reporting_code in reserved_codes:
            while True:
                code_numeric = allocate_numeric(bucket)
                reporting_code = ac._make_reporting_code(bucket, code_numeric)
                if reporting_code not in existing_codes and reporting_code not in reserved_codes:
                    break

        existing_codes.add(reporting_code)

        # Persist normalized fields
        row["template_code"] = template_code  # keep semantic ID (or None)
        row["code_family"] = bucket
        row["code_numeric"] = code_numeric
        row["code"] = reporting_code
        row["normal_side"] = ac.NORMAL_SIDE.get(bucket, "debit")
        row["allow_opposite"] = bool(ac.ALLOW_OPPOSITE_BY_FAMILY.get(bucket, False))

        # ✅ preserve explicit role; otherwise derive from text
        row["role"] = _resolve_role(row)

        out.append(row)

    return out


