def _bucket_from_category_section(category: str, section: str, subcategory: str = "", standard: str = "") -> str:
    raw_cat = (category or "").strip().lower()
    cat = raw_cat
    sec = (section or "").strip().lower()
    sub = (subcategory or "").strip().lower()
    std = (standard or "").strip().lower()

    # include raw_cat so keywords survive later normalization
    text = " ".join(x for x in (raw_cat, sec, sub, std) if x)

    def has_any(*keys: str) -> bool:
        return any(k in text for k in keys)

    # ---- PL shortcuts first ----
    if cat in ("cost of sales", "cost of revenue", "cogs"):
        return "PL_COS"

    if cat in ("other income", "other operating income", "non-operating income"):
        return "PL_OI"
    
    # ✅ Contra-revenue / revenue adjustments (must be BEFORE revenue)
    if cat in (
        "revenue adjustments",
        "sales discounts",
        "sales rebates",
        "returns and allowances",
        "sales returns & allowances",
    ):
        return "PL_REV_ADJ"

    if cat in ("income", "revenue"):
        if has_any("grant", "grants"):
            return "PL_GNT"
        if has_any("donation", "donations"):
            return "PL_DON"
        if has_any("other income", "interest income", "fx gain", "foreign exchange gain", "gain on disposal"):
            return "PL_OI"
        return "PL_REV"

    if cat == "expense":
        if has_any("cost of sales", "cost of revenue", "direct cost", "materials", "subcontractor", "freight-in"):
            return "PL_COS"
        if has_any("depreciation", "amortization", "amortisation", "impairment"):
            return "PL_DA"
        if has_any("interest expense", "finance cost", "fx loss", "foreign exchange loss"):
            return "PL_FIN"
        if has_any("adjust", "reclass", "opening balance adjustment", "year-end reclassification"):
            return "PL_ADJ"
        return "PL_OPEX"

    if cat == "adjustment":
        return "PL_ADJ"

    if cat == "equity" or has_any("equity", "capital", "retained", "reserves", "share capital", "share premium", "drawings"):
        return "BS_EQ"

    if cat == "liability":
        if has_any("non-current", "non current", "long-term", "long term", "maturity > 12"):
            return "BS_NCL"
        return "BS_CL"

    # 🔒 ABSOLUTE: UI Group/category wins CA vs NCA
    if raw_cat in ("non-current assets", "non current assets", "non-current asset", "non current asset"):
        return "BS_NCA"
    if raw_cat in ("current assets", "current asset"):
        return "BS_CA"

    # Normalize common asset groups into "asset"
    if cat in (
        "current assets",
        "non-current assets", "non current assets",
        "property, plant & equipment", "property, plant and equipment",
        "investment property", "investment properties",
        "ppe",
        "intangible assets",
        "cash & equivalents", "cash and equivalents",
        "accumulated depreciation",
    ):
        cat = "asset"

    if cat == "asset":
        # IAS 40 / investment property is non-current
        if has_any("ias 40", "ias40", "investment property"):
            return "BS_NCA"

        if has_any("cash & equivalents", "cash and equivalents", "cash", "bank", "petty cash"):
            return "BS_CA"

        if has_any("accumulated depreciation", "accum depreciation", "acc dep"):
            return "BS_NCA"

        if has_any("lease receivable"):
            if has_any("non-current", "non current", "long-term", "long term", "due after 12 months", "after 12 months"):
                return "BS_NCA"
            if has_any("current", "within 12 months", "due within 12 months", "short-term", "short term"):
                return "BS_CA"
            return "BS_CA"

        is_ppe_like = has_any(
            "ppe", "property, plant", "plant & equipment", "equipment", "machinery",
            "motor vehicle", "vehicles", "buildings", "land", "furniture", "fixtures",
            "intangible", "software", "goodwill", "right-of-use", "right of use", "rou"
        )
        is_ppe_standard = has_any("ias 16", "ias16", "ias 38", "ias38", "ias 40", "ias40")

        if is_ppe_like or is_ppe_standard or has_any("non-current", "non current", "long-term", "long term"):
            return "BS_NCA"

        return "BS_CA"

    # ---- fallbacks ----
    if has_any("cost of sales", "cost of revenue", "direct cost", "cogs"):
        return "PL_COS"

    if has_any("revenue", "sales revenue", "turnover") and not has_any("other income"):
        return "PL_REV"

    if has_any("liab", "liabil", "payable", "creditor", "accrued", "provision", "lease liability"):
        if has_any("non-current", "non current", "long-term", "long term"):
            return "BS_NCL"
        return "BS_CL"

    if has_any("asset", "assets", "cash", "bank", "inventory", "vat input", "receivable", "prepaid"):
        return "BS_CA"

    return "PL_OPEX"


