def _tb_dr_cr(r: Dict[str, Any]) -> Tuple[float, float]:
    """
    Supports both TB shapes:
      - ledger TB: debit / credit
      - snapshot/meta TB: debit_total / credit_total
    """
    if r.get("debit_total") is not None or r.get("credit_total") is not None:
        return float(r.get("debit_total") or 0.0), float(r.get("credit_total") or 0.0)
    return float(r.get("debit") or 0.0), float(r.get("credit") or 0.0)



class DatabaseService:
    """
    Thin Postgres helper focused on users, companies, per-company COA/ledger,
    and lease schedules.
    Returns dicts via RealDictCursor for convenience.
    """

    def __init__(self, dsn: str):
        self.dsn = dsn
        self.pool = SimpleConnectionPool(
            minconn=1,
            maxconn=10,
            dsn=dsn,
        )

    @contextmanager
    def transaction(self):
        conn = self.pool.getconn()
        try:
            conn.autocommit = False
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                yield conn, cur
            conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            self.pool.putconn(conn)

    @contextmanager
    def _conn_cursor(self, *, ddl: bool = False):
        conn = None
        try:
            conn = self.pool.getconn()

            try:
                if conn.closed:
                    raise Exception("pooled connection already closed")
                with conn.cursor() as ping_cur:
                    ping_cur.execute("SELECT 1")
                    ping_cur.fetchone()
            except Exception:
                try:
                    if conn is not None:
                        self.pool.putconn(conn, close=True)
                except Exception:
                    pass
                conn = psycopg2.connect(self.dsn)
                conn.autocommit = False

            try:
                with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                    if ddl:
                        cur.execute("SET LOCAL lock_timeout = '60s';")
                        cur.execute("SET LOCAL statement_timeout = '0';")
                    else:
                        cur.execute("SET LOCAL lock_timeout = '5s';")
                        cur.execute("SET LOCAL statement_timeout = '60s';")

                    yield conn, cur

                conn.commit()   # ✅ commit on success

            except Exception:
                try:
                    conn.rollback()
                except Exception:
                    pass
                raise

        finally:
            if conn is not None:
                try:
                    if getattr(conn, "closed", 1):
                        try:
                            self.pool.putconn(conn, close=True)
                        except Exception:
                            pass
                    else:
                        self.pool.putconn(conn)
                except Exception:
                    pass

    def execute_sql(
        self,
        sql: str,
        params: Tuple[Any, ...] = (),
        *,
        cur=None,
        conn=None,
        commit: bool = True,
    ) -> Optional[int]:
        def _extract_returning(_cur) -> Optional[int]:
            row = _cur.fetchone()
            if not row:
                return None
            if isinstance(row, dict):
                if "id" in row:
                    return int(row["id"])
                if len(row) == 1:
                    return int(next(iter(row.values())))
            if isinstance(row, (tuple, list)) and len(row) >= 1:
                return int(row[0])
            return None

        if cur is not None:
            cur.execute(sql, params)

            if cur.description is not None:
                out = _extract_returning(cur)
                if commit and conn is not None:
                    conn.commit()
                return out

            if commit and conn is not None:
                conn.commit()
            return None

        with self._conn_cursor() as (conn2, cur2):
            cur2.execute(sql, params)

            if cur2.description is not None:
                out = _extract_returning(cur2)
                if commit:
                    conn2.commit()
                return out

            if commit:
                conn2.commit()
            return None


    def fetch_one(
        self,
        sql: str,
        params: ParamsType = (),
        cur=None,
    ) -> Optional[Dict[str, Any]]:
        exec_params = None

        if params is None:
            exec_params = None
        elif isinstance(params, dict):
            exec_params = params
        elif isinstance(params, tuple):
            exec_params = params if len(params) else None
        elif isinstance(params, list):
            exec_params = tuple(params) if len(params) else None
        else:
            exec_params = (params,)

        def _run(_cur):
            if exec_params is None:
                _cur.execute(sql)
            else:
                _cur.execute(sql, exec_params)

            if _cur.description is None:
                return None

            row = _cur.fetchone()
            return dict(row) if row else None

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (_c, _cur):
            return _run(_cur)

    def fetch_all(
        self,
        sql: str,
        params: ParamsType = (),
        cur=None,
    ) -> list[Dict[str, Any]]:
        exec_params = None

        if isinstance(params, dict) and "%(" not in sql:
            raise TypeError(
                "Named params dict provided, but SQL uses %s placeholders. "
                "Use tuple/list params or change SQL to %(name)s."
            )

        if params is None:
            exec_params = None
        elif isinstance(params, dict):
            exec_params = params
        elif isinstance(params, tuple):
            exec_params = params if len(params) else None
        elif isinstance(params, list):
            exec_params = tuple(params) if len(params) else None
        else:
            exec_params = (params,)

        def _run(_cur):
            try:
                if exec_params is None:
                    _cur.execute(sql)
                else:
                    _cur.execute(sql, exec_params)
            except Exception as e:
                try:
                    placeholders = sql.count("%s")
                except Exception:
                    placeholders = None

                try:
                    current_app.logger.exception(
                        "[DB] fetch_all FAILED | placeholders=%s | params=%s | sql=%s",
                        placeholders,
                        exec_params,
                        sql,
                    )
                except Exception:
                    print("\n[DB] fetch_all FAILED")
                    print("[DB] Error:", repr(e))
                    print("[DB] Placeholders:", placeholders)
                    print("[DB] Params:", exec_params)
                    print("[DB] SQL:\n", sql)
                    print("[DB] ---\n")

                raise

            if _cur.description is None:
                return []

            rows = _cur.fetchall()
            return [dict(r) for r in rows]

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (_c, _cur):
            return _run(_cur)

    def fetch_val(
        self,
        sql: str,
        params: ParamsType = (),
        cur=None,
    ) -> Any:
        """
        Execute a SELECT and return the first column of the first row.
        If cur is provided, uses it.
        """

        exec_params = None

        if params is None:
            exec_params = None
        elif isinstance(params, dict):
            exec_params = params
        elif isinstance(params, tuple):
            exec_params = params if len(params) else None
        elif isinstance(params, list):
            exec_params = tuple(params) if len(params) else None
        else:
            exec_params = (params,)

        def _run(_cur):
            try:
                if exec_params is None:
                    _cur.execute(sql)
                else:
                    _cur.execute(sql, exec_params)
            except Exception as e:
                try:
                    placeholders = sql.count("%s")
                except Exception:
                    placeholders = None

                print("\n[DB] fetch_val FAILED")
                print("[DB] Error:", repr(e))
                print("[DB] Placeholders:", placeholders)

                if isinstance(exec_params, dict):
                    print("[DB] Params type: dict")
                    print("[DB] Params keys:", list(exec_params.keys()))
                    print("[DB] Params:", exec_params)
                else:
                    print("[DB] Params len:", (len(exec_params) if exec_params else 0))
                    print("[DB] Params:", exec_params)

                print("[DB] SQL:\n", sql)
                print("[DB] ---\n")
                raise

            row = _cur.fetchone()
            if not row:
                return None
            if isinstance(row, dict):
                return next(iter(row.values()))
            return row[0]

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (_c, _cur):
            return _run(_cur)

    def company_schema(self, company_id: int) -> str:
        return f"company_{int(company_id)}"

    def _split_sql_statements(self, sql: str) -> List[str]:
        """
        Split on semicolons, but NOT inside:
          - dollar-quoted blocks $$...$$ (your DO blocks)
          - single quotes '...'
          - double quotes "..."
        """
        out: List[str] = []
        buf: List[str] = []

        in_single = False
        in_double = False
        in_dollar = False

        i = 0
        n = len(sql)

        while i < n:
            ch = sql[i]
            nxt2 = sql[i:i + 2]

            # Toggle dollar-quote on $$
            if not in_single and not in_double and nxt2 == "$$":
                in_dollar = not in_dollar
                buf.append("$$")
                i += 2
                continue

            # Toggle single quotes (handle escaped '')
            if not in_dollar and ch == "'" and not in_double:
                if i + 1 < n and sql[i + 1] == "'":  # escaped ''
                    buf.append("''")
                    i += 2
                    continue
                in_single = not in_single
                buf.append(ch)
                i += 1
                continue

            # Toggle double quotes
            if not in_dollar and ch == '"' and not in_single:
                in_double = not in_double
                buf.append(ch)
                i += 1
                continue

            # Split on ; only when not in any quote/dollar block
            if ch == ";" and not in_single and not in_double and not in_dollar:
                stmt = "".join(buf).strip()
                buf = []
                if self._is_executable_sql(stmt):
                    out.append(stmt)
                i += 1
                continue

            buf.append(ch)
            i += 1

        tail = "".join(buf).strip()
        if self._is_executable_sql(tail):
            out.append(tail)

        return out

    def _is_executable_sql(self, stmt: str) -> bool:
        """
        True if stmt has something executable after removing -- comments/blank lines.
        Prevents: "can't execute an empty query"
        """
        if not stmt.strip():
            return False

        cleaned_lines = []
        for line in stmt.splitlines():
            ln = line.strip()
            if not ln or ln.startswith("--"):
                continue
            ln = re.sub(r"\s--.*$", "", ln).strip()  # strip trailing inline comment
            if ln:
                cleaned_lines.append(ln)

        return bool(cleaned_lines)

    def _rewrite_lines_guarding_ar(self, company_id: int, lines: list) -> list:
        DEPOSIT_CODE = "BS_CL_2205"  # choose your real "Customer deposits / Unearned revenue"

        coa_map = self.get_coa_map(company_id)  # {code: {..., role:"ar"}}

        new_lines = []
        for ln in (lines or []):
            code = (ln.get("account_code") or "").strip()
            dr = float(ln.get("debit") or 0.0)
            cr = float(ln.get("credit") or 0.0)

            role = (coa_map.get(code, {}).get("role") or "").lower()

            # Guard ONLY: credit to AR
            if role == "ar" and cr > 0:
                outstanding = max(0.0, self.get_account_balance_from_tb(company_id, code))  # debit - credit

                if outstanding <= 0:
                    new_lines.append({
                        **ln,
                        "account_code": DEPOSIT_CODE,
                        "debit": 0.0,
                        "credit": cr,
                        "description": (ln.get("description") or "") + " (auto: AR overpayment -> deposits)"
                    })
                    continue

                if cr > outstanding:
                    new_lines.append({
                        **ln,
                        "account_code": code,
                        "debit": 0.0,
                        "credit": outstanding,
                        "description": (ln.get("description") or "") + " (auto: capped to AR outstanding)"
                    })
                    excess = cr - outstanding
                    new_lines.append({
                        **ln,
                        "account_code": DEPOSIT_CODE,
                        "debit": 0.0,
                        "credit": excess,
                        "description": (ln.get("description") or "") + " (auto: excess -> deposits)"
                    })
                    continue

            new_lines.append(ln)

        return new_lines


    def get_coa_map(self, company_id: int) -> Dict[str, Dict[str, Any]]:
        schema = self.company_schema(company_id)
        rows = self.fetch_all(f"SELECT code, role, code_family FROM {schema}.coa", ())
        return {r["code"]: r for r in (rows or [])}

    def approve_invoice(self, company_id, invoice_id, user_id, cur=None):
        schema = f"company_{company_id}"
        sql = f"""
        UPDATE {schema}.invoices
        SET status='approved', updated_at=NOW()
        WHERE id=%s AND status='draft'
        """
        if cur is not None:
            cur.execute(sql, (int(invoice_id),))
            return
        self.execute_sql(sql, (int(invoice_id),))

