        # -----------------------------
        cash_bank_def   = REQUIRED_CONTROL_TEMPLATES["1000"]["code"]
        ar_default      = REQUIRED_CONTROL_TEMPLATES["9002"]["code"]  # BS_CA_9002
        vat_out_def     = REQUIRED_CONTROL_TEMPLATES["2310"]["code"]  # BS_CL_2310
