        wht_payable_def = REQUIRED_CONTROL_TEMPLATES["2360"]["code"]  # BS_CL_2360
        grni_def        = REQUIRED_CONTROL_TEMPLATES["2215"]["code"]  # BS_CL_2215
        inventory_def   = REQUIRED_CONTROL_TEMPLATES["1500"]["code"]  # BS_CA_1500
        ppv_def         = REQUIRED_CONTROL_TEMPLATES["5305"]["code"]  # (your template key)

        ap_default      = REQUIRED_CONTROL_TEMPLATES["2200"]["code"]  # BS_CL_2200

        # Discounts / unallocated
        unalloc_receipts_def = REQUIRED_CONTROL_TEMPLATES["2350"]["code"]  # BS_CL_2350
