    def ensure_bill_grni_link_table(self, company_id: int):
        schema = self.company_schema(company_id)

        self.execute_sql(f"""
        CREATE TABLE IF NOT EXISTS {schema}.bill_grni_links (
        id SERIAL PRIMARY KEY,
        company_id INT NOT NULL,
        bill_id INT NOT NULL,
        receipt_tx_id INT NOT NULL,               -- inventory_tx.id
        amount NUMERIC(18,2) NOT NULL DEFAULT 0,  -- how much GRNI to clear
        created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
        );
        """)

        self.execute_sql(f"""
        CREATE INDEX IF NOT EXISTS bill_grni_links_bill_idx
        ON {schema}.bill_grni_links(company_id, bill_id);
        """)

        self.execute_sql(f"""
        CREATE INDEX IF NOT EXISTS bill_grni_links_tx_idx
        ON {schema}.bill_grni_links(company_id, receipt_tx_id);
        """)

    def ensure_asset_grni_link_table(self, company_id: int):
        schema = self.company_schema(company_id)

        # -------------------------------------------------
        # 1) Table
        # -------------------------------------------------
        self.execute_sql(f"""
        CREATE TABLE IF NOT EXISTS {schema}.asset_grni_links (
            id SERIAL PRIMARY KEY,
            company_id INT NOT NULL,

            asset_id INT NOT NULL,          -- PPE asset
            receipt_tx_id INT NOT NULL,    -- inventory_tx.id (GRN)

            amount NUMERIC(18,2) NOT NULL DEFAULT 0,

            created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
        );
        """)

        # -------------------------------------------------
        # 2) Indexes
        # -------------------------------------------------
        self.execute_sql(f"""
        CREATE INDEX IF NOT EXISTS asset_grni_links_asset_idx
        ON {schema}.asset_grni_links(company_id, asset_id);
        """)

        self.execute_sql(f"""
        CREATE INDEX IF NOT EXISTS asset_grni_links_tx_idx
        ON {schema}.asset_grni_links(company_id, receipt_tx_id);
        """)

        # -------------------------------------------------
        # 3) FK → assets
        # -------------------------------------------------
        self.execute_sql(f"""
        DO $$
        BEGIN
            IF NOT EXISTS (
                SELECT 1
                FROM pg_constraint c
                JOIN pg_namespace n ON n.oid = c.connamespace
                WHERE c.conname = 'fk_asset_grni_asset'
                AND n.nspname = '{schema}'
            ) THEN
                EXECUTE format(
                    'ALTER TABLE %I.asset_grni_links
                    ADD CONSTRAINT fk_asset_grni_asset
                    FOREIGN KEY (asset_id)
                    REFERENCES %I.assets(id)',
                    '{schema}',
                    '{schema}'
                );
            END IF;
        END $$;

        """)

        # -------------------------------------------------
        # 4) FK → inventory_tx
        # -------------------------------------------------
        self.execute_sql(f"""
        DO $$
        BEGIN
            IF NOT EXISTS (
                SELECT 1
                FROM pg_constraint c
                JOIN pg_namespace n ON n.oid = c.connamespace
                WHERE c.conname = 'fk_asset_grni_tx'
                AND n.nspname = '{schema}'
            ) THEN
                EXECUTE format(
                    'ALTER TABLE %I.asset_grni_links
                    ADD CONSTRAINT fk_asset_grni_tx
                    FOREIGN KEY (receipt_tx_id)
                    REFERENCES %I.inventory_tx(id)',
                    '{schema}',
                    '{schema}'
                );
            END IF;
        END $$;

        """)

    def execute_values(self, sql: str, values: list[tuple], page_size: int = 500) -> int:
        """
        Bulk insert/update helper. Returns cursor.rowcount where available.
        """
        if not values:
            return 0
        with self._conn_cursor() as (_c, cur):
            execute_values(cur, sql, values, page_size=page_size)
            return cur.rowcount

    def get_company_control_accounts(self, company_id: int) -> Dict[str, Any]:
        """
        Returns the account settings row for a company.
        Source of truth: public.company_account_settings
        """
        self.initialize_public_schema()  # safe; ensures table exists
        self.ensure_company_account_settings(company_id)
        self.ensure_company_account_settings_defaults(company_id)

        row = self.fetch_one("""
            SELECT
                company_id,
                ar_control_code,
                ap_control_code,
                vat_output_code,
                vat_input_code,
                sales_discount_code,
                purchases_discount_code,
                unallocated_receipts_code,
                unallocated_payments_code,
                grni_control_code,
                ppv_control_code,
                wht_payable_code,
                inventory_control_code,

                -- IFRS 16
                lease_rou_asset_code,
                lease_liability_current_code,
                lease_liability_non_current_code,
                lease_interest_expense_code,
                lease_amortization_code,
                lease_accumulated_depreciation_code,
                             
                lease_bank_account_code,

                updated_at
            FROM public.company_account_settings
            WHERE company_id=%s
            LIMIT 1;
        """, (company_id,))

        return row or {}

    def set_company_control_accounts(
        self,
        company_id: int,
        *,
        ar_control_code: str | None = None,
        ap_control_code: str | None = None,
        vat_output_code: str | None = None,
        vat_input_code: str | None = None,
        ppv_control_code: str | None = None,
        wht_payable_code: str | None = None,
        grni_control_code: str | None = None,
        purchases_discount_code: str | None = None,
        sales_discount_code: str | None = None,
        unallocated_receipts_code: str | None = None,
        unallocated_payments_code: str | None = None,
        inventory_control_code: str | None = None,

        # IFRS 16 (NEW)
        lease_rou_asset_code: str | None = None,
        lease_liability_current_code: str | None = None,
        lease_liability_non_current_code: str | None = None,
        lease_interest_expense_code: str | None = None,
        lease_amortization_code: str | None = None,
        lease_accumulated_depreciation_code: str | None = None,

        lease_bank_account_code: str | None = None,
    ) -> None:
        """
        Upsert the company control accounts.
        - NOTE: I removed your duplicated ppv_control_code column (it was listed twice).
        - NOTE: I added ap_control_code (you were missing it in INSERT).
        """
        self.initialize_public_schema()

        self.execute_sql("""
        INSERT INTO public.company_account_settings (
            company_id,
            ar_control_code,
            ap_control_code,
            vat_output_code,
            vat_input_code,
            ppv_control_code,
            wht_payable_code,
            grni_control_code,
            purchases_discount_code,
            sales_discount_code,
            unallocated_receipts_code,
            unallocated_payments_code,
            inventory_control_code,

            -- IFRS 16
            lease_rou_asset_code,
            lease_liability_current_code,
            lease_liability_non_current_code,
            lease_interest_expense_code,
            lease_amortization_code,
            lease_accumulated_depreciation_code,
                         
            lease_bank_account_code,

            updated_at
        )
        VALUES (
            %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s,
            %s, %s, %s, %s, %s, %s, %s,
            NOW()
        )
        ON CONFLICT (company_id) DO UPDATE
        SET
            ar_control_code  = COALESCE(NULLIF(EXCLUDED.ar_control_code, ''), public.company_account_settings.ar_control_code),
            ap_control_code  = COALESCE(NULLIF(EXCLUDED.ap_control_code, ''), public.company_account_settings.ap_control_code),

            vat_output_code  = COALESCE(NULLIF(EXCLUDED.vat_output_code, ''), public.company_account_settings.vat_output_code),
            vat_input_code   = COALESCE(NULLIF(EXCLUDED.vat_input_code, ''),  public.company_account_settings.vat_input_code),

            ppv_control_code = COALESCE(NULLIF(EXCLUDED.ppv_control_code, ''), public.company_account_settings.ppv_control_code),

            wht_payable_code = COALESCE(NULLIF(EXCLUDED.wht_payable_code, ''), public.company_account_settings.wht_payable_code),
            grni_control_code = COALESCE(NULLIF(EXCLUDED.grni_control_code, ''), public.company_account_settings.grni_control_code),

            purchases_discount_code = COALESCE(NULLIF(EXCLUDED.purchases_discount_code, ''), public.company_account_settings.purchases_discount_code),
            sales_discount_code = COALESCE(NULLIF(EXCLUDED.sales_discount_code, ''), public.company_account_settings.sales_discount_code),

            unallocated_receipts_code = COALESCE(NULLIF(EXCLUDED.unallocated_receipts_code, ''), public.company_account_settings.unallocated_receipts_code),
            unallocated_payments_code = COALESCE(NULLIF(EXCLUDED.unallocated_payments_code, ''), public.company_account_settings.unallocated_payments_code),

            inventory_control_code = COALESCE(NULLIF(EXCLUDED.inventory_control_code, ''), public.company_account_settings.inventory_control_code),

            -- IFRS 16
            lease_rou_asset_code = COALESCE(NULLIF(EXCLUDED.lease_rou_asset_code, ''), public.company_account_settings.lease_rou_asset_code),
            lease_liability_current_code = COALESCE(NULLIF(EXCLUDED.lease_liability_current_code, ''), public.company_account_settings.lease_liability_current_code),
            lease_liability_non_current_code = COALESCE(NULLIF(EXCLUDED.lease_liability_non_current_code, ''), public.company_account_settings.lease_liability_non_current_code),
            lease_interest_expense_code = COALESCE(NULLIF(EXCLUDED.lease_interest_expense_code, ''), public.company_account_settings.lease_interest_expense_code),
            lease_amortization_code = COALESCE(NULLIF(EXCLUDED.lease_amortization_code, ''), public.company_account_settings.lease_amortization_code),
            lease_accumulated_depreciation_code = COALESCE(NULLIF(EXCLUDED.lease_accumulated_depreciation_code, ''), public.company_account_settings.lease_accumulated_depreciation_code),

            lease_bank_account_code = COALESCE(NULLIF(EXCLUDED.lease_bank_account_code, ''), public.company_account_settings.lease_bank_account_code),
            updated_at = NOW();
        """, (
            company_id,
            ar_control_code,
            ap_control_code,
            vat_output_code,
            vat_input_code,
            ppv_control_code,
            wht_payable_code,
            grni_control_code,
            purchases_discount_code,
            sales_discount_code,
            unallocated_receipts_code,
            unallocated_payments_code,
            inventory_control_code,

            lease_rou_asset_code,
            lease_liability_current_code,
            lease_liability_non_current_code,
            lease_interest_expense_code,
            lease_amortization_code,
            lease_accumulated_depreciation_code,
            lease_bank_account_code,
        ))

