    def get_vat_settings(self, company_id: int) -> dict | None:
        row = self.fetch_one(
            """
            SELECT vat_settings, country, vat
            FROM public.companies
            WHERE id = %s
            LIMIT 1;
            """,
            (company_id,),
        )

        if not row:
            return None

        settings = row.get("vat_settings")

        # If vat_settings is stored as TEXT (json dumps), convert to dict
        if isinstance(settings, str) and settings.strip():
            try:
                settings = json.loads(settings)
            except Exception:
                settings = None

        # Default if not set
        if not settings:
            return {
                "frequency": "bi_monthly",
                "anchor_month": 1,
                "filing_lag_days": 25,
                "reminder_days_before": 10,
                "country": (row.get("country") or "ZA").upper(),
                "vat_registered": bool(row.get("vat")),
                "vat_number": row.get("vat"),
                "vat_rate": 15,
                "pricing_includes_vat": False,
                "corp_tax_rate": 27,
            }

        return settings


    def save_vat_settings(self, company_id: int, settings: dict) -> bool:
        sql = "UPDATE public.companies SET vat_settings=%s WHERE id=%s;"
        self.execute_sql(sql, (Json(settings), company_id))

        return True


    def provision_enterprise_company_and_user(
        self,
        *,
        email: str,
        password_hash: str,
        first_name: str,
        last_name: str,
        user_role: str,
        company_payload: dict,
        industry: str,
        sub_industry: str | None,
        confirmation_token: str,
        trial_start_date,
        trial_end_date,
        initialize_coa_fn,  # pass initialize_coa(db_service, company_id, industry, sub_industry)
    ) -> tuple[int, int]:
        """
        Atomic provisioning:
        company + user + schema + coa seed + set owner.
        Returns (company_id, user_id)
        """
        with self.transaction():
            # 1) company (no owner yet)
            company_id = self.insert_company(
                name=company_payload["companyName"],
                client_code=company_payload["clientCode"],
                industry=industry,
                sub_industry=sub_industry,
                currency=company_payload.get("currency"),
                fin_year_start=company_payload.get("finYearStart"),
                company_reg_date=company_payload.get("companyRegDate"),
                country=company_payload.get("country"),
                company_reg_no=company_payload.get("companyRegNo"),
                tin=company_payload.get("tin"),
                vat=company_payload.get("vat"),
                company_email=company_payload.get("companyEmail"),
                owner_user_id=None,  # set after user exists
            )

            # 2) user
            user_id = self.insert_user(
                email=email,
                password_hash=password_hash,
                user_type="Enterprise",
                first_name=first_name,
                last_name=last_name,
                user_role=user_role,
                company_id=company_id,
                is_confirmed=False,
                confirmation_token=confirmation_token,
                trial_start_date=trial_start_date,
                trial_end_date=trial_end_date,
            )
            if not user_id:
                raise RuntimeError("Failed to insert user")

            # 3) schema + COA seed (ONCE)
            self.initialize_company_schema(company_id)      # tables + any one-time setup
            initialize_coa_fn(self, company_id, industry, sub_industry)

            # 4) set owner
            self.set_company_owner(company_id, int(user_id))

            return company_id, int(user_id)

