    def sync_all_existing_company_schemas(self) -> None:
        with self._conn_cursor() as (_conn, cur):
            cur.execute("""
                SELECT schema_name
                FROM information_schema.schemata
                WHERE schema_name LIKE 'company_%'
                ORDER BY schema_name
            """)
            rows = cur.fetchall() or []

        for row in rows:
            schema = row["schema_name"] if isinstance(row, dict) else row[0]
            try:
                company_id = int(schema.split("_", 1)[1])
            except Exception:
                continue

            try:
                with self._conn_cursor() as (conn, cur):
                    cur.execute("SELECT pg_advisory_xact_lock(%s);", (company_id,))
                    print(f"RUNNING SAFE TENANT SYNC {schema}")
                    self.sync_existing_company_schema(
                        cur=cur,
                        schema=schema,
                        company_id=company_id,
                    )
                    conn.commit()
            except Exception as e:
                print(f"[SAFE-TENANT-SYNC][WARN] {schema} failed: {e}")

    def execute_ddl(
        self,
        ddl: str,
        cur=None,
        *,
        migration_key: str | None = None,
        migration_version: int | None = None,
        lock_key: str | None = None,
    ) -> None:
        """
        Runs DDL statements safely.

        - Optional advisory xact lock (lock_key) to serialize schema bootstraps.
        - Optional migration guard (migration_key + migration_version) so DDL runs only once.
        - SAVEPOINT per statement so one failure doesn't abort the entire transaction.
        - Skips comment-only / empty statements.
        """
        ddl = (ddl or "").strip()
        if not ddl:
            return

        def _split_sql_postgres(sql: str) -> list[str]:
            sql = (sql or "")
            out: list[str] = []
            buf: list[str] = []

            in_squote = False
            dollar_tag = None

            in_line_comment = False
            in_block_comment = False

            i = 0
            n = len(sql)

            while i < n:
                ch = sql[i]
                nxt = sql[i + 1] if i + 1 < n else ""

                # ----------------------------
                # Handle exiting comments
                # ----------------------------
                if in_line_comment:
                    # end line comment at newline
                    if ch == "\n":
                        in_line_comment = False
                        buf.append(ch)  # keep newline to not glue words
                    i += 1
                    continue

                if in_block_comment:
                    # end block comment at */
                    if ch == "*" and nxt == "/":
                        in_block_comment = False
                        i += 2
                    else:
                        i += 1
                    continue

                # ----------------------------
                # Enter comments (only if not in string/dollar)
                # ----------------------------
                if not in_squote and dollar_tag is None:
                    if ch == "-" and nxt == "-":
                        in_line_comment = True
                        i += 2
                        continue
                    if ch == "/" and nxt == "*":
                        in_block_comment = True
                        i += 2
                        continue

                # ----------------------------
                # Dollar-quoted blocks (only if not in single quote)
                # ----------------------------
                if not in_squote and ch == "$":
                    j = i + 1
                    while j < n and sql[j] != "$" and (sql[j].isalnum() or sql[j] == "_"):
                        j += 1
                    if j < n and sql[j] == "$":
                        tag = sql[i : j + 1]
                        if dollar_tag is None:
                            dollar_tag = tag
                            buf.append(tag)
                            i = j + 1
                            continue
                        elif sql.startswith(dollar_tag, i):
                            buf.append(dollar_tag)
                            i += len(dollar_tag)
                            dollar_tag = None
                            continue

                # ----------------------------
                # Single quotes (only if not inside dollar block)
                # ----------------------------
                if dollar_tag is None and ch == "'":
                    in_squote = not in_squote
                    buf.append(ch)
                    i += 1
                    continue

                # ----------------------------
                # Statement terminator
                # ----------------------------
                if ch == ";" and not in_squote and dollar_tag is None:
                    stmt = "".join(buf).strip()
                    if stmt:
                        out.append(stmt)
                    buf = []
                    i += 1
                    continue

                buf.append(ch)
                i += 1

            last = "".join(buf).strip()
            if last:
                out.append(last)

            return out

        statements = _split_sql_postgres(ddl)

        def _ensure_migrations_table(cursor):
            cursor.execute("""
            CREATE TABLE IF NOT EXISTS public.schema_migrations (
                migration_key TEXT PRIMARY KEY,
                version INT NOT NULL,
                applied_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            );
            """)

        def _already_applied(cursor) -> bool:
            if not migration_key or migration_version is None:
                return False

            _ensure_migrations_table(cursor)

            # ------------------------------------------------------------
            # ✅ Safety: if this is a tenant migration, verify required tables exist.
            # If missing, we must rerun DDL even if migrations table says "applied".
            # ------------------------------------------------------------
            try:
                # migration_key examples: "company_7:bootstrap", "company_7:ap"
                if migration_key.startswith("company_") and ":" in migration_key:
                    schema = migration_key.split(":", 1)[0]  # e.g. "company_7"

                    if migration_key.endswith(":bootstrap"):
                        cursor.execute(
                            """
                            SELECT 1
                            FROM information_schema.tables
                            WHERE table_schema = %s
                              AND table_name = 'coa'
                            LIMIT 1;
                            """,
                            (schema,),
                        )
                        coa_exists = cursor.fetchone() is not None

                        cursor.execute(
                            """
                            SELECT 1
                            FROM pg_proc p
                            JOIN pg_namespace n ON n.oid = p.pronamespace
                            WHERE n.nspname = %s
                              AND p.proname = 'fn_assert_asset_company'
                            LIMIT 1;
                            """,
                            (schema,),
                        )
                        fn_exists = cursor.fetchone() is not None

                        if not coa_exists or not fn_exists:
                            print(
                                f"[MIG] {migration_key} marked applied, but bootstrap objects missing "
                                f"(coa_exists={coa_exists}, fn_exists={fn_exists}) -> rerun"
                            )
                            return False

                    if migration_key.endswith(":ap"):
                        required_ap_tables = (
                            "bills",
                            "bill_lines",
                            "vendor_payments",
                            "vendor_payment_allocations",
                        )

                        for table_name in required_ap_tables:
                            cursor.execute(
                                """
                                SELECT 1
                                FROM information_schema.tables
                                WHERE table_schema = %s
                                  AND table_name = %s
                                LIMIT 1;
                                """,
                                (schema, table_name),
                            )
                            exists = cursor.fetchone() is not None
                            if not exists:
                                print(
                                    f"[MIG] {migration_key} marked applied, but {schema}.{table_name} missing -> rerun"
                                )
                                return False

            except Exception as e:
                # If introspection fails, be safe: rerun DDL
                print(f"[MIG][WARN] table-exists check failed for {migration_key}: {e} -> rerun")
                return False

            # ------------------------------------------------------------
            # Normal migration guard
            # ------------------------------------------------------------
            cursor.execute(
                "SELECT version FROM public.schema_migrations WHERE migration_key=%s;",
                (migration_key,),
            )
            row = cursor.fetchone()
            if not row:
                return False

            v = row.get("version") if isinstance(row, dict) else row[0]
            return int(v or 0) >= int(migration_version)

        def _mark_applied(cursor):
            if not migration_key or migration_version is None:
                return
            _ensure_migrations_table(cursor)
            cursor.execute(
                """
                INSERT INTO public.schema_migrations (migration_key, version)
                VALUES (%s, %s)
                ON CONFLICT (migration_key) DO UPDATE
                SET version = GREATEST(public.schema_migrations.version, EXCLUDED.version),
                    applied_at = NOW();
                """,
                (migration_key, int(migration_version)),
            )

        def _advisory_xact_lock(cursor):
            if not lock_key:
                return
            cursor.execute("SELECT pg_advisory_xact_lock(hashtext(%s));", (lock_key,))

        def _is_effectively_empty(stmt: str) -> bool:
            lines = []
            for line in (stmt or "").splitlines():
                s = line.strip()
                if not s:
                    continue
                if s.startswith("--"):
                    continue
                lines.append(s)
            return len(lines) == 0

        def _run(cursor, conn=None):
            # If caller supplies a cursor, assume caller owns the transaction + locking
            if conn is not None:
                _advisory_xact_lock(cursor)

            if _already_applied(cursor):
                return

            for i, stmt in enumerate(statements, start=1):
                if _is_effectively_empty(stmt):
                    continue

                sp = f"sp_{i}"
                cursor.execute(f"SAVEPOINT {sp};")
                try:
                    head = " ".join(stmt.split())[:140]
                    print(f"[EXEC-DDL] #{i}/{len(statements)} -> {head}")
                    cursor.execute(stmt)
                except Exception as e:
                    cursor.execute(f"ROLLBACK TO SAVEPOINT {sp};")
                    cursor.execute(f"RELEASE SAVEPOINT {sp};")
                    print(f"[EXEC-DDL][WARN] stmt #{i} failed (skipped): {e}")
                    continue
                cursor.execute(f"RELEASE SAVEPOINT {sp};")

            _mark_applied(cursor)
            if conn:
                conn.commit()

        if cur is not None:
            _run(cur, conn=None)
            return

        with self._conn_cursor() as (conn, cur2):
            _run(cur2, conn=conn)
            return

    def ensure_company_coa_table(db_service, company_id: int) -> None:
        schema = f"company_{company_id}"
        db_service.execute_ddl(f"CREATE SCHEMA IF NOT EXISTS {schema};")
        db_service.execute_ddl(f"""
            CREATE TABLE IF NOT EXISTS {schema}.coa (
                id SERIAL PRIMARY KEY,
                company_id INT NOT NULL DEFAULT {company_id},
                code TEXT NOT NULL,
                name TEXT NOT NULL,
                section TEXT NULL,
                category TEXT NULL,
                subcategory TEXT NULL,
                description TEXT NULL,
                reporting_description TEXT NULL,
                standard TEXT NULL,
                posting BOOLEAN NOT NULL DEFAULT TRUE,
                posting_rules TEXT NULL,

                cf_section TEXT NOT NULL DEFAULT 'operating',
                cf_bucket TEXT NULL,
                is_working_capital BOOLEAN NOT NULL DEFAULT FALSE,
                is_cash_equiv BOOLEAN NOT NULL DEFAULT FALSE,
                is_non_cash_addback BOOLEAN NOT NULL DEFAULT FALSE,
                is_contra BOOLEAN NOT NULL DEFAULT FALSE,

                template_code TEXT NULL,
                template_code_scoped TEXT NULL,
                template_code_base TEXT NULL,
                code_family TEXT NULL,
                code_numeric INT NULL,
                role TEXT NULL,
                created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            );
        """)
        db_service.execute_ddl(f"CREATE UNIQUE INDEX IF NOT EXISTS {schema}_coa_code_uniq ON {schema}.coa(code);")
        db_service.execute_ddl(f"""
            CREATE UNIQUE INDEX IF NOT EXISTS {schema}_coa_template_code_scoped_uniq
            ON {schema}.coa(template_code_scoped)
            WHERE template_code_scoped IS NOT NULL;
        """)

    def insert_coa(
        self,
        company_id: int,
        rows: List[Dict[str, Any]],
        *,
        dedupe_after: bool = False,
    ) -> int:
        schema = f"company_{company_id}"

        # 🔎 DEBUG: detect who is calling insert_coa with 1501/1502
        import traceback
        try:
            tc_set = {
                str(r.get("template_code") or "").strip()
                for r in (rows or [])
                if isinstance(r, dict)
            }
            tcs_set = {
                str(r.get("template_code_scoped") or "").strip()
                for r in (rows or [])
                if isinstance(r, dict)
            }

            if {"1501", "1502"} & tc_set or {"G::1501", "G::1502"} & tcs_set:
                print("\n[DEBUG][insert_coa] payload contains 1501/1502 for company", company_id)
                print("  tc_hit =", sorted(list({"1501", "1502"} & tc_set)))
                print("  tcs_hit=", sorted(list({"G::1501", "G::1502"} & tcs_set)))
                print("  stack:\n" + "".join(traceback.format_stack(limit=25)))
        except Exception as e:
            print("[DEBUG][insert_coa] debug failed:", e)

        # ------------------------------------------------------------
        # 1) Ensure schema + COA table (DDL-only)
        # ------------------------------------------------------------
        self.execute_ddl(f"CREATE SCHEMA IF NOT EXISTS {schema};")

        self.execute_ddl(f"""
            CREATE TABLE IF NOT EXISTS {schema}.coa (
                id SERIAL PRIMARY KEY,
                company_id INT NOT NULL DEFAULT {company_id},
                code TEXT NOT NULL,
                name TEXT NOT NULL,
                section TEXT NULL,
                category TEXT NULL,
                subcategory TEXT NULL,
                description TEXT NULL,
                reporting_description TEXT NULL,
                standard TEXT NULL,
                posting BOOLEAN NOT NULL DEFAULT TRUE,
                posting_rules TEXT NULL,

                cf_section TEXT NOT NULL DEFAULT 'operating',
                cf_bucket TEXT NULL,
                is_working_capital BOOLEAN NOT NULL DEFAULT FALSE,
                is_cash_equiv BOOLEAN NOT NULL DEFAULT FALSE,
                is_non_cash_addback BOOLEAN NOT NULL DEFAULT FALSE,
                is_contra BOOLEAN NOT NULL DEFAULT FALSE,

                template_code TEXT NULL,
                template_code_scoped TEXT NULL,
                template_code_base TEXT NULL,
                code_family TEXT NULL,
                code_numeric INT NULL,
                role TEXT NULL,
                created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
            );
        """)

        self.execute_ddl(f"ALTER TABLE {schema}.coa ADD COLUMN IF NOT EXISTS template_code_base TEXT NULL;")
        self.execute_ddl(f"ALTER TABLE {schema}.coa ADD COLUMN IF NOT EXISTS template_code_scoped TEXT NULL;")
        self.execute_ddl(f"ALTER TABLE {schema}.coa ADD COLUMN IF NOT EXISTS company_id INT;")
        self.execute_ddl(f"UPDATE {schema}.coa SET company_id = {company_id} WHERE company_id IS NULL;")
        self.execute_ddl(f"ALTER TABLE {schema}.coa ALTER COLUMN company_id SET DEFAULT {company_id};")
        self.execute_ddl(f"ALTER TABLE {schema}.coa ALTER COLUMN company_id SET NOT NULL;")

        # ------------------------------------------------------------
        # 2) Indexes / constraints
        # ------------------------------------------------------------
        self.execute_ddl(f"""
            CREATE UNIQUE INDEX IF NOT EXISTS {schema}_coa_code_uniq
            ON {schema}.coa(code);
        """)

        self.execute_ddl(f"""
            CREATE INDEX IF NOT EXISTS {schema}_coa_template_code_idx
            ON {schema}.coa(template_code);
        """)

        self.execute_ddl(f"""
            CREATE INDEX IF NOT EXISTS {schema}_coa_template_code_scoped_idx
            ON {schema}.coa(template_code_scoped);
        """)

        self.execute_ddl(f"""
            CREATE UNIQUE INDEX IF NOT EXISTS {schema}_coa_template_code_scoped_uniq
            ON {schema}.coa(template_code_scoped)
            WHERE template_code_scoped IS NOT NULL;
        """)

        # 🚫 DO NOT enforce UNIQUE(template_code)
        self.execute_ddl(f"ALTER TABLE {schema}.coa DROP CONSTRAINT IF EXISTS {schema}_coa_template_code_uniq;")
        self.execute_ddl(f"DROP INDEX IF EXISTS {schema}.{schema}_coa_template_code_uniq;")
        self.execute_ddl(f"DROP INDEX IF EXISTS {schema}_coa_template_code_uniq;")

        import time

        try:
            existing_n = self.fetch_val(f"SELECT COUNT(*) FROM {schema}.coa;") or 0
            if int(existing_n) > 0:
                print(f"\n[COA-WRITE] insert_coa called but {schema}.coa already has {existing_n} rows @ {time.time()}")
                print("".join(traceback.format_stack(limit=25)))
        except Exception as e:
            print("[COA-WRITE] precheck failed:", e)

        # ------------------------------------------------------------
        # 3) Reserved control identities
        # ------------------------------------------------------------
        canonical_by_tc = {
            "1410": "BS_CA_1410",
            "2310": "BS_CL_2310",
            "2300": "BS_CL_2300",
            "2105": "BS_CL_2105",
            "9002": "BS_CA_9002",
            "2200": "BS_CL_2200",
            "2350": "BS_CL_2350",
            "2325": "BS_CL_2325",
            "1730": "BS_CA_1730",
            "2360": "BS_CL_2360",
            "2215": "BS_CL_2215",
            "5305": "BS_PL_5305",
            "1500": "BS_CA_1500",
            "1000": "BS_CA_1000",
           
            "8010": "PL_REV_ADJ_8010",
            "8011": "PL_EXP_ADJ_8011",
            "1610": "BS_NCA_1610",
            "2610": "BS_CL_2610",
            "2620": "BS_NCL_2620",
            "7110": "PL_OPEX_7110",
            "6017": "PL_OPEX_6017",
            "1590": "BS_NCA_1590",
        }

        reserved_template_codes = set(canonical_by_tc.keys())
        reserved_template_code_scoped = {f"G::{tc}" for tc in reserved_template_codes}

        # Existing reporting codes
        existing_codes: Set[str] = set()
        existing_reserved_owner_by_scoped: Dict[str, str] = {}
        existing_reserved_owner_by_tc: Dict[str, str] = {}

        existing_rows = self.fetch_all(
            f"""
            SELECT code, template_code, template_code_scoped
            FROM {schema}.coa;
            """
        ) or []

        for r in existing_rows:
            code = str(r.get("code") or "").strip()
            tc = str(r.get("template_code") or "").strip()
            tcs = str(r.get("template_code_scoped") or "").strip()

            if code:
                existing_codes.add(code)

            if tc in canonical_by_tc:
                existing_reserved_owner_by_tc[tc] = code
                existing_reserved_owner_by_scoped[f"G::{tc}"] = code

            if tcs in reserved_template_code_scoped:
                existing_reserved_owner_by_scoped[tcs] = code

        # Reserved reporting codes (never allocate these)
        reserved_codes = {
            "BS_CA_1410",
            "BS_CL_2310",
            "BS_CL_2300",

            "BS_CA_1000",
           
            "BS_CL_2105",

            "BS_CA_9002",
            "BS_CL_2200",
            "BS_CL_2210",
            "BS_CL_2215",

            "BS_CL_2350",
            "BS_CL_2325",
            "BS_CA_1730",

            "BS_CA_1500",
            "BS_CA_1001",
            "BS_CA_1509",

            "BS_CL_2360",
            "BS_CL_2320",
            "BS_CL_2330",

            "BS_PL_5305",

            "PL_REV_ADJ_8010",
            "PL_EXP_ADJ_8011",

            "BS_NCA_1610",
            "BS_CL_2610",
            "BS_NCL_2620",
            "PL_OPEX_7110",
            "PL_OPEX_6017",
            "BS_NCA_1590",

            "BS_EQ_3100",
            "BS_EQ_3110",
        }

        normalized = _normalize_coa_rows_codes(
            rows,
            reserved_codes=reserved_codes,
            existing_codes=existing_codes,
        )

        # ------------------------------------------------------------
        # 4) SQL (UPSERT by code)
        # ------------------------------------------------------------
        sql_by_code = f"""
            INSERT INTO {schema}.coa
            (
                company_id,
                name, code, category, section,
                description, reporting_description,
                standard,
                template_code, template_code_scoped, template_code_base,
                code_family, code_numeric,
                subcategory,
                cf_section, cf_bucket,
                posting, posting_rules,
                is_working_capital, is_cash_equiv, is_non_cash_addback,
                is_contra, role
            )
            VALUES (
                %s,
                %s,%s,%s,%s,
                %s,%s,
                %s,
                %s,%s,%s,
                %s,%s,
                %s,
                %s,%s,
                %s,%s,
                %s,%s,%s,
                %s,%s
            )
            ON CONFLICT (code) DO UPDATE SET
                name = COALESCE(NULLIF(EXCLUDED.name,''), {schema}.coa.name),
                category = EXCLUDED.category,
                section = EXCLUDED.section,
                description = COALESCE(NULLIF(EXCLUDED.description,''), {schema}.coa.description),
                reporting_description = COALESCE(NULLIF(EXCLUDED.reporting_description,''), {schema}.coa.reporting_description),
                standard = COALESCE(NULLIF(EXCLUDED.standard,''), {schema}.coa.standard),

                template_code = COALESCE(NULLIF(EXCLUDED.template_code,''), {schema}.coa.template_code),
                template_code_scoped = COALESCE(NULLIF(EXCLUDED.template_code_scoped,''), {schema}.coa.template_code_scoped),
                template_code_base = COALESCE(NULLIF(EXCLUDED.template_code_base,''), {schema}.coa.template_code_base),

                code_family   = COALESCE(NULLIF(EXCLUDED.code_family,''), {schema}.coa.code_family),
                code_numeric  = COALESCE(EXCLUDED.code_numeric, {schema}.coa.code_numeric),
                subcategory   = COALESCE(NULLIF(EXCLUDED.subcategory,''), {schema}.coa.subcategory),

                cf_section = COALESCE(NULLIF(EXCLUDED.cf_section,''), {schema}.coa.cf_section),
                cf_bucket  = COALESCE(NULLIF(EXCLUDED.cf_bucket,''),  {schema}.coa.cf_bucket),

                posting = COALESCE(EXCLUDED.posting, {schema}.coa.posting),
                posting_rules = COALESCE(NULLIF(EXCLUDED.posting_rules,''), {schema}.coa.posting_rules),

                is_working_capital  = COALESCE(EXCLUDED.is_working_capital,  {schema}.coa.is_working_capital),
                is_cash_equiv       = COALESCE(EXCLUDED.is_cash_equiv,       {schema}.coa.is_cash_equiv),
                is_non_cash_addback = COALESCE(EXCLUDED.is_non_cash_addback, {schema}.coa.is_non_cash_addback),

                is_contra = COALESCE(EXCLUDED.is_contra, {schema}.coa.is_contra),
                role      = COALESCE(NULLIF(EXCLUDED.role,''), {schema}.coa.role)

            WHERE {schema}.coa.code NOT IN (
                'BS_CA_1410',
                'BS_CL_2310',
                'BS_CL_2300',

                'BS_CA_1000',
              
                'BS_CL_2105',

                'BS_CA_9002',
                'BS_CL_2200',
                'BS_CL_2210',
                'BS_CL_2215',

                'BS_CL_2350',
                'BS_CL_2325',
                'BS_CA_1730',

                'BS_CA_1500',
                'BS_CA_1001',
                'BS_CA_1509',

                'BS_CL_2360',
                'BS_CL_2320',
                'BS_CL_2330',

                'BS_PL_5305',

                'PL_REV_ADJ_8010',
                'PL_EXP_ADJ_8011',

                'BS_NCA_1610',
                'BS_CL_2610',
                'BS_NCL_2620',
                'PL_OPEX_7110',
                'PL_OPEX_6017',
                'BS_NCA_1590',

                'BS_EQ_3100',
                'BS_EQ_3110'
            );
        """

        # ------------------------------------------------------------
        # 5) Insert rows with reserved control protection
        # ------------------------------------------------------------
        count = 0
        with self._conn_cursor() as (conn, cur):
            for row in (normalized or []):
                name = (row.get("name") or "").strip()
                code = (row.get("code") or "").strip()

                if not name:
                    name = (row.get("reporting_description") or "").strip() or code

                if not name or not code:
                    continue

                tc = (row.get("template_code") or "").strip() or None
                tcs = (row.get("template_code_scoped") or "").strip() or None

                # --------------------------------------------------------
                # HARD RESERVATION RULE:
                # non-canonical rows may NOT claim reserved control IDs
                # --------------------------------------------------------
                if tc in canonical_by_tc:
                    canonical_code = canonical_by_tc[tc]

                    # If this row is not the canonical control row, strip reserved IDs
                    if code != canonical_code:
                        print(
                            f"[COA-RESERVE] stripping reserved tc/tcs from non-canonical row "
                            f"code={code} tc={tc} tcs={tcs!r} canonical={canonical_code}"
                        )
                        tc = None
                        tcs = None

                if tcs in reserved_template_code_scoped:
                    reserved_tc = tcs.split("::")[-1]
                    canonical_code = canonical_by_tc.get(reserved_tc)

                    if canonical_code and code != canonical_code:
                        print(
                            f"[COA-RESERVE] stripping reserved scoped template from non-canonical row "
                            f"code={code} tc={tc} tcs={tcs!r} canonical={canonical_code}"
                        )
                        tcs = None
                        if tc == reserved_tc:
                            tc = None

                # If company already has an owner for reserved tc, nobody else may claim it
                if tc and tc in existing_reserved_owner_by_tc:
                    owner_code = existing_reserved_owner_by_tc[tc]
                    if owner_code and owner_code != code:
                        print(
                            f"[COA-RESERVE] existing tenant owner for tc={tc} is {owner_code}, "
                            f"stripping from incoming code={code}"
                        )
                        tc = None
                        if tcs == f"G::{tc}":
                            tcs = None

                # If company already has an owner for reserved scoped tc, nobody else may claim it
                if tcs and tcs in existing_reserved_owner_by_scoped:
                    owner_code = existing_reserved_owner_by_scoped[tcs]
                    if owner_code and owner_code != code:
                        print(
                            f"[COA-RESERVE] existing tenant owner for tcs={tcs} is {owner_code}, "
                            f"stripping from incoming code={code}"
                        )
                        if tc and f"G::{tc}" == tcs:
                            tc = None
                        tcs = None

                if tc in ("1501", "1502"):
                    print("[COA-DEBUG] inserting tc=", tc, "tcs=", tcs, "name=", name, "code=", code)
                    print("[COA-DEBUG] stack:\n", "".join(traceback.format_stack(limit=12)))

                cur.execute(
                    sql_by_code,
                    (
                        company_id,
                        name,
                        code,
                        row.get("category"),
                        row.get("section"),
                        row.get("description"),
                        row.get("reporting_description") or "",
                        row.get("standard"),
                        tc,
                        tcs,
                        row.get("template_code_base") or None,
                        row.get("code_family"),
                        row.get("code_numeric"),
                        row.get("subcategory") or "",
                        row.get("cf_section") or "operating",
                        row.get("cf_bucket") or "",
                        row.get("posting", True),
                        row.get("posting_rules") or "",
                        row.get("is_working_capital", False),
                        row.get("is_cash_equiv", False),
                        row.get("is_non_cash_addback", False),
                        row.get("is_contra", False),
                        row.get("role") or "",
                    ),
                )
                count += 1

                # Track newly claimed reserved ownership inside this same batch
                if tc in canonical_by_tc:
                    existing_reserved_owner_by_tc[tc] = code
                    existing_reserved_owner_by_scoped[f"G::{tc}"] = code

                if tcs in reserved_template_code_scoped:
                    existing_reserved_owner_by_scoped[tcs] = code

                existing_codes.add(code)

            conn.commit()

        # ------------------------------------------------------------
        # 6) Optional: dedupe after bulk seeding/sync
        # ------------------------------------------------------------
        if dedupe_after:
            try:
                self.dedupe_company_coa(company_id)
            except Exception:
                pass

        return count

    def upsert_coa_pool(self, rows):
        print("[DEBUG] ✅ using the ONLY upsert_coa_pool() version")

        # ✅ Safety net: make sure the table exists (minimal shape)
        self.execute_ddl("""
        CREATE TABLE IF NOT EXISTS public.coa_pool (
            id SERIAL PRIMARY KEY,
            template_code TEXT NOT NULL,
            template_code_scoped TEXT NOT NULL,
            name TEXT NOT NULL,
            code TEXT NULL,
            section TEXT NULL,
            category TEXT NULL,
            subcategory TEXT NULL,
            description TEXT NULL,
            standard TEXT NULL,
            industry TEXT NULL,
            sub_industry TEXT NULL,
            is_general BOOLEAN NOT NULL DEFAULT FALSE,
            posting BOOLEAN NOT NULL DEFAULT TRUE,
            created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
        );
        """)

        # ✅ If no rows, nothing else to do
        if not rows:
            return 0

        # ✅ Guarantee uniqueness rule for ON CONFLICT(column)
        self.execute_ddl("""
        CREATE UNIQUE INDEX IF NOT EXISTS coa_pool_template_code_scoped_uniq
        ON public.coa_pool (template_code_scoped);
        """)

        sql = """
        INSERT INTO public.coa_pool
        (template_code, template_code_scoped, name, code, section, category, subcategory,
        description, standard, industry, sub_industry, is_general, posting)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        ON CONFLICT (template_code_scoped)
        DO UPDATE SET
            template_code = EXCLUDED.template_code,
            name = EXCLUDED.name,
            code = EXCLUDED.code,
            section = EXCLUDED.section,
            category = EXCLUDED.category,
            subcategory = EXCLUDED.subcategory,
            description = EXCLUDED.description,
            standard = EXCLUDED.standard,
            industry = EXCLUDED.industry,
            sub_industry = EXCLUDED.sub_industry,
            is_general = EXCLUDED.is_general,
            posting = EXCLUDED.posting,
            updated_at = NOW();
        """

        count = 0
        with self._conn_cursor() as (_conn, cur):
            for r in rows:
                cur.execute(sql, (
                    r["template_code"],
                    r["template_code_scoped"],
                    r["name"],
                    r.get("code"),
                    r.get("section"),
                    r.get("category"),
                    r.get("subcategory"),
                    r.get("description"),
                    r.get("standard"),
                    r.get("industry"),
                    r.get("sub_industry"),
                    bool(r.get("is_general", False)),
                    bool(r.get("posting", True)),
                ))
                count += 1

        return count


    def apply_basic_cashflow_tags(self, company_id: int) -> None:
        schema = f"company_{company_id}"

        # 1) Cash & Equivalents => cash accounts
        sql_cash = f"""
        UPDATE {schema}.coa
        SET
            is_cash_equiv = TRUE,
            cf_bucket = COALESCE(NULLIF(cf_bucket, ''), 'cash'),
            cf_section = 'none'
        WHERE
            LOWER(category) LIKE '%cash%equivalent%'
            OR LOWER(category) LIKE '%cash & equivalents%'
            OR LOWER(category) LIKE '%cash and equivalents%';
        """
        self.execute_ddl(sql_cash)

        # 2) Working capital assets (receivables, inventory, VAT input, prepaid)
        sql_wc_assets = f"""
        UPDATE {schema}.coa
        SET
            is_working_capital = TRUE,
            cf_section = 'operating'
        WHERE
            LOWER(section) IN ('asset','assets')
            AND (
                LOWER(name) LIKE '%receivable%'
                OR LOWER(name) LIKE '%debtors%'
                OR LOWER(name) LIKE '%inventory%'
                OR LOWER(name) LIKE '%stock%'
                OR LOWER(name) LIKE '%prepaid%'
                OR LOWER(name) LIKE '%vat input%'
                OR LOWER(name) LIKE '%vat%'
            );
        """
        self.execute_ddl(sql_wc_assets)

        # 3) Working capital liabilities (payables, accruals, VAT output)
        sql_wc_liab = f"""
        UPDATE {schema}.coa
        SET
            is_working_capital = TRUE,
            cf_section = 'operating'
        WHERE
            LOWER(section) IN ('liability','liabilities')
            AND (
                LOWER(name) LIKE '%payable%'
                OR LOWER(name) LIKE '%creditor%'
                OR LOWER(name) LIKE '%accrual%'
                OR LOWER(name) LIKE '%vat output%'
                OR LOWER(name) LIKE '%vat%'
            );
        """
        self.execute_ddl(sql_wc_liab)

        # 4) Non-cash addbacks (Depreciation & Amortisation)
        sql_addbacks = f"""
        UPDATE {schema}.coa
        SET
            is_non_cash_addback = TRUE,
            cf_section = 'operating',
            cf_bucket = COALESCE(
                NULLIF(cf_bucket, ''),
                CASE
                    WHEN LOWER(name) LIKE '%amort%' THEN 'amortization'
                    ELSE 'depreciation'
                END
            )
        WHERE
            LOWER(category) LIKE '%depreciation%amort%'
            OR LOWER(name) LIKE '%depreciation%'
            OR LOWER(name) LIKE '%amort%';
        """
        self.execute_ddl(sql_addbacks)

