    def insert_journal(self, company_id: int, entry: dict, cur=None) -> int:
        schema = f"company_{company_id}"

        je_date = entry.get("date") or date.today().isoformat()

        gross = float(entry.get("gross_amount") or 0.0)
        net   = float(entry.get("net_amount") or 0.0)
        vat   = float(entry.get("vat_amount") or 0.0)

        is_reversal = bool(entry.get("is_reversal") or False)

        # ✅ NEW (replaces reversed_journal_id)
        reversal_of_journal_id = entry.get("reversal_of_journal_id")
        reversed_by_journal_id = entry.get("reversed_by_journal_id")  # optional on insert

        sql = f"""
        INSERT INTO {schema}.journal
        (date, ref, description, gross_amount, net_amount, vat_amount,
        is_reversal, reversal_of_journal_id, reversed_by_journal_id,
        source, source_id)
        VALUES (%s, %s, %s, %s, %s, %s,
                %s, %s, %s,
                %s, %s)
        RETURNING id;
        """

        params = (
            je_date,
            entry.get("ref"),
            entry.get("description") or "",
            gross,
            net,
            vat,
            is_reversal,
            reversal_of_journal_id,
            reversed_by_journal_id,
            entry.get("source"),
            entry.get("source_id"),
        )

        if cur is not None:
            cur.execute(sql, params)
            row = cur.fetchone()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

        return int(self.execute_sql(sql, params) or 0)

    def insert_journal_line(
        self,
        company_id: int,
        journal_id: int,
        line_no: int,
        line: dict,
        *,
        source: str | None = None,
        source_id: int | None = None,
        cur=None,
    ) -> int:
        schema = self.company_schema(company_id)

        acct = (line.get("account_code") or line.get("account") or "").strip()
        if not acct:
            raise ValueError("Journal line missing account_code")

        debit = float(line.get("debit") or 0.0)
        credit = float(line.get("credit") or 0.0)

        # ✅ this is what will appear in the journal-lines table “description” column
        desc = (line.get("description") or line.get("memo") or "").strip() or None

        sql = f"""
        INSERT INTO {schema}.journal_lines
        (company_id, journal_id, line_no, account_code, description, debit, credit, source, source_id, created_at)
        VALUES
        (%s, %s, %s, %s, %s, %s, %s, %s, %s, NOW())
        RETURNING id;
        """

        params = (
            int(company_id),
            int(journal_id),
            int(line_no),
            acct,
            desc,
            debit,
            credit,
            source,
            source_id,
        )

        if cur is not None:
            cur.execute(sql, params)
            row = cur.fetchone()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

        return int(self.execute_sql(sql, params) or 0)
    
    def post_journal(self, company_id: int, entry: Dict[str, Any], *, cur=None, conn=None) -> int:
        schema = self.company_schema(company_id)

        je_date = entry.get("date") or date.today().isoformat()
        ref = (entry.get("ref") or "").strip() or None
        desc = entry.get("description") or ""

        lines = entry.get("lines") or []
        if not isinstance(lines, list) or not lines:
            raise ValueError("Journal must include at least one line")

        if hasattr(self, "_rewrite_lines_guarding_ar"):
            entry["lines"] = self._rewrite_lines_guarding_ar(company_id, lines)
            lines = entry["lines"]

        total_debit = 0.0
        total_credit = 0.0
        for line in lines:
            total_debit += float(line.get("debit") or 0.0)
            total_credit += float(line.get("credit") or 0.0)

        if round(total_debit, 2) != round(total_credit, 2):
            raise ValueError(
                f"Unbalanced journal: debits={total_debit:.2f} credits={total_credit:.2f} ref={ref or ''}"
            )

        entry_source = entry.get("source")
        entry_source_id = entry.get("source_id")

        def _run(cursor):
            journal_id = self.insert_journal(company_id, entry, cur=cursor)

            line_no = 1
            for line in lines:
                self.insert_journal_line(
                    company_id,
                    journal_id,
                    line_no,
                    line,
                    source=entry_source,
                    source_id=entry_source_id,
                    cur=cursor,
                )

                self.insert_ledger(
                    company_id,
                    journal_id,
                    je_date,
                    line,
                    ref=ref,
                    source=entry_source,
                    source_id=entry_source_id,
                    cur=cursor,
                )

                self.update_trial_balance(company_id, line, cur=cursor)

                if hasattr(self, "requires_notes") and callable(getattr(self, "requires_notes")):
                    acct = (line.get("account_code") or line.get("account") or "").strip()
                    if acct and self.requires_notes(acct):
                        if hasattr(self, "insert_note") and callable(getattr(self, "insert_note")):
                            try:
                                self.insert_note(company_id, journal_id, acct, desc, cur=cursor)
                            except TypeError:
                                self.insert_note(company_id, journal_id, acct, desc)

                line_no += 1

            # publish engagement posting activity only when this journal is engagement-linked
            engagement_company_id = entry.get("engagement_company_id")
            engagement_id = entry.get("engagement_id")

            if engagement_company_id and engagement_id:
                gross_amount = entry.get("gross_amount")
                if gross_amount is None:
                    total_debits = 0.0
                    for ln in lines:
                        try:
                            total_debits += float(ln.get("debit") or 0.0)
                        except Exception:
                            pass
                    gross_amount = total_debits

                currency_code = (entry.get("currency") or "ZAR").strip() or "ZAR"

                self.upsert_engagement_posting_activity(
                    cursor,
                    company_id=int(engagement_company_id),
                    engagement_id=int(engagement_id),
                    posting_date=je_date,
                    module_name="journal_entries",
                    event_type="posted",
                    reference_no=ref,
                    description=desc or f"Journal {ref or journal_id}",
                    prepared_by_user_id=entry.get("prepared_by_user_id"),
                    reviewer_user_id=entry.get("reviewer_user_id"),
                    status="posted",
                    amount=gross_amount,
                    currency_code=currency_code,
                    source_table="journal",
                    source_id=int(journal_id),
                    notes=f"Journal posted from source={entry_source or 'manual'} source_id={entry_source_id}",
                    created_by_user_id=entry.get("created_by_user_id"),
                    updated_by_user_id=entry.get("updated_by_user_id"),
                )

                print("[post_journal] engagement activity recorded", flush=True)

            return int(journal_id)

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (conn2, cur2):
            try:
                jid = _run(cur2)
                conn2.commit()
                return int(jid)
            except Exception:
                conn2.rollback()
                raise


    def post_journal_with_overdraft(self, company_id: int, entry: Dict[str, Any]) -> int:
        """
        Posts the user journal first using the normal posting pipeline.
        Then checks whether bank account 1000 went negative and, if so,
        posts an automatic overdraft reclassification journal.

        Important:
        - uses ONE transaction
        - delegates actual journal posting to post_journal()
        """
        bank_code = "1000"
        od_code = "2105"

        tx_date = date.fromisoformat(str(entry.get("date"))[:10])
        module = "gl"

        if self.is_date_locked(company_id, tx_date=tx_date, module=module):
            raise ValueError(f"PERIOD_LOCKED|{module}|{tx_date.isoformat()}")

        ref = (entry.get("ref") or "").strip() or None

        lines = entry.get("lines") or []
        if not isinstance(lines, list) or not lines:
            raise ValueError("Journal must include at least one line")

        with self._conn_cursor() as (conn, cur):
            try:
                # 1) Post the main journal through the REAL posting pipeline
                journal_id = self.post_journal(company_id, entry, cur=cur, conn=conn)

                # 2) Avoid recursion if somehow the incoming entry is already an auto-OD journal
                if ref and ref.startswith("AUTO-OD-"):
                    conn.commit()
                    return int(journal_id)

                # 3) Check bank balance after posting
                bank_balance = self.get_account_balance_from_tb(company_id, bank_code, cur=cur)
                if bank_balance is None:
                    bank_balance = 0.0

                # 4) If bank is credit/negative, reclass to overdraft
                if float(bank_balance) < 0:
                    amt = abs(float(bank_balance))

                    od_entry = {
                        "date": tx_date.isoformat(),
                        "ref": f"AUTO-OD-{journal_id}",
                        "description": "Auto: Bank credit balance reclassified to overdraft",
                        "source": "system",
                        "source_id": int(journal_id),
                        "lines": [
                            {
                                "account_code": bank_code,
                                "debit": amt,
                                "credit": 0.0,
                                "memo": "Auto overdraft reclass",
                            },
                            {
                                "account_code": od_code,
                                "debit": 0.0,
                                "credit": amt,
                                "memo": "Auto overdraft reclass",
                            },
                        ],
                    }

                    self.post_journal(company_id, od_entry, cur=cur, conn=conn)

                conn.commit()
                return int(journal_id)

            except Exception:
                conn.rollback()
                raise

    def list_recent_journals(self, company_id: int, limit: int = 50, date_from=None, date_to=None, q: str = ""):
        schema = self.company_schema(company_id)

        where = ["company_id = %s"]
        params = [company_id]

        if date_from:
            where.append("date >= %s")
            params.append(date_from)

        if date_to:
            where.append("date <= %s")
            params.append(date_to)

        if q:
            where.append("(ref ILIKE %s OR description ILIKE %s)")
            like = f"%{q}%"
            params.extend([like, like])

        sql = f"""
        SELECT id, date, ref, description, net_amount, vat_amount, gross_amount
        FROM {schema}.journal
        WHERE {" AND ".join(where)}
        ORDER BY date DESC, id DESC
        LIMIT %s
        """
        params.append(limit)

        return self.fetch_all(sql, tuple(params))
    
    def get_journal_with_lines(self, company_id: int, journal_id: int) -> dict:
        schema = self.company_schema(company_id)

        header = self.fetch_one(
            f"""
            SELECT id, date, ref, description, net_amount, vat_amount, gross_amount
            FROM {schema}.journal
            WHERE id = %s
            """,
            (journal_id,),
        )

        if not header:
            raise ValueError("Journal not found")

        lines = self.fetch_all(
            f"""
            SELECT
                account AS account_code,
                debit,
                credit,
                memo
            FROM {schema}.ledger
            WHERE journal_id = %s
            ORDER BY id ASC
            """,
            (journal_id,),
        ) or []

        # tag VAT lines (simple heuristic)
        for ln in lines:
            code = str(ln.get("account_code") or "").lower()
            memo = str(ln.get("memo") or "").lower()
            ln["is_vat"] = ("vat" in code) or ("vat" in memo)

        return {
            "id": header["id"],
            "date": str(header["date"]),
            "ref": header.get("ref") or "",
            "description": header.get("description") or "",
            "net_amount": float(header.get("net_amount") or 0),
            "vat_amount": float(header.get("vat_amount") or 0),
            "gross_amount": float(header.get("gross_amount") or 0),
            "lines": lines,
        }

    def get_journal_by_ref(self, company_id: int, ref: str):
        schema = self.company_schema(company_id)
        ref = (ref or "").strip()
        if not ref:
            return None

        j = self.fetch_one(
            f"""
            SELECT id, date, ref, description, net_amount, vat_amount, gross_amount
            FROM {schema}.journal
            WHERE ref = %s
            ORDER BY id DESC
            LIMIT 1
            """,
            (ref,),
        )
        if not j:
            return None

        lines = self.fetch_all(
            f"""
            SELECT account, debit, credit, memo
            FROM {schema}.ledger
            WHERE journal_id = %s
            ORDER BY id ASC
            """,
            (j["id"] if isinstance(j, dict) else j[0],),
        ) or []

        # normalize shape for UI
        out = dict(j) if isinstance(j, dict) else {
            "id": j[0], "date": j[1], "ref": j[2], "description": j[3],
            "net_amount": j[4], "vat_amount": j[5], "gross_amount": j[6],
        }

        out["lines"] = [
            {
                "account_code": (ln["account"] if isinstance(ln, dict) else ln[0]),
                "debit": float((ln["debit"] if isinstance(ln, dict) else ln[1]) or 0),
                "credit": float((ln["credit"] if isinstance(ln, dict) else ln[2]) or 0),
                "memo": (ln["memo"] if isinstance(ln, dict) else ln[3]) or "",
            }
            for ln in lines
        ]

        # ✅ ADD THIS BLOCK HERE (VAT detection)
        for ln in out["lines"]:
            code = str(ln.get("account_code") or "").lower()
            memo = str(ln.get("memo") or "").lower()
            ln["is_vat"] = ("vat" in code) or ("vat" in memo)

        return out
    
    def reverse_journal(self, company_id: int, journal_id: int, payload: Optional[Dict[str, Any]] = None) -> int:
        payload = payload or {}
        schema = self.company_schema(company_id)
      # self.ensure_company_schema(company_id)

        # Choose reversal date
        rev_date_iso = (payload.get("date") or date.today().isoformat())
        rev_date = date.fromisoformat(str(rev_date_iso)[:10])

        # ✅ period lock gate for reversal action
        if self.is_date_locked(company_id, tx_date=rev_date, module="gl"):
            raise ValueError(f"PERIOD_LOCKED|gl|{rev_date.isoformat()}")

        reason = (payload.get("reason") or "").strip() or None

        with self._conn_cursor() as (conn, cur):
            # ---- Load original journal ----
            cur.execute(
                f"""
                SELECT id, date, ref, description, reversal_of_journal_id, reversed_by_journal_id
                FROM {schema}.journal
                WHERE id=%s
                """,
                (journal_id,),
            )
            row = cur.fetchone()
            if not row:
                raise ValueError("Journal not found")

            # dict/tuple safe
            j = row if isinstance(row, dict) else {
                "id": row[0], "date": row[1], "ref": row[2], "description": row[3],
                "reversal_of_journal_id": row[4], "reversed_by_journal_id": row[5],
            }

            if j.get("reversed_by_journal_id") or j.get("reversal_of_journal_id"):
                raise ValueError("Journal is already reversed (or is itself a reversal)")

            ref0 = (j.get("ref") or "").strip()
            if ref0.startswith("AUTO-"):
                raise ValueError("System journals (AUTO-*) cannot be reversed")

            # ---- Load original ledger lines (✅ correct column names) ----
            cur.execute(
                f"""
                SELECT account, debit, credit, memo
                FROM {schema}.ledger
                WHERE journal_id=%s
                ORDER BY id ASC
                """,
                (journal_id,),
            )
            rows = cur.fetchall() or []
            if not rows:
                raise ValueError("Journal has no ledger lines to reverse")

            # ---- Create reversal journal header ----
            rev_ref = f"REV-{journal_id}"
            rev_desc = f"Reversal of {journal_id}" + (f" | {reason}" if reason else "")

            rev_entry = {
                "date": rev_date.isoformat(),
                "ref": rev_ref,
                "description": rev_desc,
                "is_reversal": True,

                # ✅ this reversal points to the original
                "reversal_of_journal_id": journal_id,
            }

            reversal_journal_id = self.insert_journal(company_id, rev_entry, cur=cur)

            # ---- Insert mirrored ledger lines + update TB ----
            je_date = rev_date.isoformat()

            for r in rows:
                ln = r if isinstance(r, dict) else {
                    "account": r[0], "debit": r[1], "credit": r[2], "memo": r[3],
                }

                dr = float(ln.get("debit") or 0.0)
                cr = float(ln.get("credit") or 0.0)

                mirrored = {
                    "account_code": ln.get("account"),   # ✅ your insert_ledger expects account_code
                    "debit": cr,                         # swap
                    "credit": dr,                        # swap
                    "memo": (ln.get("memo") or "")[:240],
                    "description": (ln.get("memo") or ""),  # optional
                }

                self.insert_ledger(company_id, reversal_journal_id, je_date, mirrored, ref=rev_ref, cur=cur)
                self.update_trial_balance(company_id, mirrored, cur=cur)

            # ---- Mark linkage on journal rows ----
            cur.execute(
                f"UPDATE {schema}.journal SET reversed_by_journal_id=%s WHERE id=%s",
                (reversal_journal_id, journal_id),
            )
            cur.execute(
                f"UPDATE {schema}.journal SET reversal_of_journal_id=%s WHERE id=%s",
                (journal_id, reversal_journal_id),
            )

            conn.commit()
            return reversal_journal_id
    
    def get_account_balance_from_tb(self, company_id: int, code: str, *, cur=None) -> float:
        schema = self.company_schema(company_id)

        sql = f"""
            SELECT debit_total, credit_total
            FROM {schema}.trial_balance
            WHERE account = %s
        """

        if cur is not None:
            row = self.fetch_one(sql, (code,), cur=cur)
        else:
            row = self.fetch_one(sql, (code,))

        d = float(row.get("debit_total") or 0.0) if row else 0.0
        c = float(row.get("credit_total") or 0.0) if row else 0.0

        return d - c

