    def update_trial_balance(self, company_id: int, line: dict, cur=None) -> None:
        schema = self.company_schema(company_id)

        # -------------------------
        # 1) Resolve account CODE
        # -------------------------
        raw = (line.get("account_code") or line.get("account") or "").strip()
        if not raw:
            return

        account_code = raw

        # If not a code, try resolve by COA name -> code (prevents name rows in TB)
        if not CODE_RE.match(account_code):
            row = self.fetch_one(
                f"""
                SELECT code
                FROM {schema}.coa
                WHERE company_id=%s AND LOWER(name)=LOWER(%s)
                LIMIT 1
                """,
                (int(company_id), account_code),
                cur=cur,
            )
            if row and row.get("code"):
                account_code = (row["code"] or "").strip()

        # Still not a valid code? skip (or raise, your choice)
        if not CODE_RE.match(account_code):
            raise ValueError(f"Trial balance account must be COA code (got '{raw}')")

        # Optional: ensure it exists
        chk = self.fetch_one(
            f"SELECT 1 FROM {schema}.coa WHERE company_id=%s AND code=%s LIMIT 1",
            (int(company_id), account_code),
            cur=cur,
        )
        if not chk:
            raise ValueError(f"Account code '{account_code}' not found in COA")

        # -------------------------
        # 2) Normalize amount
        # supports:
        #   (a) debit/credit
        #   (b) dc + amount
        # -------------------------
        debit = float(line.get("debit") or 0.0)
        credit = float(line.get("credit") or 0.0)

        if debit == 0.0 and credit == 0.0 and ("dc" in line or "amount" in line):
            amt = float(line.get("amount") or 0.0)
            dc = (line.get("dc") or "").upper().strip()
            if dc == "D":
                debit = amt
                credit = 0.0
            elif dc == "C":
                debit = 0.0
                credit = amt
            else:
                if amt != 0:
                    raise ValueError("Trial balance line has amount but missing dc (D/C)")

        # -------------------------
        # 3) Upsert TB
        # closing_balance = debit - credit (asset/expense positive convention)
        # -------------------------
        sql = f"""
        INSERT INTO {schema}.trial_balance
            (company_id, account, debit_total, credit_total, closing_balance)
        VALUES (%s, %s, %s, %s, %s)
        ON CONFLICT (company_id, account)
        DO UPDATE SET
            debit_total = {schema}.trial_balance.debit_total + EXCLUDED.debit_total,
            credit_total = {schema}.trial_balance.credit_total + EXCLUDED.credit_total,
            closing_balance = {schema}.trial_balance.closing_balance
                            + (EXCLUDED.debit_total - EXCLUDED.credit_total);
        """

        params = (
            int(company_id),
            account_code,
            float(debit),
            float(credit),
            float(debit - credit),
        )

        if cur is not None:
            cur.execute(sql, params)
        else:
            self.execute_sql(sql, params)


    def insert_note(self, company_id: int, journal_id: int, account_code: str, description: str, cur=None) -> None:
        schema = self.company_schema(company_id)  # ✅ use your helper for consistency

        sql = f"""
        INSERT INTO {schema}.notes (journal_id, account_code, description)
        VALUES (%s, %s, %s);
        """
        params = (journal_id, account_code, description)

        if cur is not None:
            cur.execute(sql, params)
            return

        self.execute_sql(sql, params)


    def get_trial_balance_as_of(self, company_id: int, as_of: date) -> List[Dict[str, Any]]:
        schema = self.company_schema(company_id)
        sql = f"""
        SELECT
            l.account                       AS account,
            COALESCE(c.name, l.account)     AS name,
            COALESCE(c.section, '')         AS section,
            COALESCE(c.category, '')        AS category,
            COALESCE(c.standard, '')        AS standard,
            SUM(l.debit)                    AS debit_total,
            SUM(l.credit)                   AS credit_total,
            SUM(l.debit - l.credit)         AS closing_balance
        FROM {schema}.ledger l
        LEFT JOIN {schema}.coa c
            ON c.code = l.account
        WHERE l.date <= %s
        GROUP BY l.account, c.name, c.section, c.category, c.standard
        ORDER BY l.account::text ASC;
        """
        rows = self.fetch_all(sql, [as_of]) or []

        out: List[Dict[str, Any]] = []
        for r in rows:
            raw = float(r.get("closing_balance") or 0.0)

            out.append({
                "code":   str(r.get("account") or "").strip(),
                "name":   r.get("name") or "",
                "section": r.get("section") or "",
                "category": r.get("category") or "",
                "standard": r.get("standard") or "",
                "debit_total":  float(r.get("debit_total") or 0.0),
                "credit_total": float(r.get("credit_total") or 0.0),
                "closing_balance_raw": raw,
                "closing_balance": raw,  # TB: same as raw
            })

        return out

    def get_trial_balance_with_meta(
        self,
        company_id: int,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None
    ) -> List[Dict[str, Any]]:
        """
        If date_from/date_to are provided -> compute TB from ledger (date-aware).
        If not -> return snapshot TB from {schema}.trial_balance.
        """
        schema = self.company_schema(company_id)

        try:
            # If filtering by date, compute from ledger so presets work
            if date_from is not None or date_to is not None:
                where_clauses = ["1=1"]
                params: list = []

                if date_from is not None:
                    where_clauses.append("l.date >= %s")   # ✅ confirm ledger column is 'date'
                    params.append(date_from)

                if date_to is not None:
                    where_clauses.append("l.date <= %s")   # ✅ confirm ledger column is 'date'
                    params.append(date_to)

                where_sql = " AND ".join(where_clauses)

                sql = f"""
                SELECT
                    l.account                       AS account,
                    SUM(l.debit)                    AS debit_total,
                    SUM(l.credit)                   AS credit_total,
                    SUM(l.debit - l.credit)         AS closing_balance,
                    COALESCE(c.name, l.account)     AS name,
                    COALESCE(c.section, '')         AS section,
                    COALESCE(c.category, '')        AS category,
                    COALESCE(c.standard, '')        AS standard
                FROM {schema}.ledger l
                LEFT JOIN {schema}.coa c
                    ON c.code = l.account
                WHERE {where_sql}
                GROUP BY l.account, c.name, c.section, c.category, c.standard
                ORDER BY l.account::text ASC;
                """
                return self.fetch_all(sql, params)

            # Otherwise: return snapshot TB table (fast)
            sql = f"""
            SELECT
                tb.account,
                tb.debit_total,
                tb.credit_total,
                tb.closing_balance,
                c.name,
                c.section,
                c.category,
                c.standard
            FROM {schema}.trial_balance tb
            LEFT JOIN {schema}.coa c
                ON c.code = tb.account
            ORDER BY tb.account::text ASC
            """
            return self.fetch_all(sql)

        except Exception as e:
            print(f"[TB] Error in get_trial_balance_with_meta: {e}")
            return []

    def get_trial_balance(
        self,
        company_id: int,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None,
    ) -> List[Dict[str, Any]]:
        where_clauses = ["1=1"]
        params: list = []

        if date_from is not None:
            where_clauses.append("l.date >= %s")
            params.append(date_from)

        if date_to is not None:
            where_clauses.append("l.date <= %s")
            params.append(date_to)

        where_sql = " AND ".join(where_clauses)
        schema = self.company_schema(company_id)

        sql = f"""
        SELECT
            l.account                       AS code,
            COALESCE(c.name, l.account)     AS name,
            COALESCE(c.section, '')         AS section,
            COALESCE(c.category, '')        AS category,
            COALESCE(c.standard, '')        AS standard,

            c.template_code                 AS template_code,
            c.code_family                   AS code_family,
            c.code_numeric                  AS code_numeric,

            COALESCE(c.subcategory, '')     AS subcategory,
            COALESCE(c.description, '')     AS description,

            SUM(l.debit)                    AS debit_total,
            SUM(l.credit)                   AS credit_total,
            SUM(l.debit - l.credit)         AS closing_balance,

            -- ✅ DEBUG: date range actually used
            MIN(l.date)                     AS min_date,
            MAX(l.date)                     AS max_date

        FROM {schema}.ledger l
        LEFT JOIN {schema}.coa c
            ON c.code = l.account
        WHERE {where_sql}
        GROUP BY
            l.account,
            c.name, c.section, c.category, c.standard,
            c.template_code, c.code_family, c.code_numeric,
            c.subcategory, c.description
        ORDER BY l.account::text ASC;
        """

        rows = self.fetch_all(sql, params) or []
        out: List[Dict[str, Any]] = []

        if rows:
            print("TB RANGE:", rows[0].get("min_date"), "->", rows[0].get("max_date"))

        if rows:
            print("TB sample row keys:", rows[0].keys())
            print("TB sample row:", rows[0])

        for r in rows:
            row = {
                "code":            str(r.get("code") or "").strip(),
                "name":            r.get("name") or "",
                "section":         r.get("section") or "",
                "category":        r.get("category") or "",
                "standard":        r.get("standard") or "",
                "template_code":   r.get("template_code"),
                "code_family":     r.get("code_family") or "",
                "code_numeric":    r.get("code_numeric"),
                "subcategory":     r.get("subcategory") or "",
                "description":     r.get("description") or "",
                "debit_total":     float(r.get("debit_total") or 0.0),
                "credit_total":    float(r.get("credit_total") or 0.0),

                # ✅ DEBUG fields
                "min_date":        r.get("min_date"),
                "max_date":        r.get("max_date"),
            }

            # raw closing always debit - credit
            raw = float(r.get("closing_balance") or 0.0)
            row["closing_balance_raw"] = raw

            # contra detection (you already do this)
            row["is_contra"] = bool(ac.is_contra_row(row))

            # presented closing balance (normalised)
            row["closing_balance"] = raw * ac.normal_balance_sign(row)

            out.append(row)

        return out

    def _get_tb_closing_balance(self, company_id: int, account_code: str) -> float:
        """
        Reads TB closing_balance (debit - credit) from company_{id}.trial_balance
        Returns 0.0 if missing.
        """
        schema = self.company_schema(company_id)
        sql = f"""
            SELECT closing_balance
            FROM {schema}.trial_balance
            WHERE account = %s
            LIMIT 1;
        """
        row = self.fetch_one(sql, (account_code,))
        return float(row.get("closing_balance") or 0.0) if row else 0.0

    def ensure_overdraft_account(self, company_id: int, od_code: str = "2105") -> None:
        """
        Creates the overdraft COA account if it doesn't exist yet.
        Adjust section/category to match your COA conventions.
        """
        schema = self.company_schema(company_id)
       # self.ensure_company_schema(company_id)

        exists = self.fetch_one(
            f"SELECT 1 FROM {schema}.coa WHERE code = %s LIMIT 1;",
            (od_code,),
        )
        if exists:
            return

        # Insert minimal row. Fill standard if you have IFRS tags you prefer.
        self.execute_sql(
            f"""
            INSERT INTO {schema}.coa (name, code, section, category, description, standard)
            VALUES (%s, %s, %s, %s, %s, %s)
            """,
            (
                "Bank Overdraft",
                od_code,
                "Liabilities",
                "Current Liabilities",
                "Auto-created: overdraft account used when bank goes credit",
                "",
            ),
        )

    def _get_company_industry_flags(self, company_id: int) -> Dict[str, Any]:
        """
        Reads company industry + sub_industry,
        maps into INDUSTRY_PROFILES to know:
            - uses_cogs?
            - service_only?
            - etc.
        """
        company = self.get_company(company_id)
        industry = (company.get("industry") or "").strip()
        sub_industry = (company.get("sub_industry") or "").strip()
        profile = get_industry_profile(industry, sub_industry)

        return {
            "industry": profile.get("key") or industry or "",
            "uses_cogs": bool(profile.get("uses_cogs", False)),
        }


    def ensure_company_vat_filings(self, company_id: int):
        schema = self.company_schema(company_id)

        sql = f"""
        CREATE TABLE IF NOT EXISTS {schema}.vat_filings (
            id SERIAL PRIMARY KEY,
            company_id INT NOT NULL DEFAULT {company_id},

            period_start DATE NOT NULL,
            period_end DATE NOT NULL,
            period_label TEXT NULL,
            due_date DATE NULL,

            input_total NUMERIC(18,2) NOT NULL DEFAULT 0,
            output_total NUMERIC(18,2) NOT NULL DEFAULT 0,
            net_vat NUMERIC(18,2) NOT NULL DEFAULT 0,

            status TEXT NOT NULL DEFAULT 'draft',
            reference TEXT NULL,
            notes TEXT NULL,

            prepared_at TIMESTAMPTZ NULL,
            prepared_by_user_id INT NULL,
            submitted_at TIMESTAMPTZ NULL,
            submitted_by_user_id INT NULL,

            source TEXT NULL,
            source_id INT NULL,

            created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
        );

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS company_id INT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS period_start DATE;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS period_end DATE;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS period_label TEXT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS due_date DATE;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS input_total NUMERIC(18,2);

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS output_total NUMERIC(18,2);

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS net_vat NUMERIC(18,2);

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS status TEXT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS reference TEXT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS notes TEXT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS prepared_at TIMESTAMPTZ;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS prepared_by_user_id INT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS submitted_at TIMESTAMPTZ;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS submitted_by_user_id INT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS source TEXT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS source_id INT;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ;

        ALTER TABLE {schema}.vat_filings
        ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ;

        UPDATE {schema}.vat_filings
        SET company_id = {company_id}
        WHERE company_id IS NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN company_id SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN company_id SET DEFAULT {company_id};

        UPDATE {schema}.vat_filings
        SET input_total = COALESCE(input_total, 0),
            output_total = COALESCE(output_total, 0),
            net_vat = COALESCE(net_vat, 0)
        WHERE input_total IS NULL
        OR output_total IS NULL
        OR net_vat IS NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN input_total SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN input_total SET DEFAULT 0;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN output_total SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN output_total SET DEFAULT 0;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN net_vat SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN net_vat SET DEFAULT 0;

        UPDATE {schema}.vat_filings
        SET status = COALESCE(NULLIF(TRIM(status), ''), 'draft')
        WHERE status IS NULL OR TRIM(status) = '';

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN status SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN status SET DEFAULT 'draft';

        UPDATE {schema}.vat_filings
        SET created_at = COALESCE(created_at, NOW()),
            updated_at = COALESCE(updated_at, NOW())
        WHERE created_at IS NULL OR updated_at IS NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN created_at SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN created_at SET DEFAULT NOW();

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN updated_at SET NOT NULL;

        ALTER TABLE {schema}.vat_filings
        ALTER COLUMN updated_at SET DEFAULT NOW();

        DO $$
        BEGIN
        IF NOT EXISTS (
            SELECT 1 FROM pg_indexes
            WHERE schemaname = '{schema}'
            AND indexname = '{schema}_vat_filings_period_uniq'
        ) THEN
            EXECUTE format(
            'CREATE UNIQUE INDEX %I ON %I.vat_filings(company_id, period_start, period_end)',
            '{schema}_vat_filings_period_uniq',
            '{schema}'
            );
        END IF;
        END $$;

        DO $$
        BEGIN
        IF NOT EXISTS (
            SELECT 1
            FROM pg_constraint c
            JOIN pg_namespace n ON n.oid = c.connamespace
            WHERE c.conname = '{schema}_vat_filings_status_check'
            AND n.nspname = '{schema}'
        ) THEN
            EXECUTE format(
            'ALTER TABLE %I.vat_filings
            ADD CONSTRAINT %I
            CHECK (status = ANY (ARRAY[''draft'',''prepared'',''submitted'',''cancelled'']::text[]))',
            '{schema}',
            '{schema}_vat_filings_status_check'
            );
        END IF;
        END $$;

        CREATE INDEX IF NOT EXISTS {schema}_vat_filings_status_idx
        ON {schema}.vat_filings(company_id, status);

        CREATE INDEX IF NOT EXISTS {schema}_vat_filings_due_date_idx
        ON {schema}.vat_filings(company_id, due_date);

        CREATE INDEX IF NOT EXISTS {schema}_vat_filings_period_idx
        ON {schema}.vat_filings(company_id, period_start, period_end);
        """

        with self._conn_cursor() as (conn, cur):
            cur.execute(sql)
            conn.commit()

    def get_vat_filing(self, company_id: int, period_start, period_end):
        schema = self.company_schema(company_id)
        sql = f"""
        SELECT
            id,
            company_id,
            period_start,
            period_end,
            period_label,
            due_date,
            input_total,
            output_total,
            net_vat,
            status,
            reference,
            notes,
            prepared_at,
            prepared_by_user_id,
            submitted_at,
            submitted_by_user_id,
            source,
            source_id,
            created_at,
            updated_at
        FROM {schema}.vat_filings
        WHERE company_id = %s
            AND period_start = %s
            AND period_end = %s
        LIMIT 1
        """
        with self._conn_cursor() as (_conn, cur):
            cur.execute(sql, (int(company_id), period_start, period_end))
            return cur.fetchone() or None

    def upsert_vat_filing_prepared(
        self,
        company_id: int,
        *,
        period_start,
        period_end,
        period_label=None,
        due_date=None,
        input_total=0,
        output_total=0,
        net_vat=0,
        notes=None,
        prepared_by_user_id=None,
        source="api",
        source_id=None,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
        INSERT INTO {schema}.vat_filings (
            company_id,
            period_start,
            period_end,
            period_label,
            due_date,
            input_total,
            output_total,
            net_vat,
            status,
            notes,
            prepared_at,
            prepared_by_user_id,
            source,
            source_id,
            created_at,
            updated_at
        )
        VALUES (
            %s, %s, %s, %s, %s,
            %s, %s, %s,
            'prepared',
            %s,
            NOW(),
            %s,
            %s,
            %s,
            NOW(),
            NOW()
        )
        ON CONFLICT (company_id, period_start, period_end)
        DO UPDATE SET
            period_label = EXCLUDED.period_label,
            due_date = EXCLUDED.due_date,
            input_total = EXCLUDED.input_total,
            output_total = EXCLUDED.output_total,
            net_vat = EXCLUDED.net_vat,
            status = 'prepared',
            notes = COALESCE(EXCLUDED.notes, {schema}.vat_filings.notes),
            prepared_at = NOW(),
            prepared_by_user_id = EXCLUDED.prepared_by_user_id,
            source = EXCLUDED.source,
            source_id = EXCLUDED.source_id,
            updated_at = NOW()
        RETURNING id
        """

        params = (
            int(company_id),
            period_start,
            period_end,
            period_label,
            due_date,
            float(input_total or 0),
            float(output_total or 0),
            float(net_vat or 0),
            notes,
            int(prepared_by_user_id) if prepared_by_user_id else None,
            source,
            source_id,
        )

        with self._conn_cursor() as (conn, cur):
            cur.execute(sql, params)
            row = cur.fetchone() or {}
            conn.commit()
            return int(row.get("id") if isinstance(row, dict) else row[0])

    def mark_vat_filing_submitted(
        self,
        company_id: int,
        filing_id: int,
        *,
        submitted_by_user_id=None,
        reference=None,
        notes=None,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
        UPDATE {schema}.vat_filings
        SET
            status = 'submitted',
            submitted_at = NOW(),
            submitted_by_user_id = %s,
            reference = COALESCE(%s, reference),
            notes = COALESCE(%s, notes),
            updated_at = NOW()
        WHERE company_id = %s
            AND id = %s
        RETURNING id
        """

        with self._conn_cursor() as (conn, cur):
            cur.execute(sql, (
                int(submitted_by_user_id) if submitted_by_user_id else None,
                reference,
                notes,
                int(company_id),
                int(filing_id),
            ))
            row = cur.fetchone()
            conn.commit()
            return bool(row)

