    def get_income_statement_v2(
        self,
        company_id: int = None,
        date_from: date = None,
        date_to: date = None,
        template: str = "ifrs",
        basis: str = "external",
        compare: str = "none",
        cols_mode: int = 1,
        detail: str = "summary",
        prior_from: Optional[date] = None,
        prior_to: Optional[date] = None,
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """
        Unified external/management P&L entry point used by /api/.../pnl.

        - basis = external    -> IAS 1 engine (get_pnl_full_v2)
        - basis = management  -> internal builder (build_income_statement_template)

        Compare support:
        - If prior_from/prior_to are provided, they are forwarded to IAS 1 engine.
        - If not provided, IAS 1 engine may compute fallback priors.
        """
        # context
        ctx = get_company_context(self, company_id) or {}
        kwargs.pop("ctx", None)

        # allow passing via kwargs too (non-breaking for older callers)
        if prior_from is None and "prior_from" in kwargs:
            prior_from = kwargs.pop("prior_from", None)
        if prior_to is None and "prior_to" in kwargs:
            prior_to = kwargs.pop("prior_to", None)

        basis_norm = (basis or "external").lower().strip()

        # -------- MANAGEMENT / INTERNAL (classic + Hunter) --------
        if basis_norm == "management":
            prof = ctx.get("industry_profile") or get_industry_profile(
                ctx.get("industry"), ctx.get("sub_industry")
            )
            layout = choose_layout("pnl", prof)

            return build_income_statement_template(
                get_trial_balance_range_fn=self.get_trial_balance,
                get_company_context_fn=lambda cid: get_company_context(self, cid),
                company_id=company_id,
                date_from=date_from,
                date_to=date_to,
                template=template,
                basis="management",
                layout=layout,
                cols_mode=cols_mode,
            )

        # -------- EXTERNAL / IAS 1 --------
        kwargs_for_compare = {}
        if compare != "none":
            kwargs_for_compare = {"prior_from": prior_from, "prior_to": prior_to}

        return get_pnl_full_v2(
            self,
            company_id=company_id,
            date_from=date_from,
            date_to=date_to,
            template=template,
            basis="external",
            compare=compare,
            cols_mode=1,
            detail=detail,
            ctx=ctx,
            **kwargs_for_compare,
        )


    # ✅ Legacy shim for older code paths
    def get_pnl_full(
        self,
        company_id: int,
        date_from: date,
        date_to: date,
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """
        Old entry that now just forwards to get_pnl_full_v2 (external only).
        """
        return get_pnl_full_v2(
            self,
            company_id=company_id,
            date_from=date_from,
            date_to=date_to,
            template=kwargs.get("template", "ifrs"),
            basis=kwargs.get("basis", "external"),
            compare=kwargs.get("compare", "none"),
            cols_mode=int(kwargs.get("cols_mode", 1)),
            detail=kwargs.get("detail", "summary"),
            prior_from=kwargs.get("prior_from"),   # ✅ allow legacy callers to pass
            prior_to=kwargs.get("prior_to"),       # ✅ allow legacy callers to pass
        )


    def get_cashflow_full_v2(
        self,
        company_id: int,
        date_from: date,
        date_to: date,
        template: str = "ifrs",
        basis: str = "external",
        compare: str = "none",
        method: str = "direct",
        compare_mode: Optional[str] = None,
        prior_from: Optional[date] = None,
        prior_to: Optional[date] = None,
        preview_columns: int = 2,
        cols_mode: int = 1,
    ) -> Dict[str, Any]:

        if not date_from or not date_to:
            return {
                "meta": {"statement": "cf", "template": template, "basis": basis},
                "columns": [{"key": "cur", "label": "Amount"}],
                "sections": [],
                "error": "from/to are required",
            }

        # legacy param support
        if compare_mode is not None:
            compare = compare_mode

        preview_columns = norm_preview_columns(preview_columns)
        compare = norm_compare(compare)

        method = (method or "direct").lower().strip()
        if method not in ("direct", "indirect"):
            method = "direct"

        # RULE: preview=2 => NO compare
        if preview_columns == 2:
            compare = "none"
            prior_from = None
            prior_to = None

        # ✅ Use explicit priors if supplied; only compute as fallback
        if compare == "none":
            prior_from = None
            prior_to = None
        elif prior_from is None or prior_to is None:
            pf, pt = build_compare_range(date_from, date_to, compare)
            prior_from = prior_from or pf
            prior_to = prior_to or pt

        # ---- adapters ----
        def _get_company_context(cid: int) -> Dict[str, Any]:
            return get_company_context(self, cid)

        def _get_journals_period(cid: int, df: date, dt: date):
            return self.get_journals_with_lines_for_period(cid, df, dt)

        def _tb_as_of(cid: int, as_of: date):
            return self.get_trial_balance_with_meta(cid, date(1900, 1, 1), as_of)

        def _cash_position_from_tb(tb_rows):
            return self._cash_position_from_tb(tb_rows)

        # route indirect
        if method == "indirect":
            return self.get_cashflow_indirect_v2(
                company_id=company_id,
                date_from=date_from,
                date_to=date_to,
                template=template,
                basis=basis,
                compare=compare,
                prior_from=prior_from,
                prior_to=prior_to,
                preview_columns=preview_columns,
                cols_mode=cols_mode,
            )

        return build_cashflow_full_v2(
            get_company_context_fn=_get_company_context,
            get_journals_period_fn=_get_journals_period,
            tb_as_of_fn=_tb_as_of,
            cash_position_from_tb_fn=_cash_position_from_tb,
            company_id=company_id,
            date_from=date_from,
            date_to=date_to,
            template=template,
            basis=basis,
            compare_mode=compare,
            prior_from=prior_from,
            prior_to=prior_to,
            preview_columns=preview_columns,
            cols_mode=cols_mode,
        )


    def get_cashflow_indirect_v2(
        self,
        company_id: int,
        date_from: date,
        date_to: date,
        template: str = "ifrs",
        basis: str = "external",
        compare: str = "none",
        compare_mode: Optional[str] = None,
        prior_from: Optional[date] = None,
        prior_to: Optional[date] = None,
        preview_columns: int = 2,
        cols_mode: int = 1,
    ) -> Dict[str, Any]:

        if compare_mode is not None:
            compare = compare_mode

        preview_columns = norm_preview_columns(preview_columns)
        compare = norm_compare(compare)

        # RULE: preview=2 => NO compare
        if preview_columns == 2:
            compare = "none"
            prior_from = None
            prior_to = None

        # ✅ Use explicit priors if supplied; only compute as fallback
        if compare == "none":
            prior_from = None
            prior_to = None
        elif prior_from is None or prior_to is None:
            pf, pt = build_compare_range(date_from, date_to, compare)
            prior_from = prior_from or pf
            prior_to = prior_to or pt

        def _get_company_context(cid: int) -> Dict[str, Any]:
            return get_company_context(self, cid)

        def _get_pnl_full(cid: int, df: date, dt: date) -> Dict[str, Any]:
            pnl = self.get_pnl_full(cid, df, dt) or {}
            net = (pnl.get("net_result") or {}).get("amount")
            if net is None:
                pnl["net_result"] = {"amount": float((pnl.get("net") or 0.0) or 0.0)}
            return pnl

        def _decorate_lines_with_coa(lines, coa_map):
            for ln in lines or []:
                code = str(ln.get("code") or ln.get("account") or ln.get("account_code") or "").strip()
                if not code:
                    continue
                coa = coa_map.get(code) or {}
                ln["cf_bucket"] = coa.get("cf_bucket") or ln.get("cf_bucket") or ""
                ln["cf_section"] = coa.get("cf_section") or ln.get("cf_section") or ""
                ln["code_family"] = coa.get("code_family") or ln.get("code_family") or ""
                ln["is_working_capital"] = bool(coa.get("is_working_capital") or ln.get("is_working_capital") or False)
                ln["is_cash_equiv"] = bool(coa.get("is_cash_equiv") or ln.get("is_cash_equiv") or False)
                ln["is_non_cash_addback"] = bool(coa.get("is_non_cash_addback") or ln.get("is_non_cash_addback") or False)
                ln["is_contra"] = bool(coa.get("is_contra") or ln.get("is_contra") or False)

        def _get_journals_period(cid: int, df: date, dt: date):
            journals = self.get_journals_with_lines_for_period(cid, df, dt) or []
            coa_rows = self.get_company_coa(cid) or []
            coa_map = {str(a.get("code") or "").strip(): a for a in coa_rows if a.get("code")}
            for j in journals:
                _decorate_lines_with_coa(j.get("journal_lines") or [], coa_map)
            return journals

        def _get_trial_balance_asof_rows(cid: int, _unused: Optional[date], as_of: date):
            rows = self.get_trial_balance_as_of(cid, as_of) or []

            coa_rows = self.get_company_coa(cid) or []
            coa_map = {str(a.get("code") or "").strip(): a for a in coa_rows if a.get("code")}

            out = []
            for r in rows:
                code = str(r.get("code") or r.get("account") or "").strip()
                if not code:
                    continue

                coa = coa_map.get(code, {})

                tb = {
                    "code": code,
                    "name": r.get("name") or "",
                    "section": r.get("section") or "",
                    "category": r.get("category") or "",
                    "standard": r.get("standard") or "",
                    "debit_total": float(r.get("debit") or r.get("debit_total") or 0.0),
                    "credit_total": float(r.get("credit") or r.get("credit_total") or 0.0),
                    "closing_balance": float(r.get("closing_balance") or 0.0),
                }

                tb["cf_bucket"] = coa.get("cf_bucket") or ""
                tb["cf_section"] = coa.get("cf_section") or ""
                tb["code_family"] = coa.get("code_family") or ""
                tb["is_working_capital"] = bool(coa.get("is_working_capital") or False)
                tb["is_cash_equiv"] = bool(coa.get("is_cash_equiv") or False)
                tb["is_contra"] = bool(coa.get("is_contra") or False)

                out.append(tb)
            return out

        return build_cashflow_indirect_v2(
            get_company_context_fn=_get_company_context,
            get_pnl_full_fn=_get_pnl_full,
            get_trial_balance_asof_fn=_get_trial_balance_asof_rows,
            get_journals_period_fn=_get_journals_period,
            company_id=company_id,
            date_from=date_from,
            date_to=date_to,
            template=template,
            basis=basis,
            compare_mode=compare,
            prior_from=prior_from,
            prior_to=prior_to,
            preview_columns=preview_columns,
            cols_mode=cols_mode,
        )

    def _closing_balance_from_tb_row(self, r: Dict[str, Any]) -> float:
        """
        Returns (debit - credit) style balance.
        Works with both get_trial_balance() and get_trial_balance_with_meta() shapes.
        """
        # 1) If closing_balance already exists, trust it.
        if r is None:
            return 0.0

        if "closing_balance" in r and r.get("closing_balance") is not None:
            return float(r.get("closing_balance") or 0.0)

        # 2) Otherwise compute from debit/credit totals (support both key styles)
        debit = float(
            r.get("debit_total")
            if r.get("debit_total") is not None
            else r.get("debit") or 0.0
        )
        credit = float(
            r.get("credit_total")
            if r.get("credit_total") is not None
            else r.get("credit") or 0.0
        )
        return debit - credit

    def _cash_position_from_tb(self, tb_rows: List[Dict[str, Any]]) -> Dict[str, float]:
        from BackEnd.Services import accounting_classifiers as ac

        cash_positive = 0.0
        overdraft = 0.0

        for r in (tb_rows or []):
            # ✅ normalize fields for classifier
            rr = dict(r or {})
            if "code" not in rr and "account" in rr:
                rr["code"] = rr.get("account")
            if "account" not in rr and "code" in rr:
                rr["account"] = rr.get("code")

            if not ac._is_cash_bank(rr):
                continue

            closing = float(self._closing_balance_from_tb_row(rr))
            if closing >= 0:
                cash_positive += closing
            else:
                overdraft += abs(closing)

        return {
            "cash_positive": float(cash_positive),
            "overdraft": float(overdraft),
            "position": float(cash_positive - overdraft),
        }


    def _tb_as_of(self, company_id: int, as_of: date) -> List[Dict[str, Any]]:
        """
        Uses your existing TB query (ledger aggregated up to as_of).
        """
        return self.get_trial_balance(company_id, None, as_of) or []


    def get_cashflow_mini(
        self,
        company_id: int,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None,
        method: str = "direct",
        compare: str = "none",
    ):
        if not date_from or not date_to:
            return []

        compare = (compare or "none").lower().strip()
        if compare not in ("none", "prior_period", "prior_year"):
            compare = "none"

        method = (method or "direct").lower().strip()
        if method not in ("direct", "indirect"):
            method = "direct"

        stmt = self.get_cashflow_full_v2(
            company_id=company_id,
            date_from=date_from,
            date_to=date_to,
            compare=compare,
            method=method,
            cols_mode=1,          # ✅ force safe default for mini
            preview_columns=1,    # ✅ also safest for mini (compare-capable)
        )

        sec = {s.get("key"): float((s.get("totals") or {}).get("cur") or 0.0)
            for s in (stmt.get("sections") or [])}

        return [
            {"section": "operating", "label": "Net cash from operating activities", "amount": sec.get("operating", 0.0)},
            {"section": "investing", "label": "Net cash from investing activities", "amount": sec.get("investing", 0.0)},
            {"section": "financing", "label": "Net cash from financing activities", "amount": sec.get("financing", 0.0)},
        ]


    def get_pnl_mini(
        self,
        company_id: int,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None,
    ) -> List[Dict[str, Any]]:
        """
        Returns a compact P&L summary.
        """
        company = self.get_company(company_id)
        if not company:
            raise ValueError(f"Company {company_id} not found")

        flags = self._get_company_industry_flags(company_id) or {}
        uses_cogs = bool(flags.get("uses_cogs", False))

        tb_rows = self.get_trial_balance(company_id, date_from, date_to) or []

        revenue = 0.0
        cogs = 0.0
        expenses = 0.0
        other_income = 0.0

        for r in tb_rows:
            kind = ac._classify_tb_row(r)

            dr = float(r.get("debit_total") or 0.0)
            cr = float(r.get("credit_total") or 0.0)

            # P&L display sign:
            # revenue/other income positive
            # cogs/expenses negative
            amount = cr - dr

            if kind == "revenue":
                revenue += amount
            elif kind == "cogs":
                cogs += amount
            elif kind == "expense":
                expenses += amount
            elif kind == "other":
                other_income += amount

        rows: List[Dict[str, Any]] = []

        is_npo = "npo" in str(flags.get("industry") or "").lower()
        total_income = revenue + other_income

        if total_income != 0:
            rows.append({
                "label": "Revenue" if not is_npo else "Income",
                "amount": total_income
            })

        if uses_cogs and cogs != 0:
            rows.append({"label": "Cost of Sales", "amount": cogs})
            gross = total_income + cogs
            rows.append({"label": "Gross Profit", "amount": gross})
        else:
            gross = total_income

        if expenses != 0:
            rows.append({"label": "Operating Expenses", "amount": expenses})

        operating_profit = gross + expenses
        label_profit = "Net Profit" if not is_npo else "Surplus / (Deficit)"
        rows.append({"label": label_profit, "amount": operating_profit})

        return rows


    def get_bs_mini(
        self,
        company_id: int,
        as_of: Optional[date] = None,
        *,
        use_meta_when_no_date: bool = True,
    ) -> List[Dict[str, Any]]:
        """
        Compact BS summary for mini card.

        Rules:
        - Assets use debit-credit sign
        - Liabilities/equity use credit-debit sign
        - Negative cash/bank balances are presented as overdraft liabilities
        - Current-year P&L is folded into equity
        """

        if as_of:
            tb_rows = self.get_trial_balance(company_id, None, as_of) or []
        else:
            if use_meta_when_no_date and hasattr(self, "get_trial_balance_with_meta"):
                tb_rows = self.get_trial_balance_with_meta(company_id) or []
            else:
                tb_rows = self.get_trial_balance(company_id, None, None) or []

        assets = 0.0
        liabilities = 0.0
        equity = 0.0
        current_year_pnl = 0.0

        for r in tb_rows:
            kind = ac._classify_tb_row(r)

            code = str(r.get("code") or r.get("account") or "").strip()
            fam = str(r.get("code_family") or "").upper().strip()
            name = str(r.get("name") or "").lower()

            raw = float(
                r.get("closing_balance_raw")
                if r.get("closing_balance_raw") is not None
                else r.get("closing_balance")
                or 0.0
            )

            is_cash = (
                fam == "BS_CA"
                or code == "BS_CA_1000"
                or "cash" in name
                or "bank" in name
            )

            # Reclass negative cash to overdraft liability
            if kind == "asset" and is_cash and raw < 0:
                liabilities += abs(raw)
                continue

            if kind == "asset":
                assets += float(ac._bs_signed_amount(kind, r))
                continue

            if kind == "liability":
                liabilities += float(ac._bs_signed_amount(kind, r))
                continue

            if kind == "equity":
                equity += float(ac._bs_signed_amount(kind, r))
                continue

            if kind in ("revenue", "cogs", "expense", "other"):
                # TB convention is debit-credit:
                # positive = loss, negative = profit
                current_year_pnl += raw

        # net loss reduces equity; net profit increases equity
        equity -= current_year_pnl

        assets = round(assets, 2)
        liabilities = round(liabilities, 2)
        equity = round(equity, 2)

        return [
            {"section": "asset", "label": "Total Assets", "amount": assets},
            {"section": "liability", "label": "Total Liabilities", "amount": liabilities},
            {"section": "equity", "label": "Total Equity", "amount": equity},
            {
                "section": "check",
                "label": "Assets - (Liabilities + Equity)",
                "amount": round(assets - (liabilities + equity), 2),
            },
        ]

    def requires_notes(self, account_code: str) -> bool:
        """
        Simple rule: which accounts automatically get note disclosures.
        You can refine later. For now, receivables/provisions/leases.
        """
        return (
            account_code.startswith("17")
            or account_code.startswith("21")
            or account_code.startswith("26")
        )



