    def find_coa_account(
        self,
        company_id: int,
        *,
        keywords: list[str],
        standard: str | None = None,
        section_hint: str | None = None,
    ) -> Optional[str]:
        schema = f"company_{company_id}"
       # self.ensure_company_schema(company_id)

        if not keywords:
            return None

        # Build WHERE: each keyword must match (name OR description)
        kw_sql_parts = []
        params: list[str] = []
        for k in keywords:
            kw_sql_parts.append("((name ILIKE %s) OR (description ILIKE %s))")
            like = f"%{k}%"
            params.extend([like, like])

        extra_sql = ""
        if standard:
            extra_sql += " AND (standard ILIKE %s)"
            params.append(f"%{standard}%")

        if section_hint:
            extra_sql += " AND (section ILIKE %s)"
            params.append(f"%{section_hint}%")

        sql = f"""
            SELECT code
            FROM {schema}.coa
            WHERE posting = TRUE
            AND {" AND ".join(kw_sql_parts)}
            {extra_sql}
            ORDER BY
            (standard ILIKE %s) DESC,
            code_numeric NULLS LAST,
            code ASC
            LIMIT 1
        """
        # small preference boost when standard provided
        params.append(f"%{standard}%" if standard else "%")

        row = self.fetch_one(sql, tuple(params))
        if not row:
            return None
        return row["code"] if isinstance(row, dict) else row[0]

    def get_ifrs16_default_accounts(self, company_id: int) -> Dict[str, str]:
        # Keyword-first for IFRS16 tagged accounts
        rou = (
            self.find_coa_account(
                company_id,
                keywords=["right-of-use", "asset"],
                standard="IFRS 16",
                section_hint="Non-Current",
            )
            or self.find_coa_account(
                company_id,
                keywords=["rou", "asset"],
                standard="IFRS 16",
            )
        )

        liab_cl = self.find_coa_account(
            company_id,
            keywords=["lease", "liability"],
            standard="IFRS 16",
            section_hint="Current",
        )

        liab_ncl = self.find_coa_account(
            company_id,
            keywords=["lease", "liability"],
            standard="IFRS 16",
            section_hint="Non-Current",
        )

        interest = (
            self.find_coa_account(company_id, keywords=["interest"], section_hint="Expense")
            or self.find_coa_account(company_id, keywords=["finance", "cost"])
        )

        depr = (
            self.find_coa_account(company_id, keywords=["depreciation"])
            or self.find_coa_account(company_id, keywords=["amort"])
        )

        offset = (
            self.find_coa_account(company_id, keywords=["payable"], section_hint="Current Liab")
            or self.find_coa_account(company_id, keywords=["accrued"])
            or self.find_coa_account(company_id, keywords=["bank"])
        )

        # Fallback chain: bucket -> BUCKET_BASE
        def fb(bucket: str, base: int) -> str:
            return self.get_default_account_by_bucket(company_id, bucket) or str(base)

        return {
            "rou_asset_account": rou or fb("BS_NCA", 1100),

            # return both; journal builder will split amounts
            "lease_liability_current_account": liab_cl or fb("BS_CL", 2000),
            "lease_liability_noncurrent_account": liab_ncl or fb("BS_NCL", 2400),

            "interest_expense_account": interest or fb("PL_FIN", 7200),
            "depreciation_expense_account": depr or fb("PL_DA", 7100),
            "direct_costs_offset_account": offset or fb("BS_CL", 2000),
        }

