    def get_active_lease_schedule_version(self, company_id: int, lease_id: int, *, cur=None) -> int:
        schema = f"company_{int(company_id)}"
        sql = f"""
            SELECT MAX(version_no) AS v
            FROM {schema}.lease_schedule
            WHERE lease_id=%s AND is_active=TRUE
        """

        if cur is not None:
            cur.execute(sql, (int(lease_id),))
            row = cur.fetchone() or {}
            v = row.get("v") if isinstance(row, dict) else row[0]
            return int(v or 1)

        row = self.fetch_one(sql, (int(lease_id),)) or {}
        return int(row.get("v") or 1)


    def list_lease_schedule(
        self,
        company_id: int,
        lease_id: int,
        *,
        version_no: Optional[int] = None,
        active_only: bool = True,
        limit: int = 500,
        offset: int = 0,
        cur=None,
    ) -> Dict[str, Any]:
        """
        List schedule periods for a lease.
        - If version_no is None and active_only=True, it uses the active version.
        - Returns {rows, total, version_no, active_only, limit, offset}
        """
        schema = f"company_{int(company_id)}"
        lease_id = int(lease_id)
        limit = int(limit or 500)
        offset = int(offset or 0)

        if version_no is None and active_only:
            version_no = self.get_active_lease_schedule_version(company_id, lease_id, cur=cur)

        where = ["lease_id=%(lease_id)s"]
        params = {
            "lease_id": lease_id,
            "limit": limit,
            "offset": offset,
        }

        if active_only:
            where.append("is_active=TRUE")

        if version_no is not None:
            where.append("version_no=%(version_no)s")
            params["version_no"] = int(version_no)

        where_sql = " WHERE " + " AND ".join(where)

        sql = f"""
        SELECT
            id,
            lease_id,
            version_no,
            is_active,
            modification_id,
            period_no,
            period_start,
            period_end,
            payment_timing,
            opening_liability,
            interest,
            payment,
            principal,
            closing_liability,
            depreciation,
            vat_portion,
            net_payment,
            posted_journal_id,
            posted_at,
            created_at
        FROM {schema}.lease_schedule
        {where_sql}
        ORDER BY period_no ASC
        LIMIT %(limit)s OFFSET %(offset)s
        """

        rows = self.fetch_all(sql, params, cur=cur) or []

        count_sql = f"""
        SELECT count(*) AS n
        FROM {schema}.lease_schedule
        {where_sql}
        """
        total_row = self.fetch_one(count_sql, params, cur=cur) or {}
        total = int(total_row.get("n") or 0)

        return {
            "rows": rows,
            "total": total,
            "lease_id": lease_id,
            "version_no": int(version_no or 1),
            "active_only": bool(active_only),
            "limit": limit,
            "offset": offset,
        }

    def get_lease_schedule_row(
        self,
        company_id: int,
        *,
        lease_id: int,
        period_no: int,
        version_no: Optional[int] = None,
        active_only: bool = True,
        cur=None,
    ) -> Optional[Dict[str, Any]]:
        """
        Get one schedule row for a lease + period.
        - If version_no is None and active_only=True, uses active version.
        """
        schema = f"company_{int(company_id)}"
        lease_id = int(lease_id)
        period_no = int(period_no)

        if version_no is None and active_only:
            version_no = self.get_active_lease_schedule_version(company_id, lease_id, cur=cur)

        where = ["lease_id=%(lease_id)s", "period_no=%(period_no)s"]
        params = {"lease_id": lease_id, "period_no": period_no}

        if active_only:
            where.append("is_active=TRUE")

        if version_no is not None:
            where.append("version_no=%(version_no)s")
            params["version_no"] = int(version_no)

        sql = f"""
        SELECT
            id,
            lease_id,
            version_no,
            is_active,
            modification_id,
            period_no,
            period_start,
            period_end,
            payment_timing,
            opening_liability,
            interest,
            payment,
            principal,
            closing_liability,
            depreciation,
            vat_portion,
            net_payment,
            posted_journal_id,
            posted_at,
            created_at
        FROM {schema}.lease_schedule
        WHERE {" AND ".join(where)}
        LIMIT 1
        """
        return self.fetch_one(sql, params, cur=cur)
    
    def list_leases(self, company_id: int, *, limit: int = 200, offset: int = 0, q: str = "", cur=None):
        schema = f"company_{int(company_id)}"
        params = {"limit": int(limit), "offset": int(offset)}
        where = ""

        if q:
            where = "WHERE (l.lease_name ILIKE %(q)s OR COALESCE(le.name,'') ILIKE %(q)s)"
            params["q"] = f"%{q}%"

        sql = f"""
        SELECT
        l.id,
        l.lease_name,
        l.lessor_id,
        le.name AS lessor_name,
        l.start_date,
        l.end_date,
        l.payment_amount,
        l.payment_frequency,
        l.payment_timing,
        l.annual_rate,
        l.vat_rate,
        l.opening_lease_liability,
        l.opening_rou_asset
        FROM {schema}.leases l
        LEFT JOIN {schema}.lessors le ON le.id = l.lessor_id
        {where}
        ORDER BY l.id DESC
        LIMIT %(limit)s OFFSET %(offset)s
        """

        if cur is not None:
            cur.execute(sql, params)
            rows = cur.fetchall() or []
        else:
            rows = self.fetch_all(sql, params) or []

        # ✅ IMPORTANT: for count query, don't pass limit/offset unless SQL uses them
        count_params = {}
        if q:
            count_params["q"] = params["q"]

        count_sql = f"""
        SELECT count(*) AS n
        FROM {schema}.leases l
        LEFT JOIN {schema}.lessors le ON le.id = l.lessor_id
        {where}
        """

        total_row = self.fetch_one(count_sql, (count_params if q else None), cur=cur) or {}
        total = int(total_row.get("n") or 0)

        return rows, total

    def get_lease(self, company_id: int, lease_id: int, cur=None):
        """
        Fetch a single lease master record + lessor info.

        Returns:
            dict | None
        """

        schema = f"company_{int(company_id)}"

        sql = f"""
        SELECT
            l.id,
            l.company_id,
            l.lessor_id,
            le.name AS lessor_name,
            le.reg_no AS lessor_reg_no,
            le.vat_no AS lessor_vat_no,

            l.lease_name,
            l.role,
            l.start_date,
            l.end_date,

            l.payment_amount,
            l.payment_frequency,
            l.payment_timing,

            l.annual_rate,
            l.initial_direct_costs,
            l.residual_value,
            l.vat_rate,

            l.opening_lease_liability,
            l.opening_rou_asset,

            -- Optional metadata
            l.created_at,
            l.updated_at

        FROM {schema}.leases l
        LEFT JOIN {schema}.lessors le
            ON le.id = l.lessor_id

        WHERE l.id = %(lease_id)s
        LIMIT 1
        """

        params = {"lease_id": int(lease_id)}

        if cur is not None:
            cur.execute(sql, params)
            row = cur.fetchone()
            return dict(row) if row else None

        return self.fetch_one(sql, params)

