    def post_lease_payment(
        self,
        *,
        company_id: int,
        lease_id: int,
        amount,
        payment_date: date,
        bank_account_id: int | None,
        reference: str | None,
        description: str | None,
        user_id: int | None,
        engagement_company_id: int | None = None,
        engagement_id: int | None = None,
        schedule_id: int | None = None,
    ) -> dict:
        """
        Posts a lease payment as a journal entry + ledger lines.

        IMPORTANT DESIGN:
        - Payment posting = cash/VAT/liability settlement ONLY.
        - Monthly IFRS16 posting (interest + ROU depreciation) is posted separately.
        - Therefore: this function MUST NOT write company_*.lease_schedule.posted_journal_id,
        because that column is reserved for monthly posting.
        """
        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> Decimal:
            return Decimal(str(x or "0")).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

        schema = f"company_{int(company_id)}"
        TOL = money("0.02")

        with self._conn_cursor() as (conn, cur):
            # 1) Load lease (and ensure lessor exists)
            lease = self.get_lease_by_id(company_id, lease_id, cur=cur)
            if not lease:
                raise ValueError("Lease not found")

            lessor_id = int(lease.get("lessor_id") or 0)
            if not lessor_id:
                raise ValueError("Lease missing lessor_id (cannot post payment without a lessor)")

            amt_in = money(amount)
            if amt_in <= money("0"):
                raise ValueError("Amount must be > 0")

            # 2) Resolve bank posting code
            if not bank_account_id:
                raise ValueError("No bank account selected")

            bank = self.get_company_bank_account(company_id, int(bank_account_id))
            if not bank:
                raise ValueError("Bank account not found")

            bank_code = (bank.get("ledger_account_code") or "").strip()
            if not bank_code:
                raise ValueError("Selected bank account has no ledger_account_code")

            # 3) Resolve lease posting accounts (from settings)
            accts = self.get_lease_posting_accounts(company_id, cur=cur)

            def resolve(raw: str | None, label: str) -> str:
                raw = (raw or "").strip()
                if not raw:
                    raise ValueError(f"Missing {label} account in company settings")
                row = self.get_account_row_for_posting(company_id, raw, cur=cur)
                if not row:
                    raise ValueError(f"{label} '{raw}' not found in COA")
                posting = (row[1] or "").strip()
                if not posting:
                    raise ValueError(f"{label} resolved blank for '{raw}'")
                return posting

            LIAB_CUR = resolve(accts.get("liability_current"), "Lease liability current")
            LIAB_NCUR = resolve(
                accts.get("liability_noncurrent") or accts.get("liability_current"),
                "Lease liability non-current",
            )
            INT_EXP = resolve(accts.get("interest_exp"), "Lease interest expense")
            VAT_INPUT = resolve(accts.get("vat_input"), "VAT input")

            # 4) Choose schedule row (lock it)
            if schedule_id:
                sched = self.fetch_one(
                    f"""
                    SELECT *
                    FROM {schema}.lease_schedule
                    WHERE id=%s AND lease_id=%s
                    LIMIT 1
                    FOR UPDATE
                    """,
                    (int(schedule_id), int(lease_id)),
                    cur=cur,
                )
                if not sched:
                    raise ValueError("Invalid schedule_id (not found for this lease)")
            else:
                sched = self.fetch_one(
                    f"""
                    SELECT *
                    FROM {schema}.lease_schedule
                    WHERE lease_id=%s
                    AND %s BETWEEN period_start AND period_end
                    ORDER BY period_no ASC
                    LIMIT 1
                    FOR UPDATE
                    """,
                    (int(lease_id), payment_date),
                    cur=cur,
                )
                if not sched:
                    raise ValueError("No schedule period found for payment_date")

            # 5) Idempotency checks (DO NOT use lease_schedule.posted_journal_id!)
            already_pay = self.fetch_one(
                f"""
                SELECT id, posted_journal_id
                FROM {schema}.lease_payments
                WHERE lease_id=%s
                AND COALESCE(schedule_id,0)=COALESCE(%s,0)
                AND status='posted'
                ORDER BY id DESC
                LIMIT 1
                """,
                (int(lease_id), int(sched["id"])),
                cur=cur,
            )
            if already_pay:
                return {
                    "ok": False,
                    "error": "ALREADY_PAID",
                    "schedule_id": int(sched["id"]),
                    "journal_id": int(already_pay.get("posted_journal_id") or 0),
                    "lease_payment_id": int(already_pay.get("id")),
                }

            # 6) Compute allocation from schedule row
            interest = money(sched.get("interest"))
            principal = money(sched.get("principal"))
            gross_expected = money(sched.get("payment") or 0)
            vat_portion = money(sched.get("vat_portion") or 0)

            alloc = min(amt_in, gross_expected) if gross_expected > money("0") else amt_in
            ratio = (alloc / gross_expected) if gross_expected > money("0") else money("0")

            timing = (sched.get("payment_timing") or lease.get("payment_timing") or "").strip().lower()

            alloc_vat = money(vat_portion * ratio)

            # ✅ Design A: payment flow is settlement only
            alloc_interest = money("0")
            alloc_principal = money(alloc - alloc_vat)
            alloc_net = money(alloc - alloc_vat)

            if (alloc_interest + alloc_principal + alloc_vat - alloc).copy_abs() > money("0.05"):
                raise ValueError(
                    f"Allocation mismatch: interest({alloc_interest}) + principal({alloc_principal}) + vat({alloc_vat}) != alloc({alloc})"
                )

            # Duplicate prevention (same lease/date/amount/reference)
            existing = self.fetch_one(
                f"""
                SELECT id, posted_journal_id, status
                FROM {schema}.lease_payments
                WHERE lease_id=%s
                AND payment_date=%s
                AND amount_gross=%s
                AND COALESCE(reference,'')=COALESCE(%s,'')
                ORDER BY id DESC
                LIMIT 1
                """,
                (int(lease_id), payment_date, float(amt_in), reference),
                cur=cur,
            )
            if existing:
                return {
                    "ok": False,
                    "error": "DUPLICATE_PAYMENT",
                    "lease_payment_id": int(existing["id"]),
                    "journal_id": int(existing.get("posted_journal_id") or 0) or None,
                    "status": existing.get("status"),
                }

            # 7) Insert lease_payment row (draft)
            pay_id = self.insert_lease_payment(
                company_id=company_id,
                lease_id=int(lease_id),
                lessor_id=int(lessor_id),
                schedule_id=int(sched["id"]),
                payment_date=payment_date,
                amount_gross=float(amt_in),
                amount_net=float(alloc_net),
                vat_amount=float(alloc_vat),
                reference=reference,
                notes=description,
                bank_account_code=bank_code,
                status="draft",
                created_by=user_id,
                cur=cur,
            )
            if not pay_id:
                raise ValueError("Failed to create lease payment record")

            # 8) Build journal lines (payment only)
            lines: list[dict] = []
            lines.append({"account_code": bank_code, "debit": 0.0, "credit": float(alloc), "memo": "Lease payment (cash)"})

            # (Optional) keep this for legacy flows; currently alloc_interest = 0 by design
            if alloc_interest > money("0"):
                lines.append({"account_code": INT_EXP, "debit": float(alloc_interest), "credit": 0.0, "memo": "Lease interest"})

            if alloc_principal > money("0"):
                lines.append({
                    "account_code": LIAB_NCUR or LIAB_CUR,  # reduce liability bucket (your chosen design)
                    "debit": float(alloc_principal),
                    "credit": 0.0,
                    "memo": "Reduce lease liability"
                })

            if alloc_vat > money("0"):
                lines.append({"account_code": VAT_INPUT, "debit": float(alloc_vat), "credit": 0.0, "memo": "VAT input (lease payment)"})

            entry = {
                "date": payment_date.isoformat(),
                "ref": (reference or f"LEASEPAY-{pay_id}").strip(),
                "description": description or f"Lease payment – {lease.get('lease_name') or f'Lease {lease_id}'}",
                "gross_amount": float(alloc),
                "net_amount": float(alloc_net),
                "vat_amount": float(alloc_vat),
                "source": "lease_payment",
                "source_id": int(pay_id),
                "lines": lines,
            }

            journal_id = int(self.post_journal(company_id, entry, cur=cur) or 0)
            if journal_id <= 0:
                raise ValueError("Failed to post lease payment journal")

            # 9) Mark payment posted (ONLY the payment table)
            self.set_lease_payment_posted(company_id, int(pay_id), journal_id, cur=cur, conn=conn)

            # 10) publish engagement posting activity (INSIDE transaction)
            if engagement_company_id and engagement_id:
                currency_code = (
                    (lease.get("currency_code") or "").strip()
                    or (lease.get("currency") or "").strip()
                    or (self.get_company_profile(company_id).get("currency") if self.get_company_profile(company_id) else "")
                    or "ZAR"
                )

                self.upsert_engagement_posting_activity(
                    cur,
                    company_id=int(engagement_company_id),
                    engagement_id=int(engagement_id),
                    posting_date=payment_date,
                    module_name="leases",
                    event_type="payment",
                    reference_no=(reference or f"LEASEPAY-{pay_id}"),
                    description=(description or f"Lease payment posted for lease {lease_id}"),
                    prepared_by_user_id=user_id,
                    reviewer_user_id=None,
                    status="posted",
                    amount=float(alloc),
                    currency_code=currency_code,
                    source_table="lease_payments",
                    source_id=int(pay_id),
                    notes=f"Lease payment posted to journal {journal_id}",
                    created_by_user_id=user_id,
                    updated_by_user_id=user_id,
                )

                print("[post_lease_payment] engagement activity recorded", flush=True)

            # 11) DO NOT touch lease_schedule.posted_journal_id here
            fully_paid = (gross_expected > money("0")) and (alloc + TOL >= gross_expected)

            conn.commit()

            return {
                "ok": True,
                "lease_payment_id": int(pay_id),
                "journal_id": int(journal_id),
                "lease_id": int(lease_id),
                "lessor_id": int(lessor_id),
                "schedule_id": int(sched["id"]),
                "period_no": int(sched.get("period_no") or 0),
                "payment_timing": timing,
                "amount_input": str(amt_in),
                "amount_expected": str(gross_expected),
                "amount_allocated": str(alloc),
                "interest": str(alloc_interest),
                "principal": str(alloc_principal),
                "vat": str(alloc_vat),
                "fully_paid": bool(fully_paid),
                "bank_code": bank_code,
                "liability_current_code": LIAB_CUR,
                "liability_noncurrent_code": LIAB_NCUR,
            }

    def get_lease_schedule_by_id(
        self,
        company_id: int,
        *,
        lease_id: int,
        schedule_id: int,
        version_no: Optional[int] = None,
        active_only: bool = True,
        cur=None,
    ) -> Optional[Dict[str, Any]]:
        schema = f"company_{int(company_id)}"
        lease_id = int(lease_id)
        schedule_id = int(schedule_id)

        where = ["id=%(schedule_id)s", "lease_id=%(lease_id)s"]
        params = {"schedule_id": schedule_id, "lease_id": lease_id}

        if active_only:
            where.append("is_active=TRUE")

        if version_no is not None:
            where.append("version_no=%(version_no)s")
            params["version_no"] = int(version_no)

        sql = f"""
        SELECT
            id,
            lease_id,
            version_no,
            is_active,
            modification_id,
            period_no,
            period_start,
            period_end,
            payment_timing,
            opening_liability,
            interest,
            payment,
            principal,
            closing_liability,
            depreciation,
            vat_portion,
            net_payment,
            posted_journal_id,
            posted_at,
            created_at
        FROM {schema}.lease_schedule
        WHERE {" AND ".join(where)}
        LIMIT 1
        """
        return self.fetch_one(sql, params, cur=cur)

    def preview_lease_payment(
        self,
        *,
        company_id: int,
        lease_id: int,
        amount,
        payment_date: date,
        bank_account_id: int,
        reference: str | None,
        description: str | None,
        user_id: int | None,
        schedule_id: int | None = None,
    ) -> dict:
        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> Decimal:
            return Decimal(str(x or "0")).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

        def acct_name(code: str):
            r = self.get_account_row_for_posting(company_id, code)
            return r[0] if r else code   # fallback to code if not found

        lease = self.get_lease_by_id(company_id, lease_id)
        if not lease:
            raise ValueError("Lease not found")

        lessor_id = int(lease.get("lessor_id") or 0)
        if not lessor_id:
            raise ValueError("Lease missing lessor_id (cannot post payment without a lessor)")

        lessor = self.get_lessor(company_id, lessor_id) if hasattr(self, "get_lessor") else None

        amt = money(amount)
        if amt <= money("0"):
            raise ValueError("Amount must be > 0")

        bank = self.get_company_bank_account(company_id, int(bank_account_id))
        if not bank:
            raise ValueError("Bank account not found")

        bank_code = (bank.get("ledger_account_code") or "").strip()
        if not bank_code:
            raise ValueError("Selected bank account has no ledger_account_code")

        # resolve lease accounts from company_account_settings
        accts = self.get_lease_posting_accounts(company_id)

        def resolve(raw: str | None, label: str) -> str:
            raw = (raw or "").strip()
            if not raw:
                raise ValueError(f"Missing {label} account in company settings")
            row = self.get_account_row_for_posting(company_id, raw)
            if not row:
                raise ValueError(f"{label} '{raw}' not found in COA")
            posting = (row[1] or "").strip()
            if not posting:
                raise ValueError(f"{label} resolved blank for '{raw}'")
            return posting

        LIAB_CUR  = resolve(accts.get("liability_current"), "Lease liability current")
        LIAB_NCUR = resolve(accts.get("liability_noncurrent") or accts.get("liability_current"), "Lease liability non-current")
        INT_EXP   = resolve(accts.get("interest_exp"), "Lease interest expense")
        VAT_INPUT = resolve(accts.get("vat_input"), "VAT input")

        # pick schedule period
        if schedule_id:
            sched = self.get_lease_schedule_by_id(
                company_id,
                lease_id=int(lease_id),
                schedule_id=int(schedule_id),
                active_only=True,
            )
            if not sched:
                raise ValueError("Invalid schedule_id")
            
        if not sched:
            sched = self.get_next_unpaid_lease_period(company_id, int(lease_id))
            if not sched:
                raise ValueError("No unpaid schedule period found to allocate this payment")

        interest = money(sched.get("interest"))
        principal = money(sched.get("principal"))
        gross_expected = money(sched.get("payment"))
        vat_portion = money(sched.get("vat_portion") or 0)

        alloc = min(amt, gross_expected) if gross_expected > money("0") else amt
        ratio = (alloc / gross_expected) if gross_expected > money("0") else money("0")

        alloc_interest = money(interest * ratio)
        alloc_principal = money(principal * ratio)
        alloc_vat = money(vat_portion * ratio)

        period_no = int(sched.get("period_no") or 0)
        ref_txt = (reference or "").strip()
        desc_txt = (description or "").strip()

        # Use payment_date/reference/description in memos + returned object
        base_memo = desc_txt or f"Lease payment – {lease.get('lease_name') or f'Lease {lease_id}'} – P{period_no}"
        if ref_txt:
            base_memo = f"{base_memo} ({ref_txt})"

        timing = (sched.get("payment_timing") or lease.get("payment_timing") or "").lower()

        if timing == "advance":
            # cash payment doesn't "pay" interest in your schedule definition
            alloc_interest = money("0")
            # allocate ALL net portion to principal
            alloc_principal = money(alloc - alloc_vat)
        else:
            # arrears logic (your existing ratio split)
            alloc_interest = money(interest * ratio)
            alloc_principal = money(principal * ratio)

        lines = []
        lines.append({
            "account_code": bank_code,
            "account_name": acct_name(bank_code),
            "debit": 0.0,
            "credit": float(alloc),
            "memo": f"{base_memo} [cash]",
        })

        if alloc_interest > money("0"):
            lines.append({
                "account_code": INT_EXP,
                "account_name": acct_name(INT_EXP),
                "debit": float(alloc_interest),
                "credit": 0.0,
                "memo": f"{base_memo} [interest]",
            })

        if alloc_vat > money("0"):
            lines.append({
                "account_code": VAT_INPUT,
                "account_name": acct_name(VAT_INPUT),
                "debit": float(alloc_vat),
                "credit": 0.0,
                "memo": f"{base_memo} [VAT input]",
            })

        if alloc_principal > money("0"):
            lines.append({
                "account_code": LIAB_CUR,
                "account_name": acct_name(LIAB_CUR),
                "debit": float(alloc_principal),
                "credit": 0.0,
                "memo": f"{base_memo} [principal]",
            })

        # Ensure all signature params are "used" (also useful for UI/audit)
        return {
            "company_id": int(company_id),
            "lease_id": int(lease_id),
            "lease_name": lease.get("lease_name"),

            "lessor_id": int(lessor_id),
            "lessor_name": (lessor.get("name") if isinstance(lessor, dict) else None),

            "schedule_id": int(sched["id"]),
            "period_no": period_no,
            "period_start": str(sched.get("period_start")),
            "period_end": str(sched.get("period_end")),

            "payment_date": payment_date.isoformat(),
            "reference": reference,
            "description": description,
            "requested_by_user_id": int(user_id) if user_id is not None else None,

            "amount_input": str(amt),
            "amount_expected": str(gross_expected),
            "amount_allocated": str(alloc),

            "split": {
                "interest": str(alloc_interest),
                "principal": str(alloc_principal),
                "vat": str(alloc_vat),
            },

            "posting": {
                "bank_account_code": bank_code,
                "interest_expense_code": INT_EXP,
                "liability_current_code": LIAB_CUR,
                "liability_noncurrent_code": LIAB_NCUR,
            },

            "preview_journal": {
                "date": payment_date.isoformat(),
                "ref": ref_txt or f"LEASEPAY-PREVIEW-{lease_id}-P{period_no}",
                "description": desc_txt or base_memo,
                "source": "lease_payment_preview",
                "source_id": None,
            },

            "preview_journal_lines": [
                ln for ln in lines
                if (ln.get("debit") or 0) != 0 or (ln.get("credit") or 0) != 0
            ],
        }

    def create_lease_modification_draft(
        self,
        company_id: int,
        *,
        lease_id: int,
        modification_date: date,
        change_type: str,
        reason: Optional[str] = None,
        old_payment_amount: Optional[float] = None,
        new_payment_amount: Optional[float] = None,
        old_annual_rate: Optional[float] = None,
        new_annual_rate: Optional[float] = None,
        old_end_date: Optional[date] = None,
        new_end_date: Optional[date] = None,
        created_by: Optional[int] = None,
    ) -> Dict[str, Any]:
        sch = self._sch(company_id)
        sql = f"""
            INSERT INTO {sch}.lease_modifications (
                company_id, lease_id,
                modification_date, change_type, reason,
                old_payment_amount, new_payment_amount,
                old_annual_rate, new_annual_rate,
                old_end_date, new_end_date,
                status, created_by
            )
            VALUES (
                %s, %s,
                %s, %s, %s,
                %s, %s,
                %s, %s,
                %s, %s,
                'draft', %s
            )
            RETURNING *;
        """
        return self.fetch_one(sql, (
            int(company_id), int(lease_id),
            modification_date, str(change_type), reason,
            old_payment_amount, new_payment_amount,
            old_annual_rate, new_annual_rate,
            old_end_date, new_end_date,
            created_by
        )) or {}

    def update_lease_modification_draft(
        self,
        company_id: int,
        mod_id: int,
        *,
        patch: Dict[str, Any],
    ) -> Dict[str, Any]:
        """
        Only updates allowed fields while status='draft'.
        """
        sch = self._sch(company_id)

        allowed = {
            "modification_date", "change_type", "reason",
            "old_payment_amount", "new_payment_amount",
            "old_annual_rate", "new_annual_rate",
            "old_end_date", "new_end_date",
        }

        sets = []
        params: List[Any] = []
        for k, v in (patch or {}).items():
            if k in allowed:
                sets.append(f"{k} = %s")
                params.append(v)

        if not sets:
            return self.get_lease_modification(company_id, mod_id)

        params.extend([int(mod_id)])
        sql = f"""
            UPDATE {sch}.lease_modifications
            SET {", ".join(sets)}
            WHERE id=%s AND status='draft'
            RETURNING *;
        """
        return self.fetch_one(sql, tuple(params)) or {}

    def set_lease_modification_computed(
        self,
        company_id: int,
        mod_id: int,
        *,
        liability_before: float,
        liability_after: float,
        rou_before: float,
        rou_after: float,
    ) -> Dict[str, Any]:
        sch = self._sch(company_id)
        adj_liab = float(liability_after) - float(liability_before)
        adj_rou  = float(rou_after) - float(rou_before)

        sql = f"""
            UPDATE {sch}.lease_modifications
            SET
                liability_before=%s,
                liability_after=%s,
                rou_before=%s,
                rou_after=%s,
                liability_adjustment=%s,
                rou_adjustment=%s
            WHERE id=%s AND status='draft'
            RETURNING *;
        """
        return self.fetch_one(sql, (
            liability_before, liability_after,
            rou_before, rou_after,
            adj_liab, adj_rou,
            int(mod_id),
        )) or {}

    def mark_lease_modification_posted(
        self,
        company_id: int,
        mod_id: int,
        *,
        posted_journal_id: int,
        posted_by: Optional[int] = None,   # if you keep audit in created_by only, ignore
    ) -> Dict[str, Any]:
        sch = self._sch(company_id)
        sql = f"""
            UPDATE {sch}.lease_modifications
            SET status='posted',
                posted_journal_id=%s,
                posted_at=NOW()
            WHERE id=%s AND status='draft'
            RETURNING *;
        """
        return self.fetch_one(sql, (int(posted_journal_id), int(mod_id))) or {}

    def get_lease_modification(self, company_id: int, mod_id: int) -> Optional[Dict[str, Any]]:
        sch = self._sch(company_id)
        sql = f"SELECT * FROM {sch}.lease_modifications WHERE id=%s LIMIT 1;"
        return self.fetch_one(sql, (int(mod_id),))

    def list_lease_modifications(self, company_id: int, lease_id: int) -> List[Dict[str, Any]]:
        sch = self._sch(company_id)
        sql = f"""
            SELECT *
            FROM {sch}.lease_modifications
            WHERE lease_id=%s AND status <> 'void'
            ORDER BY modification_date DESC, id DESC;
        """
        return self.fetch_all(sql, (int(lease_id),)) or []

