    def mark_lease_termination_posted_and_close_lease(
        self,
        company_id: int,
        term_id: int,
        *,
        posted_journal_id: int,
        cur=None,
    ) -> Dict[str, Any]:
        sch = self._sch(company_id)

        if cur is None:
            with self._conn_cursor() as (conn, cur2):
                out = self.mark_lease_termination_posted_and_close_lease(
                    company_id, term_id, posted_journal_id=posted_journal_id, cur=cur2
                )
                conn.commit()
                return out

        # mark termination posted
        cur.execute(
            f"""
            UPDATE {sch}.lease_terminations
            SET status='posted',
                posted_journal_id=%s,
                posted_at=NOW()
            WHERE id=%s AND COALESCE(status,'draft') <> 'posted'
            RETURNING lease_id, termination_date;
            """,
            (int(posted_journal_id), int(term_id)),
        )
        row = cur.fetchone()
        if not row:
            return {}

        lease_id = row["lease_id"] if isinstance(row, dict) else row[0]
        tdate    = row["termination_date"] if isinstance(row, dict) else row[1]

        # close lease
        cur.execute(
            f"""
            UPDATE {sch}.leases
            SET status='terminated',
                termination_date=%s,
                termination_id=%s
            WHERE id=%s
            RETURNING *;
            """,
            (tdate, int(term_id), int(lease_id)),
        )
        lease_row = cur.fetchone()

        return lease_row if isinstance(lease_row, dict) else {}

    def get_lease_termination(self, company_id: int, term_id: int) -> Optional[Dict[str, Any]]:
        sch = self._sch(company_id)
        return self.fetch_one(f"SELECT * FROM {sch}.lease_terminations WHERE id=%s LIMIT 1;", (int(term_id),))

