    def deactivate_lease_schedule(
        self,
        company_id: int,
        lease_id: int,
        *,
        version_no: int | None = None,
        cur=None,
    ) -> int:
        """
        Deactivate schedule rows for a lease.
        If version_no is given, deactivate ONLY that version.
        Otherwise deactivate all active rows for the lease.
        """
        sch = self._sch(company_id)

        where = ["lease_id=%s", "is_active=TRUE"]
        params = [int(lease_id)]

        if version_no is not None:
            where.append("version_no=%s")
            params.append(int(version_no))

        sql = f"""
            UPDATE {sch}.lease_schedule
            SET is_active=FALSE
            WHERE {" AND ".join(where)};
        """

        if cur is not None:
            cur.execute(sql, tuple(params))
            return int(cur.rowcount or 0)

        return int(self.execute(sql, tuple(params)) or 0)

    def activate_lease_schedule_version(
        self,
        company_id: int,
        lease_id: int,
        *,
        version_no: int,
        cur=None,
    ) -> int:
        sch = self._sch(company_id)

        sql = f"""
            UPDATE {sch}.lease_schedule
            SET is_active=TRUE
            WHERE lease_id=%s AND version_no=%s;
        """

        if cur is not None:
            cur.execute(sql, (int(lease_id), int(version_no)))
            return int(cur.rowcount or 0)

        return int(self.execute(sql, (int(lease_id), int(version_no))) or 0)

    def swap_active_lease_schedule_version(
        self,
        company_id: int,
        lease_id: int,
        *,
        new_version_no: int,
        cur=None,
    ) -> int:
        """
        Atomically deactivate current active schedule and activate new_version_no.
        Returns number of rows activated for new version.
        """
        sch = self._sch(company_id)

        if cur is None:
            with self._conn_cursor() as (conn, cur2):
                n = self.swap_active_lease_schedule_version(
                    company_id, lease_id, new_version_no=new_version_no, cur=cur2
                )
                conn.commit()
                return n

        # 1) deactivate current active rows
        cur.execute(
            f"UPDATE {sch}.lease_schedule SET is_active=FALSE WHERE lease_id=%s AND is_active=TRUE;",
            (int(lease_id),),
        )

        # 2) activate new version rows
        cur.execute(
            f"UPDATE {sch}.lease_schedule SET is_active=TRUE WHERE lease_id=%s AND version_no=%s;",
            (int(lease_id), int(new_version_no)),
        )

        return int(cur.rowcount or 0)

    def _sch(self, company_id: int) -> str:
        return f"company_{int(company_id)}"

    def build_lease_modification_journal_lines(
        self,
        company_id: int,
        *,
        modification_id: int,
        cur=None,
    ):
        schema = f"company_{company_id}"

        m = self.fetch_one(
            f"""
            SELECT
                m.*,
                l.lease_name,
                l.status AS lease_status
            FROM {schema}.lease_modifications m
            JOIN {schema}.leases l ON l.id = m.lease_id
            WHERE m.id=%s
            """,
            (int(modification_id),),
            cur=cur,
        )
        if not m:
            return []

        if (m.get("lease_status") or "active").lower() == "terminated":
            raise ValueError("LEASE_TERMINATED|cannot_modify")

        def _resolve_posting_code(candidate: str | None) -> str | None:
            cand = (candidate or "").strip()
            if not cand:
                return None
            row = self.get_account_row_for_posting(company_id, cand)  # no cur=
            if not row:
                return None
            return (row[1] if not isinstance(row, dict) else row.get("code"))

        self.ensure_company_account_settings(company_id)
        self.ensure_company_lease_defaults(company_id)

        settings = self.fetch_one(
            """
            SELECT
                roa_code,
                lease_liability_current_code
            FROM public.company_account_settings
            WHERE company_id=%s
            LIMIT 1;
            """,
            (int(company_id),),
            cur=cur,
        ) or {}

        roa  = _resolve_posting_code(settings.get("roa_code"))
        liab = _resolve_posting_code(settings.get("lease_liability_current_code"))

        adj = round(float(m.get("liability_adjustment") or 0.0), 2)

        missing = []
        if adj != 0:
            if not roa:  missing.append("roa_code")
            if not liab: missing.append("lease_liability_current_code")

        if missing:
            raise ValueError("LEASE_ACCOUNTS_MISSING|" + ",".join(sorted(set(missing))))

        if adj == 0:
            return []

        memo = f"IFRS16 modification – {m.get('lease_name') or ''} – MOD {modification_id}".strip()

        if adj > 0:
            # Dr ROU, Cr Liability
            return [
                {"account_code": roa,  "debit": adj, "credit": 0.0, "memo": memo},
                {"account_code": liab, "debit": 0.0, "credit": adj, "memo": memo},
            ]

        amt = abs(adj)
        # Dr Liability, Cr ROU
        return [
            {"account_code": liab, "debit": amt, "credit": 0.0, "memo": memo},
            {"account_code": roa,  "debit": 0.0, "credit": amt, "memo": memo},
        ]

    def _lease_account_balance_up_to(
        self,
        schema: str,
        *,
        lease_id: int,
        account_code: str,
        as_of_date,
        cur=None,
    ) -> float:
        row = self.fetch_one(
            f"""
            WITH lease_journals AS (
                SELECT j.id
                FROM {schema}.journal j
                JOIN {schema}.lease_schedule s
                ON j.source='lease_monthly'
                AND j.source_id=s.id
                WHERE s.lease_id=%s
                AND j.date <= %s

                UNION ALL

                SELECT j.id
                FROM {schema}.journal j
                JOIN {schema}.lease_payments p
                ON j.source='lease_payment'
                AND j.source_id=p.id
                WHERE p.lease_id=%s
                AND j.date <= %s
                AND COALESCE(p.status,'') <> 'void'

                UNION ALL

                SELECT j.id
                FROM {schema}.journal j
                JOIN {schema}.lease_modifications m
                ON j.source='lease_modification'
                AND j.source_id=m.id
                WHERE m.lease_id=%s
                AND j.date <= %s
                AND COALESCE(m.status,'') <> 'void'
            )
            SELECT COALESCE(SUM(l.debit),0) - COALESCE(SUM(l.credit),0) AS bal
            FROM {schema}.ledger l
            JOIN lease_journals lj ON lj.id = l.journal_id
            WHERE l.account_code = %s
            """,
            (int(lease_id), as_of_date, int(lease_id), as_of_date, int(lease_id), as_of_date, str(account_code)),
            cur=cur,
        ) or {}
        return float(row.get("bal") or 0.0)


    def build_lease_termination_journal_lines(
        self,
        company_id: int,
        *,
        termination_id: int,
        cur=None,
    ):
        schema = f"company_{company_id}"

        t = self.fetch_one(
            f"""
            SELECT
                t.*,
                l.lease_name,
                l.status AS lease_status
            FROM {schema}.lease_terminations t
            JOIN {schema}.leases l ON l.id = t.lease_id
            WHERE t.id=%s
            """,
            (int(termination_id),),
            cur=cur,
        )
        if not t:
            return []

        lease_id = int(t.get("lease_id") or 0)
        term_date = t.get("termination_date")
        if not lease_id or not term_date:
            return []

        def _resolve_posting_code(candidate: str | None) -> str | None:
            cand = (candidate or "").strip()
            if not cand:
                return None
            row = self.get_account_row_for_posting(company_id, cand)  # no cur=
            if not row:
                return None
            return (row[1] if not isinstance(row, dict) else row.get("code"))

        self.ensure_company_account_settings(company_id)
        self.ensure_company_lease_defaults(company_id)

        settings = self.fetch_one(
            """
            SELECT
                roa_code,
                lease_liability_current_code,
                lease_liability_non_current_code,
                lease_accumulated_depreciation_code
            FROM public.company_account_settings
            WHERE company_id=%s
            LIMIT 1;
            """,
            (int(company_id),),
            cur=cur,
        ) or {}

        roa      = _resolve_posting_code(settings.get("roa_code"))
        liab_cur = _resolve_posting_code(settings.get("lease_liability_current_code"))
        liab_non = _resolve_posting_code(settings.get("lease_liability_non_current_code")) or liab_cur
        acc_depr = _resolve_posting_code(settings.get("lease_accumulated_depreciation_code"))

        gain_code = _resolve_posting_code("4385")
        loss_code = _resolve_posting_code("6029")

        missing = []
        for key, val in [
            ("roa_code", roa),
            ("lease_liability_current_code", liab_cur),
            ("lease_accumulated_depreciation_code", acc_depr),
        ]:
            if not val:
                missing.append(key)

        if missing:
            raise ValueError("LEASE_ACCOUNTS_MISSING|" + ",".join(sorted(set(missing))))

        roa_bal = round(self._lease_account_balance_up_to(schema, lease_id=lease_id, account_code=roa, as_of_date=term_date, cur=cur), 2)

        acc_bal = round(self._lease_account_balance_up_to(schema, lease_id=lease_id, account_code=acc_depr, as_of_date=term_date, cur=cur), 2)
        acc_credit = round(abs(acc_bal) if acc_bal < 0 else 0.0, 2)

        liab_cur_bal = round(self._lease_account_balance_up_to(schema, lease_id=lease_id, account_code=liab_cur, as_of_date=term_date, cur=cur), 2)
        liab_non_bal = round(self._lease_account_balance_up_to(schema, lease_id=lease_id, account_code=liab_non, as_of_date=term_date, cur=cur), 2) if (liab_non and liab_non != liab_cur) else 0.0

        liab_credit = 0.0
        if liab_cur_bal < 0: liab_credit += abs(liab_cur_bal)
        if liab_non and liab_non != liab_cur and liab_non_bal < 0: liab_credit += abs(liab_non_bal)
        liab_credit = round(liab_credit, 2)

        rou_nbv = round(roa_bal - acc_credit, 2)
        gl = round(liab_credit - rou_nbv, 2)

        memo = f"IFRS16 termination – {t.get('lease_name') or ''} – TERM {termination_id}".strip()

        lines = []

        # Dr liability (split current/non-current based on actual balances)
        cur_amt = round(abs(liab_cur_bal) if liab_cur_bal < 0 else 0.0, 2)
        non_amt = round(abs(liab_non_bal) if (liab_non and liab_non != liab_cur and liab_non_bal < 0) else 0.0, 2)
        if cur_amt > 0:
            lines.append({"account_code": liab_cur, "debit": cur_amt, "credit": 0.0, "memo": memo})
        if non_amt > 0 and liab_non and liab_non != liab_cur:
            lines.append({"account_code": liab_non, "debit": non_amt, "credit": 0.0, "memo": memo})

        # Dr accum dep
        if acc_credit > 0:
            lines.append({"account_code": acc_depr, "debit": acc_credit, "credit": 0.0, "memo": memo})

        # Cr ROU cost
        if roa_bal > 0:
            lines.append({"account_code": roa, "debit": 0.0, "credit": roa_bal, "memo": memo})

        # Plug gain/loss
        if gl > 0:
            if not gain_code:
                raise ValueError("LEASE_ACCOUNTS_MISSING|gain_on_lease_termination(4385)")
            lines.append({"account_code": gain_code, "debit": 0.0, "credit": gl, "memo": memo})
        elif gl < 0:
            if not loss_code:
                raise ValueError("LEASE_ACCOUNTS_MISSING|loss_on_lease_termination(6029)")
            lines.append({"account_code": loss_code, "debit": abs(gl), "credit": 0.0, "memo": memo})

        return [ln for ln in lines if (ln.get("debit") or 0) != 0 or (ln.get("credit") or 0) != 0]


    def get_ifrs16_disclosure_strict(
        self,
        company_id: int,
        *,
        from_date: date,
        to_date: date,
        as_of: Optional[date] = None,
        include_terminated: bool = True,   # strict FS usually includes terminated in the period
        cur=None,
    ) -> Dict[str, Any]:
        """
        IFRS 16 disclosure (STRICT):
        - P/L: ONLY posted lease_schedule rows in the reporting period (by period_end)
        - Cashflow: ONLY posted lease_payments in the reporting period (by payment_date)
        - Mods/Terms: ONLY posted items (status='posted' AND posted_journal_id>0)
        - As-of balances:
            * liability: reconciliation method (opening + interest - principal + mods - derec)
            * plus a cross-check using last posted schedule closing_liability per lease
            * ROU NBV: opening ROU + posted ROU adjustments - posted depreciation - disposed NBV
        - Maturity:
            * future unposted schedule rows only (posted_journal_id=0) after as_of
            * provides net/VAT/gross, plus discount gap (undiscounted net - carrying liability)
        """
        schema = f"company_{int(company_id)}"
        as_of = as_of or to_date

        if from_date > to_date:
            raise ValueError("from_date must be <= to_date")

        # NOTE: lease_status_sql is injected into queries with alias `l`
        lease_status_sql = "" if include_terminated else "AND COALESCE(l.status,'active')='active'"

        # ------------------------------------------------------------
        # A) P/L amounts (STRICTLY posted schedule rows in period)
        # ------------------------------------------------------------
        sched_period = self.fetch_one(
            f"""
            SELECT
                COALESCE(SUM(s.interest),0)     AS interest_total,
                COALESCE(SUM(s.depreciation),0) AS depreciation_total
            FROM {schema}.lease_schedule s
            JOIN {schema}.leases l ON l.id = s.lease_id
            WHERE s.company_id=%s
            AND s.is_active=TRUE
            AND COALESCE(s.posted_journal_id,0) > 0
            AND s.period_end >= %s AND s.period_end <= %s
            {lease_status_sql}
            """,
            (int(company_id), from_date, to_date),
            cur=cur,
        ) or {}

        interest_total = float(sched_period.get("interest_total") or 0.0)
        depreciation_total = float(sched_period.get("depreciation_total") or 0.0)

        # ------------------------------------------------------------
        # B) Payments (STRICTLY posted lease_payments in period)
        # ------------------------------------------------------------
        pay_totals = self.fetch_one(
            f"""
            SELECT
                COALESCE(SUM(p.amount_gross),0) AS payments_gross,
                COALESCE(SUM(p.amount_net),0)   AS payments_net,
                COALESCE(SUM(p.vat_amount),0)   AS payments_vat
            FROM {schema}.lease_payments p
            JOIN {schema}.leases l ON l.id = p.lease_id
            WHERE p.company_id=%s
            AND p.status='posted'
            AND COALESCE(p.posted_journal_id,0) > 0
            AND p.payment_date >= %s AND p.payment_date <= %s
            {lease_status_sql}
            """,
            (int(company_id), from_date, to_date),
            cur=cur,
        ) or {}

        payments_gross = float(pay_totals.get("payments_gross") or 0.0)
        payments_net   = float(pay_totals.get("payments_net") or 0.0)
        payments_vat   = float(pay_totals.get("payments_vat") or 0.0)

        # ------------------------------------------------------------
        # C) Modifications (STRICTLY posted in period)
        # ------------------------------------------------------------
        mod_totals = self.fetch_one(
            f"""
            SELECT
                COALESCE(SUM(m.liability_adjustment),0) AS liab_adj,
                COALESCE(SUM(m.rou_adjustment),0)       AS rou_adj
            FROM {schema}.lease_modifications m
            JOIN {schema}.leases l ON l.id = m.lease_id
            WHERE m.company_id=%s
            AND COALESCE(m.status,'')='posted'
            AND COALESCE(m.posted_journal_id,0) > 0
            AND m.modification_date >= %s AND m.modification_date <= %s
            {lease_status_sql}
            """,
            (int(company_id), from_date, to_date),
            cur=cur,
        ) or {}

        liab_adj_period = float(mod_totals.get("liab_adj") or 0.0)
        rou_adj_period  = float(mod_totals.get("rou_adj") or 0.0)

        # ------------------------------------------------------------
        # D) Terminations (STRICTLY posted in period)
        # ------------------------------------------------------------
        term_totals = self.fetch_one(
            f"""
            SELECT
                COALESCE(SUM(t.settlement_amount),0)         AS settlement_total,
                COALESCE(SUM(t.liability_carrying_amount),0) AS liab_carry_total,
                COALESCE(SUM(t.rou_nbv),0)                   AS rou_nbv_total,
                COALESCE(SUM(t.gain_loss_amount),0)          AS gain_loss_total
            FROM {schema}.lease_terminations t
            JOIN {schema}.leases l ON l.id = t.lease_id
            WHERE t.company_id=%s
            AND COALESCE(t.status,'')='posted'
            AND COALESCE(t.posted_journal_id,0) > 0
            AND t.termination_date >= %s AND t.termination_date <= %s
            """,
            (int(company_id), from_date, to_date),
            cur=cur,
        ) or {}

        settlement_total = float(term_totals.get("settlement_total") or 0.0)
        liab_carry_total = float(term_totals.get("liab_carry_total") or 0.0)
        rou_nbv_total    = float(term_totals.get("rou_nbv_total") or 0.0)
        gain_loss_total  = float(term_totals.get("gain_loss_total") or 0.0)

        additions_row = self.fetch_one(
            f"""
            SELECT
            COALESCE(SUM(l.opening_rou_asset),0)       AS rou_additions,
            COALESCE(SUM(l.opening_lease_liability),0) AS liab_additions
            FROM {schema}.leases l
            WHERE l.company_id=%s
            AND l.start_date >= %s
            AND l.start_date <= %s
            {lease_status_sql}
            """,
            (int(company_id), from_date, to_date),
            cur=cur,
        ) or {}

        rou_additions_period  = float(additions_row.get("rou_additions")  or 0.0)
        liab_additions_period = float(additions_row.get("liab_additions") or 0.0)

        # ------------------------------------------------------------
        # E) Closing liability cross-check (last POSTED schedule row per lease <= as_of)
        # ------------------------------------------------------------
        closing_liab_check_row = self.fetch_one(
            f"""
            WITH last_posted AS (
                SELECT DISTINCT ON (s.lease_id)
                    s.lease_id,
                    s.closing_liability
                FROM {schema}.lease_schedule s
                JOIN {schema}.leases l ON l.id = s.lease_id
                WHERE s.company_id=%s
                AND s.is_active=TRUE
                AND COALESCE(s.posted_journal_id,0) > 0
                AND s.period_end <= %s
                {lease_status_sql}
                ORDER BY s.lease_id, s.period_end DESC, s.period_no DESC
            )
            SELECT COALESCE(SUM(closing_liability),0) AS closing_liability
            FROM last_posted;
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}

        closing_liability_from_last_posted = float(closing_liab_check_row.get("closing_liability") or 0.0)

        # ------------------------------------------------------------
        # F) Undiscounted principal split (future unposted periods after as_of)
        #     IMPORTANT: this is NOT a carrying amount split — label accordingly.
        # ------------------------------------------------------------
        liab_split_rows = self.fetch_all(
            f"""
            SELECT q.bucket, COALESCE(SUM(q.principal),0) AS principal_sum
            FROM (
                SELECT
                    CASE
                        WHEN s.period_end <= (%s::date + INTERVAL '12 months') THEN 'current'
                        ELSE 'non_current'
                    END AS bucket,
                    COALESCE(s.principal,0) AS principal
                FROM {schema}.lease_schedule s
                JOIN {schema}.leases l ON l.id = s.lease_id
                WHERE s.company_id=%s
                AND s.is_active=TRUE
                AND s.period_end > %s
                AND COALESCE(s.posted_journal_id,0) = 0
                {lease_status_sql}
            ) q
            GROUP BY q.bucket
            """,
            (as_of, int(company_id), as_of),
            cur=cur,
        ) or []

        undiscounted_principal_current = 0.0
        undiscounted_principal_non_current = 0.0
        for r in liab_split_rows:
            if not isinstance(r, dict):
                continue
            b = (r.get("bucket") or "").strip()
            amt = float(r.get("principal_sum") or 0.0)
            if b == "current":
                undiscounted_principal_current = amt
            elif b == "non_current":
                undiscounted_principal_non_current = amt

        undiscounted_principal_current = round(undiscounted_principal_current, 2)
        undiscounted_principal_non_current = round(undiscounted_principal_non_current, 2)
        undiscounted_principal_total = round(
            undiscounted_principal_current + undiscounted_principal_non_current, 2
        )

        # ------------------------------------------------------------
        # G) Liability reconciliation as-of (STRICT truth)
        #     opening + posted interest - posted principal + posted mods - posted derec
        # ------------------------------------------------------------
        opening_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.opening_lease_liability),0) AS opening
            FROM {schema}.leases l
            WHERE l.company_id=%s
            AND l.start_date < %s
            AND (
                COALESCE(l.status,'active') <> 'terminated'
                OR (l.termination_date IS NULL OR l.termination_date >= %s)
            )
            """,
            (int(company_id), from_date, from_date),
            cur=cur,
        ) or {}
        opening_liability = float(opening_row.get("opening") or 0.0)

        sched_asof_row = self.fetch_one(
            f"""
            SELECT
                COALESCE(SUM(s.interest),0)  AS interest_posted,
                COALESCE(SUM(s.principal),0) AS principal_posted,
                COALESCE(SUM(s.payment),0)   AS payment_posted
            FROM {schema}.lease_schedule s
            JOIN {schema}.leases l ON l.id = s.lease_id
            WHERE s.company_id=%s
            AND s.is_active=TRUE
            AND s.period_end <= %s
            AND COALESCE(s.posted_journal_id,0) > 0
            AND COALESCE(l.status,'active') IN ('active','terminated')
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}

        interest_posted  = float(sched_asof_row.get("interest_posted") or 0.0)
        principal_posted = float(sched_asof_row.get("principal_posted") or 0.0)
        scheduled_payments_posted = float(sched_asof_row.get("payment_posted") or 0.0)

        mods_asof_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(m.liability_adjustment),0) AS liab_adj
            FROM {schema}.lease_modifications m
            JOIN {schema}.leases l ON l.id = m.lease_id
            WHERE m.company_id=%s
            AND COALESCE(m.status,'')='posted'
            AND COALESCE(m.posted_journal_id,0) > 0
            AND m.modification_date <= %s
            {lease_status_sql}
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}
        liab_adj_posted = float(mods_asof_row.get("liab_adj") or 0.0)

        terms_asof_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(t.liability_carrying_amount),0) AS liab_derec
            FROM {schema}.lease_terminations t
            WHERE t.company_id=%s
            AND COALESCE(t.status,'')='posted'
            AND COALESCE(t.posted_journal_id,0) > 0
            AND t.termination_date <= %s
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}
        liab_derec_posted = float(terms_asof_row.get("liab_derec") or 0.0)

        closing_liability_from_recon = (
            opening_liability
            + liab_additions_period      # ✅ ADD THIS
            + interest_posted
            - principal_posted
            + liab_adj_posted
            - liab_derec_posted
        )
        closing_liability_from_recon = round(closing_liability_from_recon, 2)

        closing_liability_check_diff = round(
            closing_liability_from_last_posted - closing_liability_from_recon, 2
        )

        # ------------------------------------------------------------
        # H) ROU NBV as-of (STRICT)
        # ------------------------------------------------------------
        rou_opening_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.opening_rou_asset),0) AS rou_opening
            FROM {schema}.leases l
            WHERE l.company_id=%s
            AND l.start_date < %s
            {lease_status_sql}
            """,
            (int(company_id), from_date),
            cur=cur,
        ) or {}
        rou_opening_total = float(rou_opening_row.get("rou_opening") or 0.0)

        rou_adj_to_date_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(m.rou_adjustment),0) AS rou_adj_to_date
            FROM {schema}.lease_modifications m
            JOIN {schema}.leases l ON l.id = m.lease_id
            WHERE m.company_id=%s
            AND COALESCE(m.status,'')='posted'
            AND COALESCE(m.posted_journal_id,0) > 0
            AND m.modification_date <= %s
            {lease_status_sql}
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}
        rou_adj_to_date = float(rou_adj_to_date_row.get("rou_adj_to_date") or 0.0)

        dep_to_date_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(s.depreciation),0) AS dep_total
            FROM {schema}.lease_schedule s
            JOIN {schema}.leases l ON l.id = s.lease_id
            WHERE s.company_id=%s
            AND s.is_active=TRUE
            AND COALESCE(s.posted_journal_id,0) > 0
            AND s.period_end <= %s
            {lease_status_sql}
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}
        depreciation_to_date = float(dep_to_date_row.get("dep_total") or 0.0)

        term_rou_to_date_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(t.rou_nbv),0) AS rou_nbv_terminated
            FROM {schema}.lease_terminations t
            WHERE t.company_id=%s
            AND COALESCE(t.status,'')='posted'
            AND COALESCE(t.posted_journal_id,0) > 0
            AND t.termination_date <= %s
            """,
            (int(company_id), as_of),
            cur=cur,
        ) or {}
        rou_nbv_terminated = float(term_rou_to_date_row.get("rou_nbv_terminated") or 0.0)

        rou_closing_nbv = round(
            rou_opening_total
            + rou_additions_period      # ✅ ADD THIS
            + rou_adj_to_date
            - depreciation_to_date
            - rou_nbv_terminated, 2
        )

        leases_rows = self.fetch_all(
            f"""
            SELECT
            id,
            lease_name,
            start_date,
            end_date,
            payment_amount,
            payment_frequency,
            vat_rate,
            COALESCE(status,'active') AS status
            FROM {schema}.leases
            WHERE company_id=%s
            ORDER BY start_date NULLS LAST, id
            """,
            (int(company_id),),
            cur=cur,
        ) or []

        # ------------------------------------------------------------
        # I) Maturity analysis (future unposted schedule rows)
        #     Provide a single table (net/vat/gross) + totals
        # ------------------------------------------------------------
        maturity_table_rows = self.fetch_all(
            f"""
            SELECT
            q.bucket,
            COALESCE(SUM(q.undiscounted_net),0) AS undiscounted_net,
            COALESCE(SUM(q.vat),0)             AS vat,
            COALESCE(SUM(q.gross),0)           AS gross
            FROM (
            SELECT
                CASE
                WHEN s.period_end <= (%s::date + INTERVAL '12 months') THEN '0-12m'
                WHEN s.period_end <= (%s::date + INTERVAL '24 months') THEN '12-24m'
                WHEN s.period_end <= (%s::date + INTERVAL '60 months') THEN '2-5y'
                ELSE '>5y'
                END AS bucket,
                COALESCE(s.net_payment, s.payment) AS undiscounted_net,
                COALESCE(s.vat_portion,0)          AS vat,
                COALESCE(s.payment,0)              AS gross
            FROM {schema}.lease_schedule s
            JOIN {schema}.leases l ON l.id = s.lease_id
            WHERE s.company_id=%s
                AND s.is_active=TRUE
                AND s.period_end > %s
                AND COALESCE(s.posted_journal_id,0) = 0
                {lease_status_sql}
            ) q
            GROUP BY q.bucket
            ORDER BY
            CASE q.bucket
                WHEN '0-12m'  THEN 1
                WHEN '12-24m' THEN 2
                WHEN '2-5y'   THEN 3
                ELSE 4
            END
            """,
            (as_of, as_of, as_of, int(company_id), as_of),
            cur=cur,
        ) or []

        maturity_table: list[dict] = []
        undisc_net_total = 0.0
        undisc_gross_total = 0.0
        vat_total_future = 0.0

        for r in maturity_table_rows:
            if not isinstance(r, dict):
                continue
            bucket = (r.get("bucket") or "").strip()
            und_net = float(r.get("undiscounted_net") or 0.0)
            vat_amt = float(r.get("vat") or 0.0)
            gross   = float(r.get("gross") or 0.0)

            maturity_table.append({
                "bucket": bucket,
                "undiscounted_net": round(und_net, 2),
                "vat": round(vat_amt, 2),
                "gross": round(gross, 2),
            })

            undisc_net_total += und_net
            undisc_gross_total += gross
            vat_total_future += vat_amt

        undisc_net_total = round(undisc_net_total, 2)
        undisc_gross_total = round(undisc_gross_total, 2)
        vat_total_future = round(vat_total_future, 2)

        # Discount gap uses carrying amount (liability excludes VAT) vs undiscounted net
        discount_gap = round(undisc_net_total - closing_liability_from_recon, 2)

        # Cross-check warning flag
        checks = {
            "closing_from_recon": closing_liability_from_recon,
            "closing_from_last_posted_schedule": round(closing_liability_from_last_posted, 2),
            "difference": closing_liability_check_diff,
            "ok": abs(closing_liability_check_diff) <= 0.05,
        }

        # ------------------------------------------------------------
        # J) ROU movement per lease (STRICT posted only)
        # ------------------------------------------------------------
        rou_rows = self.fetch_all(
            f"""
            WITH dep_period AS (
                SELECT s.lease_id, SUM(COALESCE(s.depreciation,0)) AS dep_period
                FROM {schema}.lease_schedule s
                JOIN {schema}.leases l ON l.id = s.lease_id
                WHERE s.company_id=%s
                AND s.is_active=TRUE
                AND COALESCE(s.posted_journal_id,0) > 0
                AND s.period_end BETWEEN %s AND %s
                {lease_status_sql}
                GROUP BY s.lease_id
            ),
            mods_period AS (
                SELECT m.lease_id, SUM(COALESCE(m.rou_adjustment,0)) AS mods_period
                FROM {schema}.lease_modifications m
                JOIN {schema}.leases l ON l.id = m.lease_id
                WHERE m.company_id=%s
                AND COALESCE(m.status,'')='posted'
                AND COALESCE(m.posted_journal_id,0) > 0
                AND m.modification_date BETWEEN %s AND %s
                {lease_status_sql}
                GROUP BY m.lease_id
            ),
            term_period AS (
                SELECT t.lease_id, SUM(COALESCE(t.rou_nbv,0)) AS disposed_period
                FROM {schema}.lease_terminations t
                JOIN {schema}.leases l ON l.id = t.lease_id
                WHERE t.company_id=%s
                AND COALESCE(t.status,'')='posted'
                AND COALESCE(t.posted_journal_id,0) > 0
                AND t.termination_date BETWEEN %s AND %s
                {lease_status_sql}
                GROUP BY t.lease_id
            )
            SELECT
                l.id AS lease_id,
                l.lease_name,

                CASE WHEN l.start_date < %s THEN COALESCE(l.opening_rou_asset,0) ELSE 0 END AS opening,
                CASE WHEN l.start_date BETWEEN %s AND %s THEN COALESCE(l.opening_rou_asset,0) ELSE 0 END AS additions,

                COALESCE(mp.mods_period,0)     AS remeasurements,
                COALESCE(dp.dep_period,0)      AS depreciation,
                COALESCE(tp.disposed_period,0) AS disposals

            FROM {schema}.leases l
            LEFT JOIN dep_period dp ON dp.lease_id = l.id
            LEFT JOIN mods_period mp ON mp.lease_id = l.id
            LEFT JOIN term_period tp ON tp.lease_id = l.id
            WHERE l.company_id=%s
            ORDER BY l.start_date NULLS LAST, l.id
            """,
            (
                int(company_id), from_date, to_date,     # dep_period
                int(company_id), from_date, to_date,     # mods_period
                int(company_id), from_date, to_date,     # term_period
                from_date, from_date, to_date,           # opening/additions split
                int(company_id),
            ),
            cur=cur,
        ) or []

        rou_table = []
        for r in rou_rows:
            opening = float(r.get("opening") or 0)
            additions = float(r.get("additions") or 0)
            mods = float(r.get("remeasurements") or 0)
            dep = float(r.get("depreciation") or 0)
            disp = float(r.get("disposals") or 0)

            closing = opening + additions + mods - dep - disp

            rou_table.append({
                "lease_id": r.get("lease_id"),
                "lease_name": r.get("lease_name"),
                "opening": round(opening, 2),
                "additions": round(additions, 2),
                "remeasurements": round(mods, 2),
                "depreciation": round(dep, 2),
                "disposals": round(disp, 2),
                "closing": round(closing, 2),
            })

        return {
            "company_id": int(company_id),
            "mode": "strict_posted_only",
            "from_date": from_date.isoformat(),
            "to_date": to_date.isoformat(),
            "as_of": as_of.isoformat(),

            "basis": {
                "pnl_recognition": "posted lease_schedule rows by period_end",
                "cashflow_recognition": "posted lease_payments rows by payment_date",
                "as_of_balances": "liability by reconciliation; ROU NBV by opening+movements",
                "include_terminated": bool(include_terminated),
            },

            # in return dict:
            "leases": leases_rows,

            "rou": {
                "opening_rou_asset_total": round(rou_opening_total, 2),
                "additions_period": round(rou_additions_period, 2),  # ✅ NEW
                "remeasurements_modifications_period": round(rou_adj_period, 2),
                "remeasurements_modifications_to_date": round(rou_adj_to_date, 2),
                "depreciation_charge_period": round(depreciation_total, 2),
                "depreciation_charge_to_date": round(depreciation_to_date, 2),
                "terminations_nbv_disposed_period": round(rou_nbv_total, 2),
                "terminations_nbv_disposed_to_date": round(rou_nbv_terminated, 2),
                "closing_rou_nbv_as_of": round(rou_closing_nbv, 2),
            },

            "rou_asset_table": rou_table,

            "liability": {
                # Use reconciliation as the official carrying amount (strict truth)
                "closing_liability_as_of": round(closing_liability_from_recon, 2),

                # undiscounted principal split (label correctly)
                "undiscounted_principal_current": undiscounted_principal_current,
                "undiscounted_principal_non_current": undiscounted_principal_non_current,
                "undiscounted_principal_total": undiscounted_principal_total,

                "interest_expense_period": round(interest_total, 2),

                # cashflow totals (actual payments)
                "payments_gross_period": round(payments_gross, 2),
                "payments_net_period": round(payments_net, 2),
                "vat_on_payments_period": round(payments_vat, 2),

                # modifications / terminations in period (strict posted)
                "remeasurements_modifications_period": round(liab_adj_period, 2),
                "settlements_terminations_period": round(settlement_total, 2),
                "liability_derecognised_terminations_period": round(liab_carry_total, 2),
            },

            "liability_reconciliation": {
                "opening_liability": round(opening_liability, 2),
                "additions_new_leases": round(liab_additions_period, 2),  # ✅ NEW (optional)
                "interest_accretion": round(interest_posted, 2),
                "principal_reduction": round(principal_posted, 2),

                # IMPORTANT: schedule payments posted are not the same as cash payments
                "scheduled_payments_posted": round(scheduled_payments_posted, 2),

                "remeasurements_modifications": round(liab_adj_posted, 2),
                "derecognitions_terminations": round(liab_derec_posted, 2),
                "closing_liability": round(closing_liability_from_recon, 2),
            },

            "liability_closing_checks": checks,

            "pnl": {
                "depreciation": round(depreciation_total, 2),
                "interest": round(interest_total, 2),
                "gain_loss_on_termination": round(gain_loss_total, 2),
            },

            "cashflow": {
                "lease_payments_gross": round(payments_gross, 2),
                "lease_payments_net": round(payments_net, 2),
                "vat": round(payments_vat, 2),
            },

            "maturity_analysis": {
                "as_of": as_of.isoformat(),
                "rows": maturity_table,
                "undiscounted_net_total": undisc_net_total,
                "vat_total": vat_total_future,
                "gross_total": undisc_gross_total,
                "carrying_amount_liability": round(closing_liability_from_recon, 2),
                "discount_gap": discount_gap,
            },

            # Explicit placeholders for common IFRS16 exemptions you may not track yet
            "exemptions": {
                "short_term_lease_expense": None,
                "low_value_lease_expense": None,
                "note": "Not tracked in this module yet",
            },
        }

    # ---------------------------
    # POS SUMMARIES (daily POS imports)
    # ---------------------------
    def insert_pos_summary(
        self,
        company_id: int,
        pos_date,
        source_name: str,
        gross_amount: float,
        net_amount: float,
        vat_amount: float,
    ) -> int:
        schema = f"company_{company_id}"

        sql = f"""
        INSERT INTO {schema}.pos_summaries
            (company_id, pos_date, source_name, gross_amount, net_amount, vat_amount)
        VALUES (%s, %s, %s, %s, %s, %s)
        RETURNING id;
        """
        params = (int(company_id), pos_date, source_name, gross_amount, net_amount, vat_amount)

        with self._conn_cursor() as (conn, cur):
            cur.execute(sql, params)
            row = cur.fetchone()
            conn.commit()
            if isinstance(row, dict):
                return int(row.get("id") or next(iter(row.values())))
            return int(row[0]) if row else 0

    def insert_pos_summary_lines(
        self,
        company_id: int,
        summary_id: int,
        lines: List[Dict[str, Any]],
    ) -> int:
        schema = f"company_{company_id}"

        sql = f"""
        INSERT INTO {schema}.pos_summary_lines (
            company_id,
            summary_id,
            line_no,
            item_code,
            description,
            qty,
            unit_price,
            gross_amount,
            net_amount,
            vat_amount,
            income_account,
            cogs_account,
            inventory_account,
            item_type,
            item_id
        )
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s);
        """

        count = 0
        with self._conn_cursor() as (conn, cur):
            for line in lines:
                cur.execute(
                    sql,
                    (
                        int(company_id),
                        int(summary_id),
                        int(line.get("line_no") or 0),
                        line.get("item_code"),
                        line.get("description"),
                        float(line.get("qty") or 0),
                        float(line.get("unit_price") or 0),
                        float(line.get("gross_amount") or 0),
                        float(line.get("net_amount") or 0),
                        float(line.get("vat_amount") or 0),
                        line.get("income_account"),
                        line.get("cogs_account"),
                        line.get("inventory_account"),
                        line.get("item_type"),
                        line.get("item_id"),
                    ),
                )
                count += 1

            conn.commit()

        return count

    def list_pos_summaries(
        self,
        company_id: int,
        limit: int = 50,
    ) -> List[Dict[str, Any]]:
        """
        Return latest POS summaries for a company (header only).
        """
        schema = f"company_{company_id}"
        sql = f"""
        SELECT id,
               pos_date,
               source_name,
               gross_amount,
               net_amount,
               vat_amount,
               posted_journal_id,
               created_at
        FROM {schema}.pos_summaries
        ORDER BY pos_date DESC, id DESC
        LIMIT %s;
        """
        return self.fetch_all(sql, (limit,))

    def get_pos_summary_with_lines(
        self,
        company_id: int,
        summary_id: int,
    ) -> Optional[Dict[str, Any]]:
        """
        Fetch a POS summary + its lines.
        """
        schema = f"company_{company_id}"

        header_sql = f"""
        SELECT id,
               pos_date,
               source_name,
               gross_amount,
               net_amount,
               vat_amount,
               posted_journal_id,
               created_at
        FROM {schema}.pos_summaries
        WHERE id = %s
        LIMIT 1;
        """
        header = self.fetch_one(header_sql, (summary_id,))
        if not header:
            return None

        lines_sql = f"""
        SELECT id,
               line_no,
               item_code,
               description,
               qty,
               unit_price,
               gross_amount,
               net_amount,
               vat_amount,
               income_account,
               cogs_account,
               inventory_account
        FROM {schema}.pos_summary_lines
        WHERE summary_id = %s
        ORDER BY line_no ASC, id ASC;
        """
        lines = self.fetch_all(lines_sql, (summary_id,))
        header["lines"] = lines
        return header

    def post_pos_summary_to_gl(self, company_id: int, summary_id: int, jlines: list[dict]) -> int:
        from decimal import Decimal, ROUND_HALF_UP
        from datetime import date

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = f"company_{company_id}"

        with self._conn_cursor() as (_conn, cur):
            pos = self.get_pos_summary_with_lines(company_id, summary_id)
            if not pos:
                raise ValueError("POS summary not found")

            pos_date = pos.get("pos_date") or date.today()
            if isinstance(pos_date, str):
                try:
                    pos_date = date.fromisoformat(pos_date[:10])
                except Exception:
                    pos_date = date.today()

            ref = f"POS-{summary_id}"
            src = (pos.get("source_name") or "").strip()
            desc = src or f"POS Summary {summary_id}"

            # 1) Lock pos summary row
            cur.execute(
                f"SELECT posted_journal_id FROM {schema}.pos_summaries WHERE id=%s FOR UPDATE;",
                (int(summary_id),),
            )
            hdr = cur.fetchone()
            if not hdr:
                raise ValueError("POS summary not found")

            already_jid = hdr.get("posted_journal_id")
            if already_jid:
                return int(already_jid)

            if not jlines:
                raise ValueError("No journal lines provided for POS posting")

            # 2) Journal header
            journal_entry = {
                "date": pos_date,
                "ref": ref,
                "description": desc,
                "gross_amount": money(pos.get("gross_amount") or 0.0),
                "net_amount":   money(pos.get("net_amount") or 0.0),
                "vat_amount":   money(pos.get("vat_amount") or 0.0),
                "source": "pos",
                "source_id": int(summary_id),
            }

            journal_id = int(self.insert_journal(company_id, journal_entry, cur=cur) or 0)
            if journal_id <= 0:
                raise ValueError("Failed to create journal header")

            # 3) Ledger + TB
            for jl in jlines:
                raw_code = (jl.get("account_code") or "").strip()
                dc = (jl.get("dc") or "").upper()
                amt = money(jl.get("amount") or 0.0)

                if not raw_code or dc not in ("D", "C") or amt <= 0:
                    raise ValueError(f"Bad journal line: {jl}")

                row = self.get_account_row_for_posting(company_id, raw_code)
                if not row:
                    raise ValueError(f"Account '{raw_code}' not found in company COA.")

                code = (row[1] or "").strip()
                if not code:
                    raise ValueError(f"Resolved posting code blank for '{raw_code}'")

                line = {
                    "account_code": code,
                    "debit":  amt if dc == "D" else 0.0,
                    "credit": amt if dc == "C" else 0.0,
                    "description": desc,
                }

                self.insert_ledger(
                    company_id=company_id,
                    journal_id=journal_id,
                    je_date=pos_date,
                    line=line,
                    ref=ref,
                    customer_id=None,
                    source="pos",
                    source_id=int(summary_id),
                    cur=cur,
                )

                self.update_trial_balance(company_id, line, cur=cur)

                if self.requires_notes(code):
                    self.insert_note(company_id, journal_id, code, desc, cur=cur)

            # ✅ 3b) Inventory depletion hook (COGS/Inventory)
            self.post_pos_inventory_if_needed(
                company_id=company_id,
                summary_id=int(summary_id),
                journal_id=journal_id,
                pos_date=pos_date,
                ref=ref,
                desc=desc,
                cur=cur,
            )

            # 4) Stamp posted
            cur.execute(
                f"""
                UPDATE {schema}.pos_summaries
                SET posted_journal_id=%s
                WHERE id=%s
                AND posted_journal_id IS NULL
                RETURNING id;
                """,
                (int(journal_id), int(summary_id)),
            )
            row2 = cur.fetchone()
            if not row2:
                return journal_id

            return journal_id

    def post_pos_inventory_if_needed(
        self,
        company_id: int,
        summary_id: int,
        journal_id: int,
        pos_date,
        ref: str,
        desc: str,
        cur,
    ) -> None:
        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = f"company_{company_id}"

        cur.execute(
            f"""
            SELECT
            item_type, item_id, qty,
            cogs_account, inventory_account
            FROM {schema}.pos_summary_lines
            WHERE summary_id=%s
            AND lower(coalesce(item_type,''))='inventory'
            AND item_id IS NOT NULL
            AND qty > 0;
            """,
            (int(summary_id),),
        )
        rows = cur.fetchall() or []
        if not rows:
            return

        for r in rows:
            item_id = int(r.get("item_id"))
            qty = float(r.get("qty") or 0)

            # Get cost from inventory item
            inv_row = self.fetch_one(
                f"SELECT avg_cost, cost_price, cogs_account, inventory_account FROM {schema}.inventory_items WHERE id=%s LIMIT 1;",
                (item_id,),
                cur=cur,
            ) or {}

            unit_cost = inv_row.get("avg_cost")
            if unit_cost is None:
                unit_cost = inv_row.get("cost_price")

            unit_cost = float(unit_cost or 0.0)
            if unit_cost <= 0:
                # skip if you don’t have costs yet (or raise if you want strict)
                continue

            amount = money(unit_cost * qty)
            if amount <= 0:
                continue

            cogs = (r.get("cogs_account") or inv_row.get("cogs_account") or "").strip()
            inv_acc = (r.get("inventory_account") or inv_row.get("inventory_account") or "").strip()

            if not cogs or not inv_acc:
                # if you want strict behaviour, raise
                continue

            # Resolve posting codes + write ledger entries
            for raw_code, dc in ((cogs, "D"), (inv_acc, "C")):
                row = self.get_account_row_for_posting(company_id, raw_code)
                if not row:
                    raise ValueError(f"COA account not found for POS inventory posting: '{raw_code}'")
                code = (row[1] or "").strip()
                line = {
                    "account_code": code,
                    "debit": amount if dc == "D" else 0.0,
                    "credit": amount if dc == "C" else 0.0,
                    "description": desc,
                }
                self.insert_ledger(
                    company_id=company_id,
                    journal_id=journal_id,
                    je_date=pos_date,
                    line=line,
                    ref=ref,
                    customer_id=None,
                    source="pos",
                    source_id=int(summary_id),
                    cur=cur,
                )
                self.update_trial_balance(company_id, line, cur=cur)

    def insert_pos_import(
        self,
        company_id: int,
        *,
        source_name: str | None,
        file_name: str | None,
        file_hash: str | None,
        created_by: int | None,
        status: str = "uploaded",
        error: str | None = None,
        preview_json: dict | None = None,
    ) -> int:
        schema = f"company_{company_id}"
        sql = f"""
        INSERT INTO {schema}.pos_imports
        (company_id, source_name, file_name, file_hash, status, error, created_by, preview_json)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s)
        RETURNING id;
        """
        return int(self.execute_sql(sql, (
            int(company_id),
            source_name,
            file_name,
            file_hash,
            status,
            error,
            int(created_by) if created_by is not None else None,
            psycopg2.extras.Json(preview_json) if preview_json is not None else None,
        )) or 0)

    def set_pos_import_mapping(self, company_id: int, import_id: int, mapping: dict) -> None:
        schema = f"company_{company_id}"
        sql = f"""
        UPDATE {schema}.pos_imports
        SET mapping_json=%s, updated_at=NOW()
        WHERE id=%s AND company_id=%s;
        """
        with self._conn_cursor() as (conn, cur):
            cur.execute(sql, (psycopg2.extras.Json(mapping), int(import_id), int(company_id)))
            conn.commit()

    def get_pos_import(self, company_id: int, import_id: int) -> dict | None:
        schema = f"company_{company_id}"
        sql = f"""
        SELECT id, company_id, source_name, file_name, file_hash,
            status, error, created_by, created_at,
            mapping_json, preview_json, parsed_summary_id
        FROM {schema}.pos_imports
        WHERE id=%s AND company_id=%s
        LIMIT 1;
        """
        return self.fetch_one(sql, (int(import_id), int(company_id)))

    def create_service_item(self, company_id: int, data: dict, cur=None) -> int:
        schema = f"company_{company_id}"

        code = (data.get("code") or "").strip()
        name = (data.get("name") or "").strip()
        if not code:
            raise ValueError("code is required")
        if not name:
            raise ValueError("name is required")

        description = (data.get("description") or "").strip() or None
        unit = (data.get("unit") or "").strip() or None

        revenue_account = (data.get("revenue_account") or "").strip() or None
        cost_account = (data.get("cost_account") or "").strip() or None
        vat_code = (data.get("vat_code") or "").strip().upper() or None

        def _to_float(x, d=0.0):
            try:
                if x is None:
                    return d
                if isinstance(x, str):
                    x = x.replace(",", "").strip()
                return float(x)
            except Exception:
                return d

        price = _to_float(data.get("price"), 0.0)
        is_taxable = bool(data.get("is_taxable", True))
        is_active = bool(data.get("is_active", True))

        sql = f"""
        INSERT INTO {schema}.service_items
        (company_id, code, name, description, unit, price,
        revenue_account, cost_account, vat_code,
        is_taxable, is_active, created_at, updated_at)
        VALUES
        (%s,%s,%s,%s,%s,%s,
        %s,%s,%s,
        %s,%s,NOW(),NOW())
        RETURNING id;
        """
        params = (
            int(company_id), code, name, description, unit, price,
            revenue_account, cost_account, vat_code,
            is_taxable, is_active
        )

        if cur is not None:
            cur.execute(sql, params)
            row = cur.fetchone()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

        with self._conn_cursor() as (conn, _cur):
            _cur.execute(sql, params)
            row = _cur.fetchone()
            conn.commit()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

    def _row_id(row):
        if not row:
            return None
        return int(row.get("id") if isinstance(row, dict) else row[0])

    def list_service_items(
        self,
        company_id: int,
        *,
        q: str = "",
        active_only: bool = True,
        limit: int = 50,
        offset: int = 0,
        cur=None,
    ) -> List[Dict[str, Any]]:
        schema = f"company_{company_id}"

        q = (q or "").strip()
        where = ["company_id=%s"]
        params: list[Any] = [int(company_id)]

        if active_only:
            where.append("is_active=TRUE")

        if q:
            where.append("(LOWER(code) LIKE LOWER(%s) OR LOWER(name) LIKE LOWER(%s))")
            params += [f"%{q}%", f"%{q}%"]

        sql = f"""
        SELECT *
        FROM {schema}.service_items
        WHERE {" AND ".join(where)}
        ORDER BY is_active DESC, name ASC, id ASC
        LIMIT %s OFFSET %s
        """
        params += [int(limit), int(offset)]

        if cur is not None:
            cur.execute(sql, tuple(params))
            return list(cur.fetchall() or [])

        with self._conn_cursor() as (_conn, _cur):
            _cur.execute(sql, tuple(params))
            return list(_cur.fetchall() or [])


    def get_service_item(
        self,
        company_id: int,
        service_id: int,
        *,
        cur=None,
    ) -> Optional[Dict[str, Any]]:
        schema = f"company_{company_id}"
        sql = f"""
        SELECT *
        FROM {schema}.service_items
        WHERE company_id=%s AND id=%s
        LIMIT 1
        """
        params = (int(company_id), int(service_id))

        if cur is not None:
            cur.execute(sql, params)
            return cur.fetchone()

        with self._conn_cursor() as (_conn, _cur):
            _cur.execute(sql, params)
            return _cur.fetchone()


    def get_service_item_by_code(
        self,
        company_id: int,
        code: str,
        *,
        cur=None,
    ) -> Optional[Dict[str, Any]]:
        schema = f"company_{company_id}"
        code = (code or "").strip()
        if not code:
            return None

        sql = f"""
        SELECT *
        FROM {schema}.service_items
        WHERE company_id=%s AND LOWER(code)=LOWER(%s)
        LIMIT 1
        """
        params = (int(company_id), code)

        if cur is not None:
            cur.execute(sql, params)
            return cur.fetchone()

        with self._conn_cursor() as (_conn, _cur):
            _cur.execute(sql, params)
            return _cur.fetchone()

    def archive_service_item(self, company_id: int, service_id: int, *, cur=None) -> None:
        schema = f"company_{company_id}"
        sql = f"""
        UPDATE {schema}.service_items
        SET is_active=FALSE, updated_at=NOW()
        WHERE company_id=%s AND id=%s
        """
        params = (int(company_id), int(service_id))

        if cur is not None:
            cur.execute(sql, params)
            return

        with self._conn_cursor() as (conn, _cur):
            _cur.execute(sql, params)
            conn.commit()


    def update_service_item(self, company_id: int, service_id: int, data: dict, *, cur=None) -> None:
        schema = f"company_{company_id}"

        # only update fields that are present
        sets = []
        params: list[Any] = []

        def put(col, val):
            sets.append(f"{col}=%s")
            params.append(val)

        if "code" in data:
            put("code", (data.get("code") or "").strip())
        if "name" in data:
            put("name", (data.get("name") or "").strip())
        if "description" in data:
            put("description", (data.get("description") or "").strip() or None)
        if "unit" in data:
            put("unit", (data.get("unit") or "").strip() or None)
        if "price" in data:
            put("price", float(str(data.get("price") or 0).replace(",", "") or 0))
        if "vat_code" in data:
            put("vat_code", (data.get("vat_code") or "").strip().upper() or None)
        if "is_taxable" in data:
            put("is_taxable", bool(data.get("is_taxable")))
        if "revenue_account" in data:
            put("revenue_account", (data.get("revenue_account") or "").strip() or None)
        if "cost_account" in data:
            put("cost_account", (data.get("cost_account") or "").strip() or None)
        if "is_active" in data:
            put("is_active", bool(data.get("is_active")))

        if not sets:
            return

        sets.append("updated_at=NOW()")

        sql = f"""
        UPDATE {schema}.service_items
        SET {", ".join(sets)}
        WHERE company_id=%s AND id=%s
        """
        params += [int(company_id), int(service_id)]

        if cur is not None:
            cur.execute(sql, tuple(params))
            return

        with self._conn_cursor() as (conn, _cur):
            _cur.execute(sql, tuple(params))
            conn.commit()

    def insert_coa_pool_missing(self, rows: list[dict]) -> int:
        if not rows:
            return 0

        sql = """
        INSERT INTO public.coa_pool (
        template_code,
        template_code_scoped,
        name,
        code,
        section,
        category,
        subcategory,
        description,
        standard,
        industry,
        sub_industry,
        is_general,
        posting
        )
        VALUES %s
        ON CONFLICT (template_code_scoped) DO NOTHING
        """
        return self.bulk_insert(sql, rows)

    def find_default_inventory_account_code(self, company_id: int, *, cur) -> str | None:
        """
        Industry-agnostic inventory asset detector.

        Works even when cf_bucket is NULL by ranking based on name/section/category/code.

        Prefers:
        - 'Inventory - Raw Materials', 'Inventory - Finished Goods'
        - 'Vehicle Inventory'
        - 'Work-in-Progress' / 'Project Work-in-Progress' (job-costing)
        Avoids contra inventory (write-down/obsolescence/allowance).
        """
        schema = f"company_{company_id}"

        cur.execute(
            f"""
            SELECT code, name, section, category, cf_bucket
            FROM {schema}.coa
            WHERE company_id=%s
            AND posting=true
            ORDER BY
            CASE
                -- 🚫 reject obvious contra / non-inventory
                WHEN lower(coalesce(name,'')) LIKE '%%write-down%%' THEN 999
                WHEN lower(coalesce(name,'')) LIKE '%%obsol%%' THEN 999
                WHEN lower(coalesce(name,'')) LIKE '%%allowance%%' THEN 999
                WHEN lower(coalesce(name,'')) LIKE '%%accumulated%%' THEN 999
                WHEN lower(coalesce(section,'')) LIKE '%%depreciation%%' THEN 999

                -- ✅ best: explicit cf_bucket inventory (if present)
                WHEN lower(coalesce(cf_bucket,''))='inventory' THEN 1

                -- ✅ best: inventory / stock wording in NAME
                WHEN lower(coalesce(name,'')) LIKE 'inventory%%raw%%' THEN 2
                WHEN lower(coalesce(name,'')) LIKE 'inventory%%finished%%' THEN 3
                WHEN lower(coalesce(name,'')) LIKE '%%vehicle inventory%%' THEN 4
                WHEN lower(coalesce(name,'')) LIKE '%%work-in-progress%%' THEN 5
                WHEN lower(coalesce(name,'')) LIKE '%%wip%%' THEN 6
                WHEN lower(coalesce(name,'')) LIKE '%%inventory%%' THEN 7
                WHEN lower(coalesce(name,'')) LIKE '%%stock%%' THEN 8

                -- ✅ next: inventory wording in SECTION/CATEGORY
                WHEN lower(coalesce(section,'')) LIKE '%%inventor%%' THEN 20
                WHEN lower(coalesce(category,'')) LIKE '%%inventor%%' THEN 21

                -- ✅ weak but useful: code patterns (your templates use BS_CA_150x a lot)
                WHEN code ILIKE 'BS\\_CA\\_15%%' ESCAPE '\\' THEN 30
                WHEN code ILIKE 'BS\\_CA\\_10%%' ESCAPE '\\' THEN 40

                ELSE 500
            END,
            id ASC
            """
            ,
            (int(company_id),),
        )
        rows = cur.fetchall() or []
        if not rows:
            return None

        # rows might be dicts or tuples depending on cursor factory
        def _get(r, k, idx):
            if isinstance(r, dict):
                return (r.get(k) or "").strip()
            return (r[idx] or "").strip() if len(r) > idx else ""

        for r in rows:
            code = _get(r, "code", 0)
            name = _get(r, "name", 1).lower()

            # final safety: skip contra inventory candidates
            if any(x in name for x in ["write-down", "obsol", "allowance"]):
                continue

            if code:
                return code

        return None


    def find_default_cogs_account_code(self, company_id: int, *, cur) -> str | None:
        """
        Industry-agnostic COGS detector.

        Prefers true Cost-of-Sales accounts, but supports industries like construction:
        - Direct Materials
        - Subcontractor costs
        - Material Purchases

        Avoids:
        - PPV
        - Discounts / rebates
        - Adjustments
        """
        schema = f"company_{company_id}"

        cur.execute(
            f"""
            SELECT code, name, section, category, cf_bucket
            FROM {schema}.coa
            WHERE company_id=%s
            AND posting=true
            ORDER BY
            CASE
                -- 🚫 push down non-COGS or special accounts
                WHEN lower(coalesce(name,'')) LIKE '%%variance%%' THEN 900
                WHEN lower(coalesce(name,'')) LIKE '%%ppv%%' THEN 900
                WHEN lower(coalesce(name,'')) LIKE '%%discount%%' THEN 900
                WHEN lower(coalesce(name,'')) LIKE '%%rebate%%' THEN 900
                WHEN lower(coalesce(section,'')) LIKE '%%adjust%%' THEN 900
                WHEN lower(coalesce(category,'')) LIKE '%%adjust%%' THEN 900

                -- ✅ best signals
                WHEN code ILIKE 'PL\\_COS\\_%%' ESCAPE '\\' THEN 1
                WHEN lower(coalesce(section,'')) LIKE '%%cost of sales%%' THEN 2
                WHEN lower(coalesce(category,'')) LIKE 'cost of sales%%' THEN 3
                WHEN lower(coalesce(name,'')) IN ('cost of sales','cost of goods sold','cogs') THEN 4

                -- ✅ construction / job-costing common COGS names
                WHEN lower(coalesce(name,'')) LIKE 'direct materials%%' THEN 10
                WHEN lower(coalesce(name,'')) LIKE 'material purchases%%' THEN 11
                WHEN lower(coalesce(name,'')) LIKE 'subcontractor%%' THEN 12
                WHEN lower(coalesce(name,'')) LIKE 'direct subcontractor%%' THEN 13
                WHEN lower(coalesce(name,'')) LIKE 'purchases%%' THEN 20

                ELSE 500
            END,
            id ASC
            """,
            (int(company_id),),
        )

        rows = cur.fetchall() or []
        if not rows:
            return None

        def _get(r, k, idx):
            if isinstance(r, dict):
                return (r.get(k) or "").strip()
            return (r[idx] or "").strip() if len(r) > idx else ""

        for r in rows:
            code = _get(r, "code", 0)
            name = _get(r, "name", 1).lower()

            # skip the known “not-cogs” even if it matches loosely
            if any(x in name for x in ["ppv", "variance", "discount", "rebate"]):
                continue
            if code:
                return code

        return None
            
    def post_invoice_inventory_if_needed(
        self,
        company_id: int,
        *,
        invoice_id: int,
        journal_id: int,
        inv: dict,
        inv_date,
        inv_no: str,
        cur,
    ) -> None:
        """
        Inventory hook for invoice posting (ID-based):

        - Processes ONLY invoice lines where item_type == 'inventory' AND item_id exists
        - Ignores service lines
        - Supports valuation_method per item:
            AVG  -> insert ONE stock-out row into inventory_layers
            FIFO -> fifo_consume() updates inbound layers.qty_out + writes inventory_fifo_allocations
                    (NO extra inventory_layers insert, to avoid double depletion)
        - Posts COGS JE lines (Dr COGS, Cr Inventory) into SAME journal
        - Idempotent:
            - if any inventory_layers exists for (source='invoice', source_id=invoice_id) => return (AVG already done)
            - if any inventory_fifo_allocations exists for (source='invoice', source_id=invoice_id) => return (FIFO already done)
        """
        if not inv or not isinstance(inv, dict):
            return

        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = f"company_{company_id}"

        # normalize inv_date once
        if hasattr(inv_date, "isoformat"):
            inv_date = inv_date.isoformat()[:10]
        else:
            inv_date = str(inv_date)[:10]

        lines = inv.get("lines") or []
        if not lines:
            return

        # ✅ idempotent for AVG
        cur.execute(
            f"""
            SELECT 1
            FROM {schema}.inventory_layers
            WHERE company_id=%s AND source='invoice' AND source_id=%s
            LIMIT 1
            """,
            (int(company_id), int(invoice_id)),
        )
        if cur.fetchone():
            return

        # ✅ idempotent for FIFO
        cur.execute(
            f"""
            SELECT 1
            FROM {schema}.inventory_fifo_allocations
            WHERE company_id=%s AND source='invoice' AND source_id=%s
            LIMIT 1
            """,
            (int(company_id), int(invoice_id)),
        )
        if cur.fetchone():
            return

        # -------------------------
        # helpers
        # -------------------------
        def _get_onhand(item_id: int) -> float:
            cur.execute(
                f"""
                SELECT COALESCE(SUM(qty_in - qty_out),0)::numeric(18,4) AS onhand
                FROM {schema}.inventory_layers
                WHERE company_id=%s AND item_id=%s
                """,
                (int(company_id), int(item_id)),
            )
            r = cur.fetchone() or {}
            return float(r.get("onhand") or 0.0)

        def _avg_cost(item_id: int) -> float:
            cur.execute(
                f"""
                SELECT
                COALESCE(SUM(qty_in * unit_cost),0) AS total_cost_in,
                COALESCE(SUM(qty_in),0)            AS total_qty_in
                FROM {schema}.inventory_layers
                WHERE company_id=%s AND item_id=%s
                """,
                (int(company_id), int(item_id)),
            )
            r = cur.fetchone() or {}
            total_cost_in = float(r.get("total_cost_in") or 0.0)
            total_qty_in = float(r.get("total_qty_in") or 0.0)
            if total_qty_in <= 0:
                return 0.0
            return total_cost_in / total_qty_in

        cogs_totals: dict[str, float] = {}
        inv_totals: dict[str, float] = {}

        ref_text = str(inv_no or f"INV-{invoice_id}")

        warnings: list[dict] = []

        # -------------------------
        # loop invoice lines
        # -------------------------
        for ln in lines:
            item_type = (ln.get("item_type") or ln.get("itemType") or "").strip().lower()
            item_id_raw = ln.get("item_id") or ln.get("itemId")

            if item_type == "service":
                continue
            if item_type != "inventory" or not item_id_raw:
                continue

            try:
                item_id = int(item_id_raw)
            except Exception:
                continue

            qty = float(ln.get("quantity") or ln.get("qty") or 0.0)
            if qty <= 0:
                continue

            # Load item details (include valuation_method)
            cur.execute(
                f"""
                SELECT
                is_active,
                track_stock,
                inventory_account,
                cogs_account,
                valuation_method
                FROM {schema}.inventory_items
                WHERE company_id=%s AND id=%s
                LIMIT 1
                """,
                (int(company_id), int(item_id)),
            )
            it = cur.fetchone() or {}
            if not it:
                raise ValueError(f"INVENTORY_ITEM_NOT_FOUND|item_id={item_id}")
            if it.get("is_active") is False:
                raise ValueError(f"INVENTORY_ITEM_INACTIVE|item_id={item_id}")

            track_stock = bool(it.get("track_stock", True))

            inv_acct_raw = (it.get("inventory_account") or "").strip()
            cogs_acct_raw = (it.get("cogs_account") or "").strip()
            inv_acct_raw = (it.get("inventory_account") or "").strip()
            cogs_acct_raw = (it.get("cogs_account") or "").strip()

            # 1) If missing, use company controls (recommended)
            if not inv_acct_raw:
                inv_acct_raw = (self.get_control_account_code(company_id, "INVENTORY_CONTROL") or "").strip()

            if not cogs_acct_raw:
                cogs_acct_raw = (self.get_control_account_code(company_id, "COGS_CONTROL") or "").strip()

            # 2) If still missing, auto-detect from COA metadata (industry-agnostic)
            if not inv_acct_raw:
                inv_acct_raw = (self.find_default_inventory_account_code(company_id, cur=cur) or "").strip()

            if not cogs_acct_raw:
                cogs_acct_raw = (self.find_default_cogs_account_code(company_id, cur=cur) or "").strip()

            # 3) Still missing? now error with helpful message
            if not inv_acct_raw or not cogs_acct_raw:
                raise ValueError(
                    f"INVENTORY_ITEM_ACCOUNTS_MISSING|item_id={item_id}|"
                    f"need inventory_account+cogs_account OR set controls INVENTORY_CONTROL/COGS_CONTROL"
                )

            inv_row = self.get_account_row_for_posting(company_id, inv_acct_raw)
            cogs_row = self.get_account_row_for_posting(company_id, cogs_acct_raw)
            inv_acct = (inv_row[1] if inv_row else inv_acct_raw) or inv_acct_raw
            cogs_acct = (cogs_row[1] if cogs_row else cogs_acct_raw) or cogs_acct_raw

            valuation_method = (it.get("valuation_method") or "AVG").strip().upper()
            if valuation_method not in ("AVG", "FIFO"):
                valuation_method = "AVG"

            # shared stock check (optional but nicer errors)
            if track_stock:
                onhand = _get_onhand(item_id)
                if qty > onhand:
                    raise ValueError(
                        f"Cannot post invoice. Item ID {item_id} has only {onhand} in stock but {qty} was invoiced."
                    )
    
            # -------------------------
            # COST
            # -------------------------
            if valuation_method == "FIFO":
                # ✅ FIFO updates inbound layers.qty_out + writes allocations
                total_cost = money(self.fifo_consume(
                    company_id,
                    item_id=item_id,
                    qty_out=qty,
                    tx_date=inv_date,
                    source="invoice",
                    source_id=int(invoice_id),
                    posted_journal_id=int(journal_id),
                    cur=cur,
                ))
                if total_cost <= 0:
                    raise ValueError(f"MISSING_COST|item_id={item_id}")

            else:
                # ✅ AVG: compute cost and write ONE stock-out layer
                unit_cost = money(_avg_cost(item_id))
                if unit_cost <= 0:
                    raise ValueError(f"MISSING_COST|item_id={item_id}")

                total_cost = money(qty * unit_cost)
                if total_cost <= 0:
                    continue

                if track_stock:
                    cur.execute(
                        f"""
                        INSERT INTO {schema}.inventory_layers
                        (company_id, item_id, tx_date, qty_in, qty_out, unit_cost,
                        ref, source, source_id, posted_journal_id)
                        VALUES (%s,%s,%s,0,%s,%s,%s,'invoice',%s,%s)
                        """,
                        (
                            int(company_id),
                            int(item_id),
                            inv_date,
                            float(qty),
                            float(unit_cost),
                            ref_text,
                            int(invoice_id),
                            int(journal_id),
                        ),
                    )

            # ✅ accumulate GL totals from computed total_cost
            cogs_totals[cogs_acct] = money(cogs_totals.get(cogs_acct, 0.0) + total_cost)
            inv_totals[inv_acct]   = money(inv_totals.get(inv_acct, 0.0) + total_cost)

        # -------------------------
        # post GL lines (summarized)
        # -------------------------
        for acct, amt in cogs_totals.items():
            if amt <= 0:
                continue
            self.insert_ledger(
                company_id=company_id,
                journal_id=int(journal_id),
                je_date=inv_date,
                line={"account_code": acct, "debit": amt, "credit": 0.0, "memo": "COGS"},
                ref=ref_text,
                source="invoice",
                source_id=int(invoice_id),
                cur=cur,
            )
            self.update_trial_balance(company_id, {"account_code": acct, "debit": amt, "credit": 0.0}, cur=cur)

        for acct, amt in inv_totals.items():
            if amt <= 0:
                continue
            self.insert_ledger(
                company_id=company_id,
                journal_id=int(journal_id),
                je_date=inv_date,
                line={"account_code": acct, "debit": 0.0, "credit": amt, "memo": "Inventory out"},
                ref=ref_text,
                source="invoice",
                source_id=int(invoice_id),
                cur=cur,
            )
            self.update_trial_balance(company_id, {"account_code": acct, "debit": 0.0, "credit": amt}, cur=cur)

        if warnings:
            msg = "Inventory warning (COGS not posted for some lines): " + "; ".join(
                [f"item_id={w['item_id']} onhand={w['onhand']} req={w['requested']}" for w in warnings]
            )
            # simplest: log it
            print(msg)

    def inventory_receive_stock(
        self,
        company_id: int,
        *,
        item_id: int,
        tx_date,
        qty_in: float,
        unit_cost: float,
        ref: str = None,
        source: str = "inventory_put",
        source_id: int = None,
        cur=None,
    ) -> int:
        schema = f"company_{company_id}"

        if qty_in is None or float(qty_in) <= 0:
            raise ValueError("qty_in must be > 0")
        if unit_cost is None or float(unit_cost) < 0:
            raise ValueError("unit_cost must be >= 0")

        # normalize date
        if hasattr(tx_date, "isoformat"):
            tx_date = tx_date.isoformat()[:10]
        else:
            tx_date = str(tx_date)[:10]

        sql = f"""
        INSERT INTO {schema}.inventory_layers
            (company_id, item_id, tx_date, qty_in, qty_out, unit_cost, ref, source, source_id)
        VALUES (%s,%s,%s,%s,0,%s,%s,%s,%s)
        RETURNING id;
        """
        params = (
            int(company_id),
            int(item_id),
            tx_date,
            float(qty_in),
            float(unit_cost),
            (ref or ""),
            (source or None),
            int(source_id) if source_id is not None else None,
        )

        if cur is not None:
            cur.execute(sql, params)
            row = cur.fetchone()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

        with self._conn_cursor() as (conn, _cur):
            _cur.execute(sql, params)
            row = _cur.fetchone()
            conn.commit()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

    def _inventory_avg_cost_cur(self, company_id: int, item_id: int, cur) -> float:
        schema = f"company_{company_id}"
        cur.execute(f"""
            SELECT
            COALESCE(SUM(qty_in * unit_cost),0) AS total_cost_in,
            COALESCE(SUM(qty_in),0)            AS total_qty_in,
            COALESCE(SUM(qty_out),0)           AS total_qty_out
            FROM {schema}.inventory_layers
            WHERE company_id=%s AND item_id=%s
        """, (int(company_id), int(item_id)))
        r = cur.fetchone() or {}
        total_cost_in = float(r.get("total_cost_in") or 0.0)
        total_in = float(r.get("total_qty_in") or 0.0)
        # avg cost based on purchases only (simple)
        if total_in <= 0:
            return 0.0
        return total_cost_in / total_in

    def _inventory_onhand_cur(self, company_id: int, item_id: int, cur) -> float:
        schema = f"company_{company_id}"
        cur.execute(f"""
            SELECT COALESCE(SUM(qty_in - qty_out),0)::numeric(18,4) AS onhand
            FROM {schema}.inventory_layers
            WHERE company_id=%s AND item_id=%s
        """, (int(company_id), int(item_id)))
        r = cur.fetchone() or {}
        return float(r.get("onhand") or 0.0)

    def get_item_by_id(self, company_id: int, item_id: int, cur=None):
        schema = f"company_{company_id}"
        sql = f"SELECT * FROM {schema}.items WHERE id=%s LIMIT 1;"
        return self.fetch_one(sql, (int(item_id),), cur=cur) if cur else self.fetch_one(sql, (int(item_id),))

    def get_item_by_name(self, company_id: int, name: str, cur=None):
        schema = f"company_{company_id}"
        sql = f"SELECT * FROM {schema}.items WHERE LOWER(name)=LOWER(%s) LIMIT 1;"
        return self.fetch_one(sql, (name.strip(),), cur=cur) if cur else self.fetch_one(sql, (name.strip(),))

    def insert_stock_move(self, company_id: int, move: dict, cur=None):
        schema = f"company_{company_id}"
        sql = f"""
        INSERT INTO {schema}.stock_moves (
            item_id, date, qty_in, qty_out, unit_cost,
            source, source_id, journal_id, memo, created_at
        ) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,NOW())
        RETURNING id;
        """
        params = (
            int(move["item_id"]),
            str(move["date"])[:10],
            float(move.get("qty_in") or 0.0),
            float(move.get("qty_out") or 0.0),
            float(move.get("unit_cost") or 0.0),
            move.get("source"),
            int(move.get("source_id") or 0),
            int(move.get("journal_id") or 0),
            move.get("memo") or "",
        )
        if cur:
            cur.execute(sql, params)
            r = cur.fetchone()
            return int((r.get("id") if isinstance(r, dict) else r[0]) or 0)
        return int(self.execute_sql(sql, params) or 0)

    def decrement_item_stock(self, company_id: int, item_id: int, qty_out: float, cur=None):
        schema = f"company_{company_id}"
        sql = f"""
        UPDATE {schema}.items
        SET qty_on_hand = COALESCE(qty_on_hand,0) - %s,
            updated_at = NOW()
        WHERE id=%s
        RETURNING qty_on_hand;
        """
        params = (float(qty_out), int(item_id))
        if cur:
            cur.execute(sql, params)
            return cur.fetchone()
        cur2 = self.execute_sql(sql, params)
        return cur2

    def get_inventory_item_by_barcode(self, company_id: int, barcode: str, cur=None):
        schema = f"company_{company_id}"
        bc = (barcode or "").strip()
        if not bc:
            return None

        sql = f"""
        SELECT *
        FROM {schema}.inventory_items
        WHERE company_id=%s
        AND barcode IS NOT NULL
        AND lower(trim(barcode)) = lower(trim(%s))
        LIMIT 1
        """
        return self.fetch_one(sql, (int(company_id), bc), cur=cur)

    def update_inventory_item(
        self,
        company_id: int,
        item_id: int,
        patch: dict,
    ) -> dict | None:
        """
        Partial update inventory item with:
        - strict allowed fields (mapped to real DB columns)
        - SKU/barcode uniqueness enforced per company
        """
        schema = f"company_{int(company_id)}"

        # Map API keys -> DB column names (IMPORTANT)
        field_map = {
            "sku": "sku",
            "name": "name",
            "description": "description",
            "unit": "unit",
            "uom": "unit",  # accept uom but store in unit
            "category": "category",
            "track_stock": "track_stock",
            "is_active": "is_active",
            "meta": "meta",
            "valuation_method": "valuation_method",
            "sales_price": "sales_price",
            "purchase_cost": "purchase_cost",
            "reorder_level": "reorder_level",
            "barcode": "barcode",
            "vat_code": "vat_code",
            "is_taxable": "is_taxable",
            "inventory_account": "inventory_account",
            "income_account": "income_account",
            "cogs_account": "cogs_account",
        }

        def _norm_str(v):
            return (str(v).strip() if v is not None else "")

        def _to_bool(v):
            if v is None:
                return None
            if isinstance(v, bool):
                return v
            s = str(v).strip().lower()
            return s in {"1", "true", "yes", "y", "on"}

        def _to_num(v, default=None):
            try:
                if v is None:
                    return default
                if isinstance(v, str):
                    v = v.replace(",", "").strip()
                return float(v)
            except Exception:
                return default

        # Load existing first (so we can enforce uniqueness vs self)
        existing = self.fetch_one(
            f"SELECT * FROM {schema}.inventory_items WHERE company_id=%s AND id=%s LIMIT 1",
            (int(company_id), int(item_id)),
        )
        if not existing:
            return None

        # Normalize + build updates
        sets = []
        params = []

        # ✅ Uniqueness checks if these fields are changing
        incoming_sku = _norm_str(patch.get("sku")) if "sku" in (patch or {}) else ""
        incoming_barcode = _norm_str(patch.get("barcode")) if "barcode" in (patch or {}) else ""

        if "sku" in (patch or {}):
            if not incoming_sku:
                raise ValueError("sku cannot be blank")
            dup = self.fetch_one(
                f"""
                SELECT id FROM {schema}.inventory_items
                WHERE company_id=%s AND lower(sku)=lower(%s) AND id<>%s
                LIMIT 1
                """,
                (int(company_id), incoming_sku, int(item_id)),
            )
            if dup:
                raise ValueError("SKU already exists")
            patch["sku"] = incoming_sku

        if "barcode" in (patch or {}):
            patch["barcode"] = incoming_barcode or None
            if incoming_barcode:
                dup = self.fetch_one(
                    f"""
                    SELECT id FROM {schema}.inventory_items
                    WHERE company_id=%s AND barcode=%s AND id<>%s
                    LIMIT 1
                    """,
                    (int(company_id), incoming_barcode, int(item_id)),
                )
                if dup:
                    raise ValueError("Barcode already exists")

            incoming_meta = (patch or {}).get("meta")
            if isinstance(incoming_meta, dict) and incoming_meta:
                existing_meta = existing.get("meta") if isinstance(existing, dict) else {}
                if not isinstance(existing_meta, dict):
                    existing_meta = {}
                merged_meta = {**existing_meta, **incoming_meta}
                sets.append("meta=%s")
                params.append(Json(merged_meta))
                
        for k, v in (patch or {}).items():
            if k not in field_map:
                continue

            if k == "meta":
                continue

            col = field_map[k]

            # Normalize common types
            if col in {"sku", "name", "category", "unit", "vat_code"}:
                v = _norm_str(v) or None
                if col in {"sku", "name"} and not v:
                    raise ValueError(f"{col} cannot be blank")

            if col in {"track_stock", "is_active", "is_taxable"}:
                b = _to_bool(v)
                if b is None:
                    continue
                v = bool(b)

            if col in {"sales_price", "purchase_cost", "reorder_level"}:
                n = _to_num(v, default=0.0)
                if n is None:
                    continue
                if n < 0:
                    raise ValueError(f"{col} must be >= 0")
                v = float(n)

            sets.append(f"{col}=%s")
            params.append(v)

        if not sets:
            return existing

        params.extend([int(company_id), int(item_id)])

        sql = f"""
        UPDATE {schema}.inventory_items
        SET {", ".join(sets)}, updated_at=NOW()
        WHERE company_id=%s AND id=%s
        RETURNING *;
        """
        return self.fetch_one(sql, tuple(params))

    def get_inventory_item(self, company_id: int, item_id: int):
        schema = f"company_{int(company_id)}"
        return self.fetch_one(
            f"SELECT * FROM {schema}.inventory_items WHERE company_id=%s AND id=%s LIMIT 1",
            (int(company_id), int(item_id)),
        )

    def create_inventory_item(self, company_id: int, data: dict, cur=None) -> int:
        schema = f"company_{company_id}"

        def _norm_str(v):
            return (str(v).strip() if v is not None else "")

        def _to_bool(v, default=False):
            if v is None:
                return default
            if isinstance(v, bool):
                return v
            s = str(v).strip().lower()
            return s in {"1", "true", "yes", "y", "on"}

        def _to_num(v, default=0.0):
            try:
                if v is None:
                    return default
                if isinstance(v, str):
                    v = v.replace(",", "").strip()
                return float(v)
            except Exception:
                return default

        sku = _norm_str(data.get("sku"))
        name = _norm_str(data.get("name"))
        if not sku:
            raise ValueError("sku is required")
        if not name:
            raise ValueError("name is required")

        barcode = _norm_str(data.get("barcode")) or None
        unit = _norm_str(data.get("unit") or data.get("uom")) or None
        category = _norm_str(data.get("category")) or None

        is_taxable = _to_bool(data.get("is_taxable"), default=True)
        track_stock = _to_bool(data.get("track_stock"), default=True)
        is_active = _to_bool(data.get("is_active"), default=True)

        inv_acc = _norm_str(data.get("inventory_account")) or None
        cogs_acc = _norm_str(data.get("cogs_account")) or None
        income_acc = _norm_str(data.get("income_account")) or None

        sales_price = _to_num(data.get("sales_price"), 0.0)
        purchase_cost = _to_num(data.get("purchase_cost"), 0.0)
        reorder_level = _to_num(data.get("reorder_level"), 0.0)

        if sales_price < 0 or purchase_cost < 0 or reorder_level < 0:
            raise ValueError("sales_price, purchase_cost, reorder_level must be >= 0")

        vat_code = _norm_str(data.get("vat_code")) or None
        valuation_method = _norm_str(data.get("valuation_method")) or None

        def _run(_cur):
            # ✅ enforce SKU uniqueness
            dup = self.fetch_one(
                f"SELECT id FROM {schema}.inventory_items WHERE company_id=%s AND lower(sku)=lower(%s) LIMIT 1",
                (int(company_id), sku),
                cur=_cur,
            )
            if dup:
                raise ValueError("SKU already exists")

            # ✅ enforce barcode uniqueness (if provided)
            if barcode:
                dupb = self.fetch_one(
                    f"SELECT id FROM {schema}.inventory_items WHERE company_id=%s AND barcode=%s LIMIT 1",
                    (int(company_id), barcode),
                    cur=_cur,
                )
                if dupb:
                    raise ValueError("Barcode already exists")

            meta = data.get("meta")
            if not isinstance(meta, dict):
                meta = {}

            sql = f"""
            INSERT INTO {schema}.inventory_items
            (company_id, sku, name, description, category, unit, barcode,
            inventory_account, income_account, cogs_account,
            sales_price, purchase_cost, vat_code, valuation_method, reorder_level,
            track_stock, is_taxable, is_active, meta, created_at, updated_at)
            VALUES
            (%s,%s,%s,%s,%s,%s,%s,
            %s,%s,%s,
            %s,%s,%s,%s,%s,
            %s,%s,%s,%s, NOW(), NOW())
            RETURNING id;
            """

            params = (
                int(company_id),
                sku,
                name,
                _norm_str(data.get("description")) or None,
                category,
                unit,
                barcode,

                inv_acc,
                income_acc,
                cogs_acc,

                float(sales_price),
                float(purchase_cost),
                vat_code,
                valuation_method,
                float(reorder_level),

                bool(track_stock),
                bool(is_taxable),
                bool(is_active),

                Json(meta),
            )

            _cur.execute(sql, params)
            row = _cur.fetchone()
            return int((row.get("id") if isinstance(row, dict) else row[0]) or 0)

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (conn, _cur):
            item_id = _run(_cur)
            conn.commit()
            return int(item_id)

    def receive_inventory_stock(
        self,
        company_id: int,
        *,
        tx_date,
        ref: str = None,
        notes: str = None,
        lines: list[dict],
        created_by: int = None,
        vendor_id: int | None = None,
        po_id: int | None = None,
        supplier_invoice_no: str | None = None,
        cur=None,
    ) -> int:
        """
        Receipt flow (idempotent by ref):
        - inventory_tx header (tx_type='receipt')
        - inventory_tx_lines (optionally linked to po_line_id)
        - inventory_layers (qty_in)
        - updates purchase_order_lines.received_qty when po_line_id present
        - posts to GL (Dr Inventory / Cr GRNI) via post_inventory_receipt_to_gl (idempotent)
        """

        schema = f"company_{company_id}"
        if not lines or not isinstance(lines, list):
            raise ValueError("lines required")

        # normalize date
        if hasattr(tx_date, "isoformat"):
            tx_date = tx_date.isoformat()[:10]
        else:
            tx_date = str(tx_date)[:10]

        ref = (ref or "").strip() or None
        if not ref:
            raise ValueError("ref is required (supplier doc / GRN reference)")

        supplier_invoice_no = (supplier_invoice_no or "").strip() or None

        def _to_float(x, d=0.0):
            try:
                if x is None:
                    return d
                if isinstance(x, str):
                    x = x.replace(",", "").strip()
                return float(x)
            except Exception:
                return d

        def _to_int(x, d=0):
            try:
                if x is None:
                    return d
                if isinstance(x, str):
                    x = x.strip()
                    if not x:
                        return d
                return int(x)
            except Exception:
                return d

        def _run(_cur):
            # ✅ Idempotency (receipt + ref), trimmed + lower-safe
            _cur.execute(
                f"""
                SELECT id
                FROM {schema}.inventory_tx
                WHERE company_id=%s
                AND lower(tx_type)=lower('receipt')
                AND lower(trim(ref))=lower(trim(%s))
                LIMIT 1
                """,
                (int(company_id), ref),
            )
            ex = _cur.fetchone()
            if ex:
                return int(ex["id"] if isinstance(ex, dict) else ex[0])

            # 1) create header
            _cur.execute(
                f"""
                INSERT INTO {schema}.inventory_tx
                (company_id, tx_date, tx_type, status, ref, notes,
                source, source_id, created_by,
                vendor_id, po_id, supplier_invoice_no, grni_status,
                created_at, updated_at)
                VALUES
                (%s,%s,'receipt','posted',%s,%s,
                'manual',NULL,%s,
                %s,%s,%s,'unbilled',
                NOW(),NOW())
                RETURNING id;
                """,
                (
                    int(company_id),
                    tx_date,
                    ref,
                    (notes or None),
                    (created_by or None),
                    (int(vendor_id) if vendor_id else None),
                    (int(po_id) if po_id else None),
                    supplier_invoice_no,
                ),
            )
            row = _cur.fetchone()
            tx_id = int((row.get("id") if isinstance(row, dict) else row[0]) or 0)
            if tx_id <= 0:
                raise ValueError("Failed to create inventory_tx")

            # 2) insert lines + layers (+ optional PO updates)
            for i, ln in enumerate(lines, start=1):
                item_id = _to_int(ln.get("item_id"), 0)
                if item_id <= 0:
                    raise ValueError(f"line {i}: item_id required")

                qty = _to_float(ln.get("qty_in") or ln.get("qty") or ln.get("quantity") or 0.0)
                if qty <= 0:
                    raise ValueError(f"line {i}: qty must be > 0")

                unit_cost = _to_float(ln.get("unit_cost") or 0.0)
                if unit_cost < 0:
                    raise ValueError(f"line {i}: unit_cost must be >= 0")

                expiry_date = ln.get("expiry_date")
                batch_no = (ln.get("batch_no") or "").strip() or None
                memo = (ln.get("memo") or "").strip() or None
                vat_code = (ln.get("vat_code") or None)

                # ✅ NEW: link to PO line if provided
                po_line_id = _to_int(ln.get("po_line_id"), 0) or None

                # A) tx line (now includes po_line_id)
                _cur.execute(
                    f"""
                    INSERT INTO {schema}.inventory_tx_lines
                    (company_id, tx_id, line_no, item_id, qty, unit_cost, unit_price,
                    vat_code, memo, expiry_date, batch_no, po_line_id, created_at)
                    VALUES
                    (%s,%s,%s,%s,%s,%s,0,
                    %s,%s,%s,%s,%s,NOW());
                    """,
                    (
                        int(company_id),
                        int(tx_id),
                        int(i),
                        int(item_id),
                        float(qty),
                        float(unit_cost),
                        vat_code,
                        memo,
                        expiry_date,
                        batch_no,
                        (int(po_line_id) if po_line_id else None),
                    ),
                )

                # ✅ If linked to PO line: update received_qty
                if po_line_id:
                    _cur.execute(
                        f"""
                        UPDATE {schema}.purchase_order_lines
                        SET received_qty = COALESCE(received_qty,0) + %s
                        WHERE company_id=%s AND id=%s
                        """,
                        (float(qty), int(company_id), int(po_line_id)),
                    )

                # B) layer (stock in)
                _cur.execute(
                    f"""
                    INSERT INTO {schema}.inventory_layers
                    (company_id, item_id, tx_date, qty_in, qty_out, unit_cost,
                    ref, source, source_id, tx_id, expiry_date, batch_no, created_at)
                    VALUES
                    (%s,%s,%s,%s,0,%s,
                    %s,'inventory_tx',%s,%s,%s,%s,NOW());
                    """,
                    (
                        int(company_id),
                        int(item_id),
                        tx_date,
                        float(qty),
                        float(unit_cost),
                        ref,
                        int(tx_id),   # source_id = tx_id
                        int(tx_id),   # tx_id
                        expiry_date,
                        batch_no,
                    ),
                )

            # ✅ optional GL posting (idempotent inside post fn via posted_journal_id)
            self.post_inventory_receipt_to_gl(company_id, tx_id=tx_id, cur=_cur)

            return tx_id

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (conn, _cur):
            tx_id = _run(_cur)
            conn.commit()
            return tx_id


    def _money6(x) -> Decimal:
        return Decimal(str(x or 0)).quantize(Decimal("0.000001"), rounding=ROUND_HALF_UP)

    def allocate_landed_cost_to_open_layers(
        self,
        company_id: int,
        *,
        item_id: int,
        amount: float,
        tx_date,                 # date or str
        source: str,
        source_id: int,
        variance_account: str = "PPV_CONTROL",   # fallback when stock already sold
        cur=None,
    ) -> None:
        schema = f"company_{company_id}"

        amt = self._money6(amount)
        if amt <= 0:
            return

        if hasattr(tx_date, "isoformat"):
            d = tx_date.isoformat()[:10]
        else:
            d = str(tx_date)[:10]

        # idempotency: if already allocated for this (source,source_id,item)
        cur.execute(
            f"""
            SELECT 1
            FROM {schema}.inventory_landed_cost_allocations
            WHERE company_id=%s AND source=%s AND source_id=%s AND item_id=%s
            LIMIT 1
            """,
            (int(company_id), str(source), int(source_id), int(item_id)),
        )
        if cur.fetchone():
            return

        # Get open layers (inbound layers with remaining qty)
        cur.execute(
            f"""
            SELECT id, qty_in, qty_out, unit_cost
            FROM {schema}.inventory_layers
            WHERE company_id=%s AND item_id=%s
            AND qty_in > 0
            AND (qty_in - qty_out) > 0
            ORDER BY tx_date ASC, id ASC
            """,
            (int(company_id), int(item_id)),
        )
        layers = cur.fetchall() or []

        total_remaining = Decimal("0")
        for r in layers:
            rem = self._money6((r.get("qty_in") or 0) - (r.get("qty_out") or 0))
            if rem > 0:
                total_remaining += rem

        # No stock left -> push to variance (PPV/COGS)
        if total_remaining <= 0:
            # You already have control-account mapping helpers; use them if you want.
            # Here we just post a GL line later in caller (recommended), or do it here if you pass journal_id.
            raise ValueError(f"LANDED_COST_NO_STOCK|item_id={item_id}|amount={float(amt)}")

        remaining_to_allocate = amt

        # Allocate proportionally by remaining qty
        for i, r in enumerate(layers):
            layer_id = int(r["id"])
            rem_qty  = self._money6((r.get("qty_in") or 0) - (r.get("qty_out") or 0))
            if rem_qty <= 0:
                continue

            if i == len(layers) - 1:
                part = remaining_to_allocate
            else:
                part = (amt * (rem_qty / total_remaining)).quantize(Decimal("0.000001"), rounding=ROUND_HALF_UP)

            if part <= 0:
                continue

            # Increase unit_cost of the layer by (part / rem_qty)
            add_per_unit = (part / rem_qty).quantize(Decimal("0.000001"), rounding=ROUND_HALF_UP)

            cur.execute(
                f"""
                UPDATE {schema}.inventory_layers
                SET unit_cost = (unit_cost + %s)
                WHERE company_id=%s AND id=%s
                """,
                (float(add_per_unit), int(company_id), layer_id),
            )

            cur.execute(
                f"""
                INSERT INTO {schema}.inventory_landed_cost_allocations
                (company_id, item_id, layer_id, source, source_id, tx_date, amount)
                VALUES (%s,%s,%s,%s,%s,%s,%s)
                """,
                (int(company_id), int(item_id), int(layer_id), str(source), int(source_id), d, float(part)),
            )

            remaining_to_allocate -= part
            if remaining_to_allocate <= 0:
                break 

    def replace_bill_grni_links(self, company_id: int, bill_id: int, links: list[dict], cur=None) -> None:
        schema = self.company_schema(company_id)

        def _norm_amt(x):
            try:
                return float(str(x or 0).replace(",", "").strip() or 0)
            except Exception:
                return 0.0

        links = links if isinstance(links, list) else []

        def _run(_cur):
            # 0) load bill vendor
            _cur.execute(
                f"SELECT vendor_id FROM {schema}.bills WHERE company_id=%s AND id=%s LIMIT 1",
                (int(company_id), int(bill_id)),
            )
            b = _cur.fetchone() or {}
            bill_vendor_id = int((b.get("vendor_id") if isinstance(b, dict) else b[0]) or 0)
            if bill_vendor_id <= 0:
                raise ValueError("BILL_NOT_FOUND_OR_VENDOR_MISSING")

            # 1) wipe existing links
            _cur.execute(
                f"DELETE FROM {schema}.bill_grni_links WHERE company_id=%s AND bill_id=%s",
                (int(company_id), int(bill_id)),
            )

            # 2) insert new links with validation
            for ln in links:
                tx_id = int(ln.get("receipt_tx_id") or 0)
                amt = _norm_amt(ln.get("amount"))
                if tx_id <= 0 or amt <= 0:
                    continue

                # A) validate receipt belongs to vendor + is posted receipt
                _cur.execute(
                    f"""
                    SELECT id, vendor_id, tx_type, status
                    FROM {schema}.inventory_tx
                    WHERE company_id=%s AND id=%s
                    LIMIT 1
                    """,
                    (int(company_id), int(tx_id)),
                )
                r = _cur.fetchone() or {}
                r_vendor = int(r.get("vendor_id") or 0)
                tx_type = (r.get("tx_type") or "").lower()
                status = (r.get("status") or "").lower()

                if r_vendor != bill_vendor_id:
                    raise ValueError(f"RECEIPT_VENDOR_MISMATCH|tx_id={tx_id}")
                if tx_type != "receipt":
                    raise ValueError(f"INVALID_RECEIPT_TX_TYPE|tx_id={tx_id}|tx_type={tx_type}")
                if status != "posted":
                    raise ValueError(f"RECEIPT_NOT_POSTED|tx_id={tx_id}|status={status}")

                # B) compute receipt total (cost) and remaining (excluding current bill because we deleted)
                _cur.execute(
                    f"""
                    SELECT COALESCE(SUM(qty*unit_cost),0)::numeric(18,2) AS tot
                    FROM {schema}.inventory_tx_lines
                    WHERE company_id=%s AND tx_id=%s
                    """,
                    (int(company_id), int(tx_id)),
                )
                tot_row = _cur.fetchone() or {}
                receipt_total = float(tot_row.get("tot") or 0)

                _cur.execute(
                    f"""
                    SELECT COALESCE(SUM(amount),0)::numeric(18,2) AS linked
                    FROM {schema}.bill_grni_links
                    WHERE company_id=%s AND receipt_tx_id=%s
                    """,
                    (int(company_id), int(tx_id)),
                )
                lrow = _cur.fetchone() or {}
                linked_total = float(lrow.get("linked") or 0)

                remaining = max(0.0, receipt_total - linked_total)
                if amt > remaining + 0.0001:
                    raise ValueError(f"GRNI_OVERLINK|tx_id={tx_id}|amt={amt}|remaining={remaining}")

                _cur.execute(
                    f"""
                    INSERT INTO {schema}.bill_grni_links (company_id, bill_id, receipt_tx_id, amount)
                    VALUES (%s,%s,%s,%s)
                    """,
                    (int(company_id), int(bill_id), int(tx_id), float(amt)),
                )

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (conn, _cur):
            _run(_cur)
            conn.commit()


    def list_open_grni_receipts(
        self,
        company_id: int,
        *,
        vendor_id: int,
        q: str = "",
        limit: int = 50,
        offset: int = 0
    ):
        schema = self.company_schema(company_id)
        q = (q or "").strip()

        where = [
            "t.company_id=%s",
            "t.vendor_id=%s",
            "lower(t.status)=lower('posted')",
            # ✅ accept both (your system uses 'receive' today)
            "lower(t.tx_type) IN ('receive','receipt')",
        ]
        params = [int(company_id), int(vendor_id)]

        if q:
            where.append("""
            (
            lower(coalesce(t.ref,''))   LIKE lower(%s)
            OR lower(coalesce(t.notes,'')) LIKE lower(%s)
            )
            """)
            params += [f"%{q}%", f"%{q}%"]

        sql = f"""
        WITH receipt_totals AS (
        SELECT
            l.tx_id,
            COALESCE(SUM(COALESCE(l.qty,0) * COALESCE(l.unit_cost,0)),0)::numeric(18,2) AS receipt_total
        FROM {schema}.inventory_tx_lines l
        WHERE l.company_id=%s
        GROUP BY l.tx_id
        ),
        linked AS (
        SELECT
            receipt_tx_id AS tx_id,
            COALESCE(SUM(amount),0)::numeric(18,2) AS linked_total
        FROM {schema}.bill_grni_links
        WHERE company_id=%s
        GROUP BY receipt_tx_id
        )
        SELECT
        -- ✅ give the UI a consistent id
        t.id AS id,
        t.id AS receipt_tx_id,
        t.tx_date,
        t.ref,
        t.notes,
        COALESCE(rt.receipt_total,0)::numeric(18,2) AS receipt_total,
        COALESCE(li.linked_total,0)::numeric(18,2)  AS linked_total,

        -- ✅ UI-friendly name (what you should display)
        (COALESCE(rt.receipt_total,0) - COALESCE(li.linked_total,0))::numeric(18,2) AS open_amount

        FROM {schema}.inventory_tx t
        LEFT JOIN receipt_totals rt ON rt.tx_id=t.id
        LEFT JOIN linked li ON li.tx_id=t.id
        WHERE {" AND ".join(where)}
        AND (COALESCE(rt.receipt_total,0) - COALESCE(li.linked_total,0)) > 0
        ORDER BY t.tx_date DESC, t.id DESC
        LIMIT %s OFFSET %s
        """

        # CTE params first (company_id twice), then WHERE params, then paging
        params2 = [int(company_id), int(company_id)] + params + [int(limit), int(offset)]
        return self.fetch_all(sql, tuple(params2)) or []

    def list_inventory_items(self, company_id: int, *, q: str | None = None, active: int | None = 1, limit: int = 50, offset: int = 0):
        schema = f"company_{int(company_id)}"
        where = ["company_id=%s"]
        params = [int(company_id)]

        if active is not None:
            where.append("is_active=%s")
            params.append(bool(int(active)) if isinstance(active, (int, str)) else bool(active))

        if q:
            q = str(q).strip()
            if q:
                where.append("(name ILIKE %s OR sku ILIKE %s OR COALESCE(barcode,'') ILIKE %s)")
                like = f"%{q}%"
                params.extend([like, like, like])

        sql = f"""
        SELECT
        id, sku, name, unit, barcode,
        sales_price, vat_code, reorder_level,
        track_stock, valuation_method,
        is_taxable, is_active, updated_at
        FROM {schema}.inventory_items
        WHERE {" AND ".join(where)}
        ORDER BY name ASC, id ASC
        LIMIT %s OFFSET %s
        """
        params.extend([int(limit), int(offset)])
        return self.fetch_all(sql, tuple(params)) or []

    def create_journal_header(
        self,
        *,
        company_id: int,
        je_date,          # date or 'YYYY-MM-DD'
        ref: str,
        memo: str,
        source: str,
        source_id: int,
        gross_amount: float = 0.0,
        net_amount: float = 0.0,
        vat_amount: float = 0.0,
        cur,
    ) -> int:
        """
        Insert journal header inside an existing transaction (uses passed cursor).
        Returns journal_id (int).

        NOTE: Update journal table name/columns if your schema differs.
        """
        from decimal import Decimal, ROUND_HALF_UP
        from datetime import date as _date

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = self.company_schema(company_id)

        # normalize date
        if hasattr(je_date, "isoformat"):
            je_date = je_date.isoformat()[:10]
        else:
            je_date = str(je_date)[:10]
            if not je_date:
                je_date = _date.today().isoformat()

        ref = (ref or "").strip() or f"JE-{source}-{source_id}"
        memo = (memo or "").strip() or ref
        source = (source or "").strip() or "manual"

        # ✅ If you already have insert_journal(), use it (preferred)
        if hasattr(self, "insert_journal"):
            entry = {
                "date": je_date,
                "ref": ref,
                "description": memo,
                "gross_amount": money(gross_amount),
                "net_amount": money(net_amount),
                "vat_amount": money(vat_amount),
                "source": source,
                "source_id": int(source_id),
            }
            jid = int(self.insert_journal(company_id, entry, cur=cur) or 0)
            if jid <= 0:
                raise ValueError("FAILED_TO_CREATE_JOURNAL_HEADER")
            return jid

        # ✅ Otherwise do direct SQL (edit table/column names if needed)
        cur.execute(
            f"""
            INSERT INTO {schema}.journals
                (company_id, je_date, ref, description, gross_amount, net_amount, vat_amount, source, source_id, created_at)
            VALUES
                (%s,%s,%s,%s,%s,%s,%s,%s,%s,NOW())
            RETURNING id;
            """,
            (
                int(company_id),
                je_date,
                ref,
                memo,
                money(gross_amount),
                money(net_amount),
                money(vat_amount),
                source,
                int(source_id),
            ),
        )
        row = cur.fetchone() or {}
        jid = int((row.get("id") if isinstance(row, dict) else row[0]) or 0)
        if jid <= 0:
            raise ValueError("FAILED_TO_CREATE_JOURNAL_HEADER")
        return jid

    def post_inventory_receipt_to_gl(
        self,
        company_id: int,
        *,
        tx_id: int,
        cur,
    ) -> int:
        """
        Posts Inventory Receipt (inventory_tx tx_type='receive') to GL:
        Dr Inventory (per item inventory_account, fallback inventory_control_code)
        Cr GRNI (control setting)
        Idempotent by inventory_tx.posted_journal_id
        MUST be called inside the SAME DB transaction as receipt creation.
        """
        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        def resolve_posting(raw: str, label: str) -> str:
            raw = (raw or "").strip()
            if not raw:
                raise ValueError(f"{label}_NOT_SET")
            row = self.get_account_row_for_posting(company_id, raw)
            if not row:
                raise ValueError(f"{label}_NOT_FOUND_IN_COA|{raw}")
            posting = (row[1] or "").strip()
            if not posting:
                raise ValueError(f"{label}_RESOLVED_BLANK|{raw}")
            return posting

        schema = f"company_{company_id}"

        # 1) lock tx header (prevents double-post)
        cur.execute(
            f"""
            SELECT *
            FROM {schema}.inventory_tx
            WHERE id=%s AND company_id=%s
            FOR UPDATE
            """,
            (int(tx_id), int(company_id)),
        )
        tx = cur.fetchone() or {}
        if not tx:
            raise ValueError(f"INVENTORY_TX_NOT_FOUND|tx_id={tx_id}")

        # already posted?
        already = tx.get("posted_journal_id")
        if already:
            return int(already)

        tx_type = (tx.get("tx_type") or "").strip().lower()
        if tx_type not in ("receipt", "receive"):
            raise ValueError(f"INVALID_TX_TYPE_FOR_RECEIPT_POST|tx_type={tx_type}")

        tx_date = str(tx.get("tx_date") or "")[:10]
        ref = (tx.get("ref") or f"RECEIPT-{tx_id}").strip()

        # 2) resolve GRNI control (fallback to ppv_control_code)
        settings = self.get_company_account_settings(company_id) or {}
        grni_raw = (settings.get("grni_control_code") or settings.get("ppv_control_code") or "").strip()
        if not grni_raw:
            raise ValueError("GRNI_NOT_CONFIGURED|set grni_control_code (or ppv_control_code) in company_account_settings")

        GRNI = resolve_posting(grni_raw, "GRNI_CONTROL")

        # OPTIONAL fallback inventory control (only works if your settings include it)
        inv_ctrl_raw = (settings.get("inventory_control_code") or "").strip()

        # 3) load receipt lines + inventory accounts
        lines = self.fetch_all(
            f"""
            SELECT
            l.item_id,
            l.qty,
            l.unit_cost,
            i.inventory_account
            FROM {schema}.inventory_tx_lines l
            JOIN {schema}.inventory_items i ON i.id=l.item_id
            WHERE l.company_id=%s AND l.tx_id=%s
            ORDER BY l.line_no ASC
            """,
            (int(company_id), int(tx_id)),
            cur=cur,
        ) or []
        if not lines:
            raise ValueError("RECEIPT_HAS_NO_LINES")

        # 4) accumulate by inventory account
        inv_totals: dict[str, float] = {}
        total = 0.0

        for ln in lines:
            qty = float(ln.get("qty") or 0.0)
            unit_cost = float(ln.get("unit_cost") or 0.0)
            if qty <= 0:
                continue

            amt = money(qty * unit_cost)
            if amt <= 0:
                continue

            inv_raw = (ln.get("inventory_account") or "").strip()
            if not inv_raw:
                if not inv_ctrl_raw:
                    raise ValueError(
                        f"ITEM_INVENTORY_ACCOUNT_MISSING|item_id={ln.get('item_id')}|"
                        f"set inventory_items.inventory_account or company_account_settings.inventory_control_code"
                    )
                inv_raw = inv_ctrl_raw

            INV_ACCT = resolve_posting(inv_raw, f"INVENTORY_ACCOUNT|item_id={ln.get('item_id')}")

            inv_totals[INV_ACCT] = money(inv_totals.get(INV_ACCT, 0.0) + amt)
            total = money(total + amt)

        if total <= 0:
            raise ValueError("RECEIPT_TOTAL_IS_ZERO")

        # 5) create journal header (same transaction)
        journal_id = int(self.create_journal_header(
            company_id=company_id,
            je_date=tx_date,
            ref=ref,
            memo=f"Inventory Receipt #{tx_id}",
            source="inventory_receipt",
            source_id=int(tx_id),
            cur=cur,
        ) or 0)
        if journal_id <= 0:
            raise ValueError("FAILED_TO_CREATE_RECEIPT_JOURNAL")

        # 6) Dr Inventory lines
        for acct, amt in inv_totals.items():
            if amt <= 0:
                continue
            self.insert_ledger(
                company_id=company_id,
                journal_id=journal_id,
                je_date=tx_date,
                line={"account_code": acct, "debit": amt, "credit": 0.0, "memo": "Inventory received"},
                ref=ref,
                source="inventory_receipt",
                source_id=int(tx_id),
                cur=cur,
            )
            self.update_trial_balance(company_id, {"account_code": acct, "debit": amt, "credit": 0.0}, cur=cur)

        # 7) Cr GRNI
        self.insert_ledger(
            company_id=company_id,
            journal_id=journal_id,
            je_date=tx_date,
            line={"account_code": GRNI, "debit": 0.0, "credit": total, "memo": "GRNI (receipt accrual)"},
            ref=ref,
            source="inventory_receipt",
            source_id=int(tx_id),
            cur=cur,
        )
        self.update_trial_balance(company_id, {"account_code": GRNI, "debit": 0.0, "credit": total}, cur=cur)

        # 8) stamp tx + layers
        cur.execute(
            f"""
            UPDATE {schema}.inventory_tx
            SET posted_journal_id=%s, posted_at=NOW(), status='posted'
            WHERE id=%s AND company_id=%s AND posted_journal_id IS NULL
            """,
            (journal_id, int(tx_id), int(company_id)),
        )

        cur.execute(
            f"""
            UPDATE {schema}.inventory_layers
            SET posted_journal_id=%s
            WHERE company_id=%s AND tx_id=%s AND source='inventory_tx'
            """,
            (journal_id, int(company_id), int(tx_id)),
        )

        return journal_id


    def build_bill_inventory_jlines(
        self,
        company_id: int,
        *,
        bill: dict,
    ) -> list[dict]:

        from decimal import Decimal, ROUND_HALF_UP

        def money(x):
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        if not bill:
            return []

        settings = self.get_company_account_settings(company_id) or {}

        AP_CODE   = settings.get("ap_control_code")
        VAT_CODE  = settings.get("vat_input_code")
        GRNI_CODE = settings.get("grni_control_code")

        if not AP_CODE:
            raise ValueError("AP control not configured")

        if not GRNI_CODE:
            raise ValueError("GRNI control not configured")

        lines = bill.get("lines") or []

        expense_totals = {}
        grni_total = 0.0
        vat_total = 0.0

        # -----------------------------
        # Loop bill lines
        # -----------------------------
        for ln in lines:

            qty = float(ln.get("quantity") or 0)
            price = float(ln.get("unit_price") or 0)
            line_total = money(qty * price)

            vat_amt = money(ln.get("vat_amount") or 0)
            vat_total += vat_amt

            item_type = (ln.get("item_type") or "").lower()

            # -----------------------------------
            # INVENTORY → debit GRNI
            # -----------------------------------
            if item_type == "inventory":
                grni_total += line_total

            # -----------------------------------
            # SERVICE / EXPENSE → debit expense
            # -----------------------------------
            else:
                acct = (ln.get("expense_account") or "").strip()
                if not acct:
                    raise ValueError("Expense account missing on bill line")

                expense_totals[acct] = money(
                    expense_totals.get(acct, 0) + line_total
                )

        jlines = []

        # -----------------------------
        # GRNI debit
        # -----------------------------
        if grni_total > 0:
            jlines.append({
                "account_code": GRNI_CODE,
                "dc": "D",
                "amount": grni_total,
                "memo": "Inventory received not invoiced",
            })

        # -----------------------------
        # Expense debits
        # -----------------------------
        for acct, amt in expense_totals.items():
            if amt <= 0:
                continue
            jlines.append({
                "account_code": acct,
                "dc": "D",
                "amount": amt,
                "memo": "Bill expense",
            })

        # -----------------------------
        # VAT input debit
        # -----------------------------
        if vat_total > 0:
            jlines.append({
                "account_code": VAT_CODE,
                "dc": "D",
                "amount": vat_total,
                "memo": "VAT input",
            })

        # -----------------------------
        # AP credit (balancing)
        # -----------------------------
        gross_total = money(bill.get("total_amount") or 0)

        jlines.append({
            "account_code": AP_CODE,
            "dc": "C",
            "amount": gross_total,
            "memo": "Accounts payable",
        })

        return jlines

    def build_bill_jlines_erp(
        self,
        company_id: int,
        *,
        bill: dict,
        cur
    ) -> list[dict]:
        from decimal import Decimal, ROUND_HALF_UP

        def money(x):
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        settings = self.get_company_account_settings(company_id) or {}

        AP_RAW   = (settings.get("ap_control_code") or "").strip()
        VAT_RAW  = (settings.get("vat_input_code") or "").strip()
        GRNI_RAW = (settings.get("grni_control_code") or "").strip()
        PPV_RAW  = (settings.get("ppv_control_code") or "").strip()

        if not AP_RAW:   raise ValueError("AP control not set")
        if not VAT_RAW:  raise ValueError("VAT input control not set")
        if not GRNI_RAW: raise ValueError("GRNI control not set")
        if not PPV_RAW:  raise ValueError("PPV control not set")

        # Resolve posting codes once
        def _resolve(raw: str, label: str) -> str:
            row = self.get_account_row_for_posting(company_id, raw)
            if not row:
                raise ValueError(f"{label}_CONTROL_NOT_FOUND_IN_COA|{raw}")
            code = (row[1] or "").strip()
            if not code:
                raise ValueError(f"{label}_CONTROL_BLANK_POSTING_CODE|{raw}")
            return code

        AP   = _resolve(AP_RAW, "AP")
        VAT  = _resolve(VAT_RAW, "VAT_INPUT")
        GRNI = _resolve(GRNI_RAW, "GRNI")
        PPV  = _resolve(PPV_RAW, "PPV")

        lines = bill.get("lines") or []

        vat_total = money(bill.get("vat_amount") or 0)
        gross_total = money(bill.get("total_amount") or 0)

        # Totals
        grni_debit = 0.0
        ppv_amt = 0.0
        expense_totals = {}

        # ---- match helper: how much received-not-invoiced exists for a PO line
        def _po_remaining(po_line_id: int) -> float:
            cur.execute(f"""
            SELECT (received_qty - billed_qty) AS rem
            FROM company_{company_id}.purchase_order_lines
            WHERE company_id=%s AND id=%s
            LIMIT 1
            """, (int(company_id), int(po_line_id)))
            r = cur.fetchone() or {}
            return float(r.get("rem") or 0.0)

        # receipt cost for that po_line (simple: weighted avg of receipt lines linked to po_line)
        def _po_receipt_cost(po_line_id: int) -> float:
            cur.execute(f"""
            SELECT
                CASE WHEN COALESCE(SUM(qty),0)=0 THEN 0
                    ELSE COALESCE(SUM(qty * unit_cost),0)/NULLIF(COALESCE(SUM(qty),0),0) END AS wavg
            FROM company_{company_id}.inventory_tx_lines
            WHERE company_id=%s AND po_line_id=%s
            """, (int(company_id), int(po_line_id)))
            r = cur.fetchone() or {}
            return float(r.get("wavg") or 0.0)

        for ln in lines:
            item_type = (ln.get("item_type") or "").lower().strip()
            qty = float(ln.get("quantity") or ln.get("qty") or 0)
            unit_price = float(ln.get("unit_price") or 0)   # bill net unit price
            line_net = money(qty * unit_price)

            if qty <= 0 or line_net <= 0:
                continue

            # inventory line? (po_line_id is the cleanest way)
            po_line_id = ln.get("po_line_id")
            if item_type == "inventory" and po_line_id:
                po_line_id = int(po_line_id)
                rem = _po_remaining(po_line_id)
                match_qty = min(qty, max(rem, 0.0))

                bill_cost = float(unit_price)
                rec_cost  = _po_receipt_cost(po_line_id)

                if match_qty > 0 and rec_cost > 0:
                    # Clear GRNI at RECEIPT COST (matched qty)
                    grni_debit += money(match_qty * rec_cost)

                    # Variance = (bill - receipt) * matched qty
                    ppv_amt += money(match_qty * (bill_cost - rec_cost))

                    # Update billed_qty on the PO line
                    cur.execute(f"""
                    UPDATE company_{company_id}.purchase_order_lines
                    SET billed_qty = COALESCE(billed_qty,0) + %s
                    WHERE company_id=%s AND id=%s
                    """, (float(match_qty), int(company_id), int(po_line_id)))

                # Any leftover qty beyond received -> still accrue to GRNI at BILL COST (bill before receipt)
                left = qty - match_qty
                if left > 0:
                    grni_debit += money(left * bill_cost)

                continue

            # Non-inventory or no PO link => treat as expense
            acct = (ln.get("expense_account") or "").strip()
            if not acct:
                raise ValueError("Expense account missing on a non-PO bill line")
            expense_totals[acct] = money(expense_totals.get(acct, 0.0) + line_net)

        jlines = []

        # Dr GRNI
        if grni_debit > 0:
            jlines.append({"account_code": GRNI, "dc": "D", "amount": money(grni_debit), "memo": "GRNI clearing/accrual"})

        # Dr/Cr PPV (only if non-zero)
        if abs(ppv_amt) >= 0.01:
            if ppv_amt > 0:
                # bill > receipt => debit variance (extra cost)
                jlines.append({"account_code": PPV, "dc": "D", "amount": money(ppv_amt), "memo": "Purchase price variance"})
            else:
                # bill < receipt => credit variance
                jlines.append({"account_code": PPV, "dc": "C", "amount": money(abs(ppv_amt)), "memo": "Purchase price variance"})

        # Dr expenses
        for acct, amt in expense_totals.items():
            if amt > 0:
                jlines.append({"account_code": acct, "dc": "D", "amount": money(amt), "memo": "Bill expense"})

        # Dr VAT
        if vat_total > 0:
            jlines.append({"account_code": VAT, "dc": "D", "amount": money(vat_total), "memo": "VAT input"})

        # Cr AP (gross)
        jlines.append({"account_code": AP, "dc": "C", "amount": money(gross_total), "memo": "Accounts payable"})

        return jlines

    def post_bill_erp(self, company_id: int, bill_id: int) -> int:
        schema = self.company_schema(company_id)

        with self._conn_cursor() as (conn, cur):
            try:
                # lock the bill so two users can't post twice
                cur.execute(
                    f"SELECT id, posted_journal_id FROM {schema}.bills WHERE id=%s FOR UPDATE;",
                    (int(bill_id),),
                )
                hdr = cur.fetchone() or {}
                if not hdr:
                    raise ValueError("Bill not found")

                if hdr.get("posted_journal_id"):
                    conn.commit()
                    return int(hdr["posted_journal_id"])

                # load full bill (use your existing method)
                bill = self.get_bill_full(company_id, bill_id)
                if not bill:
                    raise ValueError("Bill not found")

                # ✅ build ERP-aware jlines (GRNI/PPV/Expense/VAT/AP)
                jlines = self.build_bill_jlines_erp(company_id, bill=bill, cur=cur)

                # ✅ post to GL (this function stays dumb)
                journal_id = self.post_bill_to_gl(company_id, bill_id, jlines=jlines)
                self.apply_bill_landed_costs(company_id, bill=bill, bill_id=bill_id, journal_id=journal_id, cur=cur)

                conn.commit()
                return int(journal_id)

            except Exception:
                conn.rollback()
                raise

    def fifo_consume(
        self,
        company_id: int,
        *,
        item_id: int,
        qty_out: float,
        tx_date,                 # invoice date
        source: str,
        source_id: int,
        posted_journal_id: int,
        cur
    ) -> float:
        """
        Consume qty from oldest layers first.
        Updates inventory_layers.qty_out and writes inventory_fifo_allocations rows.
        Returns total_cost consumed.
        """
        from decimal import Decimal, ROUND_HALF_UP

        def money(x):
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = f"company_{company_id}"

        if qty_out <= 0:
            return 0.0

        # idempotent: if already allocated for this source/source_id, do nothing
        cur.execute(f"""
        SELECT 1 FROM {schema}.inventory_fifo_allocations
        WHERE company_id=%s AND source=%s AND source_id=%s
        LIMIT 1
        """, (int(company_id), source, int(source_id)))
        if cur.fetchone():
            return 0.0

        # Normalize date
        if hasattr(tx_date, "isoformat"):
            tx_date = tx_date.isoformat()[:10]
        else:
            tx_date = str(tx_date)[:10]

        remaining = float(qty_out)
        total_cost = 0.0

        # Lock and pick layers FIFO: oldest first with remaining > 0
        cur.execute(f"""
        SELECT id, tx_date, unit_cost,
                (qty_in - qty_out) AS remaining_qty
        FROM {schema}.inventory_layers
        WHERE company_id=%s AND item_id=%s
            AND (qty_in - qty_out) > 0
        ORDER BY tx_date ASC, id ASC
        FOR UPDATE
        """, (int(company_id), int(item_id)))

        layers = cur.fetchall() or []

        for r in layers:
            if remaining <= 0:
                break

            layer_id = int(r["id"])
            layer_rem = float(r["remaining_qty"] or 0)
            uc = float(r["unit_cost"] or 0)

            take = min(remaining, layer_rem)
            if take <= 0:
                continue

            # 1) increase qty_out on that inbound layer
            cur.execute(f"""
            UPDATE {schema}.inventory_layers
            SET qty_out = qty_out + %s
            WHERE company_id=%s AND id=%s
            """, (float(take), int(company_id), int(layer_id)))

            # 2) write allocation record
            cur.execute(f"""
            INSERT INTO {schema}.inventory_fifo_allocations
                (company_id, item_id, layer_id, qty, unit_cost, source, source_id, posted_journal_id)
            VALUES
                (%s,%s,%s,%s,%s,%s,%s,%s)
            """, (int(company_id), int(item_id), int(layer_id), float(take), float(uc), source, int(source_id), int(posted_journal_id)))

            total_cost += money(take * uc)
            remaining -= take

        if remaining > 0.0001:
            raise ValueError(f"INSUFFICIENT_STOCK|item_id={item_id}|missing={remaining}")

        return money(total_cost)

    def apply_bill_landed_costs(
        self,
        company_id: int,
        *,
        bill: dict,
        bill_id: int, 
        journal_id: int,
        cur,
    ) -> None:
        """
        Allocate landed costs from a Bill to inventory receipt layers using bill.grni_links.

        Rules:
        - Only allocate if bill has grni_links (explicit targets).
        - Allocate landed cost across receipt items by receipt value (qty * unit_cost).
        - Update inbound inventory_layers.unit_cost for remaining qty.
        - If layer already consumed (qty_out > 0), move consumed portion to COGS (Dr COGS, Cr Inventory).
        - Idempotent: if inventory_landed_costs exists for (source='bill', source_id=bill_id) -> return.
        """

        if not bill or not isinstance(bill, dict):
            return

        schema = self.company_schema(company_id)

        # -------------------------
        # Idempotency gate
        # -------------------------
        cur.execute(
            f"""
            SELECT 1
            FROM {schema}.inventory_landed_costs
            WHERE company_id=%s AND source='bill' AND source_id=%s
            LIMIT 1;
            """,
            (int(company_id), int(bill_id)),
        )
        if cur.fetchone():
            return

        lines = bill.get("lines") or []
        grni_links = bill.get("grni_links") or []

        # No explicit targets => do NOT guess
        if not grni_links:
            return

        # -------------------------
        # Detect landed cost amount on bill
        # (works across industries: keywords fallback; you can enhance with cf_bucket later)
        # -------------------------
        def _text(*xs):
            return " ".join(str(x or "").strip().lower() for x in xs if x is not None)

        def _is_landed_cost_line(ln: dict) -> bool:
            t = _text(
                ln.get("description"),
                ln.get("name"),
                ln.get("memo"),
                ln.get("notes"),
                ln.get("account_name"),
                ln.get("account_code"),
            )
            # freight-in family (include carriage inwards ✅)
            return any(k in t for k in (
                "freight-in", "freight in",
                "carriage in", "carriage-in", "carriage inwards", "carriage inward",
                "inbound freight", "shipping in", "delivery in",
                "import duty", "customs", "clearing", "port charges",
                "handling", "landing", "landed cost",
            ))

        def _money(x):
            try:
                return float(x or 0.0)
            except Exception:
                return 0.0

        # bill line amount: prefer line_total else qty*unit_price
        def _line_amount(ln: dict) -> float:
            if ln.get("line_total") is not None:
                return _money(ln.get("line_total"))
            qty = _money(ln.get("quantity") or ln.get("qty") or 0.0)
            price = _money(ln.get("unit_price") or ln.get("price") or 0.0)
            return qty * price

        landed_total = 0.0
        for ln in lines:
            if _is_landed_cost_line(ln):
                amt = _line_amount(ln)
                if amt > 0:
                    landed_total += amt

        if landed_total <= 0:
            return

        # -------------------------
        # Create landed cost header
        # -------------------------
        tx_date = bill.get("bill_date") or bill.get("date") or bill.get("tx_date")
        if hasattr(tx_date, "isoformat"):
            tx_date = tx_date.isoformat()[:10]
        else:
            tx_date = str(tx_date)[:10]

        ref = (bill.get("bill_no") or bill.get("number") or f"BILL-{bill_id}").strip()
        notes = (bill.get("notes") or "").strip() or "Landed cost allocation"

        cur.execute(
            f"""
            INSERT INTO {schema}.inventory_landed_costs
            (company_id, tx_date, source, source_id, ref, notes)
            VALUES (%s,%s,'bill',%s,%s,%s)
            RETURNING id;
            """,
            (int(company_id), tx_date, int(bill_id), ref, notes),
        )
        r = cur.fetchone() or {}
        landed_cost_id = int(r.get("id") if isinstance(r, dict) else r[0])

        # -------------------------
        # Allocation targets: use grni_links amounts to split landed_total by receipt
        # -------------------------
        # If bill.grni_links.amount sums to 0, fall back to even split
        link_sum = sum(_money(x.get("amount")) for x in grni_links)
        if link_sum <= 0:
            weights = {int(x["receipt_tx_id"]): 1.0 for x in grni_links if x.get("receipt_tx_id")}
            wsum = sum(weights.values()) or 1.0
            receipt_share = {k: landed_total * (v / wsum) for k, v in weights.items()}
        else:
            receipt_share = {
                int(x["receipt_tx_id"]): landed_total * (_money(x.get("amount")) / link_sum)
                for x in grni_links
                if x.get("receipt_tx_id")
            }

        # -------------------------
        # For each receipt: allocate across receipt items by receipt value
        # -------------------------
        for receipt_tx_id, alloc_for_receipt in receipt_share.items():
            if alloc_for_receipt <= 0:
                continue

            # Pull receipt lines
            cur.execute(
                f"""
                SELECT item_id, COALESCE(qty,0)::numeric AS qty, COALESCE(unit_cost,0)::numeric AS unit_cost
                FROM {schema}.inventory_tx_lines
                WHERE company_id=%s AND tx_id=%s;
                """,
                (int(company_id), int(receipt_tx_id)),
            )
            rlines = cur.fetchall() or []
            if not rlines:
                continue

            # receipt total value
            def _f(v):
                try:
                    return float(v or 0.0)
                except Exception:
                    return 0.0

            rvals = []
            total_receipt_value = 0.0
            for rl in rlines:
                item_id = int(rl.get("item_id") if isinstance(rl, dict) else rl[0])
                qty = _f(rl.get("qty") if isinstance(rl, dict) else rl[1])
                unit_cost = _f(rl.get("unit_cost") if isinstance(rl, dict) else rl[2])
                value = max(qty, 0.0) * max(unit_cost, 0.0)
                if item_id and value > 0:
                    rvals.append((item_id, qty, unit_cost, value))
                    total_receipt_value += value

            if total_receipt_value <= 0:
                continue

            # Find inbound layers for this receipt
            # IMPORTANT: ensure your receipt posting uses source='inventory_tx' and source_id=receipt_tx_id when inserting layers.
            cur.execute(
                f"""
                SELECT id, item_id, COALESCE(qty_in,0)::numeric AS qty_in,
                    COALESCE(qty_out,0)::numeric AS qty_out,
                    COALESCE(unit_cost,0)::numeric AS unit_cost
                FROM {schema}.inventory_layers
                WHERE company_id=%s
                AND source IN ('inventory_tx','grv','receipt')
                AND source_id=%s
                ORDER BY id ASC;
                """,
                (int(company_id), int(receipt_tx_id)),
            )
            layers = cur.fetchall() or []
            layers_by_item: dict[int, list] = {}
            for ly in layers:
                ly_id = int(ly.get("id") if isinstance(ly, dict) else ly[0])
                item_id = int(ly.get("item_id") if isinstance(ly, dict) else ly[1])
                qty_in = _f(ly.get("qty_in") if isinstance(ly, dict) else ly[2])
                qty_out = _f(ly.get("qty_out") if isinstance(ly, dict) else ly[3])
                unit_cost = _f(ly.get("unit_cost") if isinstance(ly, dict) else ly[4])
                layers_by_item.setdefault(item_id, []).append((ly_id, qty_in, qty_out, unit_cost))

            # Allocate per item based on receipt line value
            for item_id, qty, unit_cost, value in rvals:
                item_share_amt = alloc_for_receipt * (value / total_receipt_value)
                if item_share_amt <= 0:
                    continue

                item_layers = layers_by_item.get(item_id) or []
                if not item_layers:
                    # No layer found => skip (don’t guess)
                    continue

                # If multiple layers exist for same item under this receipt, allocate by layer qty_in
                layer_qty_total = sum(max(x[1], 0.0) for x in item_layers) or 1.0

                for (layer_id, qty_in, qty_out, old_uc) in item_layers:
                    if qty_in <= 0:
                        continue

                    layer_amt = item_share_amt * (qty_in / layer_qty_total)
                    if layer_amt <= 0:
                        continue

                    # Write allocation line (idempotent via unique index)
                    cur.execute(
                        f"""
                        INSERT INTO {schema}.inventory_landed_cost_allocations
                        (company_id, landed_cost_id, receipt_tx_id, item_id, layer_id, amount)
                        VALUES (%s,%s,%s,%s,%s,%s)
                        ON CONFLICT DO NOTHING;
                        """,
                        (int(company_id), int(landed_cost_id), int(receipt_tx_id), int(item_id), int(layer_id), float(layer_amt)),
                    )

                    # Apply cost:
                    # - remaining qty increases inventory (unit_cost)
                    # - consumed portion goes to COGS adjustment (keeps inventory correct)
                    consumed = max(min(qty_out, qty_in), 0.0)
                    remaining = max(qty_in - consumed, 0.0)

                    alloc_consumed = layer_amt * (consumed / qty_in) if qty_in > 0 else 0.0
                    alloc_remaining = layer_amt - alloc_consumed

                    # Update layer unit_cost for remaining (if any)
                    if remaining > 0 and alloc_remaining > 0:
                        add_per_unit = alloc_remaining / remaining
                        new_uc = old_uc + add_per_unit
                        cur.execute(
                            f"""
                            UPDATE {schema}.inventory_layers
                            SET unit_cost=%s
                            WHERE company_id=%s AND id=%s;
                            """,
                            (float(new_uc), int(company_id), int(layer_id)),
                        )

                    # If already consumed, push consumed portion to COGS now
                    if alloc_consumed > 0:
                        # get item accounts
                        cur.execute(
                            f"""
                            SELECT inventory_account, cogs_account
                            FROM {schema}.inventory_items
                            WHERE company_id=%s AND id=%s
                            LIMIT 1;
                            """,
                            (int(company_id), int(item_id)),
                        )
                        it = cur.fetchone() or {}
                        inv_acct = (it.get("inventory_account") or "").strip()
                        cogs_acct = (it.get("cogs_account") or "").strip()
                        if inv_acct and cogs_acct:
                            inv_row = self.get_account_row_for_posting(company_id, inv_acct)
                            cogs_row = self.get_account_row_for_posting(company_id, cogs_acct)
                            inv_code = (inv_row[1] if inv_row else inv_acct) or inv_acct
                            cogs_code = (cogs_row[1] if cogs_row else cogs_acct) or cogs_acct

                            # Dr COGS, Cr Inventory
                            self.insert_ledger(
                                company_id=company_id,
                                journal_id=int(journal_id),
                                je_date=tx_date,
                                line={"account_code": cogs_code, "debit": float(alloc_consumed), "credit": 0.0, "memo": "Landed cost (consumed)"},
                                ref=ref,
                                source="bill",
                                source_id=int(bill_id),
                                cur=cur,
                            )
                            self.update_trial_balance(company_id, {"account_code": cogs_code, "debit": float(alloc_consumed), "credit": 0.0}, cur=cur)

                            self.insert_ledger(
                                company_id=company_id,
                                journal_id=int(journal_id),
                                je_date=tx_date,
                                line={"account_code": inv_code, "debit": 0.0, "credit": float(alloc_consumed), "memo": "Landed cost (consumed)"},
                                ref=ref,
                                source="bill",
                                source_id=int(bill_id),
                                cur=cur,
                            )
                            self.update_trial_balance(company_id, {"account_code": inv_code, "debit": 0.0, "credit": float(alloc_consumed)}, cur=cur)



    def list_loans(
        self,
        conn,
        company_id: int,
        *,
        status: str | None = None,
        q: str = "",
        limit: int = 200,
    ):
        schema = self.company_schema(company_id)
        with conn.cursor() as cur:
            sql = f"""
                SELECT
                    id,
                    loan_name,
                    loan_reference,
                    lender_name,
                    loan_type,
                    start_date,
                    first_payment_date,
                    maturity_date,
                    principal_amount,
                    annual_interest_rate,
                    payment_amount,
                    outstanding_principal,
                    outstanding_interest,
                    next_due_date,
                    status,
                    created_at,
                    updated_at
                FROM {schema}.loans
                WHERE company_id = %s
            """
            params = [company_id]

            if status:
                sql += " AND status = %s"
                params.append(status)

            if q:
                sql += """
                    AND (
                        loan_name ILIKE %s
                        OR COALESCE(loan_reference,'') ILIKE %s
                        OR lender_name ILIKE %s
                    )
                """
                like = f"%{q}%"
                params.extend([like, like, like])

            sql += " ORDER BY created_at DESC, id DESC LIMIT %s"
            params.append(limit)

            cur.execute(sql, tuple(params))
            rows = cur.fetchall() or []

            cols = [desc[0] for desc in cur.description]
            return [dict(zip(cols, row)) if not isinstance(row, dict) else row for row in rows]
        
    def get_loan_by_id(self, conn, company_id: int, loan_id: int):
        schema = self.company_schema(company_id)
        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT *
                FROM {schema}.loans
                WHERE company_id = %s AND id = %s
                LIMIT 1
            """, (company_id, loan_id))
            row = cur.fetchone()
            return dict(row) if row else None

    def get_loan_full(self, conn, company_id: int, loan_id: int):
        schema = self.company_schema(company_id)

        def _row_to_dict(cur, row):
            if row is None:
                return None
            if isinstance(row, dict):
                return row
            cols = [desc[0] for desc in cur.description]
            return dict(zip(cols, row))

        def _rows_to_dicts(cur, rows):
            if not rows:
                return []
            if isinstance(rows[0], dict):
                return rows
            cols = [desc[0] for desc in cur.description]
            return [dict(zip(cols, row)) for row in rows]

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT *
                FROM {schema}.loans
                WHERE company_id=%s AND id=%s
                LIMIT 1
            """, (company_id, loan_id))
            loan = _row_to_dict(cur, cur.fetchone())
            if not loan:
                return None

            cur.execute(f"""
                SELECT *
                FROM {schema}.loan_schedules
                WHERE company_id=%s AND loan_id=%s
                ORDER BY schedule_version DESC, period_no ASC
            """, (company_id, loan_id))
            schedule = _rows_to_dicts(cur, cur.fetchall() or [])

            cur.execute(f"""
                SELECT *
                FROM {schema}.loan_payments
                WHERE company_id=%s AND loan_id=%s
                ORDER BY payment_date DESC, id DESC
            """, (company_id, loan_id))
            payments = _rows_to_dicts(cur, cur.fetchall() or [])

            cur.execute(f"""
                SELECT
                    j.id,
                    j.date,
                    j.ref,
                    j.description,
                    j.gross_amount,
                    j.net_amount,
                    j.vat_amount,
                    j.source,
                    j.source_id,
                    j.created_at
                FROM {schema}.journal j
                WHERE j.company_id=%s
                AND (
                        (j.source = 'loan_origination' AND j.source_id = %s)
                    OR (j.source = 'loan_reclassification' AND j.source_id = %s)
                    OR (j.source = 'loan_payment' AND j.source_id IN (
                            SELECT id
                            FROM {schema}.loan_payments
                            WHERE company_id=%s AND loan_id=%s
                        ))
                )
                ORDER BY j.date DESC, j.id DESC
            """, (company_id, loan_id, loan_id, company_id, loan_id))
            journals = _rows_to_dicts(cur, cur.fetchall() or [])

            return {
                "loan": loan,
                "schedule": schedule,
                "payments": payments,
                "journals": journals,
            }
    
    def _period_delta_for_frequency(self, frequency: str):
        f = (frequency or "monthly").strip().lower()
        if f == "weekly":
            return relativedelta(weeks=1), Decimal("52")
        if f == "quarterly":
            return relativedelta(months=3), Decimal("4")
        if f == "annually":
            return relativedelta(years=1), Decimal("1")
        return relativedelta(months=1), Decimal("12")

    def _compute_level_payment(
        self,
        principal: Decimal,
        annual_rate: Decimal,
        periods: int,
        payments_per_year: Decimal,
        balloon: Decimal = Decimal("0.00"),
    ) -> Decimal:
        if periods <= 0:
            return Decimal("0.00")

        r = (annual_rate / Decimal("100")) / payments_per_year
        if r == 0:
            return _money((principal - balloon) / Decimal(periods))

        pv_balloon = balloon / ((Decimal("1") + r) ** periods)
        base = principal - pv_balloon
        pmt = base * (r / (Decimal("1") - ((Decimal("1") + r) ** Decimal(-periods))))
        return _money(pmt)

    def _build_loan_amortisation_rows(self, loan_row: dict) -> list[dict]:
        principal = _money(loan_row.get("principal_amount"))
        annual_rate = Decimal(str(loan_row.get("annual_interest_rate") or 0))
        periods = int(loan_row.get("term_count") or 0)
        method = (loan_row.get("interest_method") or "amortised_fixed_payment").strip().lower()
        first_payment_date = _safe_date(loan_row.get("first_payment_date"))
        balloon = _money(loan_row.get("balloon_amount"))
        holiday_count = int(loan_row.get("repayment_holiday_count") or 0)

        delta, per_year = self._period_delta_for_frequency(loan_row.get("payment_frequency"))
        rows: list[dict] = []
        opening = principal

        if method == "amortised_fixed_payment":
            payment_amount = self._compute_level_payment(principal, annual_rate, periods, per_year, balloon)
        else:
            payment_amount = _money(loan_row.get("payment_amount"))

        due = first_payment_date
        periodic_rate = (annual_rate / Decimal("100")) / per_year if per_year else Decimal("0")

        for i in range(1, periods + 1):
            interest = _money(opening * periodic_rate)

            if i <= holiday_count:
                payment = Decimal("0.00")
                principal_component = Decimal("0.00")
                closing = _money(opening + interest) if method != "manual" else opening
                status = "skipped"
            else:
                if method == "interest_only":
                    principal_component = Decimal("0.00")
                    if i == periods:
                        principal_component = _money(opening - balloon)
                    payment = _money(interest + principal_component)

                elif method == "straight_line_interest":
                    principal_component = _money((principal - balloon) / Decimal(periods))
                    if i == periods:
                        principal_component = _money(opening - balloon)
                    payment = _money(interest + principal_component)

                elif method == "manual":
                    payment = _money(loan_row.get("payment_amount"))
                    principal_component = _money(max(Decimal("0.00"), payment - interest))
                    if principal_component > opening:
                        principal_component = opening

                else:
                    payment = payment_amount
                    principal_component = _money(max(Decimal("0.00"), payment - interest))
                    if i == periods:
                        principal_component = _money(opening - balloon)
                        payment = _money(interest + principal_component)

                closing = _money(opening - principal_component)
                status = "open"

            rows.append({
                "period_no": i,
                "due_date": due,
                "opening_balance": opening,
                "scheduled_payment": _money(payment),
                "scheduled_interest": _money(interest),
                "scheduled_principal": _money(principal_component),
                "closing_balance": _money(closing),
                "current_portion_amount": Decimal("0.00"),      # fill later
                "noncurrent_portion_amount": Decimal("0.00"),   # fill later
                "payment_status": status,
            })

            opening = closing
            due = due + delta

        # classify principal due within next 12 months, frequency-aware
        periods_within_12_months = max(1, int(per_year)) if per_year else 12

        total_remaining_principal = principal
        for idx, row in enumerate(rows):
            current_due = _money(sum(
                _money(r.get("scheduled_principal"))
                for r in rows[idx: idx + periods_within_12_months]
            ))

            if current_due > total_remaining_principal:
                current_due = _money(total_remaining_principal)

            noncurrent_due = _money(total_remaining_principal - current_due)
            if noncurrent_due < 0:
                noncurrent_due = Decimal("0.00")

            row["current_portion_amount"] = _money(current_due)
            row["noncurrent_portion_amount"] = _money(noncurrent_due)

            total_remaining_principal = _money(row["closing_balance"])

        return rows

    def generate_loan_schedule(self, conn, company_id: int, *, loan_id: int, user_id=None):
        schema = self.company_schema(company_id)

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT *
                FROM {schema}.loans
                WHERE company_id=%s AND id=%s
                FOR UPDATE
            """, (company_id, loan_id))
            loan = cur.fetchone()
            if not loan:
                raise ValueError("loan not found")

            if not isinstance(loan, dict):
                cols = [desc[0] for desc in cur.description]
                loan = dict(zip(cols, loan))

            version = int(loan.get("schedule_version") or 1)

            rows = self._build_loan_amortisation_rows(loan)

            cur.execute(f"""
                DELETE FROM {schema}.loan_schedules
                WHERE company_id=%s AND loan_id=%s AND schedule_version=%s
            """, (company_id, loan_id, version))

            total_interest = Decimal("0.00")
            total_payment = Decimal("0.00")
            next_due = None

            for row in rows:
                total_interest += _money(row["scheduled_interest"])
                total_payment += _money(row["scheduled_payment"])
                if next_due is None and row["payment_status"] in {"open", "partial"}:
                    next_due = row["due_date"]

                cur.execute(f"""
                    INSERT INTO {schema}.loan_schedules (
                        company_id,
                        loan_id,
                        schedule_version,
                        period_no,
                        due_date,
                        opening_balance,
                        scheduled_payment,
                        scheduled_interest,
                        scheduled_principal,
                        closing_balance,
                        current_portion_amount,
                        noncurrent_portion_amount,
                        payment_status
                    )
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                """, (
                    company_id,
                    loan_id,
                    version,
                    row["period_no"],
                    row["due_date"],
                    row["opening_balance"],
                    row["scheduled_payment"],
                    row["scheduled_interest"],
                    row["scheduled_principal"],
                    row["closing_balance"],
                    row["current_portion_amount"],
                    row["noncurrent_portion_amount"],
                    row["payment_status"],
                ))

            first_payment_amount = rows[0]["scheduled_payment"] if rows else Decimal("0.00")

            cur.execute(f"""
                UPDATE {schema}.loans
                SET
                    payment_amount = %s,
                    total_interest_projected = %s,
                    total_repayment_projected = %s,
                    next_due_date = %s,
                    outstanding_principal = %s,
                    outstanding_interest = COALESCE(accrued_interest_opening, 0),
                    updated_at = NOW()
                WHERE company_id=%s AND id=%s
            """, (
                first_payment_amount,
                _money(total_interest),
                _money(total_payment),
                next_due,
                _money(loan.get("principal_amount")),
                company_id,
                loan_id,
            ))

        conn.commit()
        return self.get_loan_full(conn, company_id, loan_id)

    def create_loan(self, conn, company_id: int, *, data: dict, user_id=None):
        schema = self.company_schema(company_id)

        loan_name = (data.get("loan_name") or "").strip()
        lender_name = (data.get("lender_name") or "").strip()
        start_date = _safe_date(data.get("start_date"))
        first_payment_date = _safe_date(data.get("first_payment_date"))

        if not loan_name:
            raise ValueError("loan_name is required")
        if not lender_name:
            raise ValueError("lender_name is required")
        if not start_date:
            raise ValueError("start_date is required")
        if not first_payment_date:
            raise ValueError("first_payment_date is required")

        principal_amount = _money(data.get("principal_amount"))
        if principal_amount <= 0:
            raise ValueError("principal_amount must be > 0")

        with conn.cursor() as cur:
            cur.execute(f"""
                INSERT INTO {schema}.loans (
                    company_id,
                    loan_name,
                    loan_reference,
                    lender_name,
                    lender_id,
                    loan_type,
                    start_date,
                    first_payment_date,
                    maturity_date,
                    principal_amount,
                    annual_interest_rate,
                    interest_method,
                    term_count,
                    payment_frequency,
                    balloon_amount,
                    fees_amount,
                    accrued_interest_opening,
                    repayment_holiday_count,
                    variable_rate,
                    rate_review_rule,
                    bank_account_id,
                    interest_expense_account_code,
                    accrued_interest_account_code,
                    loan_payable_current_account_code,
                    loan_payable_noncurrent_account_code,
                    fees_asset_account_code,
                    fees_expense_account_code,
                    currency,
                    outstanding_principal,
                    outstanding_interest,
                    status,
                    notes,
                    agreement_reference,
                    meta_json,
                    created_by
                )
                VALUES (
                    %s,%s,%s,%s,%s,%s,%s,%s,%s,
                    %s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,
                    %s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,
                    %s,%s,%s
                )
                RETURNING id
            """, (
                company_id,
                loan_name,
                (data.get("loan_reference") or "").strip() or None,
                lender_name,
                data.get("lender_id"),
                (data.get("loan_type") or "term_loan").strip(),
                start_date,
                first_payment_date,
                _safe_date(data.get("maturity_date")),
                principal_amount,
                Decimal(str(data.get("annual_interest_rate") or 0)),
                (data.get("interest_method") or "amortised_fixed_payment").strip(),
                int(data.get("term_count") or 0),
                (data.get("payment_frequency") or "monthly").strip(),
                _money(data.get("balloon_amount")),
                _money(data.get("fees_amount")),
                _money(data.get("accrued_interest_opening")),
                int(data.get("repayment_holiday_count") or 0),
                bool(data.get("variable_rate") or False),
                (data.get("rate_review_rule") or "").strip() or None,
                data.get("bank_account_id"),
                (data.get("interest_expense_account_code") or "").strip(),
                (data.get("accrued_interest_account_code") or "").strip() or None,
                (data.get("loan_payable_current_account_code") or "").strip(),
                (data.get("loan_payable_noncurrent_account_code") or "").strip(),
                (data.get("fees_asset_account_code") or "").strip() or None,
                (data.get("fees_expense_account_code") or "").strip() or None,
                (data.get("currency") or "ZAR").strip(),
                principal_amount,
                _money(data.get("accrued_interest_opening")),
                "active" if bool(data.get("activate_on_create", True)) else "draft",
                (data.get("notes") or "").strip() or None,
                (data.get("agreement_reference") or "").strip() or None,
                Json(data.get("meta_json") or {}),
                user_id,
            ))
            row = cur.fetchone()
            loan_id = row["id"] if isinstance(row, dict) else row[0]

        conn.commit()

        out = self.generate_loan_schedule(conn, company_id, loan_id=loan_id, user_id=user_id)

        loan_full = self.get_loan_full(conn, company_id, loan_id)
        loan_row = (loan_full or {}).get("loan") or {}
        if not loan_row:
            raise ValueError("loan not found after create")

        entry = self.preview_loan_inception_journal(
            conn,
            company_id,
            data={
                "loan_name": loan_row.get("loan_name"),
                "loan_reference": loan_row.get("loan_reference"),
                "currency": loan_row.get("currency"),
                "principal_amount": loan_row.get("principal_amount"),
                "start_date": loan_row.get("start_date"),
                "first_payment_date": loan_row.get("first_payment_date"),
                "payment_frequency": loan_row.get("payment_frequency"),
                "interest_method": loan_row.get("interest_method"),
                "annual_interest_rate": loan_row.get("annual_interest_rate"),
                "term_count": loan_row.get("term_count"),
                "balloon_amount": loan_row.get("balloon_amount"),
                "fees_amount": loan_row.get("fees_amount"),
                "accrued_interest_opening": loan_row.get("accrued_interest_opening"),
                "bank_account_id": loan_row.get("bank_account_id"),
                "interest_expense_account_code": loan_row.get("interest_expense_account_code"),
                "accrued_interest_account_code": loan_row.get("accrued_interest_account_code"),
                "loan_payable_current_account_code": loan_row.get("loan_payable_current_account_code"),
                "loan_payable_noncurrent_account_code": loan_row.get("loan_payable_noncurrent_account_code"),
                "fees_asset_account_code": loan_row.get("fees_asset_account_code"),
                "fees_expense_account_code": loan_row.get("fees_expense_account_code"),
            },
        )

        entry["source"] = "loan_origination"
        entry["source_id"] = int(loan_id)
        entry["created_by_user_id"] = user_id
        entry["prepared_by_user_id"] = user_id

        journal_id = self.post_journal(company_id, entry)

        out["inception_journal_id"] = journal_id
        out["inception_journal"] = entry
        return out

    def backfill_loan_inception_journal(self, company_id: int, loan_id: int, *, user_id=None) -> int:
        with self._conn_cursor() as (conn, cur):
            loan_full = self.get_loan_full(conn, company_id, loan_id)
            if not loan_full or not loan_full.get("loan"):
                raise ValueError("loan not found")

            loan_row = loan_full["loan"]

            entry = self.build_saved_loan_inception_journal_entry(
                conn,
                company_id,
                loan_row=loan_row,
            )

            entry["source"] = "loan_origination"
            entry["source_id"] = int(loan_id)
            entry["created_by_user_id"] = user_id
            entry["prepared_by_user_id"] = user_id

            journal_id = self.post_journal(company_id, entry)
            return int(journal_id)
    
    def build_saved_loan_inception_journal_entry(self, conn, company_id: int, *, loan_row: dict) -> dict:
        built = self.build_loan_inception_journal_lines(
            conn,
            company_id,
            loan_row=loan_row,
            strict=True,
        )

        loan_id = loan_row.get("id")

        return {
            "date": str(loan_row["start_date"]),
            "ref": loan_row.get("loan_reference") or f"LOAN-OPEN-{loan_id}",
            "description": f"Initial recognition of loan - {loan_row['loan_name']}",
            "gross_amount": float(_money(loan_row.get("principal_amount"))),
            "net_amount": float(_money(loan_row.get("principal_amount"))),
            "vat_amount": 0.0,
            "currency": loan_row.get("currency") or "ZAR",
            "lines": built["journal_lines"],
            "resolved_accounts": built.get("resolved_accounts", {}),
            "dr_total": built.get("dr_total"),
            "cr_total": built.get("cr_total"),
        }

    def loan_origination_journal_exists(self, conn, company_id: int, loan_id: int) -> bool:
        schema = self.company_schema(company_id)
        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT 1
                FROM {schema}.journal
                WHERE company_id = %s
                AND source = 'loan_origination'
                AND source_id = %s
                LIMIT 1
            """, (company_id, loan_id))
            return cur.fetchone() is not None
        
    def update_loan(self, conn, company_id: int, loan_id: int, *, data: dict, user_id: int | None):
        schema = self.company_schema(company_id)

        loan_name = (data.get("loan_name") or "").strip()
        lender_name = (data.get("lender_name") or "").strip()
        start_date = _safe_date(data.get("start_date"))
        first_payment_date = _safe_date(data.get("first_payment_date"))

        if not loan_name:
            raise ValueError("loan_name is required")
        if not lender_name:
            raise ValueError("lender_name is required")
        if not start_date:
            raise ValueError("start_date is required")
        if not first_payment_date:
            raise ValueError("first_payment_date is required")

        principal_amount = _money(data.get("principal_amount"))
        if principal_amount <= 0:
            raise ValueError("principal_amount must be > 0")

        annual_interest_rate = Decimal(str(data.get("annual_interest_rate") or 0))
        term_count = int(data.get("term_count") or 0)
        if term_count <= 0:
            raise ValueError("term_count must be > 0")

        loan_type = (data.get("loan_type") or "term_loan").strip()
        if loan_type not in {"term_loan", "vehicle", "mortgage", "overdraft", "director_loan", "other"}:
            raise ValueError("invalid loan_type")

        interest_method = (data.get("interest_method") or "amortised_fixed_payment").strip()
        if interest_method not in {
            "amortised_fixed_payment",
            "straight_line_interest",
            "interest_only",
            "manual",
        }:
            raise ValueError("invalid interest_method")

        payment_frequency = (data.get("payment_frequency") or "monthly").strip()
        if payment_frequency not in {"weekly", "monthly", "quarterly", "annually"}:
            raise ValueError("invalid payment_frequency")

        status = (data.get("status") or "").strip().lower() or None
        if status and status not in {"draft", "active", "closed", "restructured", "void"}:
            raise ValueError("invalid status")

        balloon_amount = _money(data.get("balloon_amount"))
        fees_amount = _money(data.get("fees_amount"))
        accrued_interest_opening = _money(data.get("accrued_interest_opening"))
        repayment_holiday_count = int(data.get("repayment_holiday_count") or 0)

        if balloon_amount < 0:
            raise ValueError("balloon_amount cannot be negative")
        if fees_amount < 0:
            raise ValueError("fees_amount cannot be negative")
        if accrued_interest_opening < 0:
            raise ValueError("accrued_interest_opening cannot be negative")
        if repayment_holiday_count < 0:
            raise ValueError("repayment_holiday_count cannot be negative")

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT *
                FROM {schema}.loans
                WHERE company_id = %s
                AND id = %s
                FOR UPDATE
            """, (company_id, loan_id))
            existing = cur.fetchone()
            if not existing:
                raise ValueError("loan not found")

            if not isinstance(existing, dict):
                cols = [desc[0] for desc in cur.description]
                existing = dict(zip(cols, existing))

            outstanding_principal = _money(
                data["outstanding_principal"]
            ) if "outstanding_principal" in data else _money(
                existing.get("outstanding_principal", existing.get("principal_amount"))
            )

            outstanding_interest = _money(
                data["outstanding_interest"]
            ) if "outstanding_interest" in data else _money(
                existing.get("outstanding_interest", existing.get("accrued_interest_opening"))
            )

            final_status = status or (existing.get("status") or "draft")

            schedule_sensitive_fields = {
                "start_date",
                "first_payment_date",
                "principal_amount",
                "annual_interest_rate",
                "interest_method",
                "term_count",
                "payment_frequency",
                "balloon_amount",
                "repayment_holiday_count",
            }
            needs_schedule_refresh = any(k in data for k in schedule_sensitive_fields)
            schedule_version = int(existing.get("schedule_version") or 1)
            if needs_schedule_refresh:
                schedule_version += 1

            cur.execute(f"""
                UPDATE {schema}.loans
                SET
                    loan_name = %s,
                    loan_reference = %s,
                    lender_name = %s,
                    lender_id = %s,
                    loan_type = %s,
                    start_date = %s,
                    first_payment_date = %s,
                    maturity_date = %s,
                    principal_amount = %s,
                    annual_interest_rate = %s,
                    interest_method = %s,
                    term_count = %s,
                    payment_frequency = %s,
                    balloon_amount = %s,
                    fees_amount = %s,
                    accrued_interest_opening = %s,
                    repayment_holiday_count = %s,
                    variable_rate = %s,
                    rate_review_rule = %s,
                    bank_account_id = %s,
                    interest_expense_account_code = %s,
                    accrued_interest_account_code = %s,
                    loan_payable_current_account_code = %s,
                    loan_payable_noncurrent_account_code = %s,
                    fees_asset_account_code = %s,
                    fees_expense_account_code = %s,
                    currency = %s,
                    outstanding_principal = %s,
                    outstanding_interest = %s,
                    status = %s,
                    schedule_version = %s,
                    notes = %s,
                    agreement_reference = %s,
                    meta_json = %s,
                    closed_at = CASE
                        WHEN %s = 'closed' AND closed_at IS NULL THEN NOW()
                        WHEN %s <> 'closed' THEN NULL
                        ELSE closed_at
                    END,
                    updated_at = NOW()
                WHERE company_id = %s
                AND id = %s
            """, (
                loan_name,
                (data.get("loan_reference") or "").strip() or None,
                lender_name,
                data.get("lender_id"),
                loan_type,
                start_date,
                first_payment_date,
                _safe_date(data.get("maturity_date")),
                principal_amount,
                annual_interest_rate,
                interest_method,
                term_count,
                payment_frequency,
                balloon_amount,
                fees_amount,
                accrued_interest_opening,
                repayment_holiday_count,
                bool(data.get("variable_rate") or False),
                (data.get("rate_review_rule") or "").strip() or None,
                data.get("bank_account_id"),
                (data.get("interest_expense_account_code") or "").strip(),
                (data.get("accrued_interest_account_code") or "").strip() or None,
                (data.get("loan_payable_current_account_code") or "").strip(),
                (data.get("loan_payable_noncurrent_account_code") or "").strip(),
                (data.get("fees_asset_account_code") or "").strip() or None,
                (data.get("fees_expense_account_code") or "").strip() or None,
                (data.get("currency") or "ZAR").strip(),
                outstanding_principal,
                outstanding_interest,
                final_status,
                schedule_version,
                (data.get("notes") or "").strip() or None,
                (data.get("agreement_reference") or "").strip() or None,
                Json(data.get("meta_json")) if "meta_json" in data else Json(existing.get("meta_json") or {}),
                final_status,
                final_status,
                company_id,
                loan_id,
            ))

        conn.commit()
        return self.get_loan_full(conn, company_id, loan_id)

    def _allocate_loan_payment(self, cur, company_id: int, *, payment_id: int):
        schema = self.company_schema(company_id)

        cur.execute(f"""
            SELECT p.*, l.accrued_interest_opening, l.outstanding_interest
            FROM {schema}.loan_payments p
            JOIN {schema}.loans l
            ON l.company_id = p.company_id AND l.id = p.loan_id
            WHERE p.company_id=%s AND p.id=%s
            FOR UPDATE
        """, (company_id, payment_id))
        p = cur.fetchone()
        if not p:
            raise ValueError("payment not found")

        p = dict(p)
        loan_id = p["loan_id"]
        amount_left = _money(p["amount_paid"])

        cur.execute(f"""
            DELETE FROM {schema}.loan_payment_allocations
            WHERE company_id=%s AND payment_id=%s
        """, (company_id, payment_id))

        principal_total = Decimal("0.00")
        interest_total = Decimal("0.00")
        accrued_interest_total = Decimal("0.00")
        fees_total = Decimal("0.00")
        penalty_total = Decimal("0.00")
        ord_no = 1

        outstanding_interest = _money(p.get("outstanding_interest"))
        if outstanding_interest > 0 and amount_left > 0:
            alloc = min(amount_left, outstanding_interest)
            cur.execute(f"""
                INSERT INTO {schema}.loan_payment_allocations (
                    company_id, payment_id, loan_id, loan_schedule_id,
                    allocation_type, amount, allocation_order
                )
                VALUES (%s,%s,%s,%s,%s,%s,%s)
            """, (company_id, payment_id, loan_id, None, "accrued_interest", alloc, ord_no))
            accrued_interest_total += alloc
            amount_left -= alloc
            ord_no += 1

        cur.execute(f"""
            SELECT *
            FROM {schema}.loan_schedules
            WHERE company_id=%s
            AND loan_id=%s
            AND payment_status IN ('open','partial')
            ORDER BY due_date ASC, period_no ASC
            FOR UPDATE
        """, (company_id, loan_id))
        schedule_rows = [dict(x) for x in (cur.fetchall() or [])]

        for row in schedule_rows:
            if amount_left <= 0:
                break

            interest_due = _money(row["scheduled_interest"]) - _money(row["paid_interest"])
            if interest_due > 0 and amount_left > 0:
                alloc = min(amount_left, interest_due)
                cur.execute(f"""
                    INSERT INTO {schema}.loan_payment_allocations (
                        company_id, payment_id, loan_id, loan_schedule_id,
                        allocation_type, amount, allocation_order
                    )
                    VALUES (%s,%s,%s,%s,%s,%s,%s)
                """, (company_id, payment_id, loan_id, row["id"], "interest", alloc, ord_no))
                interest_total += alloc
                amount_left -= alloc
                ord_no += 1

            principal_due = _money(row["scheduled_principal"]) - _money(row["paid_principal"])
            if principal_due > 0 and amount_left > 0:
                alloc = min(amount_left, principal_due)
                cur.execute(f"""
                    INSERT INTO {schema}.loan_payment_allocations (
                        company_id, payment_id, loan_id, loan_schedule_id,
                        allocation_type, amount, allocation_order
                    )
                    VALUES (%s,%s,%s,%s,%s,%s,%s)
                """, (company_id, payment_id, loan_id, row["id"], "principal", alloc, ord_no))
                principal_total += alloc
                amount_left -= alloc
                ord_no += 1

        if amount_left > 0:
            cur.execute(f"""
                INSERT INTO {schema}.loan_payment_allocations (
                    company_id, payment_id, loan_id, loan_schedule_id,
                    allocation_type, amount, allocation_order
                )
                VALUES (%s,%s,%s,%s,%s,%s,%s)
            """, (company_id, payment_id, loan_id, None, "principal", amount_left, ord_no))
            principal_total += amount_left
            amount_left = Decimal("0.00")

        cur.execute(f"""
            UPDATE {schema}.loan_payments
            SET
                principal_amount=%s,
                interest_amount=%s,
                accrued_interest_amount=%s,
                fees_amount=%s,
                penalties_amount=%s,
                updated_at = NOW()
            WHERE company_id=%s AND id=%s
        """, (
            _money(principal_total),
            _money(interest_total),
            _money(accrued_interest_total),
            _money(fees_total),
            _money(penalty_total),
            company_id,
            payment_id,
        ))

        return {
            "principal_amount": _money(principal_total),
            "interest_amount": _money(interest_total),
            "accrued_interest_amount": _money(accrued_interest_total),
            "fees_amount": _money(fees_total),
            "penalties_amount": _money(penalty_total),
        }

    def create_loan_payment(self, conn, company_id: int, *, loan_id: int, data: dict, user_id=None):
        schema = self.company_schema(company_id)

        payment_date = _safe_date(data.get("payment_date"))
        if not payment_date:
            raise ValueError("payment_date is required")

        amount_paid = _money(data.get("amount_paid"))
        if amount_paid <= 0:
            raise ValueError("amount_paid must be > 0")

        bank_account_id = int(data.get("bank_account_id") or 0)
        if bank_account_id <= 0:
            raise ValueError("bank_account_id is required")

        with conn.cursor() as cur:
            cur.execute(f"""
                INSERT INTO {schema}.loan_payments (
                    company_id,
                    loan_id,
                    payment_date,
                    amount_paid,
                    bank_account_id,
                    reference,
                    description,
                    auto_calculate_split,
                    allocation_method,
                    status,
                    created_by,
                    notes,
                    meta_json
                )
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                RETURNING id
            """, (
                company_id,
                loan_id,
                payment_date,
                amount_paid,
                bank_account_id,
                (data.get("reference") or "").strip() or None,
                (data.get("description") or "").strip() or None,
                bool(data.get("auto_calculate_split", True)),
                "schedule_order" if bool(data.get("auto_calculate_split", True)) else "manual",
                "draft",
                user_id,
                (data.get("notes") or "").strip() or None,
                data.get("meta_json") or {},
            ))
            payment_id = cur.fetchone()["id"]

            if bool(data.get("auto_calculate_split", True)):
                self._allocate_loan_payment(cur, company_id, payment_id=payment_id)

        conn.commit()
        return self.get_loan_payment_full(conn, company_id, payment_id)

    def _append_journal_line(self, lines: list, *, account_code: str, description: str, debit=0, credit=0):
        dr = _money(debit or 0)
        cr = _money(credit or 0)
        if dr == 0 and cr == 0:
            return

        code = (account_code or "").strip()
        if not code:
            raise ValueError(f"Missing account code for journal line: {description}")

        lines.append({
            "account_code": code,
            "description": description,
            "debit": float(dr),
            "credit": float(cr),
        })


    def _finalise_journal_lines(self, lines: list, *, strict: bool = True):
        dr = _money(sum(Decimal(str(x.get("debit") or 0)) for x in lines))
        cr = _money(sum(Decimal(str(x.get("credit") or 0)) for x in lines))

        if dr != cr:
            msg = f"Journal out of balance: debit={dr} credit={cr}"
            if strict:
                raise ValueError(msg)
            return {
                "journal_lines": lines,
                "dr_total": float(dr),
                "cr_total": float(cr),
                "error": msg,
            }

        return {
            "journal_lines": lines,
            "dr_total": float(dr),
            "cr_total": float(cr),
        }

    def _get_coa_role_account(self, cur, schema: str, role: str):
        cur.execute(f"""
            SELECT code, name, role
            FROM {schema}.coa
            WHERE posting = TRUE
            AND role = %s
            ORDER BY id
            LIMIT 1
        """, (role,))
        row = cur.fetchone()
        if not row:
            return None

        if isinstance(row, dict):
            return row

        cols = [desc[0] for desc in cur.description]
        return dict(zip(cols, row))

    def resolve_loan_gl_accounts(
        self,
        conn,
        company_id: int,
        *,
        loan_row: dict,
        bank_account_id: int | None = None,
    ):
        schema = self.company_schema(company_id)

        with conn.cursor() as cur:
            resolved = {}
            missing_roles = []

            bank_row = self.get_company_bank_account(company_id, bank_account_id) if bank_account_id else None
            bank_code = ((bank_row or {}).get("ledger_account_code") or "").strip()
            resolved["bank_account_code"] = bank_code
            if not bank_code:
                missing_roles.append("bank_account_code")

            role_map = {
                "interest_expense_account_code": "loan_interest_expense",
                "accrued_interest_account_code": "loan_accrued_interest",
                "loan_payable_current_account_code": "loan_payable_current",
                "loan_payable_noncurrent_account_code": "loan_payable_noncurrent",
            }

            for field_name, role in role_map.items():
                coa = self._get_coa_role_account(cur, schema, role)
                code = ((coa or {}).get("code") or "").strip()
                resolved[field_name] = code
                if not code:
                    missing_roles.append(role)

        if missing_roles:
            raise ValueError("Missing required loan posting accounts: " + ", ".join(missing_roles))

        return resolved

    def build_loan_payment_journal_lines(
        self,
        conn,
        company_id: int,
        *,
        loan_row: dict,
        payment_row: dict,
        breakdown: dict,
        strict: bool = False,
    ):
        accounts = self.resolve_loan_gl_accounts(
            conn,
            company_id,
            loan_row=loan_row,
            bank_account_id=payment_row.get("bank_account_id") or loan_row.get("bank_account_id"),
        )

        lines = []
        loan_name = loan_row.get("loan_name") or f"Loan {loan_row.get('id')}"
        base_desc = f"Loan payment - {loan_name}"

        principal = _money(breakdown.get("principal_amount"))
        interest = _money(breakdown.get("interest_amount"))
        accrued_interest = _money(breakdown.get("accrued_interest_amount"))
        fees = _money(breakdown.get("fees_amount"))
        penalties = _money(breakdown.get("penalties_amount"))
        total = _money(breakdown.get("total_amount") or payment_row.get("amount_paid"))

        if principal > 0:
            self._append_journal_line(
                lines,
                account_code=accounts.get("loan_payable_current_account_code"),
                description=f"{base_desc} - principal",
                debit=principal,
                credit=0,
            )

        if interest > 0:
            self._append_journal_line(
                lines,
                account_code=accounts.get("interest_expense_account_code"),
                description=f"{base_desc} - interest",
                debit=interest,
                credit=0,
            )

        if accrued_interest > 0:
            self._append_journal_line(
                lines,
                account_code=accounts.get("accrued_interest_account_code"),
                description=f"{base_desc} - accrued interest settlement",
                debit=accrued_interest,
                credit=0,
            )

        if fees > 0:
            raise ValueError("fees posting not yet enabled in MVP")

        if penalties > 0:
            raise ValueError("penalties posting not yet enabled in MVP")

        self._append_journal_line(
            lines,
            account_code=accounts.get("bank_account_code"),
            description=f"{base_desc} - cash out",
            debit=0,
            credit=total,
        )

        out = self._finalise_journal_lines(lines, strict=strict)
        out["resolved_accounts"] = accounts
        return out

    def _loan_liability_split_current_noncurrent(self, conn, company_id: int, *, loan_id: int):
        schema = self.company_schema(company_id)

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT
                    current_portion_amount,
                    noncurrent_portion_amount
                FROM {schema}.loan_schedules
                WHERE company_id = %s
                AND loan_id = %s
                ORDER BY schedule_version DESC, period_no ASC
                LIMIT 1
            """, (company_id, loan_id))
            row = cur.fetchone()

            if not row:
                return Decimal("0.00"), Decimal("0.00")

            if not isinstance(row, dict):
                cols = [desc[0] for desc in cur.description]
                row = dict(zip(cols, row))

        cur_amt = _money(row.get("current_portion_amount"))
        ncur_amt = _money(row.get("noncurrent_portion_amount"))
        return cur_amt, ncur_amt


    def build_loan_inception_journal_lines(
        self,
        conn,
        company_id: int,
        *,
        loan_row: dict,
        strict: bool = False,
    ):
        loan_id = loan_row.get("id")
        principal = _money(loan_row.get("principal_amount"))
        if principal <= 0:
            raise ValueError("Loan principal_amount must be greater than zero")

        accounts = self.resolve_loan_gl_accounts(
            conn,
            company_id,
            loan_row=loan_row,
            bank_account_id=loan_row.get("bank_account_id"),
        )

        if loan_id:
            # saved-loan path
            cur_amt, ncur_amt = self._loan_liability_split_current_noncurrent(
                conn,
                company_id,
                loan_id=loan_id,
            )
        else:
            # preview path: use OPENING split only, not totals across all rows
            amort_rows = self._build_loan_amortisation_rows(loan_row)

            if amort_rows:
                cur_amt = _money(amort_rows[0].get("current_portion_amount"))
                ncur_amt = _money(amort_rows[0].get("noncurrent_portion_amount"))
            else:
                cur_amt = principal
                ncur_amt = Decimal("0.00")

        split_total = _money(cur_amt + ncur_amt)

        # hard safety: opening liability must equal principal
        if split_total <= 0:
            cur_amt = principal
            ncur_amt = Decimal("0.00")
        elif split_total != principal:
            diff = _money(principal - split_total)
            ncur_amt = _money(ncur_amt + diff)

        loan_name = loan_row.get("loan_name") or f"Loan {loan_id or 'Preview'}"
        desc = f"Initial recognition of loan - {loan_name}"

        lines = []

        self._append_journal_line(
            lines,
            account_code=accounts.get("bank_account_code"),
            description=desc,
            debit=principal,
            credit=0,
        )

        if cur_amt > 0:
            self._append_journal_line(
                lines,
                account_code=accounts.get("loan_payable_current_account_code"),
                description=desc + " - current portion",
                debit=0,
                credit=cur_amt,
            )

        if ncur_amt > 0:
            self._append_journal_line(
                lines,
                account_code=accounts.get("loan_payable_noncurrent_account_code"),
                description=desc + " - non-current portion",
                debit=0,
                credit=ncur_amt,
            )

        out = self._finalise_journal_lines(lines, strict=strict)
        out["resolved_accounts"] = accounts
        return out

    def preview_loan_inception_journal(self, conn, company_id: int, *, data: dict):
        loan_name = (data.get("loan_name") or "").strip()
        start_date = _safe_date(data.get("start_date"))
        first_payment_date = _safe_date(data.get("first_payment_date"))
        principal_amount = _money(data.get("principal_amount"))

        if not loan_name:
            raise ValueError("loan_name is required")
        if not start_date:
            raise ValueError("start_date is required")
        if not first_payment_date:
            raise ValueError("first_payment_date is required")
        if principal_amount <= 0:
            raise ValueError("principal_amount must be > 0")

        loan_row = {
            "id": None,
            "company_id": int(company_id),
            "loan_name": loan_name,
            "loan_reference": (data.get("loan_reference") or "").strip() or None,
            "currency": (data.get("currency") or "ZAR").strip() or "ZAR",
            "principal_amount": principal_amount,
            "start_date": start_date,
            "first_payment_date": first_payment_date,
            "payment_frequency": (data.get("payment_frequency") or "monthly").strip(),
            "interest_method": (data.get("interest_method") or "amortised_fixed_payment").strip(),
            "annual_interest_rate": Decimal(str(data.get("annual_interest_rate") or 0)),
            "term_count": int(data.get("term_count") or 0),
            "balloon_amount": _money(data.get("balloon_amount")),
            "fees_amount": _money(data.get("fees_amount")),
            "accrued_interest_opening": _money(data.get("accrued_interest_opening")),
            "bank_account_id": data.get("bank_account_id"),
            "interest_expense_account_code": (data.get("interest_expense_account_code") or "").strip() or None,
            "accrued_interest_account_code": (data.get("accrued_interest_account_code") or "").strip() or None,
            "loan_payable_current_account_code": (data.get("loan_payable_current_account_code") or "").strip() or None,
            "loan_payable_noncurrent_account_code": (data.get("loan_payable_noncurrent_account_code") or "").strip() or None,
            "fees_asset_account_code": (data.get("fees_asset_account_code") or "").strip() or None,
            "fees_expense_account_code": (data.get("fees_expense_account_code") or "").strip() or None,
        }

        built = self.build_loan_inception_journal_lines(
            conn,
            company_id,
            loan_row=loan_row,
            strict=True,
        )

        return {
            "date": str(loan_row["start_date"]),
            "ref": loan_row.get("loan_reference") or "LOAN-OPEN-PREVIEW",
            "description": f"Initial recognition of loan - {loan_row['loan_name']}",
            "gross_amount": float(_money(loan_row.get("principal_amount"))),
            "net_amount": float(_money(loan_row.get("principal_amount"))),
            "vat_amount": 0.0,
            "currency": loan_row.get("currency") or "ZAR",
            "source": "loan_inception_preview",
            "source_id": None,
            "lines": built["journal_lines"],
            "resolved_accounts": built.get("resolved_accounts", {}),
            "dr_total": built.get("dr_total"),
            "cr_total": built.get("cr_total"),
        }

    def preview_loan_payment_journal(self, conn, company_id: int, *, data: dict):
        loan_id = data.get("loan_id")
        if not loan_id:
            raise ValueError("loan_id is required")

        loan_full = self.get_loan_full(conn, company_id, int(loan_id))
        if not loan_full or not loan_full.get("loan"):
            raise ValueError("loan not found")

        loan_row = loan_full["loan"]

        payment_date = _safe_date(data.get("payment_date"))
        if not payment_date:
            raise ValueError("payment_date is required")

        amount_paid = _money(data.get("amount_paid"))
        if amount_paid <= 0:
            raise ValueError("amount_paid must be > 0")

        payment_row = {
            "id": None,
            "company_id": int(company_id),
            "loan_id": int(loan_id),
            "payment_date": payment_date,
            "amount_paid": amount_paid,
            "bank_account_id": data.get("bank_account_id") or loan_row.get("bank_account_id"),
            "reference": (data.get("reference") or "").strip() or None,
            "description": (data.get("description") or "").strip() or None,
            "auto_calculate_split": bool(data.get("auto_calculate_split", True)),
            "principal_amount": _money(data.get("principal_amount")),
            "interest_amount": _money(data.get("interest_amount")),
            "accrued_interest_amount": _money(data.get("accrued_interest_amount")),
            "fees_amount": _money(data.get("fees_amount")),
            "penalties_amount": _money(data.get("penalties_amount")),
            "allocation_method": (data.get("allocation_method") or "").strip() or None,
            "status": "preview",
            "notes": (data.get("notes") or "").strip() or None,
        }

        bank_account_id = payment_row.get("bank_account_id")
        bank_row = self.get_company_bank_account(company_id, bank_account_id)
        if not bank_row:
            raise ValueError("bank account not found")

        bank_account_code = (bank_row.get("ledger_account_code") or "").strip()
        if not bank_account_code:
            raise ValueError("bank account missing ledger_account_code")

        breakdown = self.calculate_loan_payment_breakdown(
            conn,
            company_id,
            loan_row=loan_row,
            payment_row=payment_row,
            strict=True,
        )

        built = self.build_loan_payment_journal_lines(
            conn,
            company_id,
            loan_row=loan_row,
            payment_row=payment_row,
            breakdown=breakdown,
            strict=True,
        )

        total = _money(breakdown.get("total_amount") or payment_row.get("amount_paid") or 0)

        return {
            "date": str(payment_row["payment_date"]),
            "ref": payment_row.get("reference") or "LOAN-PAY-PREVIEW",
            "description": f"Loan payment - {loan_row['loan_name']}",
            "gross_amount": float(total),
            "net_amount": float(total),
            "vat_amount": 0.0,
            "currency": (loan_row.get("currency") or bank_row.get("currency") or "ZAR"),
            "source": "loan_payment_preview",
            "source_id": None,
            "lines": built["journal_lines"],
            "resolved_accounts": built.get("resolved_accounts", {}),
            "calculation": breakdown,
            "dr_total": built.get("dr_total"),
            "cr_total": built.get("cr_total"),
        }

    def post_loan_payment(self, conn, company_id: int, *, payment_id: int, user_id=None):
        schema = self.company_schema(company_id)

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT *
                FROM {schema}.loan_payments
                WHERE company_id = %s
                AND id = %s
                FOR UPDATE
            """, (company_id, payment_id))
            payment = cur.fetchone()
            if not payment:
                raise ValueError("payment not found")

            payment = dict(payment)

            if payment["status"] == "posted" and payment.get("posted_journal_id"):
                return {
                    "payment_id": payment_id,
                    "posted_journal_id": payment["posted_journal_id"],
                    "status": "posted",
                }

            if payment["status"] not in {"draft", "approved"}:
                raise ValueError(f"cannot post payment in status '{payment['status']}'")

            # ensure allocation is rebuilt inside same txn
            self._allocate_loan_payment(cur, company_id, payment_id=payment_id)

        preview_entry = self.preview_loan_payment_journal(conn, company_id, payment_id=payment_id)

        with conn.cursor() as cur:
            journal_id = self.post_journal(company_id, preview_entry, cur=cur)

            cur.execute(f"""
                UPDATE {schema}.loan_payments
                SET
                    status = 'posted',
                    posted_journal_id = %s,
                    posted_at = NOW()
                WHERE company_id = %s
                AND id = %s
            """, (journal_id, company_id, payment_id))

            cur.execute(f"""
                SELECT *
                FROM {schema}.loan_payment_allocations
                WHERE company_id = %s
                AND payment_id = %s
                ORDER BY allocation_order ASC, id ASC
            """, (company_id, payment_id))
            allocs = [dict(x) for x in (cur.fetchall() or [])]

            for a in allocs:
                sched_id = a.get("loan_schedule_id")
                if not sched_id:
                    continue

                if a["allocation_type"] == "interest":
                    cur.execute(f"""
                        UPDATE {schema}.loan_schedules
                        SET
                            paid_interest = COALESCE(paid_interest, 0) + %s,
                            paid_amount = COALESCE(paid_amount, 0) + %s,
                            last_payment_date = (
                                SELECT payment_date
                                FROM {schema}.loan_payments
                                WHERE company_id = %s
                                AND id = %s
                            )
                        WHERE company_id = %s
                        AND id = %s
                    """, (a["amount"], a["amount"], company_id, payment_id, company_id, sched_id))

                elif a["allocation_type"] == "principal":
                    cur.execute(f"""
                        UPDATE {schema}.loan_schedules
                        SET
                            paid_principal = COALESCE(paid_principal, 0) + %s,
                            paid_amount = COALESCE(paid_amount, 0) + %s,
                            last_payment_date = (
                                SELECT payment_date
                                FROM {schema}.loan_payments
                                WHERE company_id = %s
                                AND id = %s
                            )
                        WHERE company_id = %s
                        AND id = %s
                    """, (a["amount"], a["amount"], company_id, payment_id, company_id, sched_id))

            cur.execute(f"""
                UPDATE {schema}.loan_schedules
                SET payment_status = CASE
                    WHEN COALESCE(paid_principal,0) >= COALESCE(scheduled_principal,0)
                    AND COALESCE(paid_interest,0) >= COALESCE(scheduled_interest,0)
                        THEN 'paid'
                    WHEN COALESCE(paid_amount,0) > 0
                        THEN 'partial'
                    ELSE payment_status
                END
                WHERE company_id = %s
                AND loan_id = (
                    SELECT loan_id
                    FROM {schema}.loan_payments
                    WHERE company_id = %s
                        AND id = %s
                )
            """, (company_id, company_id, payment_id))

            cur.execute(f"""
                UPDATE {schema}.loans l
                SET
                    outstanding_principal = GREATEST(
                        0,
                        COALESCE(l.outstanding_principal,0) - COALESCE(p.principal_amount,0)
                    ),
                    outstanding_interest = GREATEST(
                        0,
                        COALESCE(l.outstanding_interest,0) - COALESCE(p.accrued_interest_amount,0)
                    ),
                    last_payment_date = p.payment_date,
                    next_due_date = (
                        SELECT MIN(s.due_date)
                        FROM {schema}.loan_schedules s
                        WHERE s.company_id = l.company_id
                        AND s.loan_id = l.id
                        AND s.payment_status IN ('open','partial')
                    ),
                    updated_at = NOW()
                FROM {schema}.loan_payments p
                WHERE p.company_id = l.company_id
                AND p.id = %s
                AND l.company_id = %s
                AND l.id = p.loan_id
            """, (payment_id, company_id))

        conn.commit()
        return {
            "payment_id": payment_id,
            "posted_journal_id": journal_id,
            "status": "posted",
        }

    def calculate_loan_payment_breakdown(
        self,
        conn,
        company_id: int,
        *,
        loan_row: dict,
        payment_row: dict,
        strict: bool = False,
    ) -> dict:

        method_raw = (loan_row.get("interest_method") or "manual")
        method = str(method_raw).strip().lower()

        # normalize common storage/display variants
        method_key = (
            method
            .replace("-", "_")
            .replace(" ", "_")
        )

        aliases = {
            "amortised_fixed_payment": "amortised_fixed_payment",
            "amortized_fixed_payment": "amortised_fixed_payment",
            "straight_line_interest": "straight_line_interest",
            "interest_only": "interest_only",
            "manual": "manual",
        }

        method_key = aliases.get(method_key, method_key)

        if not payment_row.get("auto_calculate_split", True):
            return self._calc_manual_payment_breakdown(payment_row)

        if method_key == "amortised_fixed_payment":
            return self._calc_amortised_from_schedule(conn, company_id, loan_row, payment_row)

        if method_key == "straight_line_interest":
            return self._calc_straight_line(conn, company_id, loan_row, payment_row)

        if method_key == "interest_only":
            return self._calc_interest_only(conn, company_id, loan_row, payment_row)

        if method_key == "manual":
            return self._calc_manual_payment_breakdown(payment_row)

        raise ValueError(f"Unsupported interest method: {method_raw}")

    def _calc_amortised_from_schedule(self, conn, company_id, loan_row, payment_row):
        schema = self.company_schema(company_id)

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT *
                FROM {schema}.loan_schedules
                WHERE company_id = %s
                AND loan_id = %s
                AND payment_status IN ('open','partial')
                ORDER BY due_date
                LIMIT 1
            """, (company_id, loan_row["id"]))

            sched = cur.fetchone()

        if not sched:
            raise ValueError("No open schedule found for amortised loan")

        sched = dict(sched)

        remaining_interest = _money(sched["scheduled_interest"] - sched["paid_interest"])
        remaining_principal = _money(sched["scheduled_principal"] - sched["paid_principal"])

        total_due = _money(remaining_interest + remaining_principal)
        payment = _money(payment_row["amount_paid"])

        if payment > total_due:
            # extra payment → reduce principal
            extra = payment - total_due
            principal = remaining_principal + extra
            interest = remaining_interest
        else:
            # proportional split
            ratio = payment / total_due if total_due > 0 else Decimal("0")
            interest = _money(remaining_interest * ratio)
            principal = _money(payment - interest)

        return {
            "principal_amount": float(principal),
            "interest_amount": float(interest),
            "accrued_interest_amount": 0.0,
            "fees_amount": 0.0,
            "penalties_amount": 0.0,
            "total_amount": float(payment),
            "method_used": "amortised_schedule",
            "warnings": [],
        }

    def _calc_straight_line(self, conn, company_id, loan_row, payment_row):
        principal = _money(loan_row["principal_amount"])
        rate = _money(loan_row["annual_interest_rate"]) / Decimal("100")
        term = int(loan_row.get("term_count") or 1)

        total_interest = _money(principal * rate)
        per_period_interest = _money(total_interest / term)

        payment = _money(payment_row["amount_paid"])

        interest = min(per_period_interest, payment)
        principal_component = _money(payment - interest)

        return {
            "principal_amount": float(principal_component),
            "interest_amount": float(interest),
            "accrued_interest_amount": 0.0,
            "fees_amount": 0.0,
            "penalties_amount": 0.0,
            "total_amount": float(payment),
            "method_used": "straight_line",
            "warnings": [],
        }

    def _calc_interest_only(self, conn, company_id, loan_row, payment_row):
        principal_balance = _money(loan_row["principal_amount"])
        rate = _money(loan_row["annual_interest_rate"]) / Decimal("100")

        _, per_year = self._period_delta_for_frequency(
            loan_row.get("payment_frequency")
        )

        periodic_rate = rate / per_year if per_year else Decimal("0")

        interest = _money(principal_balance * periodic_rate)
        payment = _money(payment_row["amount_paid"])

        if payment <= interest:
            return {
                "principal_amount": 0.0,
                "interest_amount": float(payment),
                "accrued_interest_amount": float(interest - payment),
                "fees_amount": 0.0,
                "penalties_amount": 0.0,
                "total_amount": float(payment),
                "method_used": "interest_only_partial",
                "warnings": ["Payment less than interest → accrued interest created"],
            }

        principal_component = _money(payment - interest)

        return {
            "principal_amount": float(principal_component),
            "interest_amount": float(interest),
            "accrued_interest_amount": 0.0,
            "fees_amount": 0.0,
            "penalties_amount": 0.0,
            "total_amount": float(payment),
            "method_used": "interest_only",
            "warnings": [],
        }


    def compute_loan_current_noncurrent_split(self, conn, company_id: int, *, loan_id: int, as_of_date=None):
        schema = self.company_schema(company_id)
        as_of_date = _safe_date(as_of_date) or date.today()

        with conn.cursor() as cur:
            cur.execute(f"""
                SELECT
                    COALESCE(SUM(
                        CASE WHEN due_date <= %s + INTERVAL '12 months'
                            THEN GREATEST(0, scheduled_principal - paid_principal)
                            ELSE 0 END
                    ), 0) AS current_portion,
                    COALESCE(SUM(
                        CASE WHEN due_date > %s + INTERVAL '12 months'
                            THEN GREATEST(0, scheduled_principal - paid_principal)
                            ELSE 0 END
                    ), 0) AS noncurrent_portion
                FROM {schema}.loan_schedules
                WHERE company_id=%s AND loan_id=%s
            """, (as_of_date, as_of_date, company_id, loan_id))
            row = cur.fetchone() or {}
            return {
                "as_of_date": str(as_of_date),
                "current_portion": float(_money(row.get("current_portion"))),
                "noncurrent_portion": float(_money(row.get("noncurrent_portion"))),
            }

    def post_loan_reclassification(self, conn, company_id: int, *, loan_id: int, as_of_date=None, user_id=None):
        schema = self.company_schema(company_id)
        split = self.compute_loan_current_noncurrent_split(conn, company_id, loan_id=loan_id, as_of_date=as_of_date)

        loan = self.get_loan_by_id(conn, company_id, loan_id)
        if not loan:
            raise ValueError("loan not found")

        current_code = (loan.get("loan_payable_current_account_code") or "").strip()
        noncurrent_code = (loan.get("loan_payable_noncurrent_account_code") or "").strip()

        amt = _money(split["current_portion"])
        if amt <= 0:
            return {"ok": True, "message": "no current portion to reclassify", "amount": 0}

        header = {
            "date": split["as_of_date"],
            "ref": f"LOAN-RECLASS-{loan_id}",
            "description": f"Loan current/non-current reclassification - {loan['loan_name']}",
            "gross_amount": float(amt),
            "net_amount": float(amt),
            "vat_amount": 0.0,
            "source": "loan_reclassification",
            "source_id": loan_id,
        }
        lines = [
            {
                "account_code": noncurrent_code,
                "description": f"Reclass to current - {loan['loan_name']}",
                "debit": float(amt),
                "credit": 0.0,
            },
            {
                "account_code": current_code,
                "description": f"Reclass to current - {loan['loan_name']}",
                "debit": 0.0,
                "credit": float(amt),
            },
        ]

        with conn.cursor() as cur:
            jid = self._insert_journal_and_lines(cur, company_id, header=header, lines=lines)
            cur.execute(f"""
                UPDATE {schema}.loans
                SET last_reclass_journal_id=%s, updated_at=NOW()
                WHERE company_id=%s AND id=%s
            """, (jid, company_id, loan_id))

        conn.commit()
        return {"loan_id": loan_id, "posted_journal_id": jid, "split": split}


