    def delete_customer(self, company_id: int, customer_id: int, *, hard: bool = False) -> bool:
        """
        Delete (or archive) a customer safely.

        Default (hard=False): soft delete (archive) by setting is_active=false.
        Hard delete (hard=True): only deletes if the customer has NO invoices.

        Returns True if something was changed/deleted, False if customer not found.
        Raises ValueError for blocked hard delete.
        """
        schema = f"company_{int(company_id)}"
        cid = int(customer_id)

        # Ensure schema exists (safe no-op if it already does)
       # self.ensure_company_schema(int(company_id))

        # 1) Confirm customer exists
        exists = self.fetch_one(
            f"SELECT id, is_active FROM {schema}.customers WHERE id=%s LIMIT 1;",
            (cid,)
        )
        if not exists:
            return False

        # 2) If hard delete requested, block if invoices exist
        if hard:
            inv = self.fetch_one(
                f"SELECT 1 FROM {schema}.invoices WHERE customer_id=%s LIMIT 1;",
                (cid,)
            )
            if inv:
                raise ValueError("Cannot hard-delete customer: invoices exist. Archive instead (is_active=false).")

            # No invoices -> safe to hard delete
            self.execute_sql(
                f"DELETE FROM {schema}.customers WHERE id=%s;",
                (cid,)
            )
            return True

        # 3) Soft delete (archive)
        self.execute_sql(
            f"""
            UPDATE {schema}.customers
            SET is_active = FALSE,
                updated_at = NOW()
            WHERE id=%s;
            """,
            (cid,)
        )
        return True

