    def insert_vendor(self, company_id: int, data: Dict[str, Any]) -> int:
        schema = f"company_{company_id}"

        def pick(*keys, default=None):
            for k in keys:
                v = data.get(k)
                if v not in (None, ""):
                    return v
            return default

        sql = f"""
        INSERT INTO {schema}.vendors (
            company_id,
            external_code,
            name,
            email,
            phone,
            remit_address,
            country,
            tax_number,
            vat_number,
            registration_no,
            wht_percent,
            payment_terms,
            vendor_status,
            on_hold,
            notes,
            tags,
            contacts,
            is_active,
            approved_by_user_id,
            approved_at,

            bank_name,
            branch_code,
            account_name,
            account_number,
            account_type,
            bank_currency,
            swift_code,

            compliance_status,
            compliance_required,
            missing_docs,
            compliance_updated_at
        )
        VALUES (
            %s,%s,%s,%s,%s,%s,%s,%s,%s,%s,
            %s,%s,%s,%s,%s,%s,%s,%s,%s,%s,
            %s,%s,%s,%s,%s,%s,%s,
            %s,%s,%s,NOW()
        )
        RETURNING id;
        """

        # numbers
        wht_raw = pick("wht", "wht_percent", "whtPercent")
        wht_val = float(wht_raw) if wht_raw not in (None, "") else None

        # normalize text fields
        name = (pick("name") or "").strip()
        email = (pick("email") or "").strip() or None
        phone = (pick("phone") or "").strip() or None
        reg_no = (pick("regNo", "registration_no", "registrationNo") or "").strip() or None

        bank_name = (pick("bank_name", "bankName") or "").strip() or None
        branch_code = (pick("branch_code", "branchCode") or "").strip() or None
        account_name = (pick("account_name", "accountName") or "").strip() or None
        account_number = (pick("account_number", "accountNumber") or "").strip() or None
        account_type = (pick("account_type", "accountType") or "").strip() or None
        bank_currency = (pick("bank_currency", "bankCurrency") or "").strip() or None
        swift_code = (pick("swift_code", "swiftCode") or "").strip() or None

        compliance_status = (pick("compliance_status", default="draft") or "draft").strip().lower()
        compliance_required = bool(pick("compliance_required", default=False))
        missing_docs = data.get("missing_docs") or []

        params = (
            int(company_id),
            pick("external_code", "externalCode"),
            name,
            email,
            phone,
            pick("remitAddr", "remit_address", "remitAddress"),
            pick("country", default="ZA"),
            pick("taxNo", "tax_number", "taxNumber"),
            pick("vatNo", "vat_number", "vatNumber"),
            reg_no,
            wht_val,
            pick("terms", "payment_terms", "paymentTerms"),
            (pick("vendor_status", "vendorStatus", default="active") or "active"),
            pick("onHold", "on_hold", default="no"),
            pick("notes", default=""),
            pick("tags", default=""),
            psycopg2.extras.Json(data.get("contacts") or []),
            bool(data.get("is_active", True)),
            data.get("approved_by_user_id"),
            data.get("approved_at"),

            bank_name,
            branch_code,
            account_name,
            account_number,
            account_type,
            bank_currency,
            swift_code,

            compliance_status,
            compliance_required,
            psycopg2.extras.Json(missing_docs),
        )

        row = self.fetch_one(sql, params) or {}
        return int(row.get("id") or 0)


