    def upsert_vendor_document(
        self,
        company_id: int,
        vendor_id: int,
        *,
        doc_type: str,
        status: str = "uploaded",
        file_name: str | None = None,
        file_url: str | None = None,
        uploaded_by: int | None = None,
        reviewed_by: int | None = None,
        notes: str | None = None,
        cur=None,
    ):
        schema = self.company_schema(company_id)
        dt = (doc_type or "").strip().lower()
        st = (status or "uploaded").strip().lower()

        sql = f"""
        INSERT INTO {schema}.vendor_documents
        (company_id, vendor_id, doc_type, file_name, file_url, status, uploaded_by, uploaded_at, reviewed_by, reviewed_at, notes)
        VALUES
        (%s,%s,%s,%s,%s,%s,%s,NOW(),%s,CASE WHEN %s IS NULL THEN NULL ELSE NOW() END,%s)
        ON CONFLICT (company_id, vendor_id, doc_type)
        DO UPDATE SET
        file_name = COALESCE(EXCLUDED.file_name, {schema}.vendor_documents.file_name),
        file_url  = COALESCE(EXCLUDED.file_url,  {schema}.vendor_documents.file_url),
        status    = EXCLUDED.status,
        reviewed_by = COALESCE(EXCLUDED.reviewed_by, {schema}.vendor_documents.reviewed_by),
        reviewed_at = CASE WHEN EXCLUDED.reviewed_by IS NULL THEN {schema}.vendor_documents.reviewed_at ELSE NOW() END,
        notes = COALESCE(EXCLUDED.notes, {schema}.vendor_documents.notes)
        RETURNING id;
        """
        # ⚠️ To use ON CONFLICT you need a unique constraint:
        # UNIQUE(company_id, vendor_id, doc_type)
        return int(self.execute_sql(sql, (
            int(company_id), int(vendor_id), dt, file_name, file_url, st,
            int(uploaded_by) if uploaded_by else None,
            int(reviewed_by) if reviewed_by else None,
            int(reviewed_by) if reviewed_by else None,
            notes,
        ), cur=cur) or 0)


    def archive_duplicate_vendors(self, company_id: int) -> Dict[str, Any]:
        """
        Archives duplicates by (LOWER(name), LOWER(email)).
        Keeps the newest active record; archives older duplicates.
        """
        schema = f"company_{company_id}"

        find_sql = f"""
        SELECT
            LOWER(COALESCE(name,''))  AS k_name,
            LOWER(COALESCE(email,'')) AS k_email,
            ARRAY_AGG(id ORDER BY is_active DESC, updated_at DESC NULLS LAST, created_at DESC NULLS LAST, id DESC) AS ids
        FROM {schema}.vendors
        GROUP BY 1,2
        HAVING COUNT(*) > 1
        AND (LOWER(COALESCE(name,'')) <> '' OR LOWER(COALESCE(email,'')) <> '');
        """

        groups = self.fetch_all(find_sql) or []
        archived = []

        with self._conn_cursor() as (_c, cur):
            for g in groups:
                ids = g.get("ids") or []
                if len(ids) < 2:
                    continue
                keep_id = ids[0]
                drop_ids = ids[1:]

                cur.execute(
                    f"UPDATE {schema}.vendors SET is_active = FALSE, updated_at = NOW() WHERE id = ANY(%s);",
                    (drop_ids,),
                )
                archived.append({"keep": keep_id, "archived": drop_ids})

        return {"groups": len(groups), "actions": archived}

