    def delete_vendor(self, company_id: int, vendor_id: int, *, hard: bool = False) -> bool:
        """
        Default: soft delete (is_active=false).
        Hard delete only if no bills exist for vendor.
        """
        schema = f"company_{int(company_id)}"
        vid = int(vendor_id)

        exists = self.fetch_one(f"SELECT id, is_active FROM {schema}.vendors WHERE id=%s LIMIT 1;", (vid,))
        if not exists:
            return False

        if hard:
            b = self.fetch_one(f"SELECT 1 FROM {schema}.bills WHERE vendor_id=%s LIMIT 1;", (vid,))
            if b:
                raise ValueError("Cannot hard-delete vendor: bills exist. Archive instead (is_active=false).")
            self.execute_sql(f"DELETE FROM {schema}.vendors WHERE id=%s;", (vid,))
            return True

        self.execute_sql(
            f"UPDATE {schema}.vendors SET is_active=FALSE, updated_at=NOW() WHERE id=%s;",
            (vid,),
        )
        return True

