    def list_unbilled_receipts(self, company_id: int, *, vendor_id: int, q: str = "", limit: int = 50, offset: int = 0):
        schema = f"company_{int(company_id)}"
        where = ["company_id=%s", "lower(tx_type)=lower('receipt')", "vendor_id=%s"]
        params = [int(company_id), int(vendor_id)]

        # not fully billed
        where.append("coalesce(grni_status,'unbilled') <> 'billed'")

        q = (q or "").strip()
        if q:
            where.append("(lower(coalesce(ref,'')) LIKE lower(%s) OR lower(coalesce(notes,'')) LIKE lower(%s))")
            like = f"%{q}%"
            params += [like, like]

        sql = f"""
        SELECT id, tx_date, ref, notes, vendor_id, po_id, grni_status, posted_journal_id
        FROM {schema}.inventory_tx
        WHERE {" AND ".join(where)}
        ORDER BY tx_date DESC, id DESC
        LIMIT %s OFFSET %s
        """
        params += [int(limit), int(offset)]
        return self.fetch_all(sql, tuple(params)) or []

    def _insert_bill_with_lines_cur(self, company_id: int, header: dict, lines: list[dict], cur) -> int:
        """
        Insert or update bill + lines + GRN links.
        - header discount is an AMOUNT (discount_amount) preferred
        - discount_rate used only as fallback
        - other_amount added after discount allocation
        - VAT computed from discounted vatable base (other does NOT affect VAT)
        - store POSTING codes in bill_lines.account_code
        """

        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        def _to_float(x, default=0.0):
            try:
                if x is None:
                    return default
                if isinstance(x, str):
                    x = x.replace(",", "").strip()
                return float(x)
            except Exception:
                return default

        schema = self.company_schema(company_id)

        status = (header.get("status") or "draft").strip().lower()
        incoming_no = (header.get("number") or "").strip()

        # ✅ auto-assign vendor invoice number if missing
        if not incoming_no:
            header["number"] = self.next_bill_number_cur(company_id, cur)
        else:
            header["number"] = incoming_no

        if not header.get("vendor_id"):
            raise ValueError("vendor_id is required")
        if not header.get("bill_date"):
            raise ValueError("bill_date is required")
        if not isinstance(lines, list) or not lines:
            raise ValueError("At least one bill line is required")

        # ---- compute totals ----
        prepared = []
        subtotal_net = 0.0
        line_discount_total = 0.0
        vatable_net = 0.0
        vatable_by_rate: dict[float, float] = {}

        for idx, ln in enumerate(lines, start=1):
            qty = float(ln.get("quantity") or 0.0)
            price = float(ln.get("unit_price") or 0.0)
            disc_line = money(ln.get("discount_amount") or 0.0)
            vat_rate = float(ln.get("vat_rate") or 0.0)

            raw = (ln.get("account_code") or "").strip()
            if not raw:
                raise ValueError(f"Missing account_code on bill line {idx}")

            row = self.get_account_row_for_posting(company_id, raw)
            if not row:
                raise ValueError(f"Bill line account_code '{raw}' not found in COA (line {idx})")

            posting_code = (row[1] or "").strip()
            if not posting_code:
                raise ValueError(f"Resolved posting code blank for '{raw}' (line {idx})")

            net = max(0.0, (qty * price) - disc_line)
            net = money(net)

            subtotal_net = money(subtotal_net + net)
            line_discount_total = money(line_discount_total + disc_line)

            if vat_rate > 0:
                vatable_net = money(vatable_net + net)
                vatable_by_rate[vat_rate] = money(vatable_by_rate.get(vat_rate, 0.0) + net)

            prepared.append({
                "line_no": idx,
                "item_name": (ln.get("item_name") or ln.get("itemName") or "").strip() or None,
                "description": (ln.get("description") or "").strip(),
                "account_code": posting_code,
                "quantity": qty,
                "unit_price": price,
                "discount_amount": disc_line,
                "net_amount": net,
                "vat_rate": vat_rate,
                "vat_amount": 0.0,
                "total_amount": 0.0,
            })

        # ---- header discount ----
        header_disc_amt = money(header.get("discount_amount") or header.get("discount") or 0.0)
        disc_rate = float(header.get("discount_rate") or 0.0)
        if disc_rate > 1.0: disc_rate = disc_rate / 100.0
        if header_disc_amt <= 0 and disc_rate > 0:
            header_disc_amt = money(subtotal_net * disc_rate)
        header_disc_amt = max(0.0, min(header_disc_amt, subtotal_net))
        if subtotal_net > 0:
            disc_rate = max(disc_rate, min(1.0, float(header_disc_amt / subtotal_net)))
        else:
            disc_rate = 0.0

        # ---- other amount ----
        other_raw = header.get("other")
        if other_raw is None:
            other_raw = header.get("other_amount")
        other = money(_to_float(other_raw, 0.0))

        # ---- VAT after discount ----
        vat_total = 0.0
        for pl in prepared:
            rate = float(pl.get("vat_rate") or 0.0)
            net = money(pl.get("net_amount") or 0.0)
            vat = money(net * (rate / 100.0)) if rate > 0 else 0.0
            pl["vat_amount"] = vat
            pl["total_amount"] = money(net + vat)
            vat_total = money(vat_total + vat)

        net_after = money(max(0.0, subtotal_net - header_disc_amt + other))
        grand_total = money(net_after + vat_total)
        discount_total = money(line_discount_total + header_disc_amt)

        # ---- insert or update header ----
        bill_id = None
        if header.get("id"):  # UPDATE flow
            bill_id = int(header["id"])
            cur.execute(
                f"""
                UPDATE {schema}.bills
                SET vendor_id=%s, number=%s, bill_date=%s, due_date=%s, currency=%s,
                    subtotal_amount=%s, discount_amount=%s, discount_rate=%s,
                    vat_amount=%s, total_amount=%s, other_amount=%s,
                    status=%s, notes=%s, updated_at=NOW()
                WHERE company_id=%s AND id=%s
                """,
                (
                    int(header["vendor_id"]),
                    header.get("number"),
                    header["bill_date"],
                    header.get("due_date"),
                    header.get("currency"),
                    net_after,
                    discount_total,
                    disc_rate,
                    vat_total,
                    grand_total,
                    other,
                    header.get("status") or "draft",
                    header.get("notes"),
                    int(company_id),
                    bill_id,
                ),
            )
            cur.execute(f"DELETE FROM {schema}.bill_lines WHERE company_id=%s AND bill_id=%s", (company_id, bill_id))
        else:  # INSERT flow
            cur.execute(
                f"""
                INSERT INTO {schema}.bills (
                    company_id, vendor_id, number, bill_date, due_date, currency,
                    subtotal_amount, discount_amount, discount_rate, vat_amount, total_amount,
                    other_amount, status, notes
                )
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                RETURNING id;
                """,
                (
                    int(company_id),
                    int(header["vendor_id"]),
                    header.get("number"),
                    header["bill_date"],
                    header.get("due_date"),
                    header.get("currency"),
                    net_after,
                    discount_total,
                    disc_rate,
                    vat_total,
                    grand_total,
                    other,
                    header.get("status") or "draft",
                    header.get("notes"),
                ),
            )
            row = cur.fetchone()
            if not row:
                raise ValueError("Failed to insert bill header")
            bill_id = row["id"] if isinstance(row, dict) else row[0]

            # ---- insert lines ----
            for pl in prepared:
                cur.execute(
                    f"""
                    INSERT INTO {schema}.bill_lines (
                        company_id, bill_id, line_no, item_name, description, account_code,
                        quantity, unit_price, discount_amount, net_amount,
                        vat_rate, vat_amount, total_amount
                    )
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s);
                    """,
                    (
                        int(company_id),
                        int(bill_id),
                        int(pl["line_no"]),
                        pl.get("item_name"),
                        pl["description"],
                        pl.get("account_code"),
                        pl["quantity"],
                        pl["unit_price"],
                        pl["discount_amount"],
                        pl["net_amount"],
                        pl["vat_rate"],
                        pl["vat_amount"],
                        pl["total_amount"],
                    ),
                )

            # ---- insert GRN links ----
            grni_links = header.get("grni_links") or []
            if grni_links:
                # clear existing links if updating
                cur.execute(
                    f"DELETE FROM {schema}.bill_grni_links WHERE company_id=%s AND bill_id=%s",
                    (company_id, bill_id)
                )
                for link in grni_links:
                    receipt_tx_id = int(link.get("receipt_tx_id") or 0)
                    amount = float(link.get("amount") or 0.0)
                    if receipt_tx_id > 0 and amount > 0:
                        cur.execute(
                            f"""
                            INSERT INTO {schema}.bill_grni_links
                            (company_id, bill_id, receipt_tx_id, amount, created_at)
                            VALUES (%s, %s, %s, %s, NOW())
                            """,
                            (company_id, bill_id, receipt_tx_id, amount)
                        )

            if not bill_id:
                raise ValueError("Bill ID is None at end of insert_bill_with_lines_cur")

            return int(bill_id)

    def update_bill_with_lines(self, company_id: int, bill_id: int, header: dict, lines: list[dict]) -> bool:
        """
        Update bill header + replace lines.
        Maths aligned with AP UI:
        - header discount is an AMOUNT (discount_amount) (preferred)
        - header discount_rate only used as fallback if amount not provided
        - other is added after discount allocation
        - VAT computed on discounted vatable net (other does NOT affect VAT)
        """
        from decimal import Decimal, ROUND_HALF_UP

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = self.company_schema(company_id)

        if not (header.get("number") or "").strip():
            header["number"] = None

        if not header.get("vendor_id"):
            raise ValueError("vendor_id is required")
        if not header.get("bill_date"):
            raise ValueError("bill_date is required")
        if not isinstance(lines, list) or not lines:
            raise ValueError("At least one bill line is required")

        with self._conn_cursor() as (conn, cur):
            # Ensure bill exists + belongs to company
            cur.execute(
                f"SELECT id, status, number FROM {schema}.bills WHERE company_id=%s AND id=%s FOR UPDATE;",
                (int(company_id), int(bill_id)),
            )

            existing = cur.fetchone()
            if not existing:
                return False

            # ✅ block editing once bill is locked
            st = (existing.get("status") if isinstance(existing, dict) else existing[1]) or ""
            st = str(st).lower().strip()

            existing_no = (existing.get("number") if isinstance(existing, dict) else existing[2]) or ""
            existing_no = str(existing_no).strip()

            incoming_no = (header.get("number") or "").strip()

            # ✅ If UI didn't send a number, keep existing (don't blank it)
            final_no = incoming_no or existing_no
            header["number"] = final_no or None

            # -------------------------
            # ✅ TRACEABILITY ENFORCEMENT
            # -------------------------
            ui_status = (header.get("status") or "").strip().lower()
            target_status = ui_status if ui_status else st

            # Require vendor invoice number if trying to be approved/posted
            if target_status in {"approved", "posted"}:
                if not (header.get("number") or "").strip():
                    raise ValueError("Vendor invoice number is required before approving/posting this bill")

            LOCKED = {"posted", "paid", "void", "cancelled"}
            if st in LOCKED:
                raise ValueError(f"Cannot edit bill in status '{st}'")

            # -------------------------
            # Prepare lines + compute totals
            # -------------------------
            prepared = []
            subtotal_net = 0.0
            line_discount_total = 0.0

            vatable_net = 0.0
            vatable_by_rate: dict[float, float] = {}

            for idx, ln in enumerate(lines, start=1):
                qty = float(ln.get("quantity") or 0.0)
                price = float(ln.get("unit_price") or 0.0)

                # line discount amount (if you support it)
                disc_line = money(ln.get("discount_amount") or 0.0)

                vat_rate = float(ln.get("vat_rate") or 0.0)

                raw = (ln.get("account_code") or "").strip()
                if not raw:
                    raise ValueError(f"Missing account_code on bill line {idx}")

                row = self.get_account_row_for_posting(company_id, raw)
                if not row:
                    raise ValueError(f"Bill line account_code '{raw}' not found in COA (line {idx})")

                posting_code = (row[1] or "").strip()
                if not posting_code:
                    raise ValueError(f"Resolved posting code blank for '{raw}' (line {idx})")

                net = max(0.0, (qty * price) - disc_line)
                net = money(net)

                subtotal_net = money(subtotal_net + net)
                line_discount_total = money(line_discount_total + disc_line)

                if vat_rate > 0:
                    vatable_net = money(vatable_net + net)
                    vatable_by_rate[vat_rate] = money(vatable_by_rate.get(vat_rate, 0.0) + net)

                prepared.append({
                    "line_no": idx,
                    "item_name": (ln.get("item_name") or ln.get("itemName") or "").strip() or None,
                    "description": (ln.get("description") or "").strip(),
                    "account_code": posting_code,  # store posting code
                    "quantity": qty,
                    "unit_price": price,
                    "discount_amount": disc_line,
                    "net_amount": net,
                    "vat_rate": vat_rate,
                    "vat_amount": 0.0,
                    "total_amount": 0.0,
                })

            # -------------------------
            # Header discount + other (UI-aligned)
            # -------------------------
            # Prefer discount_amount (amount-based UI)
            header_disc_amt = money(header.get("discount_amount") or header.get("discount") or 0.0)

            # If discount_amount is not provided, fallback to discount_rate * subtotal
            if header_disc_amt <= 0:
                disc_rate = header.get("discount_rate")
                try:
                    disc_rate = float(disc_rate or 0.0)
                except Exception:
                    disc_rate = 0.0
                if disc_rate > 1.0:
                    disc_rate = disc_rate / 100.0
                disc_rate = max(0.0, min(1.0, disc_rate))
                header_disc_amt = money(subtotal_net * disc_rate)
            else:
                # if amount is provided, compute an implied rate for storage (optional)
                disc_rate = (header_disc_amt / subtotal_net) if subtotal_net > 0 else 0.0
                disc_rate = max(0.0, min(1.0, float(disc_rate)))

            # clamp header discount to subtotal
            header_disc_amt = max(0.0, min(header_disc_amt, subtotal_net))
            disc_rate = float(disc_rate or 0.0)

            # Other amount (added after discount allocation)
            try:
                other = float(header.get("other") or header.get("other_amount") or 0.0)
            except Exception:
                other = 0.0
            other = money(other)

            # -------------------------
            # VAT after header discount (other does NOT affect VAT)
            # Allocate header discount across vatable base proportionally by rate
            # -------------------------
            vat_total = 0.0
            disc_share_by_rate: dict[float, float] = {}

            if subtotal_net > 0 and vatable_net > 0 and header_disc_amt > 0:
                # discount applied proportionally across ALL lines; for VAT we only care about vatable portion
                # vatable discount portion:
                disc_on_vatable_total = money(header_disc_amt * (vatable_net / subtotal_net))
                disc_on_vatable_total = max(0.0, min(disc_on_vatable_total, vatable_net))

                for rate, base in vatable_by_rate.items():
                    share = (base / vatable_net) if vatable_net > 0 else 0.0
                    disc_share_by_rate[rate] = money(disc_on_vatable_total * share)

            for pl in prepared:
                rate = float(pl.get("vat_rate") or 0.0)
                net = money(pl.get("net_amount") or 0.0)

                if rate > 0 and vatable_net > 0:
                    base_rate = vatable_by_rate.get(rate, 0.0)
                    disc_rate_total = disc_share_by_rate.get(rate, 0.0)

                    disc_line_share = 0.0
                    if base_rate > 0 and disc_rate_total > 0:
                        disc_line_share = money(disc_rate_total * (net / base_rate))

                    net_after = money(max(0.0, net - disc_line_share))
                    vat = money(net_after * (rate / 100.0))
                else:
                    vat = 0.0

                tot = money(net + vat)
                pl["vat_amount"] = vat
                pl["total_amount"] = tot
                vat_total = money(vat_total + vat)

            net_after = money(max(0.0, subtotal_net - header_disc_amt + other))
            grand_total = money(net_after + vat_total)
            discount_total = money(line_discount_total + header_disc_amt)

            # -------------------------
            # Status: choose deliberately
            # -------------------------
            # Default: keep current DB status unless UI provides one.
            ui_status = (header.get("status") or "").strip().lower()
            if ui_status:
                # allow only known statuses while editable
                allowed = {"draft", "approved"}
                new_status = ui_status if ui_status in allowed else st
            else:
                new_status = st  # keep current

            # -------------------------
            # UPDATE bill header
            # -------------------------
            cur.execute(
                f"""
                UPDATE {schema}.bills
                SET vendor_id=%s, number=%s, bill_date=%s, due_date=%s, currency=%s,
                    subtotal_amount=%s, discount_amount=%s, discount_rate=%s,
                    vat_amount=%s, total_amount=%s, status=%s, notes=%s,
                    other_amount=%s,
                    updated_at=NOW()
                WHERE company_id=%s AND id=%s;
                """,
                (
                    int(header["vendor_id"]),
                    header.get("number"),
                    header["bill_date"],
                    header.get("due_date"),
                    header.get("currency"),
                    net_after,
                    discount_total,
                    disc_rate,
                    vat_total,
                    grand_total,
                    new_status,
                    header.get("notes"),
                    other,
                    int(company_id),
                    int(bill_id),
                ),
            )

            # -------------------------
            # Replace lines
            # -------------------------
            cur.execute(
                f"DELETE FROM {schema}.bill_lines WHERE company_id=%s AND bill_id=%s;",
                (int(company_id), int(bill_id)),
            )

            for pl in prepared:
                cur.execute(
                    f"""
                    INSERT INTO {schema}.bill_lines (
                        company_id, bill_id, line_no, item_name, description, account_code,
                        quantity, unit_price, discount_amount, net_amount,
                        vat_rate, vat_amount, total_amount
                    )
                    VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s);
                    """,
                    (
                        int(company_id),
                        int(bill_id),
                        int(pl["line_no"]),
                        pl.get("item_name"),
                        pl["description"],
                        pl.get("account_code"),  # posting code
                        pl["quantity"],
                        pl["unit_price"],
                        pl["discount_amount"],
                        pl["net_amount"],
                        pl["vat_rate"],
                        pl["vat_amount"],
                        pl["total_amount"],
                    ),
                )

            conn.commit()
            return True

    def insert_bill_with_lines(self, company_id: int, header: dict, lines: list[dict]) -> int:
        with self._conn_cursor() as (conn, cur):
            bill_id = self._insert_bill_with_lines_cur(company_id, header, lines, cur)
            conn.commit()
            return int(bill_id)

    def _post_bill_to_gl_cur(
        self,
        company_id: int,
        bill_id: int,
        *,
        jlines: list[dict] = None,
        cur,
    ) -> int:

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        def resolve_posting(company_id: int, raw: str) -> str:
            raw = (raw or "").strip()
            if not raw:
                raise ValueError("Blank account_code in journal line")
            # ✅ IMPORTANT: pass cur through
            r = self.get_account_row_for_posting(company_id, raw, cur=cur)
            if not r:
                raise ValueError(f"Account '{raw}' not found in COA")
            code = (r[1] or "").strip()
            if not code:
                raise ValueError(f"Resolved posting code blank for '{raw}'")
            return code

        schema = self.company_schema(company_id)

        # ✅ lock bill row FIRST
        cur.execute(
            f"SELECT status, posted_journal_id FROM {schema}.bills WHERE id=%s FOR UPDATE;",
            (int(bill_id),),
        )
        hdr = cur.fetchone()
        if not hdr:
            raise ValueError("Bill not found")

        already = hdr.get("posted_journal_id")
        if already:
            return int(already)

        if (hdr.get("status") or "").lower() == "posted":
            raise ValueError("Bill status is posted but posted_journal_id is NULL (data inconsistency)")

        bill = self.get_bill_full(company_id, bill_id)
        if not bill:
            raise ValueError("Bill not found")

        bdate = bill.get("bill_date") or _date.today()
        if isinstance(bdate, str):
            try:
                bdate = _date.fromisoformat(bdate[:10])
            except Exception:
                bdate = _date.today()

        # ✅ period lock gate
        if hasattr(self, "is_date_locked") and self.is_date_locked(company_id, tx_date=bdate, module="ap"):
            raise ValueError(f"PERIOD_LOCKED|ap|{bdate.isoformat()}")

        if not jlines:
            raise ValueError("No journal lines provided")

        # ✅ enforce vendor invoice number at POST time (traceability)
        if not (bill.get("number") or "").strip():
            raise ValueError("VENDOR_INVOICE_NUMBER_REQUIRED|Vendor invoice number is required before posting this bill")

        # ✅ resolve controls ONCE (posting codes)
        settings = self.get_company_account_settings(company_id, cur=cur) or {}

        ap_raw     = (settings.get("ap_control_code") or "").strip()
        vat_in_raw = (settings.get("vat_input_code") or "").strip()
        grni_raw   = (settings.get("grni_control_code") or settings.get("ppv_control_code") or "").strip()

        if not ap_raw:
            raise ValueError("AP control account not set (company_account_settings.ap_control_code)")
        if not vat_in_raw:
            raise ValueError("VAT input account not set (company_account_settings.vat_input_code)")

        AP_ACCOUNT = resolve_posting(company_id, ap_raw)
        VAT_INPUT  = resolve_posting(company_id, vat_in_raw)
        GRNI_CODE  = resolve_posting(company_id, grni_raw) if grni_raw else None

        bill_subtotal = money(bill.get("subtotal_amount") or 0.0)  # net
        bill_vat      = money(bill.get("vat_amount") or 0.0)
        bill_total    = money(bill.get("total_amount") or 0.0)

        # ✅ Load GRNI links (same cur/transaction)
        links = self.fetch_all(
            f"""
            SELECT receipt_tx_id, amount
            FROM {schema}.bill_grni_links
            WHERE company_id=%s AND bill_id=%s
            """,
            (int(company_id), int(bill_id)),
            cur=cur,
        ) or []

        linked_amt = money(sum(float(r.get("amount") or 0) for r in links))

        # ----------------------------
        # ✅ GRNI LOGIC (the missing part)
        # ----------------------------
        if linked_amt > 0:
            if not GRNI_CODE:
                raise ValueError("GRNI_NOT_CONFIGURED|Set grni_control_code in company_account_settings")

            # linked_amt represents NET (no VAT). It must not exceed subtotal.
            if linked_amt > (bill_subtotal + 0.01):
                raise ValueError(f"GRNI_LINK_EXCEEDS_SUBTOTAL|linked={linked_amt}|subtotal={bill_subtotal}")

            # We will rebuild jlines so it always contains the GRNI debit correctly.
            # Rule:
            # - DR GRNI = linked_amt (net)
            # - Remaining subtotal (if any) stays on "other" debit lines (expense/inventory)
            # - VAT line must still exist if VAT > 0
            # - AP credit remains the bill total (or as in jlines; we validate totals later)

            # 1) Separate lines into groups based on resolved posting codes
            new_lines = []
            vat_lines = []
            ap_lines  = []
            other_debit_lines = []

            for jl in jlines:
                raw_code = (jl.get("account_code") or "").strip()
                dc = (jl.get("dc") or "").upper()
                amt = money(jl.get("amount") or 0.0)
                if not raw_code or dc not in ("D", "C") or amt <= 0:
                    raise ValueError(f"Bad bill journal line: {jl}")

                code = resolve_posting(company_id, raw_code)

                # classify
                if code == VAT_INPUT:
                    vat_lines.append({"account_code": code, "dc": dc, "amount": amt, "memo": jl.get("memo")})
                elif code == AP_ACCOUNT:
                    ap_lines.append({"account_code": code, "dc": dc, "amount": amt, "memo": jl.get("memo")})
                else:
                    # Keep non-AP, non-VAT lines for now
                    if dc == "D":
                        other_debit_lines.append({"account_code": code, "dc": dc, "amount": amt, "memo": jl.get("memo")})
                    else:
                        # other credits (rare, but keep)
                        new_lines.append({"account_code": code, "dc": dc, "amount": amt, "memo": jl.get("memo")})

            # 2) Validate VAT presence if bill has VAT
            if bill_vat > 0:
                vat_debit_sum = money(sum(l["amount"] for l in vat_lines if l["dc"] == "D"))
                if abs(vat_debit_sum - bill_vat) > 0.02:
                    raise ValueError(f"VAT_INPUT_LINE_MISMATCH|expected={bill_vat}|found={vat_debit_sum}")

            # 3) Ensure AP credit exists and equals total
            ap_credit_sum = money(sum(l["amount"] for l in ap_lines if l["dc"] == "C"))
            if abs(ap_credit_sum - bill_total) > 0.02:
                raise ValueError(f"AP_CREDIT_MISMATCH|expected={bill_total}|found={ap_credit_sum}")

            # 4) If fully linked (most important case): remove other net debits entirely
            remaining_subtotal = money(bill_subtotal - linked_amt)

            if remaining_subtotal <= 0.01:
                # fully GRNI-linked: do NOT double-debit inventory/expense
                other_debit_lines = []

            else:
                # partial GRNI-linked: enforce remaining debits match remaining_subtotal
                other_debit_sum = money(sum(l["amount"] for l in other_debit_lines))
                if abs(other_debit_sum - remaining_subtotal) > 0.02:
                    raise ValueError(
                        f"PARTIAL_GRNI_REQUIRES_REMAINING_DEBITS|remaining_subtotal={remaining_subtotal}|other_debits={other_debit_sum}"
                    )

            # 5) Insert GRNI debit line
            new_lines.append({
                "account_code": GRNI_CODE,
                "dc": "D",
                "amount": linked_amt,
                "memo": "GRNI clearing (bill linked to receipt)",
            })

            # 6) Add back other debits (if any), VAT lines, and AP lines
            new_lines.extend(other_debit_lines)
            new_lines.extend(vat_lines)
            new_lines.extend(ap_lines)

            # 7) Replace jlines with rebuilt safe set
            jlines = new_lines

        else:
            # If GRNI is configured and you want to force linking always:
            # if GRNI_CODE:
            #     raise ValueError("GRNI_LINK_REQUIRED|Link this bill to a goods receipt (GRNI) before posting")
            pass

        # ----------------------------
        # Journal header
        # ----------------------------
        ref = (bill.get("number") or f"BILL-{bill_id}").strip()
        desc = (bill.get("notes") or f"Bill {ref}").strip() or f"Bill {ref}"
        vend_id = int(bill.get("vendor_id") or 0) or None

        entry = {
            "date": bdate,
            "ref": ref,
            "description": desc,
            "gross_amount": bill_total,
            "net_amount":   bill_subtotal,
            "vat_amount":   bill_vat,
            "source": "bill",
            "source_id": int(bill_id),
        }

        journal_id = int(self.insert_journal(company_id, entry, cur=cur) or 0)
        if journal_id <= 0:
            raise ValueError("Failed to create journal header")

        # ----------------------------
        # Ledger + TB
        # ----------------------------
        for jl in jlines:
            code = (jl.get("account_code") or "").strip()
            dc = (jl.get("dc") or "").upper()
            amt = money(jl.get("amount") or 0.0)
            if not code or dc not in ("D", "C") or amt <= 0:
                raise ValueError(f"Bad bill journal line: {jl}")

            line = {
                "account_code": code,
                "debit":  amt if dc == "D" else 0.0,
                "credit": amt if dc == "C" else 0.0,
                "description": desc,
                "memo": (jl.get("memo") or desc),
            }

            vendor_for_line = vend_id if (vend_id is not None and code == AP_ACCOUNT) else None

            self.insert_ledger(
                company_id=company_id,
                journal_id=journal_id,
                je_date=bdate,
                line=line,
                ref=ref,
                vendor_id=vendor_for_line,
                source="bill",
                source_id=int(bill_id),
                cur=cur,
            )

            self.update_trial_balance(company_id, line, cur=cur)

            if hasattr(self, "requires_notes") and self.requires_notes(code):
                if hasattr(self, "insert_note"):
                    self.insert_note(company_id, journal_id, code, desc, cur=cur)

        # stamp posted (idempotent)
        cur.execute(
            f"""
            UPDATE {schema}.bills
            SET status='posted',
                posted_journal_id=%s,
                updated_at=NOW()
            WHERE id=%s
            AND posted_journal_id IS NULL
            RETURNING id;
            """,
            (journal_id, int(bill_id)),
        )
        _ = cur.fetchone()

        # publish engagement posting activity (TEMP hardcoded bridge for validation)
        engagement_company_id = 8
        engagement_id = 14

        currency_code = (bill.get("currency") or "ZAR").strip() or "ZAR"

        self.upsert_engagement_posting_activity(
            cur,
            company_id=int(engagement_company_id),
            engagement_id=int(engagement_id),
            posting_date=bdate,
            module_name="accounts_payable",
            event_type="posted",
            reference_no=ref,
            description=desc,
            prepared_by_user_id=None,
            reviewer_user_id=None,
            status="posted",
            amount=bill_total,
            currency_code=currency_code,
            source_table="bills",
            source_id=int(bill_id),
            notes=f"Bill posted to journal {journal_id}",
            created_by_user_id=None,
            updated_by_user_id=None,
        )

        print("[_post_bill_to_gl_cur] engagement activity recorded", flush=True)

        return journal_id

    def validate_invoice_stock_before_post(
        self,
        company_id: int,
        inv: dict,
        *,
        inv_date=None,   # optional, used if you later want date-based stock
        cur=None,
    ) -> None:
        """
        Hard validation: blocks posting if any inventory line exceeds on-hand.

        - Only checks invoice lines where item_type == 'inventory' and item_id exists
        - Skips services
        - Only enforces when inventory_items.track_stock = true
        - Raises ValueError with a structured message:
            INSUFFICIENT_STOCK|item_id=..|onhand=..|req=..
        """

        if not inv or not isinstance(inv, dict):
            return

        schema = f"company_{company_id}"
        lines = inv.get("lines") or []
        if not lines:
            return

        # Use passed cursor or open one
        def _run(_cur):
            # aggregate requested qty per item_id (so multiple lines sum correctly)
            req_by_item: dict[int, float] = {}

            for ln in lines:
                item_type = (ln.get("item_type") or ln.get("itemType") or "").strip().lower()
                if item_type == "service":
                    continue
                if item_type != "inventory":
                    continue

                item_id_raw = ln.get("item_id") or ln.get("itemId")
                if not item_id_raw:
                    continue

                try:
                    item_id = int(item_id_raw)
                except Exception:
                    continue

                qty = float(ln.get("quantity") or ln.get("qty") or 0.0)
                if qty <= 0:
                    continue

                req_by_item[item_id] = float(req_by_item.get(item_id, 0.0) + qty)

            if not req_by_item:
                return

            # Check each item
            for item_id, req_qty in req_by_item.items():
                # Lock item row to prevent race condition (two invoices selling last unit)
                _cur.execute(
                    f"""
                    SELECT id, is_active, track_stock
                    FROM {schema}.inventory_items
                    WHERE company_id=%s AND id=%s
                    FOR UPDATE
                    """,
                    (int(company_id), int(item_id)),
                )
                it = _cur.fetchone() or {}
                if not it:
                    raise ValueError(f"INVENTORY_ITEM_NOT_FOUND|item_id={item_id}")
                if it.get("is_active") is False:
                    raise ValueError(f"INVENTORY_ITEM_INACTIVE|item_id={item_id}")

                track_stock = bool(it.get("track_stock", True))
                if not track_stock:
                    continue

                # compute onhand
                _cur.execute(
                    f"""
                    SELECT COALESCE(SUM(qty_in - qty_out),0)::numeric(18,4) AS onhand
                    FROM {schema}.inventory_layers
                    WHERE company_id=%s AND item_id=%s
                    """,
                    (int(company_id), int(item_id)),
                )
                r = _cur.fetchone() or {}
                onhand = float(r.get("onhand") or 0.0)

                if req_qty > onhand:
                    # hard block
                    raise ValueError(
                        f"INSUFFICIENT_STOCK|item_id={item_id}|onhand={onhand}|req={req_qty}"
                    )

        if cur is None:
            # In SaaS best practice: require a transaction cursor so FOR UPDATE works properly.
            raise ValueError("validate_invoice_stock_before_post requires an active DB cursor/transaction (cur)")
        return _run(cur)

    def post_bill_to_gl(
        self,
        company_id: int,
        bill_id: int,
        *,
        jlines: list[dict] = None,
        build_mode: str = "auto",   # auto|normal|inventory|erp
        cur=None,
    ) -> int:
        if cur is not None:
            return self._post_bill_to_gl_cur(company_id, bill_id, jlines=jlines, build_mode=build_mode, cur=cur)

        with self._conn_cursor() as (conn, _cur):
            try:
                jid = self._post_bill_to_gl_cur(company_id, bill_id, jlines=jlines, cur=_cur)
                conn.commit()
                return jid
            except Exception:
                conn.rollback()
                raise

    def get_bill_with_relations(self, company_id: int, bill_id: int) -> Optional[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        sql = f"""
        SELECT
            b.id,
            b.company_id,
            b.vendor_id,
            b.number,
            b.bill_date,
            b.due_date,
            b.currency,
            b.subtotal_amount,
            b.discount_amount,
            b.discount_rate,
            b.vat_amount,

            b.total_amount AS total_amount,
            b.total_amount AS total,

            b.status,
            b.notes,
            b.posted_journal_id,

            COALESCE(pay.paid_amount, 0)::numeric(18,2) AS paid_amount,
            GREATEST(b.total_amount - COALESCE(pay.paid_amount, 0), 0)::numeric(18,2) AS outstanding_amount,

            CASE
                WHEN LOWER(COALESCE(b.status,'')) IN ('void','written_off') THEN LOWER(b.status)
                WHEN GREATEST(b.total_amount - COALESCE(pay.paid_amount, 0), 0) <= 0 THEN 'paid'
                WHEN COALESCE(pay.paid_amount, 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status,

            -- vendor (LEFT JOIN so bill still loads even if vendor missing)
            v.name           AS vendor_name,
            v.email          AS vendor_email,
            v.phone          AS vendor_phone,
            v.remit_address  AS vendor_address,
            v.country        AS vendor_country,
            v.tax_number     AS vendor_tax_number,
            v.vat_number     AS vendor_vat_number,
            v.payment_terms  AS vendor_payment_terms,

            -- company (join directly to b.company_id)
            co.name            AS company_name,
            co.company_email   AS company_email,
            co.company_reg_no  AS company_reg_no,
            co.tin             AS company_tin,
            co.vat             AS company_vat,
            co.country         AS company_country,
            co.currency        AS company_currency,

            cb.company_id      AS branding_company_id,
            cb.logo_url        AS branding_logo_url,
            cb.footer_text     AS branding_footer_text,
            cb.contact_phone   AS branding_contact_phone,
            cb.contact_email   AS branding_contact_email,
            cb.website         AS branding_website,
            cb.address         AS branding_address,
            cb.vat_no          AS branding_vat_no

        FROM {schema}.bills b

        LEFT JOIN {schema}.vendors v
        ON v.id = b.vendor_id
        AND v.company_id = b.company_id

        JOIN public.companies co
        ON co.id = b.company_id

        LEFT JOIN public.company_branding cb
        ON cb.company_id = co.id

        LEFT JOIN (
            SELECT
                a.bill_id,
                SUM(a.amount)::numeric(18,2) AS paid_amount
            FROM {schema}.vendor_payment_allocations a
            WHERE a.company_id = %s
            GROUP BY a.bill_id
        ) pay
        ON pay.bill_id = b.id

        WHERE b.id = %s
        AND b.company_id = %s
        LIMIT 1;
        """

        row = self.fetch_one(sql, (int(company_id), int(bill_id), int(company_id)))
        return row or None

    def bill_number_exists(self, company_id, vendor_id, number, exclude_bill_id=None):
        schema = self.company_schema(company_id)

        sql = f"""
            SELECT 1
            FROM {schema}.bills
            WHERE company_id = %s
            AND vendor_id = %s
            AND number = %s
        """
        params = [company_id, vendor_id, number]

        if exclude_bill_id:
            sql += " AND id <> %s"
            params.append(exclude_bill_id)

        sql += " LIMIT 1"

        row = self.fetch_one(sql, tuple(params))
        return bool(row)

    def list_company_bills(
        self,
        company_id: int,
        statuses: Optional[list[str]] = None,
        vendor_id: Optional[int] = None,
        limit: int = 200,
    ) -> list[dict]:
        schema = self.company_schema(company_id)

        where = ["b.company_id = %s"]
        params: list[Any] = [int(company_id)]

        if vendor_id is not None:
            where.append("b.vendor_id = %s")
            params.append(int(vendor_id))

        sts: list[str] = []
        if statuses:
            sts = [str(s).strip().lower() for s in statuses if str(s).strip()]
            if sts:
                where.append("LOWER(COALESCE(b.status,'')) = ANY(%s)")
                params.append(sts)

        sql = f"""
        SELECT
            b.id,
            b.company_id,
            b.vendor_id,
            b.number,
            b.bill_date,
            b.due_date,
            b.currency,
            b.status,
            COALESCE(b.subtotal_amount,0) AS subtotal_amount,
            COALESCE(b.discount_amount,0) AS discount_amount,
            COALESCE(b.vat_amount,0)      AS vat_amount,
            COALESCE(b.total_amount,0)    AS total_amount,
            COALESCE(b.notes,'')          AS notes,
            b.created_at
        FROM {schema}.bills b
        WHERE {" AND ".join(where)}
        ORDER BY b.bill_date DESC NULLS LAST, b.id DESC
        LIMIT %s
        """
        params.append(int(limit))

        return self.fetch_all(sql, tuple(params)) or []
    
    def get_bill_full(self, company_id: int, bill_id: int) -> Optional[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        base = self.fetch_one(
            f"SELECT * FROM {schema}.bills WHERE id=%s AND company_id=%s LIMIT 1;",
            (int(bill_id), int(company_id)),
        )
        if not base:
            return None

        header = self.get_bill_with_relations(company_id, bill_id) or base

        header["lines"] = self.fetch_all(
            f"""
            SELECT *
            FROM {schema}.bill_lines
            WHERE company_id=%s AND bill_id=%s
            ORDER BY line_no ASC, id ASC;
            """,
            (int(company_id), int(bill_id)),
        ) or []

        # ✅ Enriched GRNI links
        header["grni_links"] = self.fetch_all(
            f"""
            SELECT
            l.id,
            l.company_id,
            l.bill_id,
            l.receipt_tx_id,
            l.amount,
            l.created_at,

            t.tx_date     AS receipt_date,
            t.ref         AS receipt_ref,
            t.vendor_id   AS receipt_vendor_id,
            t.status      AS receipt_status,

            COALESCE(rt.receipt_total,0)::numeric(18,2) AS receipt_total
            FROM {schema}.bill_grni_links l
            JOIN {schema}.inventory_tx t
            ON t.company_id=l.company_id AND t.id=l.receipt_tx_id
            LEFT JOIN (
            SELECT
                tx_id,
                COALESCE(SUM(qty*unit_cost),0)::numeric(18,2) AS receipt_total
            FROM {schema}.inventory_tx_lines
            WHERE company_id=%s
            GROUP BY tx_id
            ) rt ON rt.tx_id=t.id
            WHERE l.company_id=%s AND l.bill_id=%s
            ORDER BY l.id ASC;
            """,
            (int(company_id), int(company_id), int(bill_id)),
        ) or []

        # ✅ Open GRNs for vendor (pane data)
        vendor_id = int(header.get("vendor_id") or 0)
        if vendor_id > 0:
            header["grni_open_receipts"] = self.fetch_all(
                f"""
                WITH receipt_totals AS (
                SELECT
                    l.tx_id,
                    COALESCE(SUM(COALESCE(l.qty,0) * COALESCE(l.unit_cost,0)),0)::numeric(18,2) AS receipt_total
                FROM {schema}.inventory_tx_lines l
                WHERE l.company_id=%s
                GROUP BY l.tx_id
                ),
                linked AS (
                SELECT
                    receipt_tx_id AS tx_id,
                    COALESCE(SUM(amount),0)::numeric(18,2) AS linked_total
                FROM {schema}.bill_grni_links
                WHERE company_id=%s
                GROUP BY receipt_tx_id
                )
                SELECT
                t.id AS receipt_tx_id,
                t.tx_date,
                t.ref,
                t.notes,
                t.status,
                COALESCE(rt.receipt_total,0)::numeric(18,2) AS receipt_total,
                COALESCE(li.linked_total,0)::numeric(18,2) AS linked_total,
                (COALESCE(rt.receipt_total,0) - COALESCE(li.linked_total,0))::numeric(18,2) AS open_amount
                FROM {schema}.inventory_tx t
                LEFT JOIN receipt_totals rt ON rt.tx_id=t.id
                LEFT JOIN linked li ON li.tx_id=t.id
                WHERE t.company_id=%s
                AND t.vendor_id=%s
                AND lower(t.tx_type)=lower('receipt')
                AND lower(t.status)=lower('posted')
                AND (COALESCE(rt.receipt_total,0) - COALESCE(li.linked_total,0)) > 0
                ORDER BY t.tx_date DESC, t.id DESC;
                """,
                (int(company_id), int(company_id), int(company_id), int(vendor_id)),
            ) or []
        else:
            header["grni_open_receipts"] = []

        return header

    def find_duplicate_vendor_bill_number(
        self,
        company_id: int,
        vendor_id: int,
        number: str,
        *,
        exclude_bill_id: int | None = None,
        include_drafts: bool = False,
    ) -> dict | None:
        """
        Returns the first matching bill for vendor+number.
        By default, only considers NON-DRAFT bills (matches the DB partial unique index).
        """
        schema = self.company_schema(company_id)
        num = (number or "").strip()
        if not num:
            return None

        sql = f"""
        SELECT id, status, number
        FROM {schema}.bills
        WHERE company_id = %s
        AND vendor_id  = %s
        AND lower(trim(number)) = lower(trim(%s))
        """

        params = [int(company_id), int(vendor_id), num]

        if not include_drafts:
            sql += " AND lower(coalesce(status,'')) <> 'draft' "

        if exclude_bill_id:
            sql += " AND id <> %s"
            params.append(int(exclude_bill_id))

        sql += " ORDER BY id DESC LIMIT 1;"
        return self.fetch_one(sql, tuple(params))

    def get_bill_allocated_total(self, company_id: int, bill_id: int) -> Decimal:
        schema = self.company_schema(company_id)
        row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(a.amount),0)::numeric(18,2) AS paid
            FROM {schema}.vendor_payment_allocations a
            WHERE a.company_id=%s AND a.bill_id=%s;
            """,
            (int(company_id), int(bill_id)),
        ) or {}
        return Decimal(str(row.get("paid") or "0"))

    def get_payment_allocated_total(self, company_id: int, payment_id: int) -> Decimal:
        schema = self.company_schema(company_id)

        row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(amount), 0)::numeric(18,2) AS s
            FROM {schema}.vendor_payment_allocations
            WHERE company_id=%s AND payment_id=%s;
            """,
            (int(company_id), int(payment_id)),
        ) or {}

        return Decimal(str(row.get("s") or "0")).quantize(Decimal("0.01"))


    def get_payment_unallocated_balance(self, company_id: int, payment_id: int) -> Decimal:
        schema = self.company_schema(company_id)

        p = self.fetch_one(
            f"""
            SELECT amount, gross_amount
            FROM {schema}.vendor_payments
            WHERE company_id=%s AND id=%s
            LIMIT 1;
            """,
            (int(company_id), int(payment_id)),
        )
        if not p:
            return Decimal("0.00")

        # ✅ Source of truth: gross_amount (fallback to amount)
        gross = Decimal(str(p.get("gross_amount") or "0")).quantize(Decimal("0.01"))
        if gross <= Decimal("0.00"):
            gross = Decimal(str(p.get("amount") or "0")).quantize(Decimal("0.01"))

        alloc = self.get_payment_allocated_total(company_id, payment_id).quantize(Decimal("0.01"))
        bal = (gross - alloc).quantize(Decimal("0.01"))

        return bal if bal > Decimal("0.00") else Decimal("0.00")

    def allocate_vendor_payment_to_bill(self, company_id: int, *, payment_id: int, bill_id: int, amount):
        from decimal import Decimal

        schema = self.company_schema(company_id)
        amt = Decimal(str(amount or "0")).quantize(Decimal("0.01"))
        if amt <= Decimal("0.00"):
            raise ValueError("Allocation amount must be > 0")

        with self._conn_cursor() as (conn, cur):
            try:
                # lock payment
                cur.execute(
                    f"""
                    SELECT id, status, vendor_id
                    FROM {schema}.vendor_payments
                    WHERE company_id=%s AND id=%s
                    FOR UPDATE;
                    """,
                    (int(company_id), int(payment_id)),
                )
                pay = cur.fetchone() or {}
                if not pay:
                    raise ValueError("Payment not found")

                def _p(k, default=None):
                    return pay.get(k, default) if isinstance(pay, dict) else default

                pay_status = str(_p("status", "") or "").strip().lower()
                pay_vendor_id = int(_p("vendor_id") or 0)
                if not pay_vendor_id:
                    raise ValueError("Payment missing vendor_id")

                # allow allocation for: draft/approved/released/posted
                if pay_status not in {"draft", "approved", "released", "posted"}:
                    raise ValueError(f"Cannot allocate on a payment in status '{pay_status}'")

                # bill validations
                bill = self.get_bill_full(company_id, bill_id)
                if not bill:
                    raise ValueError("Bill not found")

                bill_vendor_id = int(bill.get("vendor_id") or 0)
                if bill_vendor_id != pay_vendor_id:
                    raise ValueError("Payment vendor does not match bill vendor")

                bill_status = str(bill.get("status") or "").strip().lower()
                if bill_status in {"void", "cancelled", "written_off"}:
                    raise ValueError(f"Cannot allocate to bill in status '{bill_status}'")

                # balances
                pb = Decimal(str(self.get_payment_unallocated_balance(company_id, payment_id) or "0")).quantize(Decimal("0.01"))
                if amt > pb:
                    raise ValueError(f"Allocation exceeds payment balance (balance={pb})")

                total = Decimal(str(bill.get("total_amount") or "0")).quantize(Decimal("0.01"))
                paid = Decimal(str(self.get_bill_allocated_total(company_id, bill_id) or "0")).quantize(Decimal("0.01"))
                outstanding = (total - paid).quantize(Decimal("0.01"))
                if amt > outstanding:
                    raise ValueError(f"Allocation exceeds bill outstanding (outstanding={outstanding})")

                # insert allocation (idempotent per unique index)
                cur.execute(
                    f"""
                    INSERT INTO {schema}.vendor_payment_allocations (company_id, payment_id, bill_id, amount)
                    VALUES (%s,%s,%s,%s)
                    ON CONFLICT (company_id, payment_id, bill_id)
                    DO UPDATE SET amount = EXCLUDED.amount
                    RETURNING id;
                    """,
                    (int(company_id), int(payment_id), int(bill_id), amt),
                )
                alloc = cur.fetchone()
                alloc_id = int((alloc.get("id") if isinstance(alloc, dict) else alloc[0]) or 0)

                # ✅ If already released/posted => post APPLY journal using settings
                if pay_status in {"released", "posted"}:
                    settings = self.get_company_account_settings(company_id) or {}

                    ap_code = self.resolve_posting_code(
                        company_id,
                        settings=settings,
                        setting_key="ap_control_code",
                        fallback_reporting_code="BS_CL_2200",
                        label="AP control",
                    )

                    adv_code = self.resolve_posting_code(
                        company_id,
                        settings=settings,
                        setting_key="unallocated_payments_code",
                        fallback_reporting_code="BS_CA_1730",
                        label="Vendor advances",
                    )

                    # journal entry: DR AP, CR Vendor Advances
                    entry = {
                        "date": (bill.get("bill_date") or bill.get("posted_date") or bill.get("date") or "").isoformat()
                                if hasattr((bill.get("bill_date") or bill.get("posted_date") or bill.get("date") or ""), "isoformat")
                                else str(bill.get("bill_date") or bill.get("posted_date") or bill.get("date") or ""),
                        "ref": f"VPAY-ALLOC-{payment_id}-{bill_id}",
                        "description": f"Apply vendor prepayment: payment {payment_id} -> bill {bill_id}",
                        "gross_amount": float(amt),
                        "net_amount": float(amt),
                        "vat_amount": 0.0,
                        "source": "vendor_payment_allocation",
                        "source_id": int(alloc_id),
                        "lines": [
                            {"account_code": ap_code,  "debit": float(amt), "credit": 0.0, "memo": f"Apply to bill {bill_id}", "vendor_id": pay_vendor_id},
                            {"account_code": adv_code, "debit": 0.0,       "credit": float(amt), "memo": f"Reduce vendor advances (payment {payment_id})", "vendor_id": pay_vendor_id},
                        ],
                    }

                    jid = int(self.post_journal(company_id, entry, cur=cur) or 0)
                    if jid <= 0:
                        raise ValueError("Failed to post allocation apply journal")

                    # Optional: persist journal_id on allocation (recommended)
                    # add column once: ALTER TABLE ... ADD COLUMN IF NOT EXISTS created_journal_id INT NULL;
                    if self._table_has_column(schema, "vendor_payment_allocations", "created_journal_id", cur=cur):
                        cur.execute(
                            f"UPDATE {schema}.vendor_payment_allocations SET created_journal_id=%s WHERE company_id=%s AND id=%s;",
                            (jid, int(company_id), int(alloc_id)),
                        )

                # update bill status
                new_paid = (paid + amt).quantize(Decimal("0.01"))
                if (total - new_paid) <= Decimal("0.00"):
                    cur.execute(f"UPDATE {schema}.bills SET status='paid', updated_at=NOW() WHERE company_id=%s AND id=%s;", (int(company_id), int(bill_id)))
                else:
                    cur.execute(f"UPDATE {schema}.bills SET status='partial', updated_at=NOW() WHERE company_id=%s AND id=%s;", (int(company_id), int(bill_id)))

                conn.commit()
                return {"allocation_id": alloc_id, "payment_id": int(payment_id), "bill_id": int(bill_id), "amount": str(amt)}

            except Exception:
                conn.rollback()
                raise

    def resolve_posting_code(
        self,
        company_id: int,
        *,
        settings: dict,
        setting_key: str,
        fallback_reporting_code: str | None = None,
        label: str | None = None,
    ) -> str:
        """
        Resolve a posting-ready account code for journals.

        Priority:
        1) public.company_account_settings.<setting_key>
        2) fallback_reporting_code (if provided)

        Uses get_account_row_for_posting() so it always resolves to a valid COA posting code.

        Returns:
        posting_code (string)

        Raises:
        ValueError if nothing can be resolved.
        """
        label = label or setting_key

        raw = (settings.get(setting_key) or "").strip()
        if not raw and fallback_reporting_code:
            raw = str(fallback_reporting_code).strip()

        if not raw:
            raise ValueError(f"{label} not set (settings key '{setting_key}')")

        row = self.get_account_row_for_posting(company_id, raw)
        if not row:
            raise ValueError(f"{label} code '{raw}' not found in COA")

        # get_account_row_for_posting sometimes returns tuple-like (id, code, ...)
        posting_code = ""
        if isinstance(row, dict):
            posting_code = (row.get("code") or "").strip()
        else:
            posting_code = (row[1] or "").strip() if len(row) > 1 else ""

        if not posting_code:
            raise ValueError(f"{label} resolved blank posting code (raw='{raw}')")

        return posting_code
    
    def release_vendor_payment(self, company_id: int, payment_id: int, *, user_id: int | None) -> dict:
        """
        Release a vendor payment:
        - posts the journal (once)
        - marks payment released
        - updates affected bills to partial/paid
        Idempotent + row-locked to prevent double release.
        """
        from decimal import Decimal

        schema = self.company_schema(company_id)

        with self._conn_cursor() as (conn, cur):
            try:
                # Lock the payment row to prevent double-release races
                cur.execute(
                    f"""
                    SELECT *
                    FROM {schema}.vendor_payments
                    WHERE company_id=%s AND id=%s
                    FOR UPDATE;
                    """,
                    (int(company_id), int(payment_id)),
                )
                pay = cur.fetchone() or {}
                if not pay:
                    raise ValueError("Payment not found")

                def _get(k, default=None):
                    return pay.get(k, default) if isinstance(pay, dict) else default

                status = str(_get("status", "draft") or "draft").strip().lower()
                existing_journal_id = _get("created_journal_id")

                # ✅ Idempotent: already released → just return what we have
                if status == "released":
                    jid = int(existing_journal_id or 0)
                    conn.commit()
                    return {"payment_id": int(payment_id), "journal_id": jid, "status": "released", "idempotent": True}

                if status not in ("draft", "approved"):
                    raise ValueError(f"Payment cannot be released from status '{status}'")

                vendor_id = int(_get("vendor_id") or 0)
                if not vendor_id:
                    raise ValueError("Payment missing vendor_id")

                # ---------- policy gates ----------
                mode = str(_get("workflow_mode") or "owner_managed").strip().lower()
                if mode in ("assisted", "controlled") and status != "approved":
                    raise ValueError("Payment must be approved before release")

                # vendor hold / compliance (still OK to keep here)
                cur.execute(
                    f"""
                    SELECT on_hold, compliance_status, country
                    FROM {schema}.vendors
                    WHERE company_id=%s AND id=%s
                    LIMIT 1;
                    """,
                    (int(company_id), int(vendor_id)),
                )
                v = cur.fetchone() or {}
                on_hold = (v.get("on_hold") if isinstance(v, dict) else None)
                compliance_status = (v.get("compliance_status") if isinstance(v, dict) else None)

                if str(on_hold or "").strip().lower() in ("yes", "true", "1"):
                    raise ValueError("Vendor is on hold")
                if str(compliance_status or "").strip().lower() == "blocked":
                    raise ValueError("Vendor compliance is blocked")

                # ---------- amounts ----------
                gross = Decimal(str(_get("gross_amount") or _get("amount") or "0")).quantize(Decimal("0.01"))
                wht   = Decimal(str(_get("wht_amount") or "0")).quantize(Decimal("0.01"))
                net   = Decimal(str(_get("net_amount") or (gross - wht))).quantize(Decimal("0.01"))

                if gross <= Decimal("0.00"):
                    raise ValueError("Payment amount must be > 0")
                if wht < Decimal("0.00") or net < Decimal("0.00"):
                    raise ValueError("Invalid WHT/net amounts")
                if (net + wht) != gross:
                    # keep strict; avoids weird mismatches
                    raise ValueError("Gross must equal net + wht")

                bank_ledger_code = str(_get("bank_ledger_code") or "").strip()
                ap_code          = str(_get("ap_ledger_code") or "").strip()
                if not bank_ledger_code or not ap_code:
                    raise ValueError("Payment missing bank_ledger_code or ap_ledger_code")

                wht_code = str(_get("wht_ledger_code") or "").strip()

                # ✅ Auto-resolve WHT payable control if missing
                if wht > Decimal("0.00") and not wht_code:
                    settings = self.get_company_account_settings(company_id) or {}
                    wht_raw = (settings.get("wht_payable_code") or "").strip()
                    if not wht_raw:
                        raise ValueError("wht_payable_code not set (public.company_account_settings)")

                    wht_row = self.get_account_row_for_posting(company_id, wht_raw)
                    if not wht_row:
                        raise ValueError(f"WHT payable code '{wht_raw}' not found in COA")

                    wht_code = (wht_row[1] or "").strip()
                    if not wht_code:
                        raise ValueError("WHT payable resolved blank posting code")

                    # ✅ Persist auto-resolved WHT ledger code on the payment
                    cur.execute(
                        f"""
                        UPDATE {schema}.vendor_payments
                        SET wht_ledger_code=%s
                        WHERE company_id=%s AND id=%s;
                        """,
                        (wht_code, int(company_id), int(payment_id)),
                    )

                pdate = _get("payment_date")
                if not pdate:
                    raise ValueError("Payment missing payment_date")

                # ---------- allocations total ----------
                cur.execute(
                    f"""
                    SELECT COALESCE(SUM(amount),0)::numeric(18,2) AS s
                    FROM {schema}.vendor_payment_allocations
                    WHERE company_id=%s AND payment_id=%s;
                    """,
                    (int(company_id), int(payment_id)),
                )
                alloc_row = cur.fetchone() or {}
                alloc = Decimal(str((alloc_row.get("s") if isinstance(alloc_row, dict) else 0) or "0")).quantize(Decimal("0.01"))

                if alloc < Decimal("0.00"):
                    raise ValueError("Invalid allocations")
                if alloc > gross:
                    raise ValueError("Allocations exceed payment gross amount")

                remainder = (gross - alloc).quantize(Decimal("0.01"))

                # vendor advances (required if remainder > 0)
                adv_code = ""
                if remainder > Decimal("0.00"):
                    settings = self.get_company_account_settings(company_id) or {}
                    adv_raw = (settings.get("unallocated_payments_code") or "").strip()
                    if not adv_raw:
                        raise ValueError("unallocated_payments_code not set (vendor advances)")
                    adv_row = self.get_account_row_for_posting(company_id, adv_raw)
                    if not adv_row:
                        raise ValueError(f"Vendor advances code '{adv_raw}' not found in COA")
                    adv_code = (adv_row[1] or "").strip()

                # ---------- build journal ----------
                lines = [
                    # Bank decreases (credit)
                    {"account_code": bank_ledger_code, "debit": 0.0, "credit": float(net), "memo": "Vendor payment (net)"},
                ]
                if wht > Decimal("0.00"):
                    # Withholding payable increases (credit)
                    lines.append({"account_code": wht_code, "debit": 0.0, "credit": float(wht), "memo": "Withholding tax payable"})

                if alloc > Decimal("0.00"):
                    # Reduce AP (debit)
                    lines.append({"account_code": ap_code, "debit": float(alloc), "credit": 0.0, "memo": "Reduce AP (allocated)", "vendor_id": vendor_id})

                if remainder > Decimal("0.00"):
                    # Vendor prepayment/advances (debit)
                    lines.append({"account_code": adv_code, "debit": float(remainder), "credit": 0.0, "memo": "Vendor prepayment (unallocated)", "vendor_id": vendor_id})

                entry = {
                    "date": (pdate.isoformat() if hasattr(pdate, "isoformat") else str(pdate)),
                    "ref": (_get("reference") or f"VPAY-{payment_id}"),
                    "description": (_get("description") or f"Vendor payment {payment_id}"),
                    "gross_amount": float(gross),
                    "net_amount": float(net),
                    "vat_amount": 0.0,
                    "source": "vendor_payment",
                    "source_id": int(payment_id),
                    "lines": lines,
                }

                # IMPORTANT: post_journal likely uses its own connection.
                # Because we hold a FOR UPDATE lock in THIS transaction, we must not commit until after we stamp released.
                journal_id = int(self.post_journal(company_id, entry, cur=cur) or 0)
                if journal_id <= 0:
                    raise ValueError("Failed to post vendor payment journal")

                # finalize payment
                cur.execute(
                    f"""
                    UPDATE {schema}.vendor_payments
                    SET created_journal_id=%s,
                        status='released',
                        released_by=%s,
                        released_at=NOW()
                    WHERE company_id=%s AND id=%s;
                    """,
                    (int(journal_id), int(user_id) if user_id is not None else None, int(company_id), int(payment_id)),
                )

                # update bill statuses for bills touched by this payment
                cur.execute(
                    f"""
                    SELECT bill_id, COALESCE(SUM(amount),0)::numeric(18,2) AS amt
                    FROM {schema}.vendor_payment_allocations
                    WHERE company_id=%s AND payment_id=%s
                    GROUP BY bill_id;
                    """,
                    (int(company_id), int(payment_id)),
                )
                bills = cur.fetchall() or []

                for b in bills:
                    bid = int(b.get("bill_id") if isinstance(b, dict) else b[0])

                    cur.execute(
                        f"""
                        SELECT total_amount
                        FROM {schema}.bills
                        WHERE company_id=%s AND id=%s
                        LIMIT 1;
                        """,
                        (int(company_id), int(bid)),
                    )
                    bill_row = cur.fetchone()
                    if not bill_row:
                        continue

                    total = Decimal(str((bill_row.get("total_amount") if isinstance(bill_row, dict) else bill_row[0]) or "0")).quantize(Decimal("0.01"))

                    cur.execute(
                        f"""
                        SELECT COALESCE(SUM(a.amount),0)::numeric(18,2) AS paid
                        FROM {schema}.vendor_payment_allocations a
                        WHERE a.company_id=%s AND a.bill_id=%s;
                        """,
                        (int(company_id), int(bid)),
                    )
                    paid_row = cur.fetchone() or {}
                    paid = Decimal(str((paid_row.get("paid") if isinstance(paid_row, dict) else 0) or "0")).quantize(Decimal("0.01"))

                    remaining = (total - paid).quantize(Decimal("0.01"))

                    if remaining <= Decimal("0.00"):
                        cur.execute(
                            f"UPDATE {schema}.bills SET status='paid', updated_at=NOW() WHERE company_id=%s AND id=%s;",
                            (int(company_id), int(bid)),
                        )
                    else:
                        cur.execute(
                            f"UPDATE {schema}.bills SET status='partial', updated_at=NOW() WHERE company_id=%s AND id=%s;",
                            (int(company_id), int(bid)),
                        )

                conn.commit()
                return {"payment_id": int(payment_id), "journal_id": int(journal_id), "status": "released"}

            except Exception:
                conn.rollback()
                raise

    def create_vendor_payment_draft(
        self,
        *,
        company_id: int,
        vendor_id: int,
        payment_date,
        amount,
        bank_account_id: int,
        reference: str | None,
        description: str | None,
        created_by: int | None,
        wht_rate=None,
        wht_amount=None,
        wht_ledger_code: str | None = None,
        wht_reason: str | None = None,
        workflow_mode: str = "owner_managed",   # ✅ ADD THIS
    ) -> dict:

        from decimal import Decimal

        schema = self.company_schema(company_id)

        # ─────────────────────────────
        # ✅ NORMALISE & VALIDATE WORKFLOW MODE (ADD HERE)
        # ─────────────────────────────
        workflow_mode = (workflow_mode or "owner_managed").strip().lower()
        if workflow_mode not in ("owner_managed", "approval_managed"):
            raise ValueError(f"Invalid workflow_mode: {workflow_mode}")
        
        amt = Decimal(str(amount or "0")).quantize(Decimal("0.01"))
        if amt <= Decimal("0.00"):
            raise ValueError("amount must be > 0")

        # bank account -> bank ledger posting code
        bank = self.get_company_bank_account(company_id, int(bank_account_id))
        if not bank:
            raise ValueError("Bank account not found")
        bank_ledger_code = (bank.get("ledger_account_code") or "").strip()
        if not bank_ledger_code:
            raise ValueError("Selected bank account has no ledger_account_code")

        # AP control posting code (store posting code)
        ap_code = self._resolve_ap_control_posting(company_id)  # or your renamed _resolve_ap_control_posting_code()

        # currency: prefer bank currency, else company set
        currency = bank.get("currency") or None

        # WHT values
        wht_rate = Decimal(str(wht_rate or "0")).quantize(Decimal("0.000001"))
        wht_amount = Decimal(str(wht_amount or "0")).quantize(Decimal("0.01"))

        # if rate provided but amount not, compute
        if wht_amount <= Decimal("0.00") and wht_rate > Decimal("0.00"):
            wht_amount = (amt * wht_rate).quantize(Decimal("0.01"))

        if wht_amount < Decimal("0.00"):
            raise ValueError("wht_amount cannot be negative")
        if wht_amount > amt:
            raise ValueError("wht_amount cannot exceed amount")

        gross = amt
        net = (gross - wht_amount).quantize(Decimal("0.01"))

        # if WHT is applied, ledger code should exist (unless you want to allow draft without it)
        if wht_amount > Decimal("0.00") and not (wht_ledger_code or "").strip():
            raise ValueError("wht_ledger_code is required when wht_amount > 0")

        row = self.fetch_one(
            f"""
            INSERT INTO {schema}.vendor_payments
                (company_id, vendor_id, payment_date, amount, currency,
                bank_account_id, bank_ledger_code, ap_ledger_code,
                reference, description, created_by,
                workflow_mode, gross_amount, wht_rate, wht_amount, net_amount,
                wht_ledger_code, wht_reason,
                status, created_at)
            VALUES
                (%s,%s,%s,%s,%s,
                %s,%s,%s,
                %s,%s,%s,
                %s,%s,%s,%s,%s,
                %s,%s,
                'draft', NOW())
            RETURNING id;
            """,
            (
                int(company_id),
                int(vendor_id),
                payment_date,
                str(amt),
                currency,

                int(bank_account_id),
                bank_ledger_code,
                ap_code,

                reference,
                description,
                created_by,

                workflow_mode,          # ✅ FIXED
                str(gross),
                str(wht_rate),
                str(wht_amount),
                str(net),

                (wht_ledger_code.strip() if wht_ledger_code else None),
                wht_reason,
            ),
        ) or {}

        payment_id = int(row.get("id") or 0)
        if payment_id <= 0:
            raise ValueError("Failed to create vendor payment")

        return {
            "payment_id": payment_id,
            "status": "draft",
            "vendor_id": int(vendor_id),
            "payment_date": (payment_date.isoformat() if hasattr(payment_date, "isoformat") else str(payment_date)),
            "gross_amount": str(gross),
            "wht_amount": str(wht_amount),
            "net_amount": str(net),
            "bank_account_id": int(bank_account_id),
            "bank_ledger_code": bank_ledger_code,
            "ap_ledger_code": ap_code,
            "currency": currency,
            "reference": reference,
            "description": description,
        }

    def list_vendor_payments(
        self,
        company_id: int,
        *,
        status: str | None = None,
        vendor_id: int | None = None,
        limit: int = 200,
    ) -> list[dict]:
        schema = self.company_schema(company_id)

        where = ["p.company_id = %s"]
        params: list = [int(company_id)]

        if vendor_id is not None:
            where.append("p.vendor_id = %s")
            params.append(int(vendor_id))

        if status:
            where.append("LOWER(COALESCE(p.status,'')) = %s")
            params.append(str(status).lower())

        sql = f"""
        SELECT
            p.id,
            p.company_id,
            p.vendor_id,
            COALESCE(v.name,'') AS vendor_name,

            p.payment_date,
            p.currency,

            p.amount,
            p.gross_amount,
            p.wht_amount,
            p.net_amount,

            p.bank_account_id,
            p.bank_ledger_code,
            p.ap_ledger_code,

            p.reference,
            p.description,

            p.status,
            p.created_journal_id,
            p.created_at
        FROM {schema}.vendor_payments p
        LEFT JOIN {schema}.vendors v
        ON v.id = p.vendor_id
        AND v.company_id = p.company_id
        WHERE {" AND ".join(where)}
        ORDER BY p.payment_date DESC NULLS LAST, p.id DESC
        LIMIT %s
        """
        params.append(int(limit))

        return self.fetch_all(sql, tuple(params)) or []

    def get_vendor_payment_full(self, company_id: int, payment_id: int) -> dict | None:
        schema = self.company_schema(company_id)

        pay = self.fetch_one(
            f"""
            SELECT
                p.*,
                COALESCE(v.name,'') AS vendor_name
            FROM {schema}.vendor_payments p
            LEFT JOIN {schema}.vendors v
            ON v.id = p.vendor_id
            AND v.company_id = p.company_id
            WHERE p.company_id=%s AND p.id=%s
            LIMIT 1;
            """,
            (int(company_id), int(payment_id)),
        )
        if not pay:
            return None

        allocs = self.fetch_all(
            f"""
            SELECT
                a.id,
                a.payment_id,
                a.bill_id,
                a.amount,
                b.number AS bill_number,
                b.bill_date,
                b.total_amount AS bill_total,
                b.status AS bill_status
            FROM {schema}.vendor_payment_allocations a
            JOIN {schema}.bills b
            ON b.id = a.bill_id
            AND b.company_id = a.company_id
            WHERE a.company_id=%s AND a.payment_id=%s
            ORDER BY a.id ASC;
            """,
            (int(company_id), int(payment_id)),
        ) or []

        pay["allocations"] = allocs
        return pay

    def approve_vendor_payment(self, *, company_id: int, payment_id: int, user_id: int) -> dict:
        """
        Approve a vendor payment.
        - Locks the row to prevent double-approval races
        - Idempotent: if already approved, returns success
        - Blocks if status is not draft/approved
        """
        schema = self.company_schema(company_id)

        with self._conn_cursor() as (conn, cur):
            try:
                cur.execute(
                    f"""
                    SELECT id, status, approved_by, approved_at
                    FROM {schema}.vendor_payments
                    WHERE company_id=%s AND id=%s
                    FOR UPDATE;
                    """,
                    (int(company_id), int(payment_id)),
                )
                pay = cur.fetchone()
                if not pay:
                    raise ValueError("Payment not found")

                status = (pay.get("status") if isinstance(pay, dict) else pay[1]) or ""
                status = str(status).strip().lower()

                # ✅ idempotent behavior
                if status == "approved":
                    conn.commit()
                    return {
                        "payment_id": int(payment_id),
                        "status": "approved",
                        "approved_by": (pay.get("approved_by") if isinstance(pay, dict) else pay[2]),
                        "approved_at": (pay.get("approved_at") if isinstance(pay, dict) else pay[3]),
                        "idempotent": True,
                    }

                # only draft can be approved
                if status != "draft":
                    raise ValueError(f"Only draft payments can be approved (current status='{status}')")

                cur.execute(
                    f"""
                    UPDATE {schema}.vendor_payments
                    SET
                        status='approved',
                        approved_by=%s,
                        approved_at=NOW()
                    WHERE company_id=%s AND id=%s
                    RETURNING id, status, approved_by, approved_at;
                    """,
                    (int(user_id), int(company_id), int(payment_id)),
                )
                row = cur.fetchone() or {}

                conn.commit()
                return {
                    "payment_id": int(payment_id),
                    "status": (row.get("status") if isinstance(row, dict) else row[1]) or "approved",
                    "approved_by": (row.get("approved_by") if isinstance(row, dict) else row[2]),
                    "approved_at": (row.get("approved_at") if isinstance(row, dict) else row[3]),
                }

            except Exception:
                conn.rollback()
                raise


    def void_vendor_payment(self, *, company_id: int, payment_id: int, user_id: int | None, reason: str | None) -> dict:
        schema = self.company_schema(company_id)
        reason = (reason or "").strip() or None

        pay = self.fetch_one(
            f"""
            SELECT id, status, created_journal_id
            FROM {schema}.vendor_payments
            WHERE company_id=%s AND id=%s
            LIMIT 1;
            """,
            (int(company_id), int(payment_id)),
        )
        if not pay:
            raise ValueError("Payment not found")

        status = (pay.get("status") or "").strip().lower()
        created_journal_id = pay.get("created_journal_id")

        # ✅ cannot void after release (journal already exists / payment already paid out)
        if status == "released" or created_journal_id:
            raise ValueError("Cannot void a released payment (reverse it instead)")

        # ✅ idempotent: if already voided, return ok
        if status == "voided":
            return {"payment_id": int(payment_id), "status": "voided"}

        # allow void from draft/approved only
        if status not in ("draft", "approved"):
            raise ValueError(f"Cannot void payment in status '{status}'")

        self.execute_sql(
            f"""
            UPDATE {schema}.vendor_payments
            SET
                status='voided',
                void_reason=%s,
                voided_by=%s,
                voided_at=NOW()
            WHERE company_id=%s AND id=%s;
            """,
            (reason, int(user_id) if user_id is not None else None, int(company_id), int(payment_id)),
        )

        return {"payment_id": int(payment_id), "status": "voided", "void_reason": reason}

    def reverse_posted_bill(
        self,
        company_id: int,
        bill_id: int,
        *,
        reason: str = "",
        reversed_by: int | None = None,
        reversal_date: str | date | None = None,
    ) -> int:
        """
        Reverse a posted vendor bill by creating a reversing journal
        (mirror of reverse_invoice, but vendor/bills/AP).
        """
        schema = self.company_schema(company_id)

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01")))

        # ✅ Choose reversal date (default today)
        if reversal_date is None or str(reversal_date).strip() == "":
            rev_date = date.today()
        else:
            if isinstance(reversal_date, date):
                rev_date = reversal_date
            else:
                rev_date = date.fromisoformat(str(reversal_date)[:10])

        # ✅ Period lock gate (AP module)
        if self.is_date_locked(company_id, tx_date=rev_date, module="ap"):
            raise ValueError(f"PERIOD_LOCKED|ap|{rev_date.isoformat()}")

        with self._conn_cursor() as (conn, cur):
            try:
                # 1) Lock bill row
                cur.execute(
                    f"""
                    SELECT id, number, status, posted_journal_id, reversed_journal_id, vendor_id
                    FROM {schema}.bills
                    WHERE id=%s
                    FOR UPDATE;
                    """,
                    (bill_id,),
                )
                b = cur.fetchone()
                if not b:
                    raise ValueError("Bill not found")

                bill_no = (b.get("number") or f"BILL-{bill_id}").strip()
                status = (b.get("status") or "").lower()
                posted_journal_id = b.get("posted_journal_id")
                vendor_id = b.get("vendor_id")

                if not posted_journal_id or status != "posted":
                    raise ValueError("Only posted bills can be reversed")

                if b.get("reversed_journal_id"):
                    raise ValueError("Bill already reversed")

                # 2) Block reversal if allocations exist (payments allocated to this bill)
                cur.execute(
                    f"""
                    SELECT COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid
                    FROM {schema}.vendor_payment_allocations a
                    WHERE a.bill_id = %s
                    AND a.company_id = %s;
                    """,
                    (bill_id, company_id),
                )
                paid_row = cur.fetchone() or {}
                paid = Decimal(str(paid_row.get("paid") or "0"))
                if paid > Decimal("0.00"):
                    raise ValueError("Cannot reverse: bill has allocations. Unallocate first.")

                # 3) Fetch original journal header
                cur.execute(
                    f"""
                    SELECT id, date, ref, description, gross_amount, net_amount, vat_amount
                    FROM {schema}.journal
                    WHERE id=%s
                    LIMIT 1;
                    """,
                    (posted_journal_id,),
                )
                jh = cur.fetchone()
                if not jh:
                    raise ValueError("Original journal not found for this bill")

                # 4) Fetch original ledger lines
                cur.execute(
                    f"""
                    SELECT id, account, debit, credit, memo, vendor_id
                    FROM {schema}.ledger
                    WHERE journal_id = %s
                    ORDER BY id ASC;
                    """,
                    (posted_journal_id,),
                )
                led_lines = cur.fetchall() or []
                if not led_lines:
                    raise ValueError("Original ledger lines not found for this bill journal")

                # 5) Create reversal journal header
                rev_ref = f"REV-{bill_no}"
                rev_desc = (reason or "").strip() or f"Reversal of bill {bill_no}"

                rev_entry = {
                    "date": rev_date.isoformat(),
                    "ref": rev_ref,
                    "description": rev_desc,
                    "gross_amount": money(jh.get("gross_amount")),
                    "net_amount": money(jh.get("net_amount")),
                    "vat_amount": money(jh.get("vat_amount")),
                    "source": "bill_reversal",
                    "source_id": int(bill_id),
                }

                reversal_journal_id = int(self.insert_journal(company_id, rev_entry, cur=cur) or 0)
                if reversal_journal_id <= 0:
                    raise ValueError("Failed to create reversal journal")

                # 6) Insert reversing ledger lines + TB updates (swap Dr/Cr)
                for ln in led_lines:
                    acct = (ln.get("account") or "").strip()
                    if not acct:
                        continue

                    d = money(ln.get("debit"))
                    c = money(ln.get("credit"))

                    rev_line = {
                        "account_code": acct,
                        "debit": c,
                        "credit": d,
                        "description": rev_desc,
                        "memo": ln.get("memo") or rev_desc,
                    }

                    self.insert_ledger(
                        company_id=company_id,
                        journal_id=reversal_journal_id,
                        je_date=rev_entry["date"],
                        line=rev_line,
                        ref=rev_ref,
                        vendor_id=ln.get("vendor_id") or vendor_id,   # ✅ keep subledger trace
                        cur=cur,
                    )
                    self.update_trial_balance(company_id, rev_line, cur=cur)

                # 7) Mark original journal + reversal journal (same as AR)
                cur.execute(
                    f"UPDATE {schema}.journal SET reversed_journal_id=%s WHERE id=%s;",
                    (reversal_journal_id, posted_journal_id),
                )
                cur.execute(
                    f"""
                    UPDATE {schema}.journal
                    SET is_reversal=TRUE, reversed_journal_id=%s
                    WHERE id=%s;
                    """,
                    (posted_journal_id, reversal_journal_id),
                )

                # 8) Stamp bill (audit-safe)
                cur.execute(
                    f"""
                    UPDATE {schema}.bills
                    SET status='reversed',
                        reversed_journal_id=%s,
                        reversed_at=NOW(),
                        reversed_by=%s,
                        reversal_reason=%s,
                        updated_at=NOW()
                    WHERE id=%s
                    RETURNING id;
                    """,
                    (reversal_journal_id, reversed_by, rev_desc, bill_id),
                )
                if not cur.fetchone():
                    raise ValueError("Failed to stamp bill reversed")

                conn.commit()
                return reversal_journal_id

            except Exception:
                conn.rollback()
                raise

    def writeoff_bill(
        self,
        company_id: int,
        bill_id: int,
        *,
        writeoff_account_code: str,
        reason: str = "",
        written_off_by: int | None = None,
        writeoff_date: str | date | None = None,

        # ✅ optional VAT handling (like your AR vat_relief)
        vat_adjust: bool = False,
        vat_input_account: str | None = None,
    ) -> int:
        """
        Write-off a posted AP bill (reduce AP, offset to income/expense-reduction).
        """

        schema = self.company_schema(company_id)

        def money(x) -> Decimal:
            return Decimal(str(x or "0")).quantize(Decimal("0.01"))

        # ✅ date
        if writeoff_date is None or str(writeoff_date).strip() == "":
            wo_date = date.today()
        elif isinstance(writeoff_date, date):
            wo_date = writeoff_date
        else:
            wo_date = date.fromisoformat(str(writeoff_date)[:10])

        # ✅ Period lock gate (AP module)
        if self.is_date_locked(company_id, tx_date=wo_date, module="ap"):
            raise ValueError(f"PERIOD_LOCKED|ap|{wo_date.isoformat()}")

        writeoff_account_code = (writeoff_account_code or "").strip()
        if not writeoff_account_code:
            raise ValueError("writeoff_account_code is required")

        wo_reason = (reason or "").strip() or "Vendor bill write-off"

        with self._conn_cursor() as (conn, cur):
            try:
                # 1) Lock bill
                cur.execute(
                    f"""
                    SELECT
                        id, number, status, vendor_id,
                        posted_journal_id, reversed_journal_id,
                        writeoff_journal_id,
                        total_amount, subtotal_amount, vat_amount
                    FROM {schema}.bills
                    WHERE id=%s
                    FOR UPDATE;
                    """,
                    (bill_id,),
                )
                b = cur.fetchone()
                if not b:
                    raise ValueError("Bill not found")

                status = (b.get("status") or "").lower()
                bill_no = b.get("number") or f"BILL-{bill_id}"
                vendor_id = b.get("vendor_id")

                if status != "posted":
                    raise ValueError("Only posted bills can be written off")

                if b.get("reversed_journal_id"):
                    raise ValueError("Cannot write-off: bill is reversed")

                if b.get("writeoff_journal_id"):
                    raise ValueError("Bill already written off")

                if not b.get("posted_journal_id"):
                    raise ValueError("Bill has no posted_journal_id")

                # 2) Block write-off if allocations exist
                cur.execute(
                    f"""
                    SELECT COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid
                    FROM {schema}.vendor_payment_allocations a
                    WHERE a.bill_id = %s
                    AND a.company_id = %s;
                    """,
                    (bill_id, company_id),
                )
                paid_row = cur.fetchone() or {}
                paid = money(paid_row.get("paid"))
                if paid > money("0.00"):
                    raise ValueError("Cannot write-off: bill has allocations. Unallocate first.")

                # 3) Amounts (from bills header)
                gross = money(b.get("total_amount"))
                net   = money(b.get("subtotal_amount"))
                vat   = money(b.get("vat_amount"))

                if gross <= money("0.00"):
                    raise ValueError("Bill total is zero; nothing to write off")

                # 4) Resolve AP control
                ap_control = self.get_control_account_code(company_id, "AP_CONTROL")
                if not ap_control:
                    # fallback if you have a known code like AR did (adjust if yours differs)
                    row = self.get_account_row_for_posting(company_id, "9003")  # <— change if you use another
                    ap_control = row[1] if row else None
                if not ap_control:
                    raise ValueError("AP control account not configured (AP_CONTROL / fallback)")

                # 5) Create journal header
                wo_ref = f"WO-{bill_no}"
                wo_desc = f"Write-off {bill_no} | {wo_reason}"
                je_date = wo_date.isoformat()

                wo_entry = {
                    "date": je_date,
                    "ref": wo_ref,
                    "description": wo_desc,
                    "gross_amount": float(gross),
                    "net_amount": float(net),
                    "vat_amount": float(vat),
                    "source": "bill_writeoff",
                    "source_id": int(bill_id),
                }

                writeoff_journal_id = int(self.insert_journal(company_id, wo_entry, cur=cur) or 0)
                if writeoff_journal_id <= 0:
                    raise ValueError("Failed to create write-off journal")

                # 6) Ledger lines
                # DR AP (reduce liability) — keep vendor_id so AP subledger closes
                dr_ap = {
                    "account_code": ap_control,
                    "debit": float(gross),
                    "credit": 0.0,
                    "description": wo_desc,
                    "memo": wo_reason,
                }
                self.insert_ledger(company_id, writeoff_journal_id, je_date, dr_ap, ref=wo_ref, vendor_id=vendor_id, cur=cur)
                self.update_trial_balance(company_id, dr_ap, cur=cur)

                if vat_adjust and vat > money("0.00"):
                    # ✅ VAT-aware: CR writeoff net + CR input VAT (reversing claim)
                    if not vat_input_account:
                        raise ValueError("vat_input_account required when vat_adjust=true")

                    cr_net = {
                        "account_code": writeoff_account_code,
                        "debit": 0.0,
                        "credit": float(net),
                        "description": wo_desc,
                        "memo": wo_reason,
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, cr_net, ref=wo_ref, vendor_id=None, cur=cur)
                    self.update_trial_balance(company_id, cr_net, cur=cur)

                    cr_vat = {
                        "account_code": vat_input_account,
                        "debit": 0.0,
                        "credit": float(vat),
                        "description": wo_desc,
                        "memo": "Reverse input VAT on bill write-off",
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, cr_vat, ref=wo_ref, vendor_id=None, cur=cur)
                    self.update_trial_balance(company_id, cr_vat, cur=cur)

                else:
                    # ✅ Simple: CR one account for full gross
                    cr = {
                        "account_code": writeoff_account_code,
                        "debit": 0.0,
                        "credit": float(gross),
                        "description": wo_desc,
                        "memo": wo_reason,
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, cr, ref=wo_ref, vendor_id=None, cur=cur)
                    self.update_trial_balance(company_id, cr, cur=cur)

                # 7) Stamp bill
                cur.execute(
                    f"""
                    UPDATE {schema}.bills
                    SET status='written_off',
                        writeoff_journal_id=%s,
                        written_off_at=NOW(),
                        written_off_by=%s,
                        writeoff_reason=%s,
                        updated_at=NOW()
                    WHERE id=%s
                    RETURNING id;
                    """,
                    (writeoff_journal_id, written_off_by, wo_reason, bill_id),
                )
                if not cur.fetchone():
                    raise ValueError("Failed to stamp bill written off")

                conn.commit()
                return writeoff_journal_id

            except Exception:
                conn.rollback()
                raise

    # ---------------------------
    # CREDIT PROFILES (per-company, approvals)
    # ---------------------------
    def insert_credit_profile(
        self,
        company_id: int,
        customer_id: int,
        payload: Dict[str, Any],
        created_by_user_id: Optional[int] = None,
        created_by_role: Optional[str] = None,
    ) -> int:
        """
        Create a new credit profile for a customer.
        'payload' should match your CustomerCreditProfile JSON blueprint.
        """
        schema = self.company_schema(company_id)
       # self.ensure_company_schema(company_id)

        sql = f"""
            INSERT INTO {schema}.credit_profiles (
                company_id,
                customer_id,
                status,
                risk_band,
                requested_limit,
                requested_terms,
                approved_limit,
                approved_terms,
                created_by_user_id,
                created_by_role,
                payload
            )
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s::jsonb)
            RETURNING id;
        """

        risk_band = payload.get("riskBand") or payload.get("risk_band")
        requested_limit = payload.get("requestedLimit") or payload.get("requested_limit")
        requested_terms = payload.get("requestedTerms") or payload.get("requested_terms")
        status = payload.get("status") or "pending"

        params = (
            company_id,
            customer_id,
            status,
            risk_band,
            requested_limit,
            requested_terms,
            payload.get("approvedLimit"),
            payload.get("approvedTerms"),
            created_by_user_id,
            created_by_role,
            psycopg2.extras.Json(payload),
        )

        profile_id = self.execute_sql(sql, params) or 0

        # ✅ Stamp customer record so UI can show "Pending approval"
        if profile_id:
            try:
                self.update_customer(
                    company_id,
                    customer_id,
                    credit_status="pending",
                    credit_profile_id=profile_id,
                )
            except Exception:
                # don't block credit profile creation if customer stamping fails
                pass

        return profile_id

    def list_pending_credit_profiles(self, company_id: int) -> List[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        sql = f"""
        SELECT
            cp.id,
            cp.customer_id,
            c.name AS customer_name,
            c.email AS customer_email,
            cp.requested_limit,
            cp.requested_terms,
            cp.risk_band,
            cp.status,
            cp.created_at,
            NULL::text AS created_by,
            co.currency
        FROM {schema}.credit_profiles cp
        JOIN {schema}.customers c ON cp.customer_id = c.id
        JOIN public.companies co ON co.id = %s
        WHERE cp.status LIKE 'pending%%'
        ORDER BY cp.created_at DESC
        """

        with self._conn_cursor() as (conn, cur):
            cur.execute(sql, (company_id,))
            rows = cur.fetchall() or []

        current_app.logger.warning("list_pending_credit_profiles company=%s rows=%s", company_id, len(rows))

        items = []
        for r in rows:
            items.append({
                "id": r["id"],
                "customerId": r["customer_id"],
                "customerName": r["customer_name"],
                "requestedLimit": r["requested_limit"],
                "requestedTerms": r["requested_terms"],
                "riskBand": r["risk_band"],
                "status": r["status"],
                "currency": r["currency"],
                "email": r.get("customer_email"),
                "createdBy": r.get("created_by"),
                "createdAt": r["created_at"].isoformat() if r.get("created_at") else None,
            })

        return items
    
    def get_credit_profile(self, company_id: int, profile_id: int) -> Optional[Dict[str, Any]]:
        """
        Get the full credit profile payload + top-level fields.
        Used by /api/credit/profile/<id> to render the right-hand pane.
        """
        schema = f"company_{company_id}"
        sql = f"""
        SELECT
            cp.*,
            c.name AS customer_name,
            co.currency
        FROM {schema}.credit_profiles cp
        JOIN {schema}.customers c ON cp.customer_id = c.id
        JOIN public.companies co ON co.id = %s
        WHERE cp.id = %s
        LIMIT 1;
        """
        row = self.fetch_one(sql, (company_id, profile_id))
        if not row:
            return None

        payload = row.get("payload") or {}
        # overlay / enrich the payload with top-level fields the frontend expects
        payload["id"] = row["id"]
        payload["customerId"] = row["customer_id"]
        payload["customerName"] = row["customer_name"]
        payload["currency"] = row["currency"]
        payload["status"] = row.get("status") or payload.get("status")
        payload["riskBand"] = row.get("risk_band") or payload.get("riskBand")
        payload["requestedLimit"] = row.get("requested_limit") or payload.get("requestedLimit")
        payload["requestedTerms"] = row.get("requested_terms") or payload.get("requestedTerms")
        payload["approvedLimit"] = row.get("approved_limit") or payload.get("approvedLimit")
        payload["approvedTerms"] = row.get("approved_terms") or payload.get("approvedTerms")
        payload["createdAt"] = row.get("created_at").isoformat() if row.get("created_at") else payload.get("createdAt")
        payload["updatedAt"] = row.get("updated_at").isoformat() if row.get("updated_at") else payload.get("updatedAt")
        return payload

    
    def update_credit_decision(
        self,
        company_id: int,
        profile_id: int,
        status: str,
        risk_band: Optional[str],
        approved_limit: Optional[float],
        approved_terms: Optional[str],
        decision_payload: Dict[str, Any],
        reviewer_role: str,
        reviewer_user_id: int,
    ) -> bool:
        schema = f"company_{company_id}"

        role = (reviewer_role or "").strip().lower()

        # Treat junior like senior reviewer bucket
        is_senior_stage = role in {"junior", "senior", "manager", "accountant"}

        if is_senior_stage:
            set_extra = """
                senior_reviewer_id = %s,
                senior_reviewer_role = %s,
                senior_reviewed_at = NOW()
            """
        else:
            set_extra = """
                cfo_reviewer_id = %s,
                cfo_reviewer_role = %s,
                cfo_reviewed_at = NOW()
            """

        sql = f"""
        UPDATE {schema}.credit_profiles
        SET
            status = %s,
            risk_band = %s,
            approved_limit = %s,
            approved_terms = %s,
            payload = COALESCE(payload, '{{}}'::jsonb) || %s::jsonb,
            updated_at = NOW(),
            {set_extra}
        WHERE company_id = %s
        AND id = %s;
        """

        params = (
            str(status).strip().lower(),
            (risk_band or None),
            approved_limit,
            (approved_terms or None),
            psycopg2.extras.Json(decision_payload or {}),
            int(reviewer_user_id),
            str(role),
            int(company_id),
            int(profile_id),
        )

        with self._conn_cursor() as (_c, cur):
            cur.execute(sql, params)
            return cur.rowcount > 0
    
    def get_credit_profile_row(self, company_id: int, profile_id: int) -> Optional[Dict[str, Any]]:
        schema = f"company_{company_id}"
        sql = f"""
        SELECT id, customer_id, status, approved_limit, approved_terms
        FROM {schema}.credit_profiles
        WHERE id = %s
        LIMIT 1;
        """
        return self.fetch_one(sql, (profile_id,))
    
