    def create_company_bank_account(self, company_id: int, payload: Dict[str, Any]) -> Dict[str, Any]:
        """
        Create a bank account row in company_{id}.company_bank_accounts.
        payload keys (expected):
        name, bank_name, account_name, account_number,
        branch_code, swift_code, currency, ledger_account_code,
        is_default_receipts, is_default_payments
        """
        schema = self.company_schema(company_id)
       # self.ensure_company_schema(company_id)

        sql = f"""
        INSERT INTO {schema}.company_bank_accounts (
            company_id,
            name,
            bank_name,
            account_name,
            account_number,
            branch_code,
            swift_code,
            currency,
            ledger_account_code,
            is_default_receipts,
            is_default_payments
        )
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        RETURNING *;
        """

        params = (
            company_id,                              # ← force from URL, not from JSON
            payload.get("name"),
            payload.get("bank_name"),
            payload.get("account_name"),
            payload.get("account_number"),
            payload.get("branch_code"),
            payload.get("swift_code"),
            payload.get("currency"),
            payload.get("ledger_account_code"),
            bool(payload.get("is_default_receipts")),
            bool(payload.get("is_default_payments")),
        )
        return self.fetch_one(sql, params) or {}


