    def build_journal_from_statement(self, stmt_id: int) -> int:
        """
        Build and post a bank journal from a bank statement.
        NOTE: This assumes the following methods exist on DatabaseService:
        - get_bank_statement_with_lines
        - get_company_bank_account
        - post_journal_batch
        - mark_bank_statement_posted
        """
        stmt = self.get_bank_statement_with_lines(stmt_id)
        bank_acct = self.get_company_bank_account(stmt.company_id, stmt.bank_account_id)

        bank_gl = bank_acct["ledger_account_code"]
        recv_gl = "1100"   # Unallocated Receipts
        pay_gl  = "2100"   # Unallocated Payments

        lines = []
        for ln in stmt.lines:
            date = ln.txn_date
            desc = ln.description or ln.reference or "Bank transaction"

            if ln.credit and ln.credit > 0:
                amount = float(ln.credit)
                # Deposit: DR Bank, CR Unallocated Receipts
                lines.append({
                    "account_code": bank_gl,
                    "debit": amount,
                    "credit": 0.0,
                    "description": f"{desc} (deposit)",
                })
                lines.append({
                    "account_code": recv_gl,
                    "debit": 0.0,
                    "credit": amount,
                    "description": f"{desc} (unallocated receipt)",
                })

            elif ln.debit and ln.debit > 0:
                amount = float(ln.debit)
                # Payment: DR Unallocated Payments, CR Bank
                lines.append({
                    "account_code": pay_gl,
                    "debit": amount,
                    "credit": 0.0,
                    "description": f"{desc} (payment)",
                })
                lines.append({
                    "account_code": bank_gl,
                    "debit": 0.0,
                    "credit": amount,
                    "description": f"{desc} (bank outflow)",
                })

        total_dr = sum(l["debit"] for l in lines)
        total_cr = sum(l["credit"] for l in lines)
        if abs(total_dr - total_cr) > 0.01:
            raise ValueError("Bank journal not balanced")

        payload = {
            "date": stmt.date_to.isoformat(),
            "ref": f"BANK-{stmt.id}",
            "description": f"Bank statement import #{stmt.id}",
            "gross_amount": total_dr,
            "net_amount": total_dr,
            "vat_amount": 0,
            "lines": lines,
        }

        journal_id = self.post_journal_batch(stmt.company_id, payload)
        self.mark_bank_statement_posted(stmt.id, journal_id)
        return journal_id


    def get_invoice_with_relations(self, company_id: int, invoice_id: int) -> Optional[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        sql = f"""
        SELECT
            -- invoice
            i.id,
            i.company_id,
            i.customer_id,
            i.number,
            i.invoice_date,
            i.due_date,
            i.currency,
            i.subtotal_amount,
            i.discount_amount,
            i.discount_rate,
            i.vat_amount,

            -- ✅ expose BOTH keys to avoid frontend mismatch
            i.total_amount AS total_amount,
            i.total_amount AS total,

            i.status,
            i.bank_account_id,
            i.notes,

            -- ✅ payment totals (safe: subquery prevents join multiplication)
            COALESCE(pay.paid_amount, 0)::numeric(18,2) AS paid_amount,
            GREATEST(i.total_amount - COALESCE(pay.paid_amount, 0), 0)::numeric(18,2) AS outstanding_amount,

            CASE
                WHEN LOWER(COALESCE(i.status,'')) IN ('void','written_off') THEN LOWER(i.status)
                WHEN GREATEST(i.total_amount - COALESCE(pay.paid_amount, 0), 0) <= 0 THEN 'paid'
                WHEN COALESCE(pay.paid_amount, 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status,

            -- customer
            c.name             AS customer_name,
            c.email            AS customer_email,
            c.phone            AS customer_phone,
            c.billing_address  AS customer_address,
            c.shipping_address AS customer_shipping_address,
            c.country          AS customer_country,
            c.tax_number       AS customer_tax_number,
            c.vat_number       AS customer_vat_number,
            c.contacts         AS customer_contacts,

            -- company (public.companies)
            co.name            AS company_name,
            co.company_email   AS company_email,
            co.company_reg_no  AS company_reg_no,
            co.tin             AS company_tin,
            co.vat             AS company_vat,
            co.country         AS company_country,
            co.currency        AS company_currency,

            -- branding (public.company_branding)
            cb.company_id      AS branding_company_id,
            cb.logo_url        AS branding_logo_url,
            cb.footer_text     AS branding_footer_text,
            cb.contact_phone   AS branding_contact_phone,
            cb.contact_email   AS branding_contact_email,
            cb.website         AS branding_website,
            cb.address         AS branding_address,
            cb.vat_no          AS branding_vat_no,

            -- bank (company schema)
            ba.id              AS bank_id,
            ba.name            AS bank_label,
            ba.bank_name,
            ba.account_name,
            ba.account_number,
            ba.branch_code,
            ba.swift_code,
            ba.currency        AS bank_currency,
            ba.ledger_account_code

        FROM {schema}.invoices i
        JOIN {schema}.customers c
        ON c.id = i.customer_id

        JOIN public.companies co
        ON co.id = %s

        LEFT JOIN public.company_branding cb
        ON cb.company_id = co.id

        LEFT JOIN {schema}.company_bank_accounts ba
        ON ba.id = i.bank_account_id

        -- ✅ allocations summed separately (cannot be multiplied by joins)
        LEFT JOIN (
            SELECT invoice_id, SUM(amount)::numeric(18,2) AS paid_amount
            FROM {schema}.receipt_allocations
            WHERE company_id = %s AND invoice_id = %s
            GROUP BY invoice_id
        ) pay ON pay.invoice_id = i.id

        WHERE i.id = %s
        AND i.company_id = %s

        LIMIT 1;
        """

        row = self.fetch_one(sql, (int(company_id), int(company_id), int(invoice_id), int(invoice_id), int(company_id)))
        if not row:
            return None

        # ✅ inject default bank if invoice has none
        if not row.get("bank_id"):
            default_bank = self.get_default_receipts_bank_account(company_id)
            if default_bank:
                row.update({
                    "bank_id": default_bank["id"],
                    "bank_label": default_bank["name"],
                    "bank_name": default_bank["bank_name"],
                    "account_name": default_bank["account_name"],
                    "account_number": default_bank["account_number"],
                    "branch_code": default_bank.get("branch_code"),
                    "swift_code": default_bank.get("swift_code"),
                    "bank_currency": default_bank.get("currency"),
                    "ledger_account_code": default_bank.get("ledger_account_code"),
                })

        
        from decimal import Decimal

        try:
            total = Decimal(str(row.get("total_amount") or row.get("total") or "0"))
            paid  = Decimal(str(row.get("paid_amount") or "0"))

            if paid < 0:
                paid = Decimal("0.00")

            outstanding = total - paid
            if outstanding < 0:
                outstanding = Decimal("0.00")

            row["paid_amount"] = float(paid)
            row["outstanding_amount"] = float(outstanding)

            st = (row.get("status") or "").strip().lower()
            if st in {"void", "written_off"}:
                row["payment_status"] = st
            elif outstanding <= Decimal("0.00"):
                row["payment_status"] = "paid"
            elif paid > Decimal("0.00"):
                row["payment_status"] = "partial"
            else:
                row["payment_status"] = "unpaid"

        except Exception:
            row["payment_status"] = "unpaid"

        return row

    def mark_invoice_sent(self, company_id: int, invoice_id: int) -> None:
        """
        Simple helper to mark an invoice as 'sent'.
        """
        schema = self.company_schema(company_id)
        sql = f"""
        UPDATE {schema}.invoices
        SET status = 'sent',
            updated_at = NOW()
        WHERE id = %s;
        """
        self.execute_sql(sql, (invoice_id,))

    def list_company_invoices(self, company_id: int) -> List[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        sql = f"""
        SELECT
            i.id,
            i.number,
            i.invoice_date,
            i.due_date,

            -- document status only (draft/posted/void/written_off)
            i.status,

            -- totals
            i.total_amount,
            c.name AS customer_name,

            -- ✅ payment totals
            COALESCE(SUM(ra.amount), 0)::numeric(18,2) AS paid_amount,
            GREATEST(i.total_amount - COALESCE(SUM(ra.amount), 0), 0)::numeric(18,2) AS outstanding_amount,

            -- ✅ payment status derived
            CASE
                WHEN LOWER(COALESCE(i.status,'')) IN ('void','written_off') THEN LOWER(i.status)
                WHEN GREATEST(i.total_amount - COALESCE(SUM(ra.amount), 0), 0) <= 0 THEN 'paid'
                WHEN COALESCE(SUM(ra.amount), 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status

        FROM {schema}.invoices i
        LEFT JOIN {schema}.customers c
            ON c.id = i.customer_id
        LEFT JOIN {schema}.receipt_allocations ra
            ON ra.company_id = i.company_id
        AND ra.invoice_id = i.id

        GROUP BY i.id, c.id
        ORDER BY i.invoice_date DESC, i.id DESC
        LIMIT 100;
        """
        return self.fetch_all(sql)


    def get_invoice_full(self, company_id: int, invoice_id: int) -> Optional[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        # 1) Hard check invoice exists in tenant schema
        base = self.fetch_one(
            f"SELECT * FROM {schema}.invoices WHERE id = %s AND company_id = %s LIMIT 1;",
            (int(invoice_id), int(company_id))
        )
        if not base:
            return None

        # 2) Now fetch enriched header (relations + payment sums)
        header = self.get_invoice_with_relations(company_id, invoice_id)
        if not header:
            # fallback to base if relations query fails
            header = base

        # 3) Lines
        lines_sql = f"""
        SELECT *
        FROM {schema}.invoice_lines
        WHERE invoice_id = %s
        ORDER BY line_no ASC, id ASC;
        """
        header["lines"] = self.fetch_all(lines_sql, (invoice_id,))
        return header

    # ---------------------------
    # INVOICES (per company)
    # ---------------------------
    # ✅ Updated: support HEADER discount_rate/discount_amount and recompute VAT after header discount
    def _insert_invoice_with_lines_cur(
        self,
        company_id: int,
        header: Dict[str, Any],
        lines: List[Dict[str, Any]],
        cur,
    ) -> int:
        schema = self.company_schema(company_id)

        status = (header.get("status") or "draft").strip().lower()

        if status != "draft" and not (header.get("number") or "").strip():
            header["number"] = self.next_invoice_number_cur(company_id, cur)
        else:
            # keep drafts blank
            header["number"] = (header.get("number") or "").strip() or None

        # ---------- line totals (gross before HEADER discount) ----------
        subtotal_gross = 0.0
        line_discount_total = 0.0
        vatable_gross = 0.0
        prepared_lines: List[Dict[str, Any]] = []

        for idx, ln in enumerate(lines, start=1):
            qty = float(ln.get("quantity") or 0)
            price = float(ln.get("unit_price") or 0)

            disc_line = money(ln.get("discount_amount") or 0)
            vat_rate = float(ln.get("vat_rate") or 0)

            line_net_gross = max(0.0, (qty * price) - disc_line)
            line_vat_gross = line_net_gross * (vat_rate / 100.0)
            line_total_gross = line_net_gross + line_vat_gross

            line_net_gross = money(line_net_gross)
            line_vat_gross = money(line_vat_gross)
            line_total_gross = money(line_total_gross)

            subtotal_gross = money(subtotal_gross + line_net_gross)
            line_discount_total = money(line_discount_total + disc_line)

            if vat_rate > 0:
                vatable_gross = money(vatable_gross + line_net_gross)

            # ✅ item/service fields (ID-based)
            item_type = (ln.get("item_type") or ln.get("itemType") or "").strip().lower() or None

            item_id_raw = ln.get("item_id") or ln.get("itemId")
            try:
                item_id = int(item_id_raw) if item_id_raw is not None and str(item_id_raw).isdigit() else None
            except Exception:
                item_id = None

            item_code = (ln.get("item_code") or ln.get("itemCode") or ln.get("sku") or ln.get("code") or "").strip() or None

            vat_code = (ln.get("vat_code") or ln.get("vatCode") or "").strip().upper() or None

            prepared_lines.append({
                "line_no": idx,
                "item_name": (ln.get("item_name") or ln.get("itemName") or "").strip() or None,
                "description": (ln.get("description") or "").strip(),
                "account_code": ln.get("account_code"),
                "quantity": qty,
                "unit_price": price,
                "discount_amount": disc_line,
                "net_amount": line_net_gross,
                "vat_rate": vat_rate,
                "vat_amount": line_vat_gross,
                "total_amount": line_total_gross,

                # ✅ these now flow into DB insert
                "item_type": item_type,   # 'inventory' | 'service' | 'gl'
                "item_id": item_id,       # int
                "item_code": item_code,   # sku/service code
                "vat_code": vat_code,     # STANDARD/ZERO/EXEMPT/CUSTOM etc
            })

        # ---------- HEADER discount (percent 0..1) ----------
        disc_rate = header.get("discount_rate")
        if disc_rate is None:
            disc_rate = header.get("discount")

        try:
            disc_rate = float(disc_rate or 0.0)
        except Exception:
            disc_rate = 0.0
        disc_rate = max(0.0, min(1.0, disc_rate))

        other = header.get("other")
        try:
            other = float(other or 0.0)
        except Exception:
            other = 0.0

        header_discount_amt = money(subtotal_gross * disc_rate)

        # VAT-able base = sum of net amounts where vat_rate > 0
        vatable_base = money(sum(
            float(p.get("net_amount") or 0.0)
            for p in prepared_lines
            if float(p.get("vat_rate") or 0.0) > 0.0
        ))

        vat_total = 0.0
        for p in prepared_lines:
            rate = float(p.get("vat_rate") or 0.0)
            net  = float(p.get("net_amount") or 0.0)

            if rate > 0.0 and vatable_base > 0.0:
                alloc = header_discount_amt * (net / vatable_base)
            else:
                alloc = 0.0

            net_after = money(max(0.0, net - alloc))
            line_vat_after = money(net_after * (rate / 100.0))
            vat_total = money(vat_total + line_vat_after)

        subtotal_after = money(max(0.0, subtotal_gross - header_discount_amt + other))
        grand_total = money(subtotal_after + vat_total)
        discount_total = money(line_discount_total + header_discount_amt)

        header.setdefault("currency", None)
        header.setdefault("notes", None)
        header.setdefault("bank_account_id", None)
        header.setdefault("status", "draft")

        status = header.get("status") or "draft"

        issued_at = header.get("issued_at")
        issued_by = header.get("issued_by")
        try:
            issued_by = int(issued_by) if issued_by is not None else None
        except Exception:
            issued_by = None

        # auto-fill issued_at on insert if status is issued/sent
        if issued_at is None and status in ("issued", "sent"):
            issued_at = datetime.utcnow()  # or let SQL NOW() do it (see below)

        # insert header
        cur.execute(
            f"""
            INSERT INTO {schema}.invoices (
            company_id, customer_id, number, invoice_date, due_date, currency,
            subtotal_amount, discount_amount, discount_rate, other_amount,
            vat_amount, total_amount,
            status, bank_account_id, notes,
            issued_at, issued_by
            )
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            RETURNING id;
            """,
            (
                company_id,
                int(header["customer_id"]),
                header["number"],
                header["invoice_date"],
                header.get("due_date"),
                header.get("currency"),
                subtotal_after,
                discount_total,
                disc_rate,
                other,
                vat_total,
                grand_total,
                status,
                header.get("bank_account_id"),
                header.get("notes"),
                issued_at,
                issued_by,
            ),
        )

        row = cur.fetchone()
        invoice_id = row["id"] if isinstance(row, dict) else row[0]

        # insert lines
        for pl in prepared_lines:
            cur.execute(
                f"""
                INSERT INTO {schema}.invoice_lines (
                company_id, invoice_id, line_no,
                item_name, description, account_code,
                quantity, unit_price, discount_amount, net_amount,
                vat_rate, vat_amount, total_amount,
                item_type, item_id, item_code, vat_code
                )
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s);
                """,
                (
                    company_id,
                    invoice_id,
                    pl["line_no"],
                    pl.get("item_name"),
                    pl["description"],
                    pl["account_code"],
                    pl["quantity"],
                    pl["unit_price"],
                    pl["discount_amount"],
                    pl["net_amount"],
                    pl["vat_rate"],
                    pl["vat_amount"],
                    pl["total_amount"],
                    pl.get("item_type"),
                    pl.get("item_id"),
                    pl.get("item_code"),
                    pl.get("vat_code"),
                ),
            )

        return int(invoice_id)

    def insert_invoice_with_lines(self, company_id, header, lines, cur=None) -> int:
        if cur is not None:
            return self._insert_invoice_with_lines_cur(company_id, header, lines, cur)

        with self._conn_cursor() as (conn, _cur):
            try:
                invoice_id = self._insert_invoice_with_lines_cur(company_id, header, lines, _cur)
                conn.commit()
                return invoice_id
            except Exception:
                conn.rollback()
                raise

    def get_invoice_with_lines(self, company_id: int, invoice_id: int) -> Optional[Dict[str, Any]]:
        schema = self.company_schema(company_id)

        header_sql = f"""
        SELECT *
        FROM {schema}.invoices
        WHERE company_id = %s AND id = %s
        LIMIT 1;
        """
        header = self.fetch_one(header_sql, (int(company_id), int(invoice_id)))
        if not header:
            return None

        lines_sql = f"""
        SELECT *
        FROM {schema}.invoice_lines
        WHERE company_id = %s AND invoice_id = %s
        ORDER BY line_no ASC, id ASC;
        """
        lines = self.fetch_all(lines_sql, (int(company_id), int(invoice_id)))

        header["lines"] = lines or []
        return header

    def _update_invoice_with_lines_cur(
        self,
        company_id: int,
        invoice_id: int,
        header: Dict[str, Any],
        lines: List[Dict[str, Any]],
        cur,
    ) -> None:
        schema = self.company_schema(company_id)

        # ---------- totals (same logic you already have) ----------
        subtotal_gross = 0.0
        line_discount_total = 0.0
        prepared: List[Dict[str, Any]] = []

        for idx, ln in enumerate(lines, start=1):
            qty = float(ln.get("quantity") or 0)
            price = float(ln.get("unit_price") or 0)

            disc_line = money(ln.get("discount_amount") or 0)
            vat_rate = float(ln.get("vat_rate") or 0)

            line_net_gross = max(0.0, (qty * price) - disc_line)
            line_vat_gross = line_net_gross * (vat_rate / 100.0)
            line_total_gross = line_net_gross + line_vat_gross

            line_net_gross = money(line_net_gross)
            line_vat_gross = money(line_vat_gross)
            line_total_gross = money(line_total_gross)

            subtotal_gross = money(subtotal_gross + line_net_gross)
            line_discount_total = money(line_discount_total + disc_line)

            item_type = (ln.get("item_type") or ln.get("itemType") or "").strip().lower() or None
            item_id_raw = ln.get("item_id") or ln.get("itemId")
            try:
                item_id = int(item_id_raw) if item_id_raw is not None and str(item_id_raw).isdigit() else None
            except Exception:
                item_id = None

            item_code = (ln.get("item_code") or ln.get("itemCode") or ln.get("sku") or ln.get("code") or "").strip() or None
            vat_code  = (ln.get("vat_code") or ln.get("vatCode") or "").strip().upper() or None

            if item_type == "inventory" and not item_id:
                raise ValueError(f"Invoice line {idx} inventory item missing item_id")

            prepared.append({
                "line_no": idx,
                "item_name": (ln.get("item_name") or ln.get("itemName") or "").strip() or None,
                "description": (ln.get("description") or "").strip(),
                "account_code": ln.get("account_code"),
                "quantity": qty,
                "unit_price": price,
                "discount_amount": disc_line,
                "net_amount": line_net_gross,
                "vat_rate": vat_rate,
                "vat_amount": line_vat_gross,
                "total_amount": line_total_gross,
                "item_type": item_type,
                "item_id": item_id,
                "item_code": item_code,
                "vat_code": vat_code,
            })

        # ---------- header discount/other ----------
        disc_rate = header.get("discount_rate")
        if disc_rate is None:
            disc_rate = header.get("discount")

        try:
            disc_rate = float(disc_rate or 0.0)
        except Exception:
            disc_rate = 0.0
        disc_rate = max(0.0, min(1.0, disc_rate))

        def _to_float(x, default=0.0):
            try:
                if x is None:
                    return default
                if isinstance(x, str):
                    x = x.replace(",", "").strip()
                return float(x)
            except Exception:
                return default

        other = money(_to_float(header.get("other"), 0.0))
        header_discount_amt = money(subtotal_gross * disc_rate)

        vatable_base = money(sum(
            float(p.get("net_amount") or 0.0)
            for p in prepared
            if float(p.get("vat_rate") or 0.0) > 0.0
        ))

        vat_total = 0.0
        for p in prepared:
            rate = float(p.get("vat_rate") or 0.0)
            net  = float(p.get("net_amount") or 0.0)
            alloc = header_discount_amt * (net / vatable_base) if (rate > 0.0 and vatable_base > 0.0) else 0.0
            net_after = money(max(0.0, net - alloc))
            vat_total = money(vat_total + money(net_after * (rate / 100.0)))

        subtotal_after = money(max(0.0, subtotal_gross - header_discount_amt + other))
        grand_total = money(subtotal_after + vat_total)
        discount_total = money(line_discount_total + header_discount_amt)

        # ---------- lock + status guard ----------
        cur.execute(
            f"SELECT status, posted_journal_id, number FROM {schema}.invoices WHERE id=%s FOR UPDATE;",
            (int(invoice_id),),
        )
        hdr = cur.fetchone() or {}
        if not hdr:
            raise ValueError("Invoice not found")
        if (str(hdr.get("status") or "").lower() == "posted") or hdr.get("posted_journal_id"):
            raise ValueError("Posted invoices cannot be edited")

        # ---------- number rules on leaving draft ----------
        new_status = (header.get("status") or "draft").strip().lower()
        existing_number = (hdr.get("number") or "").strip()
        incoming_number = (header.get("number") or "").strip()

        if new_status == "draft":
            header["number"] = None
        elif not (incoming_number or existing_number):
            header["number"] = self.next_invoice_number_cur(company_id, cur)
        else:
            header["number"] = incoming_number or existing_number

        issued_at = header.get("issued_at")
        issued_by = header.get("issued_by")
        try:
            issued_by = int(issued_by) if issued_by is not None else None
        except Exception:
            issued_by = None

        # ---------- update header ----------
        cur.execute(
            f"""
            UPDATE {schema}.invoices
            SET
                customer_id     = %s,
                number          = %s,
                invoice_date    = %s,
                due_date        = %s,
                currency        = %s,
                subtotal_amount = %s,
                discount_amount = %s,
                discount_rate   = %s,
                other_amount    = %s,
                vat_amount      = %s,
                total_amount    = %s,
                status          = %s,
                bank_account_id = %s,
                notes           = %s,

                issued_by       = COALESCE(%s, issued_by),
                issued_at       = CASE
                                    WHEN (COALESCE(%s, status) IN ('issued','sent'))
                                    AND issued_at IS NULL
                                    THEN COALESCE(%s, NOW())
                                    ELSE issued_at
                                END,

                updated_at      = NOW()
            WHERE id = %s;
            """,
            (
                int(header["customer_id"]),
                header.get("number"),
                header.get("invoice_date"),
                header.get("due_date"),
                header.get("currency"),
                subtotal_after,
                discount_total,
                disc_rate,
                other,
                vat_total,
                grand_total,
                new_status,
                header.get("bank_account_id"),
                header.get("notes"),
                issued_by,
                new_status,
                issued_at,
                int(invoice_id),
            ),
        )

        # ---------- replace lines ----------
        cur.execute(
            f"DELETE FROM {schema}.invoice_lines WHERE company_id=%s AND invoice_id=%s;",
            (int(company_id), int(invoice_id)),
        )

        for pl in prepared:
            cur.execute(
                f"""
                INSERT INTO {schema}.invoice_lines (
                company_id, invoice_id, line_no,
                item_name, description, account_code,
                quantity, unit_price, discount_amount, net_amount,
                vat_rate, vat_amount, total_amount,
                item_type, item_id, item_code, vat_code
                )
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s);
                """,
                (
                    int(company_id),
                    int(invoice_id),
                    pl["line_no"],
                    pl.get("item_name"),
                    pl.get("description"),
                    pl.get("account_code"),
                    pl.get("quantity"),
                    pl.get("unit_price"),
                    pl.get("discount_amount"),
                    pl.get("net_amount"),
                    pl.get("vat_rate"),
                    pl.get("vat_amount"),
                    pl.get("total_amount"),
                    pl.get("item_type"),
                    pl.get("item_id"),
                    pl.get("item_code"),
                    pl.get("vat_code"),
                ),
            )

    def update_invoice_with_lines(
        self,
        company_id: int,
        invoice_id: int,
        header: Dict[str, Any],
        lines: List[Dict[str, Any]],
        cur=None,
    ) -> None:
        if cur is not None:
            return self._update_invoice_with_lines_cur(company_id, invoice_id, header, lines, cur)

        with self._conn_cursor() as (conn, _cur):
            try:
                self._update_invoice_with_lines_cur(company_id, invoice_id, header, lines, _cur)
                conn.commit()
            except Exception:
                conn.rollback()
                raise

    def get_invoice_with_lines_cur(self, company_id, invoice_id, cur, *, enrich=False):
        """
        Load invoice header + lines using the SAME cursor (same transaction snapshot).
        If enrich=False: no extra SELECTs that can poison posting transactions.
        """
        schema = self.company_schema(company_id)

        def _to_str(v) -> str:
            return "" if v is None else str(v)

        def _to_int(v, default=None):
            try:
                if v is None:
                    return default
                if isinstance(v, bool):
                    return default
                s = str(v).strip()
                if not s:
                    return default
                return int(float(s))
            except Exception:
                return default

        def _to_float(v, default=0.0) -> float:
            try:
                if v is None:
                    return float(default)
                if isinstance(v, str):
                    v = v.replace(",", "").strip()
                    if v == "":
                        return float(default)
                return float(v)
            except Exception:
                return float(default)

        def _lower(v) -> str:
            return _to_str(v).strip().lower()

        # --------------------------
        # 1) Load header (base)
        # --------------------------
        cur.execute(
            f"""
            SELECT *
            FROM {schema}.invoices
            WHERE company_id=%s AND id=%s
            LIMIT 1;
            """,
            (int(company_id), int(invoice_id)),
        )
        inv = cur.fetchone()
        if not inv:
            return None

        # --------------------------
        # 2) Load lines
        # --------------------------
        cur.execute(
            f"""
            SELECT *
            FROM {schema}.invoice_lines
            WHERE company_id=%s AND invoice_id=%s
            ORDER BY line_no ASC, id ASC;
            """,
            (int(company_id), int(invoice_id)),
        )
        lines = cur.fetchall() or []

        # Ensure dict shape (RealDictCursor expected)
        if not isinstance(inv, dict):
            return {"header": inv, "lines": lines}

        inv["lines"] = lines

        # --------------------------
        # 3) Inventory stock enrich (ONLY when enrich=True)
        # --------------------------
        if enrich:
            inv_item_ids = []
            for ln in lines:
                item_type = (ln.get("item_type") or ln.get("itemType") or "").strip().lower()
                item_id = ln.get("item_id") or ln.get("itemId")
                if item_type == "inventory" and item_id:
                    try:
                        inv_item_ids.append(int(item_id))
                    except Exception:
                        pass

            inv_item_ids = sorted(set(inv_item_ids))

            items_by_id = {}
            onhand_by_id = {}

            if inv_item_ids:
                # item settings
                cur.execute(
                    f"""
                    SELECT
                        id,
                        is_active,
                        track_stock,
                        valuation_method,
                        inventory_account,
                        cogs_account
                    FROM {schema}.inventory_items
                    WHERE company_id=%s AND id = ANY(%s::int[])
                    """,
                    (int(company_id), inv_item_ids),
                )
                for r in (cur.fetchall() or []):
                    items_by_id[int(r["id"])] = r

                # onhand from layers
                cur.execute(
                    f"""
                    SELECT
                        item_id,
                        COALESCE(SUM(qty_in - qty_out),0)::numeric(18,4) AS onhand
                    FROM {schema}.inventory_layers
                    WHERE company_id=%s AND item_id = ANY(%s::int[])
                    GROUP BY item_id
                    """,
                    (int(company_id), inv_item_ids),
                )
                for r in (cur.fetchall() or []):
                    onhand_by_id[int(r["item_id"])] = float(r["onhand"] or 0.0)

            # attach fields to each line
            for ln in lines:
                item_type = (ln.get("item_type") or ln.get("itemType") or "").strip().lower()
                item_id = ln.get("item_id") or ln.get("itemId")

                if item_type != "inventory" or not item_id:
                    ln["onhand"] = None
                    ln["track_stock"] = None
                    ln["is_item_active"] = None
                    ln["max_qty"] = None
                    continue

                try:
                    iid = int(item_id)
                except Exception:
                    ln["onhand"] = None
                    ln["track_stock"] = None
                    ln["is_item_active"] = None
                    ln["max_qty"] = None
                    continue

                it = items_by_id.get(iid) or {}
                onhand = float(onhand_by_id.get(iid, 0.0))

                track_stock = bool(it.get("track_stock", True))
                is_active = (it.get("is_active") is not False)

                ln["onhand"] = onhand
                ln["track_stock"] = track_stock
                ln["is_item_active"] = is_active
                ln["valuation_method"] = (it.get("valuation_method") or "AVG")
                ln["max_qty"] = onhand if track_stock else None
        else:
            # When enrich=False, keep these keys consistent (optional but nice)
            for ln in lines:
                ln.setdefault("onhand", None)
                ln.setdefault("track_stock", None)
                ln.setdefault("is_item_active", None)
                ln.setdefault("max_qty", None)

        # --------------------------
        # 4) Normalize common aliases
        # --------------------------
        if not inv.get("invoice_date") and inv.get("date"):
            inv["invoice_date"] = inv.get("date")
        if not inv.get("date") and inv.get("invoice_date"):
            inv["date"] = inv.get("invoice_date")

        if not inv.get("number") and inv.get("invoice_no"):
            inv["number"] = inv.get("invoice_no")

        if inv.get("subtotal_amount") is None and inv.get("subtotal") is not None:
            inv["subtotal_amount"] = inv.get("subtotal")

        if inv.get("vat_amount") is None and inv.get("vat_total") is not None:
            inv["vat_amount"] = inv.get("vat_total")

        if inv.get("total_amount") is None and inv.get("total") is not None:
            inv["total_amount"] = inv.get("total")

        if inv.get("notes") is None and inv.get("memo") is not None:
            inv["notes"] = inv.get("memo")

        # --------------------------
        # 5) Fallback totals compute
        # --------------------------
        subtotal = _to_float(inv.get("subtotal_amount"), None)
        vat_total = _to_float(inv.get("vat_amount"), None)
        grand_total = _to_float(inv.get("total_amount"), None)

        if subtotal is None or vat_total is None or grand_total is None:
            c_sub = c_vat = c_tot = 0.0
            for ln in lines:
                if not isinstance(ln, dict):
                    continue

                net = ln.get("net_amount")
                vat = ln.get("vat_amount")
                tot = ln.get("total_amount")

                if net is None:
                    qty = _to_float(ln.get("quantity"), 0.0)
                    up = _to_float(ln.get("unit_price"), 0.0)
                    disc = _to_float(ln.get("discount_amount"), 0.0)
                    net = max(0.0, (qty * up) - disc)

                if vat is None:
                    rate = _to_float(ln.get("vat_rate"), 0.0)
                    vat = float(net) * (rate / 100.0)

                if tot is None:
                    tot = float(net) + float(vat)

                c_sub += float(net or 0.0)
                c_vat += float(vat or 0.0)
                c_tot += float(tot or 0.0)

            if subtotal is None:
                inv["subtotal_amount"] = c_sub
            if vat_total is None:
                inv["vat_amount"] = c_vat
            if grand_total is None:
                inv["total_amount"] = c_tot

            inv.setdefault("subtotal", inv.get("subtotal_amount"))
            inv.setdefault("vat_total", inv.get("vat_amount"))
            inv.setdefault("total", inv.get("total_amount"))

        # --------------------------
        # 6) Normalize line fields
        # --------------------------
        normalized_lines = []
        for ln in lines:
            if not isinstance(ln, dict):
                continue

            if ln.get("item_type") is None and ln.get("itemType") is not None:
                ln["item_type"] = _lower(ln.get("itemType")) or None

            if ln.get("item_id") is None and ln.get("itemId") is not None:
                ln["item_id"] = _to_int(ln.get("itemId"))

            if ln.get("item_code") is None:
                ln["item_code"] = (ln.get("itemCode") or ln.get("sku") or ln.get("code") or ln.get("item_code"))

            if ln.get("vat_code") is None and ln.get("vatCode") is not None:
                ln["vat_code"] = _to_str(ln.get("vatCode")).strip().upper() or None

            for k in ("quantity", "unit_price", "discount_amount", "net_amount", "vat_rate", "vat_amount", "total_amount"):
                if k in ln and ln[k] is not None:
                    ln[k] = _to_float(ln[k], 0.0)

            normalized_lines.append(ln)

        inv["lines"] = normalized_lines

        # --------------------------
        # 7) Customer/bank enrich (ONLY when enrich=True)
        # --------------------------
        if enrich:
            cust_id = _to_int(inv.get("customer_id"))
            if cust_id:
                cur.execute(
                    f"SELECT * FROM {schema}.customers WHERE company_id=%s AND id=%s LIMIT 1;",
                    (int(company_id), int(cust_id)),
                )
                c = cur.fetchone()
                if isinstance(c, dict) and c:
                    inv["customer"] = c

            bank_id = _to_int(inv.get("bank_account_id"))
            if bank_id:
                cur.execute(
                    f"SELECT * FROM {schema}.company_bank_accounts WHERE company_id=%s AND id=%s LIMIT 1;",
                    (int(company_id), int(bank_id)),
                )
                b = cur.fetchone()
                if isinstance(b, dict) and b:
                    inv["bank_account"] = b

        return inv

    def post_invoice_to_gl(
        self,
        company_id: int,
        invoice_id: int,
        jlines: list[dict],
        *,
        enforce_credit: bool = True,
        require_approved: bool = False,
        ar_account=None,
        cur=None,
    ) -> int:
        from decimal import Decimal, ROUND_HALF_UP
        from datetime import date as _date

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))

        schema = f"company_{company_id}"

        def _run(_cur):
            print("[post_invoice_to_gl] START", {
                "company_id": company_id,
                "invoice_id": invoice_id,
                "passed_ar_account": ar_account,
                "enforce_credit": enforce_credit,
                "require_approved": require_approved,
                "line_count": len(jlines or []),
            }, flush=True)

            # 1) lock invoice row (idempotency gate)
            _cur.execute(
                f"SELECT status, posted_journal_id FROM {schema}.invoices WHERE id=%s FOR UPDATE;",
                (int(invoice_id),),
            )
            hdr = _cur.fetchone() or {}
            if not hdr:
                raise ValueError("Invoice not found")

            already_jid = hdr.get("posted_journal_id")
            if already_jid:
                return int(already_jid)

            if (hdr.get("status") or "").lower() == "posted":
                raise ValueError("Invoice status is posted but posted_journal_id is NULL (data inconsistency)")

            # 2) load invoice WITH SAME CURSOR (consistent snapshot)
            inv = self.get_invoice_with_lines_cur(company_id, int(invoice_id), _cur)
            if not inv:
                raise ValueError("Invoice not found")

            # after: inv = self.get_invoice_with_lines_cur(...)
            inv_no = (inv.get("number") or "").strip()

            if not inv_no:
                inv_no = self.next_invoice_number_cur(company_id, _cur)

                _cur.execute(
                    f"""
                    UPDATE {schema}.invoices
                    SET number = %s, updated_at = NOW()
                    WHERE id = %s
                    AND (number IS NULL OR btrim(number) = '')
                    RETURNING number;
                    """,
                    (inv_no, int(invoice_id)),
                )
                row = _cur.fetchone()
                if row:
                    inv_no = (row.get("number") if isinstance(row, dict) else row[0]) or inv_no

                inv["number"] = inv_no

            self.validate_invoice_stock_before_post(company_id, inv, cur=_cur)

            inv_date = inv.get("invoice_date") or inv.get("date") or _date.today()
            if isinstance(inv_date, str):
                try:
                    inv_date = _date.fromisoformat(inv_date[:10])
                except Exception:
                    inv_date = _date.today()

            inv_no = (inv.get("number") or inv_no or "").strip()
            if not inv_no:
                raise ValueError("Invoice number could not be assigned before posting")

            cust_id = inv.get("customer_id")

            # 3) credit enforcement (NO extra connections)
            if enforce_credit:
                self.assert_credit_ok_for_invoice_post(company_id, inv, require_approved=require_approved)

            if not jlines:
                raise ValueError("No journal lines provided for posting")

            # 4) resolve controls (ok if these read outside, but best if your helpers accept cur too)
            # 4) resolve controls (prefer passed ar_account from journal builder)
            AR_ACCOUNT  = (ar_account or self.get_control_account_code(company_id, "AR_CONTROL") or "").strip()
            VAT_ACCOUNT = (self.get_control_account_code(company_id, "VAT_OUTPUT") or "").strip()

            print("[post_invoice_to_gl] controls before resolve", {
                "passed_ar_account": ar_account,
                "AR_ACCOUNT": AR_ACCOUNT,
                "VAT_ACCOUNT": VAT_ACCOUNT,
            }, flush=True)

            if not AR_ACCOUNT:
                raise ValueError("AR control account not configured (AR_CONTROL)")
            if not VAT_ACCOUNT:
                raise ValueError("VAT output account not configured (VAT_OUTPUT)")
            
            if not AR_ACCOUNT:
                raise ValueError("AR control account not configured (AR_CONTROL)")
            if not VAT_ACCOUNT:
                raise ValueError("VAT output account not configured (VAT_OUTPUT)")

            # resolve posting codes
            ar_row = self.get_account_row_for_posting(company_id, AR_ACCOUNT)
            if ar_row and ar_row[1]:
                AR_ACCOUNT = (ar_row[1] or "").strip()

            vat_row = self.get_account_row_for_posting(company_id, VAT_ACCOUNT)
            if vat_row and vat_row[1]:
                VAT_ACCOUNT = (vat_row[1] or "").strip()

            # 5) description
            desc = (inv.get("notes") or "").strip() or f"Invoice {inv_no}"

            # 6) journal header
            journal_entry = {
                "date": inv_date,
                "ref": inv_no,
                "description": desc,
                "gross_amount": money(inv.get("total_amount") or inv.get("total") or 0.0),
                "net_amount":   money(inv.get("subtotal_amount") or inv.get("net_amount") or inv.get("total") or 0.0),
                "vat_amount":   money(inv.get("vat_amount") or inv.get("vat_total") or 0.0),
                "source": "invoice",
                "source_id": int(invoice_id),
            }
            print("[post_invoice_to_gl] journal_entry", journal_entry, flush=True)
            journal_id = int(self.insert_journal(company_id, journal_entry, cur=_cur) or 0)
            print("[post_invoice_to_gl] journal_id", journal_id, flush=True)
            if not journal_id:
                raise ValueError("Failed to create journal header")

            # 7) ledger lines
            for jl in jlines:
                print("[post_invoice_to_gl] processing line", jl, flush=True)

                raw_code = (jl.get("account_code") or "").strip()
                dc = (jl.get("dc") or "").upper()
                amt = money(jl.get("amount") or 0.0)
                if not raw_code or dc not in ("D", "C") or amt <= 0:
                    raise ValueError(f"Bad journal line: {jl}")

                row = self.get_account_row_for_posting(company_id, raw_code)
                print("[post_invoice_to_gl] resolved row", row, flush=True)

                if not row:
                    raise ValueError(f"Account '{raw_code}' not found in company COA.")
                code = (row[1] or "").strip()
                if not code:
                    raise ValueError(f"Resolved posting code blank for '{raw_code}'")

                line = {
                    "account_code": code,
                    "debit":  amt if dc == "D" else 0.0,
                    "credit": amt if dc == "C" else 0.0,
                    "description": desc,
                }

                cust_for_line = cust_id if (code == AR_ACCOUNT) else None

                print("[post_invoice_to_gl] ledger line", {
                    "account_code": code,
                    "debit": line["debit"],
                    "credit": line["credit"],
                    "customer_id": cust_for_line,
                }, flush=True)

                self.insert_ledger(
                    company_id=company_id,
                    journal_id=journal_id,
                    je_date=inv_date,
                    line=line,
                    ref=inv_no,
                    customer_id=cust_for_line,
                    source="invoice",
                    source_id=int(invoice_id),
                    cur=_cur,
                )
                print("[post_invoice_to_gl] insert_ledger done", flush=True)

                self.update_trial_balance(company_id, line, cur=_cur)
                print("[post_invoice_to_gl] update_trial_balance done", flush=True)

                if self.requires_notes(code):
                    self.insert_note(company_id, journal_id, code, desc, cur=_cur)
                    print("[post_invoice_to_gl] insert_note done", flush=True)

            # 8) inventory hook (same transaction)
            self.post_invoice_inventory_if_needed(
                company_id,
                invoice_id=int(invoice_id),
                journal_id=int(journal_id),
                inv=inv,
                inv_date=inv_date,
                inv_no=inv_no,
                cur=_cur,
            )

            # 9) stamp posted
            _cur.execute(
                f"""
                UPDATE {schema}.invoices
                SET status='posted',
                    posted_journal_id=%s,
                    updated_at=NOW()
                WHERE id=%s AND posted_journal_id IS NULL
                RETURNING id;
                """,
                (int(journal_id), int(invoice_id)),
            )
            if not _cur.fetchone():
                return int(journal_id)

            # 10) publish engagement posting activity (CRITICAL BRIDGE)
            try:
                # 🔹 TEMP: replace this with real resolver later
                # For now hardcode to validate pipeline
                engagement_company_id = 8
                engagement_id = 14

                total_amount = money(inv.get("total_amount") or inv.get("total") or 0.0)
                currency_code = (inv.get("currency") or "ZAR").strip() or "ZAR"

                self.upsert_engagement_posting_activity(
                    _cur,
                    company_id=int(engagement_company_id),
                    engagement_id=int(engagement_id),
                    posting_date=inv_date,
                    module_name="accounts_receivable",
                    event_type="posted",
                    reference_no=inv_no,
                    description=desc,
                    prepared_by_user_id=None,
                    reviewer_user_id=None,
                    status="posted",
                    amount=total_amount,
                    currency_code=currency_code,
                    source_table="invoices",
                    source_id=int(invoice_id),
                    notes=f"Invoice posted to journal {journal_id}",
                    created_by_user_id=None,
                    updated_by_user_id=None,
                )

                print("[post_invoice_to_gl] engagement activity recorded", flush=True)

            except Exception as e:
                print("[post_invoice_to_gl] engagement activity failed:", str(e), flush=True)

            return int(journal_id)

        if cur is not None:
            return _run(cur)

        with self._conn_cursor() as (conn, _cur):
            try:
                jid = _run(_cur)
                conn.commit()
                return jid
            except Exception:
                conn.rollback()
                raise

    def mark_invoice_posted(self, company_id: int, invoice_id: int, journal_id: int | None = None) -> None:
        """
        Marks an invoice as posted.
        Safe against double-posting.
        """
        schema = f"company_{company_id}"

        with self._conn_cursor() as (_conn, cur):
            # Lock row to prevent race conditions
            cur.execute(
                f"""
                SELECT status, posted_journal_id
                FROM {schema}.invoices
                WHERE id = %s
                FOR UPDATE;
                """,
                (invoice_id,),
            )
            row = cur.fetchone()
            if not row:
                raise ValueError("Invoice not found")

            status = (row.get("status") or "").lower()
            posted_journal_id = row.get("posted_journal_id")

            # Already posted → do nothing (idempotent)
            if status == "posted" or posted_journal_id:
                return

            # Update invoice status
            if journal_id:
                cur.execute(
                    f"""
                    UPDATE {schema}.invoices
                    SET status = 'posted',
                        posted_journal_id = %s,
                        updated_at = NOW()
                    WHERE id = %s;
                    """,
                    (journal_id, invoice_id),
                )
            else:
                cur.execute(
                    f"""
                    UPDATE {schema}.invoices
                    SET status = 'posted',
                        updated_at = NOW()
                    WHERE id = %s;
                    """,
                    (invoice_id,),
                )

    def list_company_invoices_filtered(
        self,
        *,
        company_id: int,
        statuses: Optional[list[str]] = None,
        customer_id: Optional[int] = None,
        limit: int = 200,
    ) -> List[Dict[str, Any]]:

        schema = self.company_schema(company_id)

        where: list[str] = []
        params: list[Any] = []

        # ✅ NORMALIZE: make status filtering case/space-insensitive
        # This fixes "draft not showing" when DB has Draft/DRAFT/draft  etc.
        if statuses:
            norm_statuses = [s.strip().lower() for s in statuses if s and s.strip()]
            if norm_statuses:
                placeholders = ",".join(["%s"] * len(norm_statuses))
                where.append(f"LOWER(TRIM(COALESCE(i.status,''))) IN ({placeholders})")
                params.extend(norm_statuses)

        if customer_id:
            where.append("i.customer_id = %s")
            params.append(int(customer_id))

        where_sql = ("WHERE " + " AND ".join(where)) if where else ""

        sql = f"""
        SELECT
            i.id,
            i.customer_id,
            i.number,
            i.invoice_date,
            i.due_date,
            i.status,
            i.total_amount,
            c.name  AS customer_name,
            c.email AS customer_email,

            -- ✅ payment totals (from allocations)
            COALESCE(SUM(ra.amount), 0)::numeric(18,2) AS paid_amount,
            GREATEST(
                i.total_amount - COALESCE(SUM(ra.amount), 0),
                0
            )::numeric(18,2) AS outstanding_amount,

            CASE
                WHEN LOWER(COALESCE(i.status,'')) IN ('void','written_off') THEN LOWER(i.status)
                WHEN GREATEST(
                    i.total_amount - COALESCE(SUM(ra.amount), 0),
                    0
                ) <= 0 THEN 'paid'
                WHEN COALESCE(SUM(ra.amount), 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status

        FROM {schema}.invoices i
        LEFT JOIN {schema}.customers c
            ON c.id = i.customer_id

        LEFT JOIN {schema}.receipt_allocations ra
            ON ra.company_id = i.company_id
        AND ra.invoice_id = i.id

        {where_sql}
        GROUP BY i.id, c.id
        ORDER BY i.invoice_date DESC, i.id DESC
        LIMIT %s;
        """

        params.append(int(limit))
        return self.fetch_all(sql, tuple(params))

    def list_company_invoices_by_status(self, company_id: int, statuses: list[str]):
        schema = self.company_schema(company_id)
        if not statuses:
            return []

        placeholders = ",".join(["%s"] * len(statuses))

        sql = f"""
        SELECT
            i.id,
            i.number,
            i.invoice_date,
            i.due_date,
            i.status,
            i.total_amount,
            c.name AS customer_name,

            COALESCE(SUM(ra.amount), 0)::numeric(18,2) AS paid_amount,
            GREATEST(i.total_amount - COALESCE(SUM(ra.amount), 0), 0)::numeric(18,2) AS outstanding_amount,

            CASE
                WHEN LOWER(COALESCE(i.status,'')) IN ('void','written_off') THEN LOWER(i.status)
                WHEN GREATEST(i.total_amount - COALESCE(SUM(ra.amount), 0), 0) <= 0 THEN 'paid'
                WHEN COALESCE(SUM(ra.amount), 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status

        FROM {schema}.invoices i
        LEFT JOIN {schema}.customers c
            ON c.id = i.customer_id
        LEFT JOIN {schema}.receipt_allocations ra
            ON ra.company_id = i.company_id
        AND ra.invoice_id = i.id

        WHERE i.status IN ({placeholders})
        GROUP BY i.id, c.id
        ORDER BY i.invoice_date DESC, i.id DESC
        LIMIT 200;
        """
        return self.fetch_all(sql, tuple(statuses))


    def _d(x) -> Decimal:
        try:
            return Decimal(str(x or "0"))
        except Exception:
            return Decimal("0")

    def get_customer_statement(
        self,
        company_id: int,
        customer_id: int,
        date_from: date,
        date_to: date,
    ) -> dict:
        schema = self.company_schema(company_id)
        ar_posting = self._resolve_ar_control_posting(company_id)

        # --------------------------
        # 0) Opening balance (RAW ledger truth)
        # --------------------------
        open_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.debit - l.credit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.company_id = %s
            AND l.customer_id = %s
            AND l.account = %s
            AND l.date < %s;
            """,
            (company_id, customer_id, ar_posting, date_from),
        ) or {}
        opening = _d(open_row.get("bal")).quantize(Decimal("0.01"))

        # --------------------------
        # 1) Per-invoice outstanding map (used to restate invoice lines)
        # --------------------------
        per_invoice = self.fetch_all(
            f"""
            SELECT
            i.id,
            i.number,
            i.invoice_date,
            i.due_date,
            i.status,
            i.total_amount::numeric(18,2) AS total_amount,
            COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid,
            (i.total_amount - COALESCE(SUM(a.amount),0))::numeric(18,2) AS outstanding
            FROM {schema}.invoices i
            LEFT JOIN {schema}.receipt_allocations a
            ON a.invoice_id = i.id
            AND a.company_id = %s
            WHERE i.company_id = %s
            AND i.customer_id = %s
            AND i.status NOT IN ('void')
            GROUP BY i.id
            ORDER BY i.invoice_date DESC, i.id DESC;
            """,
            (company_id, company_id, customer_id),
        ) or []

        outstanding_map: dict[int, Decimal] = {}
        for r in per_invoice:
            iid = int(r.get("id") or 0)
            if iid:
                outstanding_map[iid] = _d(r.get("outstanding")).quantize(Decimal("0.01"))

        # --------------------------
        # 2) Movements in period (ledger AR control)
        # --------------------------
        rows = self.fetch_all(
            f"""
            SELECT
            l.id,
            l.date,
            l.ref,
            l.journal_id,
            l.source,
            l.source_id,
            l.memo,
            l.debit,
            l.credit
            FROM {schema}.ledger l
            WHERE l.company_id = %s
            AND l.customer_id = %s
            AND l.account = %s
            AND l.date BETWEEN %s AND %s
            ORDER BY l.date ASC, l.id ASC;
            """,
            (company_id, customer_id, ar_posting, date_from, date_to),
        ) or []

        running = opening
        tx = []

        total_debit = Decimal("0.00")
        total_credit = Decimal("0.00")

        for r in rows:
            src = (r.get("source") or "").strip().lower()
            src_id = r.get("source_id")

            debit = _d(r.get("debit")).quantize(Decimal("0.01"))
            credit = _d(r.get("credit")).quantize(Decimal("0.01"))

            # ✅ Restate invoice line: show outstanding as the debit
            if src == "invoice" and src_id is not None:
                inv_id = int(src_id)
                out = outstanding_map.get(inv_id, Decimal("0.00"))
                # show only outstanding (if fully paid -> 0)
                debit = out
                credit = Decimal("0.00")

            mv = (debit - credit).quantize(Decimal("0.01"))
            running = (running + mv).quantize(Decimal("0.01"))

            total_debit += debit
            total_credit += credit

            tx.append({
                "id": r.get("id"),
                "date": r.get("date").isoformat() if hasattr(r.get("date"), "isoformat") else str(r.get("date")),
                "ref": r.get("ref") or "",
                "journal_id": r.get("journal_id"),
                "source": r.get("source"),
                "source_id": r.get("source_id"),
                "memo": r.get("memo") or "",
                "debit": float(debit),
                "credit": float(credit),
                "movement": float(mv),
                "balance": float(running),
            })

        return {
            "customer_id": int(customer_id),
            "ar_account": ar_posting,
            "from": date_from.isoformat(),
            "to": date_to.isoformat(),
            "opening_balance": float(opening),
            "closing_balance": float(running),

            "rows": tx,
            "transactions": tx,

            "totals": {
                "debits": float(total_debit),
                "credits": float(total_credit),
                "net_movement": float((total_debit - total_credit).quantize(Decimal("0.01"))),
            },

            "per_invoice": [
                {
                    "invoice_id": int(r["id"]),
                    "number": r.get("number"),
                    "invoice_date": r.get("invoice_date").isoformat() if hasattr(r.get("invoice_date"), "isoformat") else r.get("invoice_date"),
                    "due_date": r.get("due_date").isoformat() if hasattr(r.get("due_date"), "isoformat") else r.get("due_date"),
                    "status": r.get("status"),
                    "total_amount": float(_d(r.get("total_amount"))),
                    "paid": float(_d(r.get("paid"))),
                    "outstanding": float(_d(r.get("outstanding"))),
                }
                for r in per_invoice
            ],
        }


    def ar_aging(self, company_id: int, *, as_of: date) -> dict:
        schema = f"company_{company_id}"

        rows = self.fetch_all(
            f"""
            SELECT
            i.customer_id,
            i.id AS invoice_id,
            i.number,
            i.invoice_date,
            i.due_date,
            i.total_amount::numeric(18,2) AS total_amount,
            COALESCE(SUM(a.amount),0)::numeric(18,2) AS allocated,
            (i.total_amount - COALESCE(SUM(a.amount),0))::numeric(18,2) AS outstanding
            FROM {schema}.invoices i
            LEFT JOIN {schema}.receipt_allocations a
            ON a.invoice_id = i.id
            WHERE i.status IN ('posted','partial','paid')
            GROUP BY i.id
            HAVING (i.total_amount - COALESCE(SUM(a.amount),0)) > 0
            ORDER BY i.customer_id, i.due_date NULLS LAST, i.invoice_date;
            """,
            (),
        ) or []

        # buckets
        by_customer = {}
        for r in rows:
            cust = int(r["customer_id"])
            due = r.get("due_date") or r.get("invoice_date")
            if isinstance(due, str):
                due = date.fromisoformat(due[:10])
            days = (as_of - due).days if due else 0

            out = Decimal(str(r.get("outstanding") or "0"))

            if cust not in by_customer:
                by_customer[cust] = {"current": Decimal("0"), "b1_30": Decimal("0"), "b31_60": Decimal("0"),
                                    "b61_90": Decimal("0"), "b91_plus": Decimal("0"), "invoices": []}

            # bucket logic
            if days <= 0:
                by_customer[cust]["current"] += out
                bucket = "current"
            elif 1 <= days <= 30:
                by_customer[cust]["b1_30"] += out
                bucket = "1_30"
            elif 31 <= days <= 60:
                by_customer[cust]["b31_60"] += out
                bucket = "31_60"
            elif 61 <= days <= 90:
                by_customer[cust]["b61_90"] += out
                bucket = "61_90"
            else:
                by_customer[cust]["b91_plus"] += out
                bucket = "91_plus"

            by_customer[cust]["invoices"].append({
                "invoice_id": int(r["invoice_id"]),
                "number": r.get("number"),
                "invoice_date": r.get("invoice_date").isoformat() if hasattr(r.get("invoice_date"), "isoformat") else r.get("invoice_date"),
                "due_date": r.get("due_date").isoformat() if hasattr(r.get("due_date"), "isoformat") else r.get("due_date"),
                "outstanding": float(out),
                "days_past_due": int(days),
                "bucket": bucket,
            })

        # format totals
        out_customers = []
        grand = {"current": Decimal("0"), "b1_30": Decimal("0"), "b31_60": Decimal("0"),
                "b61_90": Decimal("0"), "b91_plus": Decimal("0")}

        for cust_id, data in by_customer.items():
            for k in grand:
                grand[k] += data[k]
            out_customers.append({
                "customer_id": cust_id,
                "current": float(data["current"]),
                "1_30": float(data["b1_30"]),
                "31_60": float(data["b31_60"]),
                "61_90": float(data["b61_90"]),
                "91_plus": float(data["b91_plus"]),
                "total": float(data["current"] + data["b1_30"] + data["b31_60"] + data["b61_90"] + data["b91_plus"]),
                "invoices": data["invoices"],  # you can hide this for summary-only
            })

        return {
            "company_id": int(company_id),
            "as_of": as_of.isoformat(),
            "customers": out_customers,
            "totals": {
                "current": float(grand["current"]),
                "1_30": float(grand["b1_30"]),
                "31_60": float(grand["b31_60"]),
                "61_90": float(grand["b61_90"]),
                "91_plus": float(grand["b91_plus"]),
                "total": float(grand["current"] + grand["b1_30"] + grand["b31_60"] + grand["b61_90"] + grand["b91_plus"]),
            },
        }

    def get_ar_control_balance(self, company_id: int, *, as_of: date | None = None) -> dict:
        """
        Returns AR control balance (debit - credit) from ledger for AR control posting code.
        Using ledger is safest. TB is faster but can drift if legacy bugs ever exist.
        """
        schema = self.company_schema(company_id)
        ar_posting = self._resolve_ar_control_posting(company_id)

        where_date = ""
        params = [ar_posting]
        if as_of:
            where_date = "AND l.date <= %s"
            params.append(as_of)

        row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.debit - l.credit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.account = %s
            {where_date};
            """,
            tuple(params),
        ) or {}

        bal = _d(row.get("bal"))
        return {
            "ar_account": ar_posting,
            "as_of": as_of.isoformat() if as_of else None,
            "balance": float(bal),
        }
    
    def get_ar_subledger_by_customer(self, company_id: int, *, as_of: date | None = None) -> list[dict]:
        schema = self.company_schema(company_id)
        ar_posting = self._resolve_ar_control_posting(company_id)

        where_date = ""
        params = [ar_posting]
        if as_of:
            where_date = "AND l.date <= %s"
            params.append(as_of)

        rows = self.fetch_all(
            f"""
            SELECT
            l.customer_id,
            COALESCE(SUM(l.debit - l.credit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.account = %s
            AND l.customer_id IS NOT NULL
            {where_date}
            GROUP BY l.customer_id
            HAVING COALESCE(SUM(l.debit - l.credit), 0) <> 0
            ORDER BY l.customer_id ASC;
            """,
            tuple(params),
        ) or []

        return [
            {"customer_id": int(r["customer_id"]), "balance": float(_d(r.get("bal")))}
            for r in rows
        ]

    def get_ar_control_reconciliation(self, company_id: int, *, as_at: date | None = None) -> dict:
        """
        Returns control vs subledger reconciliation.
        """
        schema = self.company_schema(company_id)

        # ✅ use as_at everywhere
        control = self.get_ar_control_balance(company_id, as_of=as_at)
        sub_rows = self.get_ar_subledger_by_customer(company_id, as_of=as_at)

        sub_total = sum(Decimal(str(r.get("balance") or 0)) for r in (sub_rows or []))
        control_total = Decimal(str(control.get("balance") or 0))
        diff = control_total - sub_total

        # enrich with customer names (optional but nice)
        if sub_rows:
            ids = [int(r["customer_id"]) for r in sub_rows if r.get("customer_id") is not None]

            if ids:
                custs = self.fetch_all(
                    f"""
                    SELECT id, name
                    FROM {schema}.customers
                    WHERE id = ANY(%s);
                    """,
                    (ids,),
                ) or []
                name_map = {int(c["id"]): c.get("name") for c in custs}
                for r in sub_rows:
                    r["customer_name"] = name_map.get(int(r["customer_id"])) if r.get("customer_id") else None

        sub_rows_sorted = sorted(sub_rows or [], key=lambda x: abs(float(x.get("balance") or 0)), reverse=True)

        return {
            "company_id": int(company_id),
            "as_at": as_at.isoformat() if as_at else None,   # ✅ rename output key too
            "ar_account": control.get("ar_account"),
            "control_balance": float(control_total),
            "subledger_total": float(sub_total),
            "difference": float(diff),
            "is_balanced": (diff.quantize(Decimal("0.01")) == Decimal("0.00")),
            "customers": sub_rows_sorted,
        }

    def ar_control_reconciliation(self, company_id: int, *, as_of: date) -> dict:
        schema = f"company_{company_id}"
        ar_posting = self._resolve_ar_control_posting(company_id)

        # Control balance from ledger
        ctrl = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(debit - credit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger
            WHERE account = %s
            AND date <= %s;
            """,
            (ar_posting, as_of),
        ) or {}
        control_balance = Decimal(str(ctrl.get("bal") or "0"))

        # Subledger by customer
        cust_rows = self.fetch_all(
            f"""
            SELECT
            customer_id,
            COALESCE(SUM(debit - credit),0)::numeric(18,2) AS bal
            FROM {schema}.ledger
            WHERE account = %s
            AND date <= %s
            GROUP BY customer_id
            HAVING COALESCE(SUM(debit - credit),0) <> 0
            ORDER BY bal DESC;
            """,
            (ar_posting, as_of),
        ) or []

        sub_total = Decimal("0")
        customers = []
        for r in cust_rows:
            b = Decimal(str(r.get("bal") or "0"))
            sub_total += b
            customers.append({"customer_id": r.get("customer_id"), "balance": float(b)})

        diff = control_balance - sub_total

        return {
            "company_id": int(company_id),
            "as_of": as_of.isoformat(),
            "ar_account": ar_posting,
            "control_balance": float(control_balance),
            "subledger_total": float(sub_total),
            "difference": float(diff),
            "customers": customers,
        }

    def _resolve_ar_control_posting(self, company_id: int) -> str:
        settings = self.get_company_account_settings(company_id) or {}
        raw = (settings.get("ar_control_code") or "").strip()
        if not raw:
            raise ValueError("AR control not set in company_account_settings.ar_control_code")

        row = self.get_account_row_for_posting(company_id, raw)
        if not row:
            raise ValueError(f"AR control '{raw}' not found in COA (code/template_code).")

        posting = (row[1] or "").strip()
        if not posting:
            raise ValueError("AR control resolved to blank posting code")
        return posting

    def _resolve_ap_control_posting(self, company_id: int) -> str:
        settings = self.get_company_account_settings(company_id) or {}
        raw = (settings.get("ap_control_code") or "").strip()
        if not raw:
            raise ValueError("AP control not set in company_account_settings.ap_control_code")

        row = self.get_account_row_for_posting(company_id, raw)
        if not row:
            raise ValueError(f"AP control '{raw}' not found in COA (code/template_code).")

        posting = (row[1] or "").strip()
        if not posting:
            raise ValueError("AP control resolved to blank posting code")
        return posting

    def _resolve_grni_control_posting(self, company_id: int) -> str:
        settings = self.get_company_account_settings(company_id) or {}
        raw = (settings.get("grni_control_code") or settings.get("ppv_control_code") or "").strip()
        if not raw:
            raise ValueError("GRNI control not set in company_account_settings.grni_control_code (or ppv_control_code)")

        row = self.get_account_row_for_posting(company_id, raw)
        if not row:
            raise ValueError(f"GRNI control '{raw}' not found in COA (code/template_code).")

        posting = (row[1] or "").strip()
        if not posting:
            raise ValueError("GRNI control resolved to blank posting code")
        return posting


    def _resolve_inventory_asset_posting(self, company_id: int) -> str:
        """
        Default inventory asset control (fallback when item.inventory_account is blank).
        Requires you to store inventory_control_code in settings OR return it in get_company_account_settings.
        """
        settings = self.get_company_account_settings(company_id) or {}
        raw = (settings.get("inventory_control_code") or "").strip()
        if not raw:
            raise ValueError("Inventory control not set in company_account_settings.inventory_control_code")

        row = self.get_account_row_for_posting(company_id, raw)
        if not row:
            raise ValueError(f"Inventory control '{raw}' not found in COA (code/template_code).")

        posting = (row[1] or "").strip()
        if not posting:
            raise ValueError("Inventory control resolved to blank posting code")
        return posting

    def get_vendor_statement(
        self,
        company_id: int,
        vendor_id: int,
        date_from: date,
        date_to: date,
    ) -> dict:
        schema = self.company_schema(company_id)
        ap_posting = self._resolve_ap_control_posting(company_id)

        # --------------------------
        # 0) Opening balance (RAW ledger truth)
        # --------------------------
        open_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.debit - l.credit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.company_id = %s
            AND l.vendor_id = %s
            AND l.account = %s
            AND l.date < %s;
            """,
            (company_id, vendor_id, ap_posting, date_from),
        ) or {}
        opening = _d(open_row.get("bal")).quantize(Decimal("0.01"))

        # --------------------------
        # 1) Per-bill outstanding map (used to restate bill lines)
        # --------------------------
        per_bill = self.fetch_all(
            f"""
            SELECT
            b.id,
            b.number,
            b.bill_date,
            b.due_date,
            b.status,
            b.total_amount::numeric(18,2) AS total_amount,
            COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid,
            (b.total_amount - COALESCE(SUM(a.amount),0))::numeric(18,2) AS outstanding
            FROM {schema}.bills b
            LEFT JOIN {schema}.vendor_payment_allocations a
            ON a.bill_id = b.id
            AND a.company_id = %s
            WHERE b.company_id = %s
            AND b.vendor_id  = %s
            AND LOWER(COALESCE(b.status,'')) NOT IN ('void')
            GROUP BY b.id
            ORDER BY b.bill_date DESC, b.id DESC;
            """,
            (company_id, company_id, vendor_id),
        ) or []

        outstanding_map: dict[int, Decimal] = {}
        for r in per_bill:
            bid = int(r.get("id") or 0)
            if bid:
                outstanding_map[bid] = _d(r.get("outstanding")).quantize(Decimal("0.01"))

        # --------------------------
        # 2) Movements in period (ledger AP control)
        # --------------------------
        rows = self.fetch_all(
            f"""
            SELECT
            l.id,
            l.date,
            l.ref,
            l.journal_id,
            l.source,
            l.source_id,
            l.memo,
            l.debit,
            l.credit
            FROM {schema}.ledger l
            WHERE l.company_id = %s
            AND l.vendor_id = %s
            AND l.account = %s
            AND l.date BETWEEN %s AND %s
            ORDER BY l.date ASC, l.id ASC;
            """,
            (company_id, vendor_id, ap_posting, date_from, date_to),
        ) or []

        running = opening
        tx = []
        total_debit = Decimal("0.00")
        total_credit = Decimal("0.00")

        for r in rows:
            src = (r.get("source") or "").strip().lower()
            src_id = r.get("source_id")

            debit = _d(r.get("debit")).quantize(Decimal("0.01"))
            credit = _d(r.get("credit")).quantize(Decimal("0.01"))

            # ✅ Mirror AR logic:
            # AR: invoice => outstanding as DEBIT
            # AP: bill    => outstanding as CREDIT
            if src == "bill" and src_id is not None:
                bill_id = int(src_id)
                out = outstanding_map.get(bill_id, Decimal("0.00"))
                debit = Decimal("0.00")
                credit = out

            mv = (debit - credit).quantize(Decimal("0.01"))
            running = (running + mv).quantize(Decimal("0.01"))

            total_debit += debit
            total_credit += credit

            tx.append({
                "id": r.get("id"),
                "date": r.get("date").isoformat() if hasattr(r.get("date"), "isoformat") else str(r.get("date")),
                "ref": r.get("ref") or "",
                "journal_id": r.get("journal_id"),
                "source": r.get("source"),
                "source_id": r.get("source_id"),
                "memo": r.get("memo") or "",
                "debit": float(debit),
                "credit": float(credit),
                "movement": float(mv),
                "balance": float(running),
            })

        return {
            "vendor_id": int(vendor_id),
            "ap_account": ap_posting,
            "from": date_from.isoformat(),
            "to": date_to.isoformat(),
            "opening_balance": float(opening),
            "closing_balance": float(running),

            "rows": tx,
            "transactions": tx,

            "totals": {
                "debits": float(total_debit),
                "credits": float(total_credit),
                "net_movement": float((total_debit - total_credit).quantize(Decimal("0.01"))),
            },

            "per_bill": [
                {
                    "bill_id": int(r["id"]),
                    "number": r.get("number"),
                    "bill_date": r.get("bill_date").isoformat() if hasattr(r.get("bill_date"), "isoformat") else r.get("bill_date"),
                    "due_date": r.get("due_date").isoformat() if hasattr(r.get("due_date"), "isoformat") else r.get("due_date"),
                    "status": r.get("status"),
                    "total_amount": float(_d(r.get("total_amount"))),
                    "paid": float(_d(r.get("paid"))),
                    "outstanding": float(_d(r.get("outstanding"))),
                }
                for r in per_bill
            ],
        }

    def get_ap_aging_report(self, company_id: int, *, as_at: date, vendor_id: int | None = None) -> dict:
        schema = self.company_schema(company_id)

        where_vendor = ""
        params = [company_id, company_id]
        if vendor_id:
            where_vendor = "AND b.vendor_id = %s"
            params.append(int(vendor_id))

        rows = self.fetch_all(
            f"""
            SELECT
            b.vendor_id,
            b.id AS bill_id,
            b.number,
            b.bill_date,
            b.due_date,
            b.total_amount::numeric(18,2) AS total_amount,
            COALESCE(SUM(a.amount),0)::numeric(18,2) AS allocated,
            (b.total_amount - COALESCE(SUM(a.amount),0))::numeric(18,2) AS outstanding
            FROM {schema}.bills b
            LEFT JOIN {schema}.vendor_payment_allocations a
            ON a.bill_id=b.id
            AND a.company_id=%s
            WHERE b.company_id=%s
            AND b.status IN ('posted','partial','approved')
            {where_vendor}
            GROUP BY b.id
            HAVING (b.total_amount - COALESCE(SUM(a.amount),0)) > 0
            ORDER BY b.vendor_id, b.due_date NULLS LAST, b.bill_date;
            """,
            tuple(params),
        ) or []

        by_vendor = {}
        for r in rows:
            vid = int(r["vendor_id"])
            due = r.get("due_date") or r.get("bill_date")
            days = (as_at - due).days if due else 0
            out = Decimal(str(r.get("outstanding") or "0"))

            if vid not in by_vendor:
                by_vendor[vid] = {
                    "current": Decimal("0"),
                    "b1_30": Decimal("0"),
                    "b31_60": Decimal("0"),
                    "b61_90": Decimal("0"),
                    "b91_plus": Decimal("0"),
                    "bills": [],
                }

            if days <= 0:
                by_vendor[vid]["current"] += out; bucket = "current"
            elif 1 <= days <= 30:
                by_vendor[vid]["b1_30"] += out; bucket = "1_30"
            elif 31 <= days <= 60:
                by_vendor[vid]["b31_60"] += out; bucket = "31_60"
            elif 61 <= days <= 90:
                by_vendor[vid]["b61_90"] += out; bucket = "61_90"
            else:
                by_vendor[vid]["b91_plus"] += out; bucket = "91_plus"

            by_vendor[vid]["bills"].append({
                "bill_id": int(r["bill_id"]),
                "number": r.get("number"),
                "bill_date": r.get("bill_date").isoformat() if hasattr(r.get("bill_date"), "isoformat") else r.get("bill_date"),
                "due_date": r.get("due_date").isoformat() if hasattr(r.get("due_date"), "isoformat") else r.get("due_date"),
                "outstanding": float(out),
                "days_past_due": int(days),
                "bucket": bucket,
            })

        # vendor names (nice for UI)
        name_map = {}
        if by_vendor:
            ids = list(by_vendor.keys())
            vend_rows = self.fetch_all(
                f"SELECT id, name FROM {schema}.vendors WHERE id = ANY(%s);",
                (ids,),
            ) or []
            name_map = {int(v["id"]): (v.get("name") or "") for v in vend_rows}

        grand = {k: Decimal("0") for k in ["current","b1_30","b31_60","b61_90","b91_plus"]}
        vendors_out = []
        for vid, data in by_vendor.items():
            for k in grand:
                grand[k] += data[k]
            total = data["current"] + data["b1_30"] + data["b31_60"] + data["b61_90"] + data["b91_plus"]
            vendors_out.append({
                "vendor_id": int(vid),
                "vendor_name": name_map.get(int(vid), ""),
                "current": float(data["current"]),
                "1_30": float(data["b1_30"]),
                "31_60": float(data["b31_60"]),
                "61_90": float(data["b61_90"]),
                "91_plus": float(data["b91_plus"]),
                "total": float(total),
                "bills": data["bills"],
            })

        return {
            "company_id": int(company_id),
            "as_at": as_at.isoformat(),
            "vendors": sorted(vendors_out, key=lambda x: x["total"], reverse=True),
            "totals": {
                "current": float(grand["current"]),
                "1_30": float(grand["b1_30"]),
                "31_60": float(grand["b31_60"]),
                "61_90": float(grand["b61_90"]),
                "91_plus": float(grand["b91_plus"]),
                "total": float(grand["current"] + grand["b1_30"] + grand["b31_60"] + grand["b61_90"] + grand["b91_plus"]),
            },
        }

    def get_ap_control_balance(self, company_id: int, *, as_of: date | None = None) -> dict:
        schema = self.company_schema(company_id)
        ap_posting = self._resolve_ap_control_posting(company_id)

        where_date = ""
        params = [ap_posting]
        if as_of:
            where_date = "AND l.date <= %s"
            params.append(as_of)

        row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.credit - l.debit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.account=%s
            {where_date};
            """,
            tuple(params),
        ) or {}

        bal = Decimal(str(row.get("bal") or "0"))
        return {"ap_account": ap_posting, "as_of": as_of.isoformat() if as_of else None, "balance": float(bal)}


    def get_ap_subledger_by_vendor(self, company_id: int, *, as_of: date | None = None) -> list[dict]:
        schema = self.company_schema(company_id)
        ap_posting = self._resolve_ap_control_posting(company_id)

        where_date = ""
        params = [ap_posting]
        if as_of:
            where_date = "AND l.date <= %s"
            params.append(as_of)

        rows = self.fetch_all(
            f"""
            SELECT
            l.vendor_id,
            COALESCE(SUM(l.credit - l.debit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.account=%s
            AND l.vendor_id IS NOT NULL
            {where_date}
            GROUP BY l.vendor_id
            HAVING COALESCE(SUM(l.credit - l.debit), 0) <> 0
            ORDER BY l.vendor_id ASC;
            """,
            tuple(params),
        ) or []

        return [{"vendor_id": int(r["vendor_id"]), "balance": float(Decimal(str(r.get("bal") or "0")))} for r in rows]


    def get_ap_control_reconciliation(self, company_id: int, *, as_at: date | None = None) -> dict:
        schema = self.company_schema(company_id)

        control = self.get_ap_control_balance(company_id, as_of=as_at)
        sub_rows = self.get_ap_subledger_by_vendor(company_id, as_of=as_at)

        sub_total = sum(Decimal(str(r.get("balance") or 0)) for r in (sub_rows or []))
        control_total = Decimal(str(control.get("balance") or 0))
        diff = control_total - sub_total

        # vendor names
        if sub_rows:
            ids = [int(r["vendor_id"]) for r in sub_rows if r.get("vendor_id") is not None]
            if ids:
                vend = self.fetch_all(
                    f"SELECT id, name FROM {schema}.vendors WHERE id = ANY(%s);",
                    (ids,),
                ) or []
                name_map = {int(v["id"]): v.get("name") for v in vend}
                for r in sub_rows:
                    r["vendor_name"] = name_map.get(int(r["vendor_id"])) if r.get("vendor_id") else None

        sub_rows_sorted = sorted(sub_rows or [], key=lambda x: abs(float(x.get("balance") or 0)), reverse=True)

        return {
            "company_id": int(company_id),
            "as_at": as_at.isoformat() if as_at else None,
            "ap_account": control.get("ap_account"),
            "control_balance": float(control_total),
            "subledger_total": float(sub_total),
            "difference": float(diff),
            "is_balanced": (diff.quantize(Decimal("0.01")) == Decimal("0.00")),
            "vendors": sub_rows_sorted,
        }

    def list_company_bills_filtered(
        self,
        *,
        company_id: int,
        statuses: Optional[list[str]] = None,
        vendor_id: Optional[int] = None,
        limit: int = 200,
    ) -> List[Dict[str, Any]]:

        schema = self.company_schema(company_id)

        where = []
        params: list[Any] = []

        if statuses:
            placeholders = ",".join(["%s"] * len(statuses))
            where.append(f"b.status IN ({placeholders})")
            params.extend(statuses)

        if vendor_id:
            where.append("b.vendor_id = %s")
            params.append(vendor_id)

        where_sql = ("WHERE " + " AND ".join(where)) if where else ""

        sql = f"""
        SELECT
            b.id,
            b.vendor_id,
            b.number,
            b.bill_date,
            b.due_date,
            b.status,
            b.total_amount,
            v.name  AS vendor_name,
            v.email AS vendor_email,

            -- ✅ payment totals (from allocations)
            COALESCE(SUM(vpa.amount), 0)::numeric(18,2) AS paid_amount,
            GREATEST(
                b.total_amount - COALESCE(SUM(vpa.amount), 0),
                0
            )::numeric(18,2) AS outstanding_amount,

            CASE
                WHEN LOWER(COALESCE(b.status,'')) IN ('void','written_off') THEN LOWER(b.status)
                WHEN GREATEST(
                    b.total_amount - COALESCE(SUM(vpa.amount), 0),
                    0
                ) <= 0 THEN 'paid'
                WHEN COALESCE(SUM(vpa.amount), 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status

        FROM {schema}.bills 
        LEFT JOIN {schema}.vendors v
        ON v.id = b.vendor_id

        LEFT JOIN {schema}.vendor_payment_allocations vpa
        ON vpa.company_id = b.company_id
        AND vpa.bill_id    = b.id

        {where_sql}
        GROUP BY b.id, v.id
        ORDER BY b.bill_date DESC, b.id DESC
        LIMIT %s;
        """

        params.append(limit)
        return self.fetch_all(sql, tuple(params))


    def list_company_bills_by_status(self, company_id: int, statuses: list[str]):
        schema = self.company_schema(company_id)
        if not statuses:
            return []

        placeholders = ",".join(["%s"] * len(statuses))

        sql = f"""
        SELECT
            b.id,
            b.number,
            b.bill_date,
            b.due_date,
            b.status,
            b.total_amount,
            v.name AS vendor_name,

            COALESCE(SUM(vpa.amount), 0)::numeric(18,2) AS paid_amount,
            GREATEST(b.total_amount - COALESCE(SUM(vpa.amount), 0), 0)::numeric(18,2) AS outstanding_amount,

            CASE
                WHEN LOWER(COALESCE(b.status,'')) IN ('void','written_off') THEN LOWER(b.status)
                WHEN GREATEST(b.total_amount - COALESCE(SUM(vpa.amount), 0), 0) <= 0 THEN 'paid'
                WHEN COALESCE(SUM(vpa.amount), 0) > 0 THEN 'partial'
                ELSE 'unpaid'
            END AS payment_status

        FROM {schema}.bills 
        LEFT JOIN {schema}.vendors v
        ON v.id = b.vendor_id

        LEFT JOIN {schema}.vendor_payment_allocations vpa
        ON vpa.company_id = b.company_id
        AND vpa.bill_id    = b.id

        WHERE b.status IN ({placeholders})
        GROUP BY b.id, v.id
        ORDER BY b.bill_date DESC, b.id DESC
        LIMIT 200;
        """
        return self.fetch_all(sql, tuple(statuses))


    def get_vendor_statement(
        self,
        company_id: int,
        vendor_id: int,
        date_from: date,
        date_to: date,
    ) -> dict:
        schema = self.company_schema(company_id)

        # AP control posting code (the one you actually post to in ledger.account)
        ap_posting = self._resolve_ap_control_posting(company_id)

        # --------------------------
        # 0) Opening balance as at date_from (AP control only)
        # --------------------------
        open_row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.credit - l.debit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.company_id = %s
            AND l.vendor_id  = %s
            AND l.account    = %s
            AND l.date < %s;
            """,
            (company_id, vendor_id, ap_posting, date_from),
        ) or {}
        opening = Decimal(str(open_row.get("bal") or "0"))

        # --------------------------
        # 1) Movements in period (ledger AP control only)
        #    AP normal balance is credit, so movement = credit - debit
        # --------------------------
        rows = self.fetch_all(
            f"""
            SELECT
            l.id,
            l.date,
            l.ref,
            l.journal_id,
            l.source,
            l.source_id,
            l.memo,
            l.debit,
            l.credit,
            (l.credit - l.debit) AS movement
            FROM {schema}.ledger l
            WHERE l.company_id = %s
            AND l.vendor_id  = %s
            AND l.account    = %s
            AND l.date BETWEEN %s AND %s
            ORDER BY l.date ASC, l.id ASC;
            """,
            (company_id, vendor_id, ap_posting, date_from, date_to),
        ) or []

        running = opening
        tx = []
        for r in rows:
            mv = Decimal(str(r.get("movement") or 0))
            running += mv
            tx.append({
                "id": r.get("id"),
                "date": r.get("date").isoformat() if hasattr(r.get("date"), "isoformat") else str(r.get("date")),
                "ref": r.get("ref") or "",
                "journal_id": r.get("journal_id"),
                "source": r.get("source"),
                "source_id": r.get("source_id"),
                "memo": r.get("memo") or "",
                "debit": float(r.get("debit") or 0),
                "credit": float(r.get("credit") or 0),
                "movement": float(mv),
                "balance": float(running),
            })

        # --------------------------
        # 2) Per-bill outstanding (bill-based using allocations)
        per_bill = self.fetch_all(
            f"""
            SELECT
            b.id,
            b.number,
            b.bill_date,
            b.due_date,
            b.status,
            b.total_amount::numeric(18,2) AS total_amount,
            COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid,
            (b.total_amount - COALESCE(SUM(a.amount),0))::numeric(18,2) AS outstanding
            FROM {schema}.bills b
            LEFT JOIN {schema}.vendor_payment_allocations a
            ON a.bill_id = b.id
            AND a.company_id = %s
            WHERE b.company_id = %s
            AND b.vendor_id = %s
            AND LOWER(COALESCE(b.status,'')) NOT IN ('void')
            GROUP BY b.id
            ORDER BY b.bill_date DESC, b.id DESC;
            """,
            (company_id, company_id, vendor_id),
        ) or []

        total_debit = sum(t["debit"] for t in tx)
        total_credit = sum(t["credit"] for t in tx)

        return {
            "vendor_id": int(vendor_id),
            "ap_account": ap_posting,
            "from": date_from.isoformat(),
            "to": date_to.isoformat(),
            "opening_balance": float(opening),
            "closing_balance": float(running),

            # ✅ what the UI expects (same as AR)
            "rows": tx,
            "transactions": tx,

            "totals": {
                "debits": float(total_debit),
                "credits": float(total_credit),
                # for AP, net movement is usually credit - debit (what we used as movement)
                "net_movement": float(sum(Decimal(str(t["movement"])) for t in tx)),
            },

            "per_bill": [
                {
                    "bill_id": int(r["id"]),
                    "number": r.get("number"),
                    "bill_date": r.get("bill_date").isoformat() if hasattr(r.get("bill_date"), "isoformat") else r.get("bill_date"),
                    "due_date": r.get("due_date").isoformat() if hasattr(r.get("due_date"), "isoformat") else r.get("due_date"),
                    "status": r.get("status"),
                    "total_amount": float(r.get("total_amount") or 0),
                    "paid": float(r.get("paid") or 0),
                    "outstanding": float(r.get("outstanding") or 0),
                }
                for r in per_bill
            ],
        }

    def ap_aging(self, company_id: int, *, as_of: date) -> dict:
        schema = f"company_{company_id}"

        rows = self.fetch_all(
            f"""
            SELECT
            b.vendor_id,
            b.id AS bill_id,
            b.number,
            b.bill_date,
            b.due_date,
            b.total_amount::numeric(18,2) AS total_amount,
            COALESCE(SUM(a.amount),0)::numeric(18,2) AS allocated,
            (b.total_amount - COALESCE(SUM(a.amount),0))::numeric(18,2) AS outstanding
            FROM {schema}.bills 
            LEFT JOIN {schema}.vendor_payment_allocations a
            ON a.bill_id = b.id
            WHERE b.status IN ('posted','partial','paid')
            GROUP BY b.id
            HAVING (b.total_amount - COALESCE(SUM(a.amount),0)) > 0
            ORDER BY b.vendor_id, b.due_date NULLS LAST, b.bill_date;
            """,
            (),
        ) or []

        by_vendor = {}
        for r in rows:
            vend = int(r["vendor_id"])
            due = r.get("due_date") or r.get("bill_date")
            if isinstance(due, str):
                due = date.fromisoformat(due[:10])
            days = (as_of - due).days if due else 0

            out = Decimal(str(r.get("outstanding") or "0"))

            if vend not in by_vendor:
                by_vendor[vend] = {
                    "current": Decimal("0"),
                    "b1_30": Decimal("0"),
                    "b31_60": Decimal("0"),
                    "b61_90": Decimal("0"),
                    "b91_plus": Decimal("0"),
                    "bills": [],
                }

            if days <= 0:
                by_vendor[vend]["current"] += out
                bucket = "current"
            elif 1 <= days <= 30:
                by_vendor[vend]["b1_30"] += out
                bucket = "1_30"
            elif 31 <= days <= 60:
                by_vendor[vend]["b31_60"] += out
                bucket = "31_60"
            elif 61 <= days <= 90:
                by_vendor[vend]["b61_90"] += out
                bucket = "61_90"
            else:
                by_vendor[vend]["b91_plus"] += out
                bucket = "91_plus"

            by_vendor[vend]["bills"].append({
                "bill_id": int(r["bill_id"]),
                "number": r.get("number"),
                "bill_date": r.get("bill_date").isoformat() if hasattr(r.get("bill_date"), "isoformat") else r.get("bill_date"),
                "due_date": r.get("due_date").isoformat() if hasattr(r.get("due_date"), "isoformat") else r.get("due_date"),
                "outstanding": float(out),
                "days_past_due": int(days),
                "bucket": bucket,
            })

        out_vendors = []
        grand = {
            "current": Decimal("0"),
            "b1_30": Decimal("0"),
            "b31_60": Decimal("0"),
            "b61_90": Decimal("0"),
            "b91_plus": Decimal("0"),
        }

        for vend_id, data in by_vendor.items():
            for k in grand:
                grand[k] += data[k]
            out_vendors.append({
                "vendor_id": vend_id,
                "current": float(data["current"]),
                "1_30": float(data["b1_30"]),
                "31_60": float(data["b31_60"]),
                "61_90": float(data["b61_90"]),
                "91_plus": float(data["b91_plus"]),
                "total": float(data["current"] + data["b1_30"] + data["b31_60"] + data["b61_90"] + data["b91_plus"]),
                "bills": data["bills"],
            })

        return {
            "company_id": int(company_id),
            "as_of": as_of.isoformat(),
            "vendors": out_vendors,
            "totals": {
                "current": float(grand["current"]),
                "1_30": float(grand["b1_30"]),
                "31_60": float(grand["b31_60"]),
                "61_90": float(grand["b61_90"]),
                "91_plus": float(grand["b91_plus"]),
                "total": float(grand["current"] + grand["b1_30"] + grand["b31_60"] + grand["b61_90"] + grand["b91_plus"]),
            },
        }

    def get_ap_control_balance(self, company_id: int, *, as_of: date | None = None) -> dict:
        schema = self.company_schema(company_id)
        ap_posting = self._resolve_ap_control_posting(company_id)

        where_date = ""
        params = [ap_posting]
        if as_of:
            where_date = "AND l.date <= %s"
            params.append(as_of)

        row = self.fetch_one(
            f"""
            SELECT COALESCE(SUM(l.credit - l.debit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.account = %s
            {where_date};
            """,
            tuple(params),
        ) or {}

        bal = Decimal(str(row.get("bal") or "0"))
        return {
            "ap_account": ap_posting,
            "as_of": as_of.isoformat() if as_of else None,
            "balance": float(bal),
        }


    def get_ap_subledger_by_vendor(self, company_id: int, *, as_of: date | None = None) -> list[dict]:
        schema = self.company_schema(company_id)
        ap_posting = self._resolve_ap_control_posting(company_id)

        where_date = ""
        params = [ap_posting]
        if as_of:
            where_date = "AND l.date <= %s"
            params.append(as_of)

        rows = self.fetch_all(
            f"""
            SELECT
            l.vendor_id,
            COALESCE(SUM(l.credit - l.debit), 0)::numeric(18,2) AS bal
            FROM {schema}.ledger l
            WHERE l.account = %s
            AND l.vendor_id IS NOT NULL
            {where_date}
            GROUP BY l.vendor_id
            HAVING COALESCE(SUM(l.credit - l.debit), 0) <> 0
            ORDER BY l.vendor_id ASC;
            """,
            tuple(params),
        ) or []

        return [
            {"vendor_id": int(r["vendor_id"]), "balance": float(Decimal(str(r.get("bal") or "0")))}
            for r in rows
        ]


    def get_ap_control_reconciliation(self, company_id: int, *, as_at: date | None = None) -> dict:
        control = self.get_ap_control_balance(company_id, as_of=as_at)
        sub_rows = self.get_ap_subledger_by_vendor(company_id, as_of=as_at)

        sub_total = sum(Decimal(str(r.get("balance") or 0)) for r in (sub_rows or []))
        control_total = Decimal(str(control.get("balance") or 0))
        diff = control_total - sub_total

        # enrich vendor names (optional)
        if sub_rows:
            schema = self.company_schema(company_id)
            ids = [int(r["vendor_id"]) for r in sub_rows if r.get("vendor_id") is not None]
            if ids:
                vrows = self.fetch_all(
                    f"""
                    SELECT id, name
                    FROM {schema}.vendors
                    WHERE id = ANY(%s);
                    """,
                    (ids,),
                ) or []
                name_map = {int(v["id"]): v.get("name") for v in vrows}
                for r in sub_rows:
                    r["vendor_name"] = name_map.get(int(r["vendor_id"])) if r.get("vendor_id") else None

        sub_rows_sorted = sorted(sub_rows or [], key=lambda x: abs(float(x.get("balance") or 0)), reverse=True)

        return {
            "company_id": int(company_id),
            "as_at": as_at.isoformat() if as_at else None,
            "ap_account": control.get("ap_account"),
            "control_balance": float(control_total),
            "subledger_total": float(sub_total),
            "difference": float(diff),
            "is_balanced": (diff.quantize(Decimal("0.01")) == Decimal("0.00")),
            "vendors": sub_rows_sorted,
        }

    def reverse_posted_invoice(
        self,
        company_id: int,
        invoice_id: int,
        *,
        reversal_date: date | None = None,
        reason: str | None = None,
        user_id: int | None = None,
    ) -> int:
        schema = f"company_{company_id}"
        reversal_date = reversal_date or date.today()

        inv = self.get_invoice_with_lines(company_id, invoice_id)
        if not inv:
            raise ValueError("Invoice not found")

        inv_no = (inv.get("number") or f"INV-{invoice_id}").strip()
        desc = f"Reversal of invoice: {inv_no}"
        if reason:
            desc = f"{desc} | {reason}"

        with self._conn_cursor() as (conn, cur):
            try:
                # 1) lock invoice
                cur.execute(
                    f"""
                    SELECT status, posted_journal_id
                    FROM {schema}.invoices
                    WHERE id=%s
                    FOR UPDATE;
                    """,
                    (invoice_id,),
                )
                hdr = cur.fetchone() or {}
                status = (hdr.get("status") or "").lower()
                orig_journal_id = hdr.get("posted_journal_id")

                if not orig_journal_id or status != "posted":
                    raise ValueError("Only posted invoices can be reversed")

                # 2) prevent double reversal (simple guard)
                # If you add invoice.reversed_journal_id later, use that instead.
                cur.execute(
                    f"""
                    SELECT 1
                    FROM {schema}.journal
                    WHERE is_reversal = TRUE
                    AND reversed_journal_id = %s
                    LIMIT 1;
                    """,
                    (int(orig_journal_id),),
                )
                if cur.fetchone():
                    raise ValueError("Invoice journal already reversed")

                # 3) fetch original ledger lines
                cur.execute(
                    f"""
                    SELECT account, debit, credit, memo, customer_id
                    FROM {schema}.ledger
                    WHERE journal_id = %s
                    ORDER BY id ASC;
                    """,
                    (int(orig_journal_id),),
                )
                orig_lines = cur.fetchall() or []
                if not orig_lines:
                    raise ValueError("Original journal has no ledger lines")

                # 4) create reversal journal header
                rev_ref = f"REV-{inv_no}"
                journal_entry = {
                    "date": reversal_date,
                    "ref": rev_ref,
                    "description": desc,
                    "gross_amount": 0.0,
                    "net_amount": 0.0,
                    "vat_amount": 0.0,
                    "is_reversal": True,
                    "reversed_journal_id": int(orig_journal_id),
                    "source": "invoice_reversal",
                    "source_id": int(invoice_id),
                }

                rev_journal_id = int(self.insert_journal(company_id, journal_entry, cur=cur) or 0)
                if rev_journal_id <= 0:
                    raise ValueError("Failed to create reversal journal")

                # 5) reverse ledger lines (swap Dr/Cr), update TB
                for ln in orig_lines:
                    acct = (ln.get("account") or "").strip()
                    dr = float(ln.get("debit") or 0.0)
                    cr = float(ln.get("credit") or 0.0)

                    if not acct:
                        raise ValueError("Bad ledger line: missing account")

                    # swap
                    rev_line = {
                        "account_code": acct,
                        "debit": cr,
                        "credit": dr,
                        "description": desc,
                    }

                    self.insert_ledger(
                        company_id=company_id,
                        journal_id=rev_journal_id,
                        je_date=reversal_date,
                        line=rev_line,
                        ref=rev_ref,
                        customer_id=ln.get("customer_id"),  # keep subledger trace
                        cur=cur,
                    )
                    self.update_trial_balance(company_id, rev_line, cur=cur)

                    if self.requires_notes(acct):
                        self.insert_note(company_id, rev_journal_id, acct, desc, cur=cur)

                # 6) mark invoice reversed (audit-safe)
                cur.execute(
                    f"""
                    UPDATE {schema}.invoices
                    SET status='reversed',
                        updated_at=NOW()
                    WHERE id=%s;
                    """,
                    (invoice_id,),
                )

                conn.commit()
                return rev_journal_id

            except Exception:
                conn.rollback()
                raise

    def writeoff_invoice(
        self,
        company_id: int,
        invoice_id: int,
        *,
        writeoff_account_code: str,
        reason: str = "",
        written_off_by: int | None = None,
        writeoff_date: str | date | None = None,
        vat_relief: bool = False,          # ✅ optional
        vat_relief_account: str | None = None,  # ✅ optional (if vat_relief True)
    ) -> int:
        schema = self.company_schema(company_id)

        def money(x) -> Decimal:
            return Decimal(str(x or "0")).quantize(Decimal("0.01"))

        # ✅ date
        if writeoff_date is None or str(writeoff_date).strip() == "":
            wo_date = date.today()
        elif isinstance(writeoff_date, date):
            wo_date = writeoff_date
        else:
            wo_date = date.fromisoformat(str(writeoff_date)[:10])

        # ✅ Period lock gate
        if self.is_date_locked(company_id, tx_date=wo_date, module="ar"):
            raise ValueError(f"PERIOD_LOCKED|ar|{wo_date.isoformat()}")

        writeoff_account_code = (writeoff_account_code or "").strip()
        if not writeoff_account_code:
            raise ValueError("writeoff_account_code is required")

        wo_reason = (reason or "").strip() or "Bad debt write-off"

        with self._conn_cursor() as (conn, cur):
            try:
                # 1) Lock invoice
                cur.execute(
                    f"""
                    SELECT
                        id, number, status, posted_journal_id, reversed_journal_id,
                        writeoff_journal_id, customer_id,
                        gross_amount, net_amount, vat_amount,
                        total, subtotal_amount
                    FROM {schema}.invoices
                    WHERE id=%s
                    FOR UPDATE;
                    """,
                    (invoice_id,),
                )
                inv = cur.fetchone()
                if not inv:
                    raise ValueError("Invoice not found")

                status = (inv.get("status") or "").lower()
                inv_no = inv.get("number") or f"INV-{invoice_id}"

                if status != "posted":
                    raise ValueError("Only posted invoices can be written off")

                if inv.get("reversed_journal_id"):
                    raise ValueError("Cannot write-off: invoice is reversed")

                if inv.get("writeoff_journal_id"):
                    raise ValueError("Invoice already written off")

                posted_journal_id = inv.get("posted_journal_id")
                if not posted_journal_id:
                    raise ValueError("Invoice has no posted_journal_id")

                # 2) Paid/allocations
                cur.execute(
                    f"""
                    SELECT COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid
                    FROM {schema}.receipt_allocations a
                    WHERE a.invoice_id = %s;
                    """,
                    (invoice_id,),
                )
                paid_row = cur.fetchone() or {}
                paid = money(paid_row.get("paid"))

                # (keep your current rule, but now it's correct even if later you allow partials)
                if paid > money("0.00"):
                    raise ValueError("Cannot write-off: invoice has receipts/allocations. Unallocate first.")

                # 3) Amounts (✅ fallback to your JSON-style fields)
                gross = money(inv.get("gross_amount") or inv.get("total"))
                net   = money(inv.get("net_amount")   or inv.get("subtotal_amount"))
                vat   = money(inv.get("vat_amount"))

                if gross <= money("0.00"):
                    raise ValueError("Invoice total is zero; nothing to write off")

                outstanding_gross = (gross - paid).quantize(Decimal("0.01"))
                if outstanding_gross <= money("0.00"):
                    raise ValueError("Invoice is fully settled; nothing to write off")

                # 4) Resolve AR control
                ar_control = self.get_control_account_code(company_id, "AR_CONTROL")
                if not ar_control:
                    row = self.get_account_row_for_posting(company_id, "9002")
                    ar_control = row[1] if row else None
                if not ar_control:
                    raise ValueError("AR control account not configured (AR_CONTROL / 9002)")

                # 5) Create journal header
                wo_ref = f"WO-{inv_no}"
                wo_desc = f"Write-off {inv_no} | {wo_reason}"

                je_date = wo_date.isoformat()

                wo_entry = {
                    "date": je_date,
                    "ref": wo_ref,
                    "description": wo_desc,
                    "gross_amount": float(outstanding_gross),
                    "net_amount": float(net),
                    "vat_amount": float(vat),
                    "source": "invoice_writeoff",
                    "source_id": int(invoice_id),
                }

                writeoff_journal_id = int(self.insert_journal(company_id, wo_entry, cur=cur) or 0)
                if writeoff_journal_id <= 0:
                    raise ValueError("Failed to create write-off journal")

                cust_id = inv.get("customer_id")

                # 6) Ledger lines
                if vat_relief and vat > money("0.00"):
                    # DR expense net
                    dr_exp = {
                        "account_code": writeoff_account_code,
                        "debit": float(net),
                        "credit": 0.0,
                        "description": wo_desc,
                        "memo": wo_reason,
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, dr_exp, ref=wo_ref, customer_id=None, cur=cur)
                    self.update_trial_balance(company_id, dr_exp, cur=cur)

                    # DR VAT relief
                    if not vat_relief_account:
                        raise ValueError("vat_relief_account required when vat_relief=true")

                    dr_vat = {
                        "account_code": vat_relief_account,
                        "debit": float(vat),
                        "credit": 0.0,
                        "description": wo_desc,
                        "memo": "VAT relief on bad debt",
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, dr_vat, ref=wo_ref, customer_id=None, cur=cur)
                    self.update_trial_balance(company_id, dr_vat, cur=cur)

                    # CR AR gross
                    cr_ar = {
                        "account_code": ar_control,
                        "debit": 0.0,
                        "credit": float(net + vat),
                        "description": wo_desc,
                        "memo": wo_reason,
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, cr_ar, ref=wo_ref, customer_id=cust_id, cur=cur)
                    self.update_trial_balance(company_id, cr_ar, cur=cur)

                else:
                    # Simple: DR expense gross
                    dr_line = {
                        "account_code": writeoff_account_code,
                        "debit": float(outstanding_gross),
                        "credit": 0.0,
                        "description": wo_desc,
                        "memo": wo_reason,
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, dr_line, ref=wo_ref, customer_id=None, cur=cur)
                    self.update_trial_balance(company_id, dr_line, cur=cur)

                    # CR AR gross (with customer_id)
                    cr_line = {
                        "account_code": ar_control,
                        "debit": 0.0,
                        "credit": float(outstanding_gross),
                        "description": wo_desc,
                        "memo": wo_reason,
                    }
                    self.insert_ledger(company_id, writeoff_journal_id, je_date, cr_line, ref=wo_ref, customer_id=cust_id, cur=cur)
                    self.update_trial_balance(company_id, cr_line, cur=cur)

                # 7) Stamp invoice
                cur.execute(
                    f"""
                    UPDATE {schema}.invoices
                    SET status='written_off',
                        writeoff_journal_id=%s,
                        written_off_at=NOW(),
                        written_off_by=%s,
                        writeoff_reason=%s,
                        updated_at=NOW()
                    WHERE id=%s
                    RETURNING id;
                    """,
                    (writeoff_journal_id, written_off_by, wo_reason, invoice_id),
                )
                if not cur.fetchone():
                    raise ValueError("Failed to stamp invoice written off")

                conn.commit()
                return writeoff_journal_id

            except Exception:
                conn.rollback()
                raise

    def get_ar_aging_report(
        self,
        company_id: int,
        *,
        as_at: date,
        customer_id: int | None = None,
    ) -> dict:
        schema = self.company_schema(company_id)

        # Optional customer filter
        cust_filter_sql = ""
        params: list[Any] = []

        # Param 1: alloc cutoff date
        params.append(as_at)

        # Param 2: days_overdue reference date
        params.append(as_at)

        if customer_id is not None:
            cust_filter_sql = "AND i.customer_id = %s"
            params.append(int(customer_id))

        # Param last: invoice cutoff date
        params.append(as_at)

        rows = self.fetch_all(
            f"""
            WITH alloc AS (
                SELECT
                    a.invoice_id,
                    COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid
                FROM {schema}.receipt_allocations a
                JOIN {schema}.receipts r ON r.id = a.receipt_id
                WHERE r.receipt_date <= %s
                GROUP BY a.invoice_id
            )
            SELECT
                i.id AS invoice_id,
                i.customer_id,
                c.name AS customer_name,
                i.number,
                i.invoice_date,
                i.due_date,
                i.total_amount::numeric(18,2) AS invoice_total,
                COALESCE(al.paid, 0)::numeric(18,2) AS paid_to_date,
                (i.total_amount - COALESCE(al.paid, 0))::numeric(18,2) AS outstanding,
                GREATEST(
                    0,
                    (%s::date - COALESCE(i.due_date, i.invoice_date))::int
                ) AS days_overdue
            FROM {schema}.invoices i
            JOIN {schema}.customers c ON c.id = i.customer_id
            LEFT JOIN alloc al ON al.invoice_id = i.id
            WHERE i.status NOT IN ('void', 'draft')
            {cust_filter_sql}
            AND i.invoice_date <= %s
            ORDER BY c.name ASC, i.invoice_date ASC, i.id ASC;
            """,
            tuple(params),
        ) or []

        def bucket(days: int) -> str:
            if days <= 30:
                return "0_30"
            if days <= 60:
                return "31_60"
            if days <= 90:
                return "61_90"
            if days <= 120:
                return "91_120"
            return "121_plus"

        customers: Dict[int, Dict[str, Any]] = {}
        grand = {
            "0_30": Decimal("0"),
            "31_60": Decimal("0"),
            "61_90": Decimal("0"),
            "91_120": Decimal("0"),
            "121_plus": Decimal("0"),
            "total": Decimal("0"),
        }

        invoice_lines_out: List[Dict[str, Any]] = []

        for r in rows:
            outstanding = _d(r.get("outstanding"))
            if outstanding <= Decimal("0.00"):
                continue

            cid = int(r["customer_id"])
            cname = r.get("customer_name") or ""

            if cid not in customers:
                customers[cid] = {
                    "customer_id": cid,
                    "customer_name": cname,
                    "buckets": {
                        "0_30": 0.0,
                        "31_60": 0.0,
                        "61_90": 0.0,
                        "91_120": 0.0,
                        "121_plus": 0.0,
                        "total": 0.0,
                    },
                    "invoices": [],
                }

            days = int(r.get("days_overdue") or 0)
            b = bucket(days)

            inv_date = r.get("invoice_date")
            due_date = r.get("due_date")

            inv_obj = {
                "invoice_id": int(r["invoice_id"]),
                "number": r.get("number"),
                "invoice_date": inv_date.isoformat() if hasattr(inv_date, "isoformat") else str(inv_date),
                "due_date": due_date.isoformat() if hasattr(due_date, "isoformat") else (str(due_date) if due_date else None),
                "invoice_total": float(_d(r.get("invoice_total"))),
                "paid_to_date": float(_d(r.get("paid_to_date"))),
                "outstanding": float(outstanding),
                "days_overdue": days,
                "bucket": b,
            }

            customers[cid]["invoices"].append(inv_obj)
            customers[cid]["buckets"][b] += float(outstanding)
            customers[cid]["buckets"]["total"] += float(outstanding)

            grand[b] += outstanding
            grand["total"] += outstanding

            invoice_lines_out.append({**inv_obj, "customer_id": cid, "customer_name": cname})

        cust_list = sorted(customers.values(), key=lambda x: (x["customer_name"] or "").lower())

        return {
            "company_id": int(company_id),
            "as_at": as_at.isoformat(),
            "customer_id": int(customer_id) if customer_id is not None else None,
            "customers": cust_list,
            "invoices": invoice_lines_out,
            "totals": {
                "0_30": float(grand["0_30"]),
                "31_60": float(grand["31_60"]),
                "61_90": float(grand["61_90"]),
                "91_120": float(grand["91_120"]),
                "121_plus": float(grand["121_plus"]),
                "total": float(grand["total"]),
            },
        }


    def reverse_invoice(
        self,
        company_id: int,
        invoice_id: int,
        *,
        reason: str = "",
        reversed_by: int | None = None,
        reversal_date: str | date | None = None,   # ✅ NEW
    ) -> int:
        """
        Reverse a posted invoice by creating a reversing journal.
        """
        schema = self.company_schema(company_id)

        def money(x) -> float:
            return float(Decimal(str(x or 0)).quantize(Decimal("0.01")))

        # ✅ Choose reversal date (default today)
        if reversal_date is None or str(reversal_date).strip() == "":
            rev_date = date.today()
        else:
            if isinstance(reversal_date, date):
                rev_date = reversal_date
            else:
                rev_date = date.fromisoformat(str(reversal_date)[:10])

        # ✅ Period lock gate (pick ONE module; I suggest "ar" for invoice ops)
        if self.is_date_locked(company_id, tx_date=rev_date, module="ar"):
            raise ValueError(f"PERIOD_LOCKED|ar|{rev_date.isoformat()}")

        with self._conn_cursor() as (conn, cur):
            try:
                # 1) Lock invoice row
                cur.execute(
                    f"""
                    SELECT id, number, status, posted_journal_id, reversed_journal_id, customer_id
                    FROM {schema}.invoices
                    WHERE id=%s
                    FOR UPDATE;
                    """,
                    (invoice_id,),
                )
                inv = cur.fetchone()
                if not inv:
                    raise ValueError("Invoice not found")

                inv_no = inv.get("number") or f"INV-{invoice_id}"
                status = (inv.get("status") or "").lower()
                posted_journal_id = inv.get("posted_journal_id")
                if not posted_journal_id or status != "posted":
                    raise ValueError("Only posted invoices can be reversed")

                if inv.get("reversed_journal_id"):
                    raise ValueError("Invoice already reversed")

                # 2) Block reversal if allocations exist
                cur.execute(
                    f"""
                    SELECT COALESCE(SUM(a.amount), 0)::numeric(18,2) AS paid
                    FROM {schema}.receipt_allocations a
                    WHERE a.invoice_id = %s;
                    """,
                    (invoice_id,),
                )
                paid_row = cur.fetchone() or {}
                paid = Decimal(str(paid_row.get("paid") or "0"))
                if paid > Decimal("0.00"):
                    raise ValueError("Cannot reverse: invoice has receipts/allocations. Unallocate first.")

                # 3) Fetch original journal header
                cur.execute(
                    f"""
                    SELECT id, date, ref, description, gross_amount, net_amount, vat_amount
                    FROM {schema}.journal
                    WHERE id=%s
                    LIMIT 1;
                    """,
                    (posted_journal_id,),
                )
                jh = cur.fetchone()
                if not jh:
                    raise ValueError("Original journal not found for this invoice")

                # 4) Fetch original ledger lines
                cur.execute(
                    f"""
                    SELECT id, account, debit, credit, memo, customer_id
                    FROM {schema}.ledger
                    WHERE journal_id = %s
                    ORDER BY id ASC;
                    """,
                    (posted_journal_id,),
                )
                led_lines = cur.fetchall() or []
                if not led_lines:
                    raise ValueError("Original ledger lines not found for this invoice journal")

                # 5) Create reversal journal header (✅ use rev_date)
                rev_ref = f"REV-{inv_no}"
                rev_desc = (reason or "").strip() or f"Reversal of invoice {inv_no}"

                rev_entry = {
                    "date": rev_date.isoformat(),  # ✅ changed
                    "ref": rev_ref,
                    "description": rev_desc,
                    "gross_amount": money(jh.get("gross_amount")),
                    "net_amount": money(jh.get("net_amount")),
                    "vat_amount": money(jh.get("vat_amount")),
                    "source": "invoice_reversal",
                    "source_id": int(invoice_id),
                }

                reversal_journal_id = int(self.insert_journal(company_id, rev_entry, cur=cur) or 0)
                if reversal_journal_id <= 0:
                    raise ValueError("Failed to create reversal journal")

                # 6) Insert reversing ledger lines + TB updates
                for ln in led_lines:
                    acct = (ln.get("account") or "").strip()
                    if not acct:
                        continue

                    d = money(ln.get("debit"))
                    c = money(ln.get("credit"))

                    rev_line = {
                        "account_code": acct,
                        "debit": c,
                        "credit": d,
                        "description": rev_desc,
                        "memo": ln.get("memo") or rev_desc,
                    }

                    self.insert_ledger(
                        company_id=company_id,
                        journal_id=reversal_journal_id,
                        je_date=rev_entry["date"],  # ✅ already rev_date.isoformat()
                        line=rev_line,
                        ref=rev_ref,
                        customer_id=ln.get("customer_id"),
                        cur=cur,
                    )
                    self.update_trial_balance(company_id, rev_line, cur=cur)

                # 7) Mark original journal + reversal journal
                cur.execute(
                    f"UPDATE {schema}.journal SET reversed_journal_id=%s WHERE id=%s;",
                    (reversal_journal_id, posted_journal_id),
                )
                cur.execute(
                    f"""
                    UPDATE {schema}.journal
                    SET is_reversal=TRUE, reversed_journal_id=%s
                    WHERE id=%s;
                    """,
                    (posted_journal_id, reversal_journal_id),
                )

                # 8) Stamp invoice
                cur.execute(
                    f"""
                    UPDATE {schema}.invoices
                    SET status='reversed',
                        reversed_journal_id=%s,
                        reversed_at=NOW(),
                        reversed_by=%s,
                        reversal_reason=%s,
                        updated_at=NOW()
                    WHERE id=%s
                    RETURNING id;
                    """,
                    (reversal_journal_id, reversed_by, rev_desc, invoice_id),
                )
                if not cur.fetchone():
                    raise ValueError("Failed to stamp invoice reversed")

                conn.commit()
                return reversal_journal_id

            except Exception:
                conn.rollback()
                raise

    def is_date_locked(
        self,
        company_id: int,
        *,
        tx_date: date,
        module: str = "gl",
        cur=None,
    ) -> bool:
        schema = self.company_schema(company_id)
        module = (module or "gl").strip().lower()

        sql = f"""
        SELECT 1
        FROM {schema}.period_locks
        WHERE company_id = %s
        AND status = 'active'
        AND (module = %s OR module = 'all')
        AND %s BETWEEN lock_from AND lock_to
        LIMIT 1;
        """
        params = (company_id, module, tx_date)

        if cur is not None:
            cur.execute(sql, params)
            return cur.fetchone() is not None

        row = self.fetch_one(sql, params)
        return bool(row)

    def assert_not_locked(
        self,
        company_id: int,
        *,
        tx_date: date,
        module: str = "gl",
        action: str = "post",
        cur=None,
    ) -> None:
        if self.is_date_locked(company_id, tx_date=tx_date, module=module, cur=cur):
            raise ValueError(f"Period is locked for {module.upper()} - cannot {action} on {tx_date.isoformat()}")


    def get_customer_ar_balance(self, company_id: int, customer_id: int, as_at: date | None = None) -> Decimal:
        schema = self.company_schema(company_id)

        # ✅ Get AR control account code (single source of truth)
        ar_code = self.get_control_account_code(company_id, "AR_CONTROL")
        if not ar_code:
            raise ValueError("AR control account not configured (AR_CONTROL)")

        params = [int(company_id), int(customer_id), str(ar_code)]
        date_sql = ""
        if as_at is not None:
            date_sql = "AND date <= %s"
            params.append(as_at)

        with self._conn_cursor() as (_conn, cur):   # ✅ FIX: define cur here
            cur.execute(
                f"""
                SELECT COALESCE(SUM(debit - credit), 0)::numeric(18,2) AS bal
                FROM {schema}.ledger
                WHERE company_id = %s
                AND customer_id = %s
                AND account = %s
                {date_sql};
                """,
                tuple(params),
            )

            row = cur.fetchone() or {}
            return Decimal(str(row.get("bal") or "0"))

    def assert_credit_ok_for_invoice_post(
        self,
        company_id: int,
        invoice: dict,
        *,
        require_approved: bool = False,
    ) -> None:
        customer_id = invoice.get("customer_id")
        if not customer_id:
            return

        cust = self.get_customer(company_id, int(customer_id)) or {}
        on_hold = str(cust.get("on_hold") or "no").strip().lower() in ("yes", "true", "1")
        credit_status = str(cust.get("credit_status") or "draft").strip().lower()

        if on_hold:
            raise ValueError("CREDIT_BLOCKED|CUSTOMER_ON_HOLD")

        if require_approved and credit_status != "approved":
            raise ValueError("CREDIT_BLOCKED|CUSTOMER_NOT_APPROVED")

        limit = Decimal(str(cust.get("credit_limit") or "0"))
        if limit <= Decimal("0"):
            raise ValueError("CREDIT_LIMIT_EXCEEDED|limit=0")

        # ✅ invoice date for as-at
        inv_date = invoice.get("invoice_date") or invoice.get("date")
        if isinstance(inv_date, str):
            inv_date = date.fromisoformat(inv_date[:10])
        elif hasattr(inv_date, "date"):
            inv_date = inv_date.date()
        elif not isinstance(inv_date, date):
            inv_date = date.today()

        # ✅ this method should accept as_at (we’ll wire it next if yours doesn’t yet)
        current = self.get_customer_ar_balance(company_id, int(customer_id), as_at=inv_date)

        gross = Decimal(str(
            invoice.get("total") or
            invoice.get("total_amount") or
            invoice.get("gross_amount") or
            "0"
        ))

        projected = current + gross
        if projected > limit:
            raise ValueError(
                f"CREDIT_LIMIT_EXCEEDED|limit={limit}|current={current}|invoice={gross}|projected={projected}"
            )

    def credit_check(self, company_id: int, customer_id: int, *, amount="0", as_at=None) -> dict:
        cust = self.get_customer(company_id, int(customer_id)) or {}
        limit = Decimal(str(cust.get("credit_limit") or "0"))
        on_hold = str(cust.get("on_hold") or "no").strip().lower() in ("yes","true","1")
        credit_status = str(cust.get("credit_status") or "draft").strip().lower()

        dt = None
        if as_at:
            dt = date.fromisoformat(str(as_at)[:10])

        current = self.get_customer_ar_balance(company_id, int(customer_id), as_at=dt)
        amt = Decimal(str(amount or "0"))
        projected = current + amt

        exceeded = (limit > 0 and projected > limit)
        pct = None
        if limit > 0:
            pct = float((projected / limit * Decimal("100")).quantize(Decimal("0.01")))

        return {
            "customer_id": int(customer_id),
            "limit": float(limit),
            "current": float(current),
            "amount": float(amt),
            "projected": float(projected),
            "exceeded": bool(exceeded),
            "on_hold": bool(on_hold),
            "credit_status": credit_status,
            "utilization_pct": pct,
        }

    def get_company_branding(self, company_id: int) -> Optional[Dict[str, Any]]:
        sql = """
        SELECT
            c.id AS company_id,

            -- Name / statutory
            c.name AS company_name,
            c.company_reg_no AS reg_no,

            -- Prefer branding table values, fallback to companies
            COALESCE(b.logo_url, c.logo_url) AS logo_url,
            COALESCE(b.footer_text, NULL) AS footer_text,
            COALESCE(b.contact_phone, c.company_phone) AS contact_phone,
            COALESCE(b.contact_email, c.company_email) AS contact_email,
            COALESCE(b.website, NULL) AS website,

            -- Address preference: branding.address, else physical/postal
            COALESCE(
                b.address,
                NULLIF(c.physical_address, ''),
                NULLIF(c.postal_address, '')
            ) AS address,

            COALESCE(b.vat_no, c.vat) AS vat_no,

            COALESCE(b.updated_at, c.created_at) AS updated_at
        FROM public.companies c
        LEFT JOIN public.company_branding b
        ON b.company_id = c.id
        WHERE c.id = %s
        LIMIT 1;
        """
        return self.fetch_one(sql, (int(company_id),))

    def upsert_company_branding(self, company_id: int, payload: Dict[str, Any]) -> Dict[str, Any]:
        """
        Upsert branding for a company.

        payload keys (any subset):
        logo_url, footer_text, contact_phone, contact_email,
        website, address, vat_no
        """
        cid = int(company_id)

        def _clean(v):
            # Normalize empty strings to None so you can "clear" a field if you want
            if v is None:
                return None
            if isinstance(v, str):
                v = v.strip()
                return v if v != "" else None
            return v

        logo_url      = _clean(payload.get("logo_url"))      if "logo_url" in payload      else None
        footer_text   = _clean(payload.get("footer_text"))   if "footer_text" in payload   else None
        contact_phone = _clean(payload.get("contact_phone")) if "contact_phone" in payload else None
        contact_email = _clean(payload.get("contact_email")) if "contact_email" in payload else None
        website       = _clean(payload.get("website"))       if "website" in payload       else None
        address       = _clean(payload.get("address"))       if "address" in payload       else None
        vat_no        = _clean(payload.get("vat_no"))        if "vat_no" in payload        else None

        # IMPORTANT: We want "partial update":
        # - If caller didn’t include a key at all, we must NOT overwrite.
        # We implement this by passing values (or NULL) and using CASE with a "has_key" flag.
        has_logo_url      = 1 if "logo_url" in payload      else 0
        has_footer_text   = 1 if "footer_text" in payload   else 0
        has_contact_phone = 1 if "contact_phone" in payload else 0
        has_contact_email = 1 if "contact_email" in payload else 0
        has_website       = 1 if "website" in payload       else 0
        has_address       = 1 if "address" in payload       else 0
        has_vat_no        = 1 if "vat_no" in payload        else 0

        sql = """
        INSERT INTO public.company_branding (
            company_id, logo_url, footer_text, contact_phone, contact_email,
            website, address, vat_no, updated_at
        )
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s, NOW())
        ON CONFLICT (company_id) DO UPDATE SET
            logo_url = CASE WHEN %s=1 THEN EXCLUDED.logo_url ELSE public.company_branding.logo_url END,
            footer_text = CASE WHEN %s=1 THEN EXCLUDED.footer_text ELSE public.company_branding.footer_text END,
            contact_phone = CASE WHEN %s=1 THEN EXCLUDED.contact_phone ELSE public.company_branding.contact_phone END,
            contact_email = CASE WHEN %s=1 THEN EXCLUDED.contact_email ELSE public.company_branding.contact_email END,
            website = CASE WHEN %s=1 THEN EXCLUDED.website ELSE public.company_branding.website END,
            address = CASE WHEN %s=1 THEN EXCLUDED.address ELSE public.company_branding.address END,
            vat_no = CASE WHEN %s=1 THEN EXCLUDED.vat_no ELSE public.company_branding.vat_no END,
            updated_at = NOW()
        RETURNING
            company_id, logo_url, footer_text, contact_phone, contact_email,
            website, address, vat_no, updated_at;
        """

        params = (
            cid,
            logo_url,
            footer_text,
            contact_phone,
            contact_email,
            website,
            address,
            vat_no,
            has_logo_url,
            has_footer_text,
            has_contact_phone,
            has_contact_email,
            has_website,
            has_address,
            has_vat_no,
        )

        row = self.fetch_one(sql, params)
        return row or {"company_id": cid}

    def create_bank_import(self, company_id: int, bank_account_id: int | None, file_name: str, file_ext: str,
                        file_hash: str, uploaded_by: int | None, currency: str = "ZAR") -> int:
        row = self.fetch_one("""
            INSERT INTO public.bank_statement_imports
            (company_id, bank_account_id, file_name, file_ext, file_hash, uploaded_by, currency, status)
            VALUES (%s,%s,%s,%s,%s,%s,%s,'uploaded')
            ON CONFLICT (company_id, file_hash) DO UPDATE
            SET uploaded_at = now(),
                file_name = EXCLUDED.file_name,
                file_ext  = EXCLUDED.file_ext,
                bank_account_id = COALESCE(EXCLUDED.bank_account_id, public.bank_statement_imports.bank_account_id),
                currency = COALESCE(EXCLUDED.currency, public.bank_statement_imports.currency)
            RETURNING id;
            """,
            (company_id, bank_account_id, file_name, file_ext, file_hash, uploaded_by, currency),
        )
        return int(row["id"])

    def insert_bank_statement_lines(self, company_id: int, import_id: int, lines: list[dict]) -> int:
        if not lines:
            return 0

        # Build tuples once
        values = []
        for ln in lines:
            values.append((
                company_id, import_id,
                ln.get("line_date"), ln.get("value_date"),
                ln["amount"],
                ln.get("currency") or "ZAR",
                ln.get("description"), ln.get("reference"),
                ln.get("counterparty"), ln.get("running_balance"),
                ln["fingerprint"],
            ))

        sql = """
        WITH ins AS (
        INSERT INTO public.bank_statement_lines
            (company_id, import_id, line_date, value_date, amount, currency,
            description, reference, counterparty, running_balance, fingerprint)
        VALUES %s
        ON CONFLICT (import_id, fingerprint) DO NOTHING
        RETURNING 1
        )
        SELECT COUNT(*)::int AS n FROM ins;
        """

        with self._conn_cursor() as (_c, cur):
            execute_values(cur, sql, values, page_size=500)
            row = cur.fetchone()
            return int(row["n"] if row else 0)

