    def seed_recon_items_from_lines(self, company_id: int, reconciliation_id: int, user_id: int | None) -> int:
        # Seeds all lines belonging to the same bank account's imports in range
        row = self.fetch_one(
            """
            WITH ins AS (
            INSERT INTO public.bank_recon_items
                (company_id, reconciliation_id, statement_line_id, match_status, prepared_by)
            SELECT
                %s, %s, l.id, 'unmatched', %s
            FROM public.bank_statement_lines l
            JOIN public.bank_statement_imports i ON i.id = l.import_id
            JOIN public.bank_reconciliations r ON r.id = %s
            WHERE l.company_id = %s
                AND i.bank_account_id = r.bank_account_id
                AND l.line_date BETWEEN r.period_start AND r.period_end
            ON CONFLICT (reconciliation_id, statement_line_id) DO NOTHING
            RETURNING 1
            )
            SELECT COUNT(*) AS n FROM ins;
            """,
            (company_id, reconciliation_id, user_id, reconciliation_id, company_id),
        )
        return int(row["n"])

