    def list_recon_items(self, company_id: int, recon_id: int, status: str | None = None):
        sql = """
        SELECT
        i.id AS recon_item_id,
        i.match_status,
        i.match_type,
        i.matched_object_type,
        i.matched_object_id,
        i.created_journal_id,
        i.excluded_reason,
        i.prepared_by,
        i.prepared_at,
        l.id AS statement_line_id,
        l.line_date,
        l.value_date,
        l.amount,
        l.currency,
        l.description,
        l.reference,
        l.counterparty,
        l.running_balance
        FROM public.bank_recon_items i
        JOIN public.bank_statement_lines l ON l.id = i.statement_line_id
        WHERE i.company_id=%s AND i.reconciliation_id=%s
        AND (%s IS NULL OR i.match_status=%s)
        ORDER BY l.line_date NULLS LAST, l.id;
        """
        return self.fetch_all(sql, (company_id, recon_id, status, status))

