    def get_recon_summary(self, company_id: int, recon_id: int):
        sql = """
        SELECT
        COUNT(*) FILTER (WHERE match_status='unmatched') AS unmatched,
        COUNT(*) FILTER (WHERE match_status='matched')   AS matched,
        COUNT(*) FILTER (WHERE match_status='partial')   AS partial,
        COUNT(*) FILTER (WHERE match_status='excluded')  AS excluded,
        COUNT(*) AS total
        FROM public.bank_recon_items
        WHERE company_id=%s AND reconciliation_id=%s;
        """
        return self.fetch_one(sql, (company_id, recon_id)) or {}

