    def create_engagement(
        self,
        cur,
        company_id: int,
        *,
        customer_id: int,
        target_company_id: int = None,
        engagement_name: str,
        engagement_type: str,
        engagement_code: str = None,
        status: str = "draft",
        governance_mode: str = None,
        reporting_cycle: str = None,
        due_date=None,
        start_date=None,
        end_date=None,
        manager_user_id: int = None,
        partner_user_id: int = None,
        description: str = None,
        scope_summary: str = None,
        fiscal_year_end=None,
        priority: str = "normal",
        workflow_stage: str = "planning",
        created_by_user_id: int = None,
        requires_workspace: bool = False,
        workspace_status: str = "not_required",
        workspace_source: str = None,
        target_company_source: str = None,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
        INSERT INTO {schema}.engagements (
            company_id,
            customer_id,
            target_company_id,
            engagement_code,
            engagement_name,
            engagement_type,
            status,
            governance_mode,
            reporting_cycle,
            due_date,
            start_date,
            end_date,
            manager_user_id,
            partner_user_id,
            created_by_user_id,
            updated_by_user_id,
            description,
            scope_summary,
            fiscal_year_end,
            priority,
            workflow_stage,
            requires_workspace,
            workspace_status,
            workspace_source,
            target_company_source
        )
        VALUES (
            %s,
            %s,
            %s,
            NULLIF(BTRIM(%s), ''),
            NULLIF(BTRIM(%s), ''),
            %s,
            %s,
            %s,
            NULLIF(BTRIM(%s), ''),
            %s,
            %s,
            %s,
            %s,
            %s,
            %s,
            %s,
            NULLIF(BTRIM(%s), ''),
            NULLIF(BTRIM(%s), ''),
            %s,
            %s,
            %s,
            %s,
            %s,
            %s,
            %s
        )
        RETURNING id
        """
        cur.execute(sql, (
            company_id,
            customer_id,
            target_company_id,
            engagement_code,
            engagement_name,
            engagement_type,
            status or "draft",
            governance_mode,
            reporting_cycle,
            due_date,
            start_date,
            end_date,
            manager_user_id,
            partner_user_id,
            created_by_user_id,
            created_by_user_id,
            description,
            scope_summary,
            fiscal_year_end,
            priority or "normal",
            workflow_stage or "planning",
            bool(requires_workspace),
            workspace_status or ("linked" if target_company_id else "not_required"),
            workspace_source,
            target_company_source,
        ))
        row = cur.fetchone()
        engagement_id = row["id"] if isinstance(row, dict) else row[0]

        if manager_user_id:
            self.add_engagement_team_member(
                cur,
                company_id,
                engagement_id=engagement_id,
                user_id=manager_user_id,
                role_on_engagement="manager",
            )

        if partner_user_id:
            self.add_engagement_team_member(
                cur,
                company_id,
                engagement_id=engagement_id,
                user_id=partner_user_id,
                role_on_engagement="partner",
            )

        return engagement_id

    def update_engagement(
        self,
        cur,
        company_id: int,
        *,
        target_company_id: int = None,
        engagement_id: int,
        updated_by_user_id: int,
        engagement_code: str = None,
        engagement_name: str = None,
        engagement_type: str = None,
        status: str = None,
        governance_mode: str = None,
        reporting_cycle: str = None,
        due_date=None,
        start_date=None,
        end_date=None,
        manager_user_id: int = None,
        partner_user_id: int = None,
        description: str = None,
        scope_summary: str = None,
        fiscal_year_end=None,
        priority: str = None,
        workflow_stage: str = None,
        is_active: bool = None,
        requires_workspace: bool = None,
        workspace_status: str = None,
        workspace_source: str = None,
        target_company_source: str = None,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            UPDATE {schema}.engagements
            SET
                engagement_code = COALESCE(NULLIF(BTRIM(%s), ''), engagement_code),
                engagement_name = COALESCE(NULLIF(BTRIM(%s), ''), engagement_name),
                engagement_type = COALESCE(NULLIF(BTRIM(%s), ''), engagement_type),
                status = COALESCE(NULLIF(BTRIM(%s), ''), status),
                governance_mode = COALESCE(NULLIF(BTRIM(%s), ''), governance_mode),
                reporting_cycle = COALESCE(NULLIF(BTRIM(%s), ''), reporting_cycle),
                due_date = COALESCE(%s, due_date),
                start_date = COALESCE(%s, start_date),
                end_date = COALESCE(%s, end_date),
                manager_user_id = COALESCE(%s, manager_user_id),
                partner_user_id = COALESCE(%s, partner_user_id),
                target_company_id = COALESCE(%s, target_company_id),
                description = COALESCE(NULLIF(BTRIM(%s), ''), description),
                scope_summary = COALESCE(NULLIF(BTRIM(%s), ''), scope_summary),
                fiscal_year_end = COALESCE(%s, fiscal_year_end),
                priority = COALESCE(NULLIF(BTRIM(%s), ''), priority),
                workflow_stage = COALESCE(NULLIF(BTRIM(%s), ''), workflow_stage),
                is_active = COALESCE(%s, is_active),
                requires_workspace = COALESCE(%s, requires_workspace),
                workspace_status = CASE
                    WHEN NULLIF(BTRIM(%s), '') IS NULL THEN workspace_status
                    ELSE NULLIF(BTRIM(%s), '')
                END,
                workspace_source = COALESCE(NULLIF(BTRIM(%s), ''), workspace_source),
                target_company_source = COALESCE(NULLIF(BTRIM(%s), ''), target_company_source),
                updated_by_user_id = %s,
                updated_at = NOW()
            WHERE company_id = %s
            AND id = %s
            RETURNING id
        """

        cur.execute(sql, (
            engagement_code,
            engagement_name,
            engagement_type,
            status,
            governance_mode,
            reporting_cycle,
            due_date,
            start_date,
            end_date,
            manager_user_id,
            partner_user_id,
            target_company_id,
            description,
            scope_summary,
            fiscal_year_end,
            priority,
            workflow_stage,
            is_active,
            requires_workspace,
            workspace_status,
            workspace_status,
            workspace_source,
            target_company_source,
            updated_by_user_id,
            company_id,
            engagement_id,
        ))
        row = cur.fetchone()
        return (row["id"] if isinstance(row, dict) else row[0]) if row else None

    def set_engagement_status(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        status: str,
        updated_by_user_id: int,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            UPDATE {schema}.engagements
            SET
                status = %s,
                updated_by_user_id = %s,
                updated_at = NOW()
            WHERE company_id = %s
            AND id = %s
            RETURNING *
        """
        cur.execute(sql, (
            status,
            updated_by_user_id,
            company_id,
            engagement_id,
        ))
        row = cur.fetchone()
        return dict(row) if row and not isinstance(row, dict) else row

    def get_engagement(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            SELECT
                e.*,
                c.name AS customer_name
            FROM {schema}.engagements e
            JOIN {schema}.customers c
            ON c.id = e.customer_id
            WHERE e.company_id = %s
            AND e.id = %s
            LIMIT 1
        """
        cur.execute(sql, (company_id, engagement_id))
        return cur.fetchone()

    def list_engagements(
        self,
        cur,
        company_id: int,
        *,
        status: str = "",
        engagement_type: str = "",
        customer_id: int = None,
        q: str = "",
        limit: int = 100,
        offset: int = 0,
        assigned_user_id: int = None,
        assignments_only: bool = False,
    ):
        schema = self.company_schema(company_id)

        where = ["e.company_id = %s"]
        where_params = [company_id]

        if status:
            where.append("LOWER(e.status) = LOWER(%s)")
            where_params.append(status)

        if engagement_type:
            where.append("LOWER(e.engagement_type) = LOWER(%s)")
            where_params.append(engagement_type)

        if customer_id:
            where.append("e.customer_id = %s")
            where_params.append(customer_id)

        if q:
            where.append("""
                (
                    e.engagement_name ILIKE %s
                    OR COALESCE(e.engagement_code, '') ILIKE %s
                    OR c.name ILIKE %s
                )
            """)
            like = f"%{q}%"
            where_params.extend([like, like, like])

        select_my_role = "NULL::text AS my_role_on_engagement"
        select_params = []

        if assigned_user_id:
            select_my_role = f"""
                (
                    SELECT et.role_on_engagement
                    FROM {schema}.engagement_team et
                    WHERE et.engagement_id = e.id
                    AND et.user_id = %s
                    AND COALESCE(et.is_active, TRUE) = TRUE
                    ORDER BY et.id DESC
                    LIMIT 1
                ) AS my_role_on_engagement
            """
            select_params.append(assigned_user_id)

        if assignments_only and assigned_user_id:
            where.append(f"""
                (
                    e.manager_user_id = %s
                    OR e.partner_user_id = %s
                    OR EXISTS (
                        SELECT 1
                        FROM {schema}.engagement_team et
                        WHERE et.engagement_id = e.id
                        AND et.user_id = %s
                        AND COALESCE(et.is_active, TRUE) = TRUE
                    )
                )
            """)
            where_params.extend([assigned_user_id, assigned_user_id, assigned_user_id])

        sql = f"""
            SELECT
                e.*,
                c.name AS customer_name,
                {select_my_role}
            FROM {schema}.engagements e
            JOIN {schema}.customers c
            ON c.id = e.customer_id
            WHERE {' AND '.join(where)}
            ORDER BY
                e.is_active DESC,
                e.due_date NULLS LAST,
                e.id DESC
            LIMIT %s OFFSET %s
        """

        params = [*select_params, *where_params, limit, offset]

        cur.execute(sql, tuple(params))
        return cur.fetchall()

    def add_engagement_team_member(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        user_id: int,
        role_on_engagement: str,
        allocation_percent: float = None,
        start_date=None,
        end_date=None,
        notes: str = None,
    ):
        schema = self.company_schema(company_id)

        check_sql = f"""
            SELECT id
            FROM {schema}.engagement_team
            WHERE company_id = %s
            AND engagement_id = %s
            AND user_id = %s
            AND LOWER(role_on_engagement) = LOWER(%s)
            AND is_active = TRUE
            LIMIT 1
        """
        cur.execute(check_sql, (
            company_id,
            engagement_id,
            user_id,
            role_on_engagement,
        ))
        existing = cur.fetchone()
        if existing:
            return existing["id"] if isinstance(existing, dict) else existing[0]

        insert_sql = f"""
            INSERT INTO {schema}.engagement_team (
                company_id,
                engagement_id,
                user_id,
                role_on_engagement,
                allocation_percent,
                start_date,
                end_date,
                notes,
                is_active
            )
            VALUES (
                %s, %s, %s, %s, %s, %s, %s, NULLIF(BTRIM(%s), ''), TRUE
            )
            RETURNING id
        """
        cur.execute(insert_sql, (
            company_id,
            engagement_id,
            user_id,
            role_on_engagement,
            allocation_percent,
            start_date,
            end_date,
            notes,
        ))
        row = cur.fetchone()
        return row["id"] if isinstance(row, dict) else row[0]

