    def list_engagement_team(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        active_only: bool = True,
    ):
        schema = self.company_schema(company_id)

        where = [
            "et.company_id = %s",
            "et.engagement_id = %s",
        ]
        params = [company_id, engagement_id]

        if active_only:
            where.append("et.is_active = TRUE")

        sql = f"""
            SELECT
                et.*,
                u.first_name,
                u.last_name,
                u.email
            FROM {schema}.engagement_team et
            JOIN public.users u
            ON u.id = et.user_id
            WHERE {' AND '.join(where)}
            ORDER BY
                et.is_active DESC,
                et.role_on_engagement,
                et.id DESC
        """
        cur.execute(sql, tuple(params))
        return cur.fetchall()

    def user_has_delegated_company_access(
        self,
        cur,
        *,
        user_id: int,
        company_id: int,
        target_company_id: int,
        engagement_id: int | None = None,
    ) -> bool:
        schema = self.company_schema(company_id)

        sql = f"""
            SELECT 1
            FROM {schema}.engagements e
            JOIN {schema}.engagement_team et
            ON et.engagement_id = e.id
            AND et.company_id = e.company_id
            WHERE e.company_id = %s
            AND e.target_company_id = %s
            AND et.user_id = %s
            AND COALESCE(et.is_active, TRUE) = TRUE
            AND COALESCE(e.is_active, TRUE) = TRUE
            AND LOWER(COALESCE(e.workspace_status, '')) = 'provisioned'
            AND (%s IS NULL OR e.id = %s)
            LIMIT 1
        """

        params = (
            int(company_id),
            int(target_company_id),
            int(user_id),
            engagement_id,
            engagement_id,
        )

        print("DELEGATED SQL CHECK", {
            "schema": schema,
            "company_id": company_id,
            "target_company_id": target_company_id,
            "user_id": user_id,
            "engagement_id": engagement_id,
            "params": params,
        })

        cur.execute(sql, params)
        row = cur.fetchone()

        print("DELEGATED SQL RESULT", {
            "matched": row is not None,
            "row": row,
        })

        return row is not None

    def assign_manager_and_partner(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        manager_user_id: int = None,
        partner_user_id: int = None,
        updated_by_user_id: int = None,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            UPDATE {schema}.engagements
            SET
                manager_user_id = %s,
                partner_user_id = %s,
                updated_by_user_id = %s,
                updated_at = NOW()
            WHERE company_id = %s
            AND id = %s
            RETURNING id
        """
        cur.execute(sql, (
            manager_user_id,
            partner_user_id,
            updated_by_user_id,
            company_id,
            engagement_id,
        ))
        row = cur.fetchone()
        out_id = (row["id"] if isinstance(row, dict) else row[0]) if row else None

        if manager_user_id:
            self.add_engagement_team_member(
                cur,
                company_id,
                engagement_id=engagement_id,
                user_id=manager_user_id,
                role_on_engagement="manager",
            )

        if partner_user_id:
            self.add_engagement_team_member(
                cur,
                company_id,
                engagement_id=engagement_id,
                user_id=partner_user_id,
                role_on_engagement="partner",
            )

        return out_id

    def list_engagement_reporting_items(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        item_type: str = "",
        status: str = "",
        owner_user_id: int = None,
        reviewer_user_id: int = None,
        q: str = "",
        active_only: bool = True,
        limit: int = 200,
        offset: int = 0,
    ):
        schema = self.company_schema(company_id)

        where = ["ri.company_id = %s", "ri.engagement_id = %s"]
        params = [company_id, engagement_id]

        if item_type:
            where.append("LOWER(ri.item_type) = LOWER(%s)")
            params.append(item_type)

        if status:
            where.append("LOWER(ri.status) = LOWER(%s)")
            params.append(status)

        if owner_user_id:
            where.append("ri.owner_user_id = %s")
            params.append(owner_user_id)

        if reviewer_user_id:
            where.append("ri.reviewer_user_id = %s")
            params.append(reviewer_user_id)

        if active_only:
            where.append("ri.is_active = TRUE")

        if q:
            where.append("""
                (
                    ri.item_name ILIKE %s
                    OR COALESCE(ri.item_code, '') ILIKE %s
                    OR COALESCE(ri.description, '') ILIKE %s
                    OR COALESCE(ri.notes, '') ILIKE %s
                )
            """)
            like = f"%{q.strip()}%"
            params.extend([like, like, like, like])

        sql = f"""
            SELECT
                ri.*,
                e.engagement_name,
                e.engagement_code,
                e.engagement_type,
                e.target_company_id,

                owner_u.first_name AS owner_first_name,
                owner_u.last_name AS owner_last_name,
                owner_u.email AS owner_email,
                COALESCE(owner_cu.assignment_role, owner_cu.role, owner_u.user_role) AS owner_role,

                reviewer_u.first_name AS reviewer_first_name,
                reviewer_u.last_name AS reviewer_last_name,
                reviewer_u.email AS reviewer_email,
                COALESCE(reviewer_cu.assignment_role, reviewer_cu.role, reviewer_u.user_role) AS reviewer_role

            FROM {schema}.engagement_reporting_items ri
            JOIN {schema}.engagements e
            ON e.id = ri.engagement_id
            AND e.company_id = ri.company_id

            LEFT JOIN public.users owner_u
            ON owner_u.id = ri.owner_user_id
            LEFT JOIN public.company_users owner_cu
            ON owner_cu.company_id = ri.company_id
            AND owner_cu.user_id = ri.owner_user_id

            LEFT JOIN public.users reviewer_u
            ON reviewer_u.id = ri.reviewer_user_id
            LEFT JOIN public.company_users reviewer_cu
            ON reviewer_cu.company_id = ri.company_id
            AND reviewer_cu.user_id = ri.reviewer_user_id

            WHERE {" AND ".join(where)}
            ORDER BY
                ri.sort_order ASC,
                ri.due_date NULLS LAST,
                ri.id DESC
            LIMIT %s OFFSET %s
        """
        params.extend([limit, offset])
        cur.execute(sql, tuple(params))
        return cur.fetchall()

