    def list_engagement_posting_activity(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        module_name: str = "",
        event_type: str = "",
        status: str = "",
        prepared_by_user_id: int = None,
        reviewer_user_id: int = None,
        date_from=None,
        date_to=None,
        q: str = "",
        active_only: bool = True,
        limit: int = 200,
        offset: int = 0,
    ):
        schema = self.company_schema(company_id)

        where = ["pa.company_id = %s", "pa.engagement_id = %s"]
        params = [company_id, engagement_id]

        if module_name:
            where.append("LOWER(pa.module_name) = LOWER(%s)")
            params.append(module_name)

        if event_type:
            where.append("LOWER(pa.event_type) = LOWER(%s)")
            params.append(event_type)

        if status:
            where.append("LOWER(pa.status) = LOWER(%s)")
            params.append(status)

        if prepared_by_user_id:
            where.append("pa.prepared_by_user_id = %s")
            params.append(prepared_by_user_id)

        if reviewer_user_id:
            where.append("pa.reviewer_user_id = %s")
            params.append(reviewer_user_id)

        if date_from:
            where.append("pa.posting_date >= %s")
            params.append(date_from)

        if date_to:
            where.append("pa.posting_date <= %s")
            params.append(date_to)

        if active_only:
            where.append("pa.is_active = TRUE")

        if q:
            where.append("""
                (
                    COALESCE(pa.reference_no, '') ILIKE %s
                    OR pa.description ILIKE %s
                    OR COALESCE(pa.source_table, '') ILIKE %s
                    OR COALESCE(pa.notes, '') ILIKE %s
                )
            """)
            like = f"%{q.strip()}%"
            params.extend([like, like, like, like])

        sql = f"""
            SELECT
                pa.*,
                e.engagement_name,
                e.engagement_code,
                e.engagement_type,
                e.target_company_id,

                prepared_u.first_name AS prepared_first_name,
                prepared_u.last_name AS prepared_last_name,
                prepared_u.email AS prepared_email,
                COALESCE(prepared_cu.assignment_role, prepared_cu.role, prepared_u.user_role) AS prepared_role,

                reviewer_u.first_name AS reviewer_first_name,
                reviewer_u.last_name AS reviewer_last_name,
                reviewer_u.email AS reviewer_email,
                COALESCE(reviewer_cu.assignment_role, reviewer_cu.role, reviewer_u.user_role) AS reviewer_role

            FROM {schema}.engagement_posting_activity pa
            JOIN {schema}.engagements e
            ON e.id = pa.engagement_id
            AND e.company_id = pa.company_id

            LEFT JOIN public.users prepared_u
            ON prepared_u.id = pa.prepared_by_user_id
            LEFT JOIN public.company_users prepared_cu
            ON prepared_cu.company_id = pa.company_id
            AND prepared_cu.user_id = pa.prepared_by_user_id

            LEFT JOIN public.users reviewer_u
            ON reviewer_u.id = pa.reviewer_user_id
            LEFT JOIN public.company_users reviewer_cu
            ON reviewer_cu.company_id = pa.company_id
            AND reviewer_cu.user_id = pa.reviewer_user_id

            WHERE {" AND ".join(where)}
            ORDER BY
                pa.posting_date DESC,
                pa.id DESC
            LIMIT %s OFFSET %s
        """
        params.extend([limit, offset])
        cur.execute(sql, tuple(params))
        return cur.fetchall()

