    def list_engagement_monthly_close_tasks(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        close_period=None,
        status: str = "",
        priority: str = "",
        owner_user_id: int = None,
        reviewer_user_id: int = None,
        q: str = "",
        active_only: bool = True,
        limit: int = 200,
        offset: int = 0,
    ):
        schema = self.company_schema(company_id)

        where = ["t.company_id = %s", "t.engagement_id = %s"]
        params = [company_id, engagement_id]

        if close_period:
            where.append("t.close_period = %s")
            params.append(close_period)

        if status:
            where.append("LOWER(t.status) = LOWER(%s)")
            params.append(status)

        if priority:
            where.append("LOWER(t.priority) = LOWER(%s)")
            params.append(priority)

        if owner_user_id:
            where.append("t.owner_user_id = %s")
            params.append(owner_user_id)

        if reviewer_user_id:
            where.append("t.reviewer_user_id = %s")
            params.append(reviewer_user_id)

        if active_only:
            where.append("t.is_active = TRUE")

        if q:
            where.append("""
                (
                    t.task_name ILIKE %s
                    OR COALESCE(t.task_code, '') ILIKE %s
                    OR COALESCE(t.description, '') ILIKE %s
                    OR COALESCE(t.notes, '') ILIKE %s
                )
            """)
            like = f"%{q.strip()}%"
            params.extend([like, like, like, like])

        sql = f"""
            SELECT
                t.*,
                e.engagement_name,
                e.engagement_code,
                e.engagement_type,
                e.target_company_id,

                owner_u.first_name AS owner_first_name,
                owner_u.last_name AS owner_last_name,
                owner_u.email AS owner_email,
                COALESCE(owner_cu.assignment_role, owner_cu.role, owner_u.user_role) AS owner_role,

                reviewer_u.first_name AS reviewer_first_name,
                reviewer_u.last_name AS reviewer_last_name,
                reviewer_u.email AS reviewer_email,
                COALESCE(reviewer_cu.assignment_role, reviewer_cu.role, reviewer_u.user_role) AS reviewer_role

            FROM {schema}.engagement_monthly_close_tasks t
            JOIN {schema}.engagements e
            ON e.id = t.engagement_id
            AND e.company_id = t.company_id

            LEFT JOIN public.users owner_u
            ON owner_u.id = t.owner_user_id
            LEFT JOIN public.company_users owner_cu
            ON owner_cu.company_id = t.company_id
            AND owner_cu.user_id = t.owner_user_id

            LEFT JOIN public.users reviewer_u
            ON reviewer_u.id = t.reviewer_user_id
            LEFT JOIN public.company_users reviewer_cu
            ON reviewer_cu.company_id = t.company_id
            AND reviewer_cu.user_id = t.reviewer_user_id

            WHERE {" AND ".join(where)}
            ORDER BY
                t.close_period DESC,
                t.sort_order ASC,
                t.due_date NULLS LAST,
                t.id DESC
            LIMIT %s OFFSET %s
        """
        params.extend([limit, offset])
        cur.execute(sql, tuple(params))
        return cur.fetchall()

