            current_user_id, current_user_id, current_user_id, company_id,
            current_user_id, current_user_id, current_user_id, company_id,
            current_user_id, current_user_id, company_id,

            queue_type, queue_type,
            status, status,
            priority, priority,
            True if mine_only else False,
