    def get_action_center_summary(
        self,
        cur,
        company_id: int,
        *,
        customer_id: int = None,
        engagement_id: int = None,
        current_user_id: int = None,
        mine_only: bool = False,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            WITH engagement_scope AS (
                SELECT
                    e.id,
                    e.customer_id
                FROM {schema}.engagements e
                WHERE e.company_id = %s
                AND e.is_active = TRUE
                AND (%s IS NULL OR e.customer_id = %s)
                AND (%s IS NULL OR e.id = %s)
            ),

            reporting_items AS (
                SELECT
                    'reporting_item'::text AS queue_type,
                    i.id,
                    i.engagement_id,
                    es.customer_id,
                    i.item_name AS item_name,
                    i.status,
                    i.priority,
                    i.due_date,
                    i.owner_user_id AS assigned_user_id,
                    i.reviewer_user_id,
                    (
                        i.due_date IS NOT NULL
                        AND i.due_date < CURRENT_DATE
                        AND i.status NOT IN ('approved', 'completed', 'waived')
                    ) AS is_overdue,
                    (i.status = 'blocked') AS is_blocked,
                    (
                        %s IS NOT NULL
                        AND (
                            i.owner_user_id = %s
                            OR i.reviewer_user_id = %s
                        )
                    ) AS is_mine,
                    (
                        i.status IN ('ready', 'in_review')
                        AND %s IS NOT NULL
                        AND i.reviewer_user_id = %s
                    ) AS awaiting_my_review,
                    FALSE AS pending_signoff
                FROM {schema}.engagement_reporting_items i
                JOIN engagement_scope es ON es.id = i.engagement_id
                WHERE i.company_id = %s
                AND i.is_active = TRUE
            ),

            deliverables AS (
                SELECT
                    'deliverable'::text AS queue_type,
                    d.id,
                    d.engagement_id,
                    es.customer_id,
                    d.deliverable_name AS item_name,
                    d.status,
                    d.priority,
                    d.due_date,
                    d.assigned_user_id,
                    d.reviewer_user_id,
                    (
                        d.due_date IS NOT NULL
                        AND d.due_date < CURRENT_DATE
                        AND d.status NOT IN ('completed', 'waived')
                    ) AS is_overdue,
                    FALSE AS is_blocked,
                    (
                        %s IS NOT NULL
                        AND (
                            d.assigned_user_id = %s
                            OR d.reviewer_user_id = %s
                        )
                    ) AS is_mine,
                    (
                        d.status = 'in_review'
                        AND %s IS NOT NULL
                        AND d.reviewer_user_id = %s
                    ) AS awaiting_my_review,
                    FALSE AS pending_signoff
                FROM {schema}.engagement_deliverables d
                JOIN engagement_scope es ON es.id = d.engagement_id
                WHERE d.company_id = %s
                AND d.is_active = TRUE
            ),

            posting_items AS (
                SELECT
                    'posting_activity'::text AS queue_type,
                    p.id,
                    p.engagement_id,
                    es.customer_id,
                    p.description AS item_name,
                    p.status,
                    'normal'::text AS priority,
                    p.posting_date AS due_date,
                    p.prepared_by_user_id AS assigned_user_id,
                    p.reviewer_user_id,
                    (
                        p.posting_date IS NOT NULL
                        AND p.posting_date < CURRENT_DATE
                        AND p.status NOT IN ('approved', 'posted', 'reversed')
                    ) AS is_overdue,
                    FALSE AS is_blocked,
                    (
                        %s IS NOT NULL
                        AND (
                            p.prepared_by_user_id = %s
                            OR p.reviewer_user_id = %s
                        )
                    ) AS is_mine,
                    (
                        p.status IN ('pending_review', 'in_review', 'approved')
                        AND %s IS NOT NULL
                        AND p.reviewer_user_id = %s
                    ) AS awaiting_my_review,
                    FALSE AS pending_signoff
                FROM {schema}.engagement_posting_activity p
                JOIN engagement_scope es ON es.id = p.engagement_id
                WHERE p.company_id = %s
                AND p.is_active = TRUE
            ),

            monthly_close_items AS (
                SELECT
                    'monthly_close'::text AS queue_type,
                    m.id,
                    m.engagement_id,
                    es.customer_id,
                    m.task_name AS item_name,
                    m.status,
                    m.priority,
                    m.due_date,
                    m.owner_user_id AS assigned_user_id,
                    m.reviewer_user_id,
                    (
                        m.due_date IS NOT NULL
                        AND m.due_date < CURRENT_DATE
                        AND m.status NOT IN ('completed', 'skipped')
                    ) AS is_overdue,
                    (m.status = 'blocked') AS is_blocked,
                    (
                        %s IS NOT NULL
                        AND (
                            m.owner_user_id = %s
                            OR m.reviewer_user_id = %s
                        )
                    ) AS is_mine,
                    (
                        m.status = 'in_review'
                        AND %s IS NOT NULL
                        AND m.reviewer_user_id = %s
                    ) AS awaiting_my_review,
                    FALSE AS pending_signoff
                FROM {schema}.engagement_monthly_close_tasks m
                JOIN engagement_scope es ON es.id = m.engagement_id
                WHERE m.company_id = %s
                AND m.is_active = TRUE
            ),

            year_end_items AS (
                SELECT
                    'year_end'::text AS queue_type,
                    y.id,
                    y.engagement_id,
                    es.customer_id,
                    y.task_name AS item_name,
                    y.status,
                    y.priority,
                    y.due_date,
                    y.owner_user_id AS assigned_user_id,
                    y.reviewer_user_id,
                    (
                        y.due_date IS NOT NULL
                        AND y.due_date < CURRENT_DATE
                        AND y.status NOT IN ('completed', 'waived')
                    ) AS is_overdue,
                    (y.status = 'blocked') AS is_blocked,
                    (
                        %s IS NOT NULL
                        AND (
                            y.owner_user_id = %s
                            OR y.reviewer_user_id = %s
                        )
                    ) AS is_mine,
                    (
                        y.status = 'in_review'
                        AND %s IS NOT NULL
                        AND y.reviewer_user_id = %s
                    ) AS awaiting_my_review,
                    FALSE AS pending_signoff
                FROM {schema}.engagement_year_end_tasks y
                JOIN engagement_scope es ON es.id = y.engagement_id
                WHERE y.company_id = %s
                AND y.is_active = TRUE
            ),

            signoff_items AS (
                SELECT
                    'signoff'::text AS queue_type,
                    s.id,
                    s.engagement_id,
                    es.customer_id,
                    s.step_name AS item_name,
                    s.status,
                    'high'::text AS priority,
                    s.due_date,
                    s.assigned_user_id,
                    NULL::int AS reviewer_user_id,
                    (
                        s.due_date IS NOT NULL
                        AND s.due_date < CURRENT_DATE
                        AND s.status NOT IN ('completed', 'waived')
                    ) AS is_overdue,
                    (s.status = 'blocked') AS is_blocked,
                    (
                        %s IS NOT NULL
                        AND s.assigned_user_id = %s
                    ) AS is_mine,
                    FALSE AS awaiting_my_review,
                    (
                        s.status IN ('not_started', 'in_progress', 'blocked')
                    ) AS pending_signoff
                FROM {schema}.engagement_signoff_steps s
                JOIN engagement_scope es ON es.id = s.engagement_id
                WHERE s.company_id = %s
                AND s.is_active = TRUE
            ),

            queue_union AS (
                SELECT * FROM reporting_items
                UNION ALL
                SELECT * FROM deliverables
                UNION ALL
                SELECT * FROM posting_items
                UNION ALL
                SELECT * FROM monthly_close_items
                UNION ALL
                SELECT * FROM year_end_items
                UNION ALL
                SELECT * FROM signoff_items
            ),

            scoped_queue AS (
                SELECT *
                FROM queue_union q
                WHERE (%s = FALSE OR q.is_mine = TRUE)
            )

            SELECT
                COUNT(*) FILTER (WHERE awaiting_my_review = TRUE)::int AS awaiting_my_review,
                COUNT(*) FILTER (
                    WHERE queue_type = 'signoff'
                    AND pending_signoff = TRUE
                )::int AS pending_approval,
                COUNT(*) FILTER (WHERE is_overdue = TRUE)::int AS overdue_items,
                COUNT(*) FILTER (WHERE is_blocked = TRUE)::int AS blocked_items,
                COUNT(*) FILTER (WHERE due_date = CURRENT_DATE)::int AS due_today,
                COUNT(*) FILTER (WHERE pending_signoff = TRUE)::int AS pending_signoffs
            FROM scoped_queue
        """

        params = (
            company_id, customer_id, customer_id, engagement_id, engagement_id,

            current_user_id, current_user_id, current_user_id, current_user_id, current_user_id, company_id,

            current_user_id, current_user_id, current_user_id, current_user_id, current_user_id, company_id,

            current_user_id, current_user_id, current_user_id, current_user_id, current_user_id, company_id,

            current_user_id, current_user_id, current_user_id, current_user_id, current_user_id, company_id,

            current_user_id, current_user_id, current_user_id, current_user_id, current_user_id, company_id,

            current_user_id, current_user_id, company_id,

            True if mine_only else False,
        )

        cur.execute(sql, params)
        row = cur.fetchone()
        if row:
            return row

        return {
            "awaiting_my_review": 0,
            "pending_approval": 0,
            "overdue_items": 0,
            "blocked_items": 0,
            "due_today": 0,
            "pending_signoffs": 0,
        }

    def get_practitioner_posting_module_summary(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        module_name: str,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            WITH scoped_engagement AS (
                SELECT
                    e.id,
                    e.engagement_name,
                    e.engagement_code,
                    e.customer_id,
                    e.status AS engagement_status,
                    e.priority AS engagement_priority,
                    e.due_date,
                    c.name AS customer_name
                FROM {schema}.engagements e
                JOIN {schema}.customers c
                ON c.id = e.customer_id
                WHERE e.company_id = %s
                AND e.id = %s
                AND e.is_active = TRUE
            ),
            scoped_activity AS (
                SELECT pa.*
                FROM {schema}.engagement_posting_activity pa
                JOIN scoped_engagement se
                ON se.id = pa.engagement_id
                WHERE pa.company_id = %s
                AND pa.engagement_id = %s
                AND pa.is_active = TRUE
                AND pa.module_name = %s
            )
            SELECT
                se.id AS engagement_id,
                se.engagement_name,
                se.engagement_code,
                se.customer_id,
                se.customer_name,
                se.engagement_status,
                se.engagement_priority,
                se.due_date,

                COALESCE((SELECT COUNT(*) FROM scoped_activity), 0) AS total_items,
                COALESCE((SELECT COUNT(*) FROM scoped_activity WHERE LOWER(status) = 'draft'), 0) AS draft_count,
                COALESCE((SELECT COUNT(*) FROM scoped_activity WHERE LOWER(status) IN ('pending_review', 'in_review')), 0) AS review_count,
                COALESCE((SELECT COUNT(*) FROM scoped_activity WHERE LOWER(status) = 'approved'), 0) AS approved_count,
                COALESCE((SELECT COUNT(*) FROM scoped_activity WHERE LOWER(status) = 'posted'), 0) AS posted_count,
                COALESCE((SELECT COUNT(*) FROM scoped_activity WHERE LOWER(status) IN ('returned', 'rejected')), 0) AS returned_or_rejected_count,
                COALESCE((SELECT COUNT(*) FROM scoped_activity WHERE posting_date = CURRENT_DATE), 0) AS activity_today_count,
                COALESCE((SELECT MAX(posting_date) FROM scoped_activity), NULL) AS last_activity_date,
                COALESCE((SELECT SUM(COALESCE(amount, 0)) FROM scoped_activity), 0) AS total_amount,
                COALESCE((SELECT SUM(COALESCE(amount, 0)) FROM scoped_activity WHERE LOWER(status) = 'posted'), 0) AS posted_amount,
                %s AS module_name
            FROM scoped_engagement se
        """

        cur.execute(
            sql,
            (
                company_id,
                engagement_id,
                company_id,
                engagement_id,
                module_name,
                module_name,
            ),
        )
        return cur.fetchone()


    def list_practitioner_posting_module_activity(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        module_name: str,
        status: str = None,
        event_type: str = None,
        prepared_by_user_id: int = None,
        reviewer_user_id: int = None,
        date_from: str = None,
        date_to: str = None,
        mine_only: bool = False,
        current_user_id: int = None,
        q: str = None,
        limit: int = 100,
        offset: int = 0,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            WITH engagement_scope AS (
                SELECT
                    e.id,
                    e.engagement_name,
                    e.engagement_code,
                    e.customer_id,
                    c.name AS customer_name
                FROM {schema}.engagements e
                JOIN {schema}.customers c
                ON c.id = e.customer_id
                WHERE e.company_id = %s
                AND e.id = %s
                AND e.is_active = TRUE
            )
            SELECT
                pa.id,
                pa.company_id,
                pa.engagement_id,
                es.engagement_name,
                es.engagement_code,
                es.customer_id,
                es.customer_name,
                pa.posting_date,
                pa.module_name,
                pa.event_type,
                pa.reference_no,
                pa.description,
                pa.status,
                pa.amount,
                pa.currency_code,
                pa.source_table,
                pa.source_id,
                pa.notes,
                pa.prepared_by_user_id,
                CONCAT(
                    COALESCE(pu.first_name, ''),
                    CASE
                        WHEN pu.last_name IS NOT NULL AND pu.last_name <> '' THEN ' ' || pu.last_name
                        ELSE ''
                    END
                ) AS prepared_by_user_name,
                pa.reviewer_user_id,
                CONCAT(
                    COALESCE(ru.first_name, ''),
                    CASE
                        WHEN ru.last_name IS NOT NULL AND ru.last_name <> '' THEN ' ' || ru.last_name
                        ELSE ''
                    END
                ) AS reviewer_user_name,
                (
                    pa.posting_date IS NOT NULL
                    AND pa.posting_date < CURRENT_DATE
                    AND LOWER(pa.status) NOT IN ('approved', 'posted', 'reversed')
                ) AS is_overdue,
                (
                    %s IS NOT NULL
                    AND (
                        pa.prepared_by_user_id = %s
                        OR pa.reviewer_user_id = %s
                    )
                ) AS is_mine,
                pa.created_at,
                pa.updated_at
            FROM {schema}.engagement_posting_activity pa
            JOIN engagement_scope es
            ON es.id = pa.engagement_id
            LEFT JOIN public.users pu
            ON pu.id = pa.prepared_by_user_id
            LEFT JOIN public.users ru
            ON ru.id = pa.reviewer_user_id
            WHERE pa.company_id = %s
            AND pa.engagement_id = %s
            AND pa.is_active = TRUE
            AND pa.module_name = %s
            AND (%s IS NULL OR %s = '' OR LOWER(pa.status) = LOWER(%s))
            AND (%s IS NULL OR %s = '' OR LOWER(pa.event_type) = LOWER(%s))
            AND (%s IS NULL OR pa.prepared_by_user_id = %s)
            AND (%s IS NULL OR pa.reviewer_user_id = %s)
            AND (%s IS NULL OR pa.posting_date >= %s::date)
            AND (%s IS NULL OR pa.posting_date <= %s::date)
            AND (
                    %s = FALSE
                    OR (
                        %s IS NOT NULL
                        AND (
                            pa.prepared_by_user_id = %s
                            OR pa.reviewer_user_id = %s
                        )
                    )
            )
            AND (
                    %s IS NULL
                    OR %s = ''
                    OR (
                        COALESCE(pa.reference_no, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(pa.description, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(pa.source_table, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(CAST(pa.source_id AS TEXT), '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(CONCAT(
                            COALESCE(pu.first_name, ''),
                            CASE
                                WHEN pu.last_name IS NOT NULL AND pu.last_name <> '' THEN ' ' || pu.last_name
                                ELSE ''
                            END
                        ), '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(CONCAT(
                            COALESCE(ru.first_name, ''),
                            CASE
                                WHEN ru.last_name IS NOT NULL AND ru.last_name <> '' THEN ' ' || ru.last_name
                                ELSE ''
                            END
                        ), '') ILIKE ('%%' || %s || '%%')
                    )
            )
            ORDER BY
                pa.posting_date DESC NULLS LAST,
                pa.updated_at DESC,
                pa.id DESC
            LIMIT %s
            OFFSET %s
        """

        params = (
            company_id,
            engagement_id,

            current_user_id,
            current_user_id,
            current_user_id,

            company_id,
            engagement_id,
            module_name,

            status, status, status,
            event_type, event_type, event_type,
            prepared_by_user_id, prepared_by_user_id,
            reviewer_user_id, reviewer_user_id,
            date_from, date_from,
            date_to, date_to,

            True if mine_only else False,
            current_user_id,
            current_user_id,
            current_user_id,

            q, q,
            q, q, q, q, q, q,

            max(1, min(int(limit or 100), 500)),
            max(0, int(offset or 0)),
        )

        cur.execute(sql, params)
        rows = cur.fetchall() or []
        return rows


