    def _review_queue_table_meta(self, queue_type: str):
        qt = (queue_type or "").strip().lower()

        mapping = {
            "reporting_item": {
                "table": "engagement_reporting_items",
                "pk": "id",
                "assigned_col": "owner_user_id",
                "reviewer_col": "reviewer_user_id",
                "status_col": "status",
                "active_col": "is_active",
                "updated_by_col": "updated_by_user_id",
                "completed_col": "completed_at",
            },
            "deliverable": {
                "table": "engagement_deliverables",
                "pk": "id",
                "assigned_col": "assigned_user_id",
                "reviewer_col": "reviewer_user_id",
                "status_col": "status",
                "active_col": "is_active",
                "updated_by_col": "updated_by_user_id",
                "completed_col": None,
            },
            "posting_activity": {
                "table": "engagement_posting_activity",
                "pk": "id",
                "assigned_col": "prepared_by_user_id",
                "reviewer_col": "reviewer_user_id",
                "status_col": "status",
                "active_col": "is_active",
                "updated_by_col": "updated_by_user_id",
                "completed_col": None,
            },
            "monthly_close": {
                "table": "engagement_monthly_close_tasks",
                "pk": "id",
                "assigned_col": "owner_user_id",
                "reviewer_col": "reviewer_user_id",
                "status_col": "status",
                "active_col": "is_active",
                "updated_by_col": "updated_by_user_id",
                "completed_col": "completed_at",
            },
            "year_end": {
                "table": "engagement_year_end_tasks",
                "pk": "id",
                "assigned_col": "owner_user_id",
                "reviewer_col": "reviewer_user_id",
                "status_col": "status",
                "active_col": "is_active",
                "updated_by_col": "updated_by_user_id",
                "completed_col": "completed_at",
            },
            "signoff": {
                "table": "engagement_signoff_steps",
                "pk": "id",
                "assigned_col": "assigned_user_id",
                "reviewer_col": None,
                "status_col": "status",
                "active_col": "is_active",
                "updated_by_col": "updated_by_user_id",
                "completed_col": "completed_at",
            },
        }
        return mapping.get(qt)

    def upsert_engagement_posting_activity(
        self,
        cur,
        *,
        company_id: int,
        engagement_id: int,
        module_name: str,
        event_type: str,
        posting_date,
        description: str,
        reference_no: str = None,
        amount=None,
        currency_code: str = "ZAR",
        source_table: str = None,
        source_id: int = None,
        prepared_by_user_id: int = None,
        reviewer_user_id: int = None,
        status: str = "posted",
        created_by_user_id: int = None,
    ):
        schema = f"company_{company_id}"

        cur.execute(f"""
            INSERT INTO {schema}.engagement_posting_activity (
                company_id,
                engagement_id,
                posting_date,
                module_name,
                event_type,
                reference_no,
                description,
                prepared_by_user_id,
                reviewer_user_id,
                status,
                amount,
                currency_code,
                source_table,
                source_id,
                created_by_user_id,
                updated_by_user_id
            )
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
            ON CONFLICT (company_id, engagement_id, module_name, source_table, source_id, event_type)
            DO UPDATE SET
                description = EXCLUDED.description,
                amount = EXCLUDED.amount,
                status = EXCLUDED.status,
                updated_at = NOW(),
                updated_by_user_id = EXCLUDED.updated_by_user_id
        """, (
            company_id,
            engagement_id,
            posting_date,
            module_name,
            event_type,
            reference_no,
            description,
            prepared_by_user_id,
            reviewer_user_id,
            status,
            amount,
            currency_code,
            source_table,
            source_id,
            created_by_user_id,
            created_by_user_id,
        ))
        
    def get_review_queue_item_detail(
        self,
        cur,
        company_id: int,
        *,
        queue_type: str,
        source_id: int,
    ):
        schema = self.company_schema(company_id)
        meta = self._review_queue_table_meta(queue_type)
        if not meta:
            return None

        table = meta["table"]

        sql = f"""
            SELECT
                t.*,
                e.customer_id,
                e.engagement_name,
                e.engagement_code,
                e.engagement_type,
                e.status AS engagement_status,
                e.priority AS engagement_priority,
                e.due_date AS engagement_due_date,
                c.name AS customer_name,

                CONCAT(COALESCE(au.first_name, ''), CASE
                    WHEN au.last_name IS NOT NULL AND au.last_name <> '' THEN ' ' || au.last_name
                    ELSE ''
                END) AS assigned_user_name,

                CONCAT(COALESCE(ru.first_name, ''), CASE
                    WHEN ru.last_name IS NOT NULL AND ru.last_name <> '' THEN ' ' || ru.last_name
                    ELSE ''
                END) AS reviewer_user_name
            FROM {schema}.{table} t
            JOIN {schema}.engagements e
            ON e.id = t.engagement_id
            JOIN {schema}.customers c
            ON c.id = e.customer_id
            LEFT JOIN public.users au
            ON au.id = t.{meta["assigned_col"]}
            {"LEFT JOIN public.users ru ON ru.id = t." + meta["reviewer_col"] if meta["reviewer_col"] else "LEFT JOIN public.users ru ON 1 = 0"}
            WHERE t.company_id = %s
            AND t.id = %s
            AND COALESCE(t.is_active, TRUE) = TRUE
        """

        cur.execute(sql, (company_id, source_id))
        row = cur.fetchone()
        if not row:
            return None

        row["queue_type"] = queue_type
        return row

    def set_review_queue_item_status(
        self,
        cur,
        company_id: int,
        *,
        queue_type: str,
        source_id: int,
        status: str,
        updated_by_user_id: int,
        completed_at=None,
    ):
        schema = self.company_schema(company_id)
        meta = self._review_queue_table_meta(queue_type)
        if not meta:
            return None

        allowed_statuses = {
            "reporting_item": {"not_started", "in_progress", "ready", "in_review", "approved", "completed", "blocked", "waived", "returned"},
            "deliverable": {"not_started", "requested", "outstanding", "received", "in_review", "completed", "waived"},
            "posting_activity": {"draft", "pending_review", "in_review", "approved", "posted", "returned", "rejected", "reversed"},
            "monthly_close": {"not_started", "in_progress", "in_review", "completed", "blocked", "skipped"},
            "year_end": {"not_started", "in_progress", "in_review", "completed", "blocked", "waived"},
            "signoff": {"not_started", "in_progress", "completed", "blocked", "waived"},
        }

        status = (status or "").strip().lower()
        if status not in allowed_statuses.get(queue_type, set()):
            raise ValueError(f"Invalid status '{status}' for queue type '{queue_type}'.")

        set_completed_sql = ""
        params = [status, updated_by_user_id]

        if meta["completed_col"]:
            if status in {"completed", "approved", "posted", "received"}:
                set_completed_sql = f", {meta['completed_col']} = COALESCE(%s, NOW())"
                params.append(completed_at)
            elif queue_type != "signoff":
                set_completed_sql = f", {meta['completed_col']} = NULL"

        sql = f"""
            UPDATE {schema}.{meta["table"]}
            SET
                {meta["status_col"]} = %s,
                {meta["updated_by_col"]} = %s,
                updated_at = NOW()
                {set_completed_sql}
            WHERE company_id = %s
            AND {meta["pk"]} = %s
            AND COALESCE({meta["active_col"]}, TRUE) = TRUE
            RETURNING {meta["pk"]}
        """

        params.extend([company_id, source_id])
        cur.execute(sql, tuple(params))
        row = cur.fetchone()
        return row[meta["pk"]] if row else None

    def assign_review_queue_item(
        self,
        cur,
        company_id: int,
        *,
        queue_type: str,
        source_id: int,
        assigned_user_id: int = None,
        reviewer_user_id: int = None,
        updated_by_user_id: int,
    ):
        schema = self.company_schema(company_id)
        meta = self._review_queue_table_meta(queue_type)
        if not meta:
            return None

        sets = [f'{meta["updated_by_col"]} = %s', "updated_at = NOW()"]
        params = [updated_by_user_id]

        if assigned_user_id is not None and meta["assigned_col"]:
            sets.append(f'{meta["assigned_col"]} = %s')
            params.append(assigned_user_id)

        if reviewer_user_id is not None and meta["reviewer_col"]:
            sets.append(f'{meta["reviewer_col"]} = %s')
            params.append(reviewer_user_id)

        if len(sets) == 2:
            raise ValueError("Nothing to update.")

        sql = f"""
            UPDATE {schema}.{meta["table"]}
            SET {", ".join(sets)}
            WHERE company_id = %s
            AND {meta["pk"]} = %s
            AND COALESCE({meta["active_col"]}, TRUE) = TRUE
            RETURNING {meta["pk"]}
        """

        params.extend([company_id, source_id])
        cur.execute(sql, tuple(params))
        row = cur.fetchone()
        return row[meta["pk"]] if row else None

    def deactivate_review_queue_item(
        self,
        cur,
        company_id: int,
        *,
        queue_type: str,
        source_id: int,
        updated_by_user_id: int,
    ):
        schema = self.company_schema(company_id)
        meta = self._review_queue_table_meta(queue_type)
        if not meta:
            return None

        sql = f"""
            UPDATE {schema}.{meta["table"]}
            SET
                {meta["active_col"]} = FALSE,
                {meta["updated_by_col"]} = %s,
                updated_at = NOW()
            WHERE company_id = %s
            AND {meta["pk"]} = %s
            AND COALESCE({meta["active_col"]}, TRUE) = TRUE
            RETURNING {meta["pk"]}
        """

        cur.execute(sql, (updated_by_user_id, company_id, source_id))
        row = cur.fetchone()
        return row[meta["pk"]] if row else None

    def get_engagement_working_paper(
        self,
        cur,
        company_id: int,
        *,
        working_paper_id: int,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            SELECT
                wp.*,
                e.engagement_name,
                e.engagement_code,
                e.customer_id,
                c.name AS customer_name,

                CONCAT(
                    COALESCE(pu.first_name, ''),
                    CASE
                        WHEN pu.last_name IS NOT NULL AND pu.last_name <> ''
                        THEN ' ' || pu.last_name
                        ELSE ''
                    END
                ) AS preparer_user_name,

                CONCAT(
                    COALESCE(ru.first_name, ''),
                    CASE
                        WHEN ru.last_name IS NOT NULL AND ru.last_name <> ''
                        THEN ' ' || ru.last_name
                        ELSE ''
                    END
                ) AS reviewer_user_name,

                ri.item_name AS linked_reporting_item_name,
                d.deliverable_name AS linked_deliverable_name

            FROM {schema}.engagement_working_papers wp
            JOIN {schema}.engagements e
              ON e.id = wp.engagement_id
            JOIN {schema}.customers c
              ON c.id = e.customer_id
            LEFT JOIN public.users pu
              ON pu.id = wp.preparer_user_id
            LEFT JOIN public.users ru
              ON ru.id = wp.reviewer_user_id
            LEFT JOIN {schema}.engagement_reporting_items ri
              ON ri.id = wp.linked_reporting_item_id
            LEFT JOIN {schema}.engagement_deliverables d
              ON d.id = wp.linked_deliverable_id
            WHERE wp.company_id = %s
              AND wp.id = %s
            LIMIT 1
        """
        cur.execute(sql, (company_id, working_paper_id))
        return cur.fetchone()

    def list_engagement_working_papers(
        self,
        cur,
        company_id: int,
        *,
        customer_id: int = None,
        engagement_id: int = None,
        paper_section: str = None,
        paper_type: str = None,
        status: str = None,
        priority: str = None,
        mine_only: bool = False,
        current_user_id: int = None,
        q: str = None,
        limit: int = 100,
        offset: int = 0,
    ):
        schema = self.company_schema(company_id)

        sql = f"""
            SELECT
                wp.id,
                wp.company_id,
                wp.engagement_id,
                wp.paper_code,
                wp.paper_name,
                wp.paper_section,
                wp.paper_type,
                wp.status,
                wp.priority,
                wp.preparer_user_id,
                wp.reviewer_user_id,
                wp.due_date,
                wp.prepared_at,
                wp.reviewed_at,
                wp.cleared_at,
                wp.version_no,
                wp.document_count,
                wp.linked_reporting_item_id,
                wp.linked_deliverable_id,
                wp.notes,
                wp.review_notes,
                wp.is_active,
                wp.created_at,
                wp.updated_at,

                e.engagement_name,
                e.engagement_code,
                e.customer_id,
                c.name AS customer_name,

                CONCAT(
                    COALESCE(pu.first_name, ''),
                    CASE
                        WHEN pu.last_name IS NOT NULL AND pu.last_name <> ''
                        THEN ' ' || pu.last_name
                        ELSE ''
                    END
                ) AS preparer_user_name,

                CONCAT(
                    COALESCE(ru.first_name, ''),
                    CASE
                        WHEN ru.last_name IS NOT NULL AND ru.last_name <> ''
                        THEN ' ' || ru.last_name
                        ELSE ''
                    END
                ) AS reviewer_user_name,

                (
                    wp.due_date IS NOT NULL
                    AND wp.due_date < CURRENT_DATE
                    AND wp.status NOT IN ('reviewed', 'cleared', 'archived')
                ) AS is_overdue,

                (wp.status = 'blocked') AS is_blocked,

                (
                    %s IS NOT NULL
                    AND (
                        wp.preparer_user_id = %s
                        OR wp.reviewer_user_id = %s
                    )
                ) AS is_mine

            FROM {schema}.engagement_working_papers wp
            JOIN {schema}.engagements e
              ON e.id = wp.engagement_id
            JOIN {schema}.customers c
              ON c.id = e.customer_id
            LEFT JOIN public.users pu
              ON pu.id = wp.preparer_user_id
            LEFT JOIN public.users ru
              ON ru.id = wp.reviewer_user_id
            WHERE wp.company_id = %s
              AND wp.is_active = TRUE
              AND e.is_active = TRUE
              AND (%s IS NULL OR e.customer_id = %s)
              AND (%s IS NULL OR wp.engagement_id = %s)
              AND (%s IS NULL OR wp.paper_section = %s)
              AND (%s IS NULL OR wp.paper_type = %s)
              AND (%s IS NULL OR wp.status = %s)
              AND (%s IS NULL OR wp.priority = %s)
              AND (%s = FALSE OR (
                    (%s IS NOT NULL AND wp.preparer_user_id = %s)
                    OR (%s IS NOT NULL AND wp.reviewer_user_id = %s)
              ))
              AND (
                    %s IS NULL
                    OR %s = ''
                    OR (
                        COALESCE(c.name, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(e.engagement_name, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(e.engagement_code, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(wp.paper_name, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(wp.paper_code, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(wp.paper_section, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(wp.paper_type, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(pu.first_name, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(pu.last_name, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(ru.first_name, '') ILIKE ('%%' || %s || '%%')
                        OR COALESCE(ru.last_name, '') ILIKE ('%%' || %s || '%%')
                    )
              )
            ORDER BY
                is_overdue DESC,
                is_blocked DESC,
                CASE wp.priority
                    WHEN 'urgent' THEN 4
                    WHEN 'high' THEN 3
                    WHEN 'normal' THEN 2
                    WHEN 'low' THEN 1
                    ELSE 0
                END DESC,
                wp.due_date NULLS LAST,
                wp.updated_at DESC
            LIMIT %s
            OFFSET %s
        """

        q_params = (q, q, q, q, q, q, q, q, q, q, q, q, q)

        params = (
            current_user_id, current_user_id, current_user_id,
            company_id,
            customer_id, customer_id,
            engagement_id, engagement_id,
            paper_section, paper_section,
            paper_type, paper_type,
            status, status,
            priority, priority,
            True if mine_only else False,
            current_user_id, current_user_id,
            current_user_id, current_user_id,
            *q_params,
            max(1, min(int(limit or 100), 500)),
            max(0, int(offset or 0)),
        )

        cur.execute(sql, params)
        return cur.fetchall() or []

    def create_engagement_working_paper(
        self,
        cur,
        company_id: int,
        *,
        engagement_id: int,
        created_by_user_id: int = None,
        paper_code: str = None,
        paper_name: str,
        paper_section: str,
        paper_type: str = "working_paper",
        status: str = "not_started",
        priority: str = "normal",
        preparer_user_id: int = None,
        reviewer_user_id: int = None,
        due_date=None,
        prepared_at=None,
        reviewed_at=None,
        cleared_at=None,
        version_no: int = 1,
        document_count: int = 0,
        linked_reporting_item_id: int = None,
        linked_deliverable_id: int = None,
        notes: str = None,
        review_notes: str = None,
    ) -> int:
        schema = self.company_schema(company_id)

        sql = f"""
            INSERT INTO {schema}.engagement_working_papers (
                company_id,
                engagement_id,
                paper_code,
                paper_name,
                paper_section,
                paper_type,
                status,
                priority,
                preparer_user_id,
                reviewer_user_id,
                due_date,
                prepared_at,
                reviewed_at,
                cleared_at,
                version_no,
                document_count,
                linked_reporting_item_id,
                linked_deliverable_id,
                notes,
                review_notes,
                created_by_user_id,
                updated_by_user_id
            )
            VALUES (
                %s, %s, %s, %s, %s, %s, %s, %s,
                %s, %s, %s, %s, %s, %s,
                %s, %s, %s, %s, %s, %s,
                %s, %s
            )
            RETURNING id
        """
        cur.execute(
            sql,
            (
                company_id,
                engagement_id,
                paper_code,
                paper_name,
                paper_section,
                paper_type or "working_paper",
                status or "not_started",
                priority or "normal",
                preparer_user_id,
                reviewer_user_id,
                due_date,
                prepared_at,
                reviewed_at,
                cleared_at,
                max(1, int(version_no or 1)),
                max(0, int(document_count or 0)),
                linked_reporting_item_id,
                linked_deliverable_id,
                notes,
                review_notes,
                created_by_user_id,
                created_by_user_id,
            ),
        )
        row = cur.fetchone()
        return int(row["id"] if isinstance(row, dict) else row[0])

    def backfill_overdue_working_paper_escalations(self, cur, company_id: int):
        schema = self.company_schema(company_id)

        cur.execute(
            f"""
            INSERT INTO {schema}.engagement_escalations (
                company_id,
                engagement_id,
                source_type,
                source_id,
                escalation_type,
                severity,
                title,
                description,
                status,
                raised_by_user_id,
                assigned_to_user_id,
                due_date,
                is_active,
                created_at,
                updated_at
            )
            SELECT
                wp.company_id,
                wp.engagement_id,
                'working_paper' AS source_type,
                wp.id AS source_id,
                'deadline_risk' AS escalation_type,
                CASE
                    WHEN wp.due_date < CURRENT_DATE - INTERVAL '7 days' THEN 'high'
                    ELSE 'medium'
                END AS severity,
                CONCAT('Overdue working paper: ', wp.paper_name) AS title,
                CONCAT(
                    'Working paper ',
                    COALESCE(wp.paper_code, '#' || wp.id::text),
                    ' is overdue and still not completed.'
                ) AS description,
                'open' AS status,
                wp.preparer_user_id AS raised_by_user_id,
                wp.reviewer_user_id AS assigned_to_user_id,
                wp.due_date,
                TRUE,
                NOW(),
                NOW()
            FROM {schema}.engagement_working_papers wp
            WHERE wp.company_id = %s
            AND wp.is_active = TRUE
            AND wp.due_date IS NOT NULL
            AND wp.due_date < CURRENT_DATE
            AND wp.status NOT IN ('reviewed', 'cleared', 'archived')
            AND NOT EXISTS (
                SELECT 1
                FROM {schema}.engagement_escalations e
                WHERE e.company_id = wp.company_id
                    AND e.engagement_id = wp.engagement_id
                    AND e.source_type = 'working_paper'
                    AND e.source_id = wp.id
                    AND e.escalation_type = 'deadline_risk'
                    AND e.is_active = TRUE
                    AND e.status IN ('open', 'in_progress')
            )
            """,
            (company_id,),
        )

    def update_engagement_working_paper(
        self,
        cur,
        company_id: int,
        *,
        working_paper_id: int,
        updated_by_user_id: int = None,
        paper_code: str = None,
        paper_name: str = None,
        paper_section: str = None,
        paper_type: str = None,
        status: str = None,
        priority: str = None,
        preparer_user_id: int = None,
        reviewer_user_id: int = None,
        due_date=None,
        prepared_at=None,
        reviewed_at=None,
        cleared_at=None,
        version_no: int = None,
        document_count: int = None,
        linked_reporting_item_id: int = None,
        linked_deliverable_id: int = None,
        notes: str = None,
        review_notes: str = None,
        is_active: bool = None,
    ) -> int | None:
        schema = self.company_schema(company_id)

        sql = f"""
            UPDATE {schema}.engagement_working_papers
            SET
                paper_code = COALESCE(%s, paper_code),
                paper_name = COALESCE(%s, paper_name),
                paper_section = COALESCE(%s, paper_section),
                paper_type = COALESCE(%s, paper_type),
                status = COALESCE(%s, status),
                priority = COALESCE(%s, priority),
                preparer_user_id = COALESCE(%s, preparer_user_id),
                reviewer_user_id = COALESCE(%s, reviewer_user_id),
                due_date = COALESCE(%s, due_date),
                prepared_at = COALESCE(%s, prepared_at),
                reviewed_at = COALESCE(%s, reviewed_at),
                cleared_at = COALESCE(%s, cleared_at),
                version_no = COALESCE(%s, version_no),
                document_count = COALESCE(%s, document_count),
                linked_reporting_item_id = COALESCE(%s, linked_reporting_item_id),
                linked_deliverable_id = COALESCE(%s, linked_deliverable_id),
                notes = COALESCE(%s, notes),
                review_notes = COALESCE(%s, review_notes),
                is_active = COALESCE(%s, is_active),
                updated_by_user_id = %s,
                updated_at = NOW()
            WHERE company_id = %s
              AND id = %s
            RETURNING id
        """
        cur.execute(
            sql,
            (
                paper_code,
                paper_name,
                paper_section,
                paper_type,
                status,
                priority,
                preparer_user_id,
                reviewer_user_id,
                due_date,
                prepared_at,
                reviewed_at,
                cleared_at,
                max(1, int(version_no)) if version_no is not None else None,
                max(0, int(document_count)) if document_count is not None else None,
                linked_reporting_item_id,
                linked_deliverable_id,
                notes,
                review_notes,
                is_active,
                updated_by_user_id,
                company_id,
                working_paper_id,
            ),
        )
        row = cur.fetchone()
        if not row:
            return None
        return int(row["id"] if isinstance(row, dict) else row[0])

